def _load_nearby_eval_source_metadata(rulespec_file: Path) -> dict[str, object] | None:
    """Load source-metadata from a nearby eval workspace when present.

    When several workspaces share a parent directory (e.g. /tmp encode runs
    for siblings a, c, d under one eval root), pick the manifest whose
    citation maps to the same RuleSpec output path as `rulespec_file`. Falling
    back to the first alphabetical manifest mixes up sibling subsections —
    validate of c.yaml would silently load a/'s metadata and reject (c) for
    not covering (a)'s siblings.
    """
    rulespec_norm = _rulespec_file_normalized_target(rulespec_file)
    fallback: dict[str, object] | None = None
    for ancestor in rulespec_file.parents:
        eval_root = ancestor / "_eval_workspaces"
        if not eval_root.exists():
            continue
        for manifest_path in sorted(eval_root.glob("**/context-manifest.json")):
            try:
                payload = json.loads(manifest_path.read_text())
            except Exception:
                continue
            metadata = payload.get("source_metadata")
            if not isinstance(metadata, dict):
                continue
            if fallback is None:
                fallback = metadata
            if rulespec_norm is None:
                continue
            citation_raw = payload.get("citation")
            manifest_norms: list[tuple[str, ...]] = []
            for candidate in (
                citation_raw,
                metadata.get("requested_source"),
                metadata.get("corpus_citation_path"),
            ):
                if not isinstance(candidate, str):
                    continue
                candidate_norm = _citation_to_normalized_target(candidate)
                if candidate_norm is not None:
                    manifest_norms.append(candidate_norm)
            if rulespec_norm in manifest_norms:
                return metadata
    return fallback


def _load_applied_encoding_manifest_source_metadata(
    rulespec_file: Path,
    policy_repo_path: Path,
) -> dict[str, object] | None:
    """Load durable requested-source metadata from a generated apply manifest."""
    try:
        relative_rulespec = rulespec_file.resolve().relative_to(
            policy_repo_path.resolve()
        )
    except (OSError, ValueError):
        return None
    manifest_path = (
        policy_repo_path
        / _APPLIED_ENCODING_MANIFEST_DIR
        / relative_rulespec.with_suffix(".json")
    )
    if not manifest_path.exists():
        return None
    try:
        payload = json.loads(manifest_path.read_text())
    except (OSError, ValueError, json.JSONDecodeError):
        return None
    if not isinstance(payload, dict):
        return None
    source_metadata = payload.get("source_metadata")
    metadata: dict[str, object] = (
        dict(source_metadata) if isinstance(source_metadata, dict) else {}
    )
    citation = payload.get("citation")
    if isinstance(citation, str) and citation.strip():
        metadata.setdefault("requested_source", citation.strip())
    return metadata or None


def _requested_source_from_metadata(metadata: dict[str, object] | None) -> str | None:
    if not isinstance(metadata, dict):
        return None
    requested_source = metadata.get("requested_source")
    if not isinstance(requested_source, str):
        return None
    requested_source = requested_source.strip()
    return requested_source or None


def _rulespec_file_normalized_target(rulespec_file: Path) -> tuple[str, ...] | None:
    """Best-effort tuple of statute/regulations path parts for matching."""
    parts = list(rulespec_file.with_suffix("").parts)
    for idx, part in enumerate(parts):
        if part in {"statutes", "regulations", "policies"}:
            return tuple(p.lower() for p in parts[idx:] if p)
    return None


def _citation_to_normalized_target(citation: str) -> tuple[str, ...] | None:
    corpus_target = _corpus_citation_to_normalized_target(citation)
    if corpus_target is not None:
        return corpus_target
    try:
        parts = parse_usc_citation(citation)
    except Exception:
        return None
    if parts is None:
        return None
    pieces = ["statutes", parts.title, parts.section, *parts.fragments]
    return tuple(p.lower() for p in pieces if p)


def _corpus_citation_to_normalized_target(citation: str) -> tuple[str, ...] | None:
    """Map corpus citation paths to the corresponding RuleSpec file target.

    Eval metadata stores state and policy targets as corpus paths such as
    ``us-co/regulation/9-ccr-2503-6/3.606.3``. The generated RuleSpec file
    lands at ``regulations/9-ccr-2503-6/3.606.3.yaml``. Normalize both shapes
    before nearby metadata matching so unrelated workspaces are not used as a
    fallback.
    """
    candidate = citation.strip()
    if not candidate:
        return None
    target_ref = _parse_rulespec_target(candidate)
    if target_ref is not None:
        return _rulespec_relative_path_parts(target_ref.relative_path)
    parts = [part.strip().lower() for part in candidate.split("/") if part.strip()]
    if len(parts) < 3 or not (parts[0] == "us" or parts[0].startswith("us-")):
        return None
    class_part = parts[1]
    tail = parts[2:]
    if class_part in {"statute", "statutes"}:
        return tuple(
            ["statutes", *_normalized_corpus_tail_parts(parts[0], "statutes", tail)]
        )
    if class_part in {"regulation", "regulations"}:
        if parts[0] == "us":
            tail = _canonical_us_regulation_tail_for_normalization(tail)
        return tuple(
            [
                "regulations",
                *_normalized_corpus_tail_parts(parts[0], "regulations", tail),
            ]
        )
    if class_part in {"policy", "policies"}:
        return tuple(
            ["policies", *_normalized_corpus_tail_parts(parts[0], "policies", tail)]
        )
    return None


def _normalized_corpus_tail_parts(
    jurisdiction: str,
    root: str,
    tail: list[str],
) -> tuple[str, ...]:
    if not tail:
        return ()
    if _preserve_state_statute_dotted_leaf_for_normalization(jurisdiction, root, tail):
        return tuple(tail)
    if _preserve_dotted_leaf_filename_for_normalization(tail):
        return tuple(tail)
    leaf_segments = [part for part in tail[-1].split(".") if part]
    if not leaf_segments:
        return tuple(tail[:-1])
    return tuple([*tail[:-1], *leaf_segments])


def _preserve_dotted_leaf_filename_for_normalization(tail: list[str]) -> bool:
    if len(tail) < 2:
        return False
    return bool(
        re.fullmatch(r"\d+-ccr-\d+-\d+", tail[0], flags=re.IGNORECASE)
        and re.fullmatch(r"\d+(?:\.\d+)+", tail[-1])
    )


def _preserve_state_statute_dotted_leaf_for_normalization(
    jurisdiction: str,
    root: str,
    tail: list[str],
) -> bool:
    if jurisdiction != "us-co" or root != "statutes" or len(tail) < 2:
        return False
    if len(tail) == 2 and tail[0].isdigit():
        return bool(re.fullmatch(r"\d+(?:-\d+)+(?:\.\d+)+", tail[-1]))
    if not re.fullmatch(r"\d+(?:\.\d+)+", tail[-1]):
        return False
    return bool(re.fullmatch(r"\d+(?:-\d+)+(?:\.\d+)?", tail[-2]))


def _canonical_us_regulation_tail_for_normalization(tail: list[str]) -> list[str]:
    if not tail:
        return tail
    title = tail[0].strip()
    if title.isdigit():
        return [f"{title}-cfr", *tail[1:]]
    return tail


_SOURCE_CITATION_SEPARATOR_RE = re.compile(
    r"\s*(?:,|;|\b(?:and|or)\b)\s*",
    flags=re.IGNORECASE,
)
_USC_ABBREVIATION_RE = re.compile(
    r"(?<![A-Za-z])U\.?\s*S\.?\s*C\.?(?![A-Za-z])",
    flags=re.IGNORECASE,
)
_IRC_ABBREVIATION_RE = re.compile(
    r"(?<![A-Za-z])I\.?\s*R\.?\s*C\.?(?![A-Za-z])",
    flags=re.IGNORECASE,
)
_SOURCE_CITATION_RANGE_SUFFIX_RE = re.compile(
    r"(?<=\))\s*(?:-|through)\s*(?P<endpoint>(?:\([^)]+\))+)\s*$",
    flags=re.IGNORECASE,
)


def _source_citation_to_normalized_targets(
    source: str,
    *,
    context_source: str | None = None,
) -> tuple[tuple[str, ...], ...]:
    """Parse one RuleSpec source field into normalized citation targets.

    Rule sources commonly cite multiple provisions in one string and omit the
    USC title after the first citation, e.g. ``26 USC 24(b)(2), 24(h)(3)``.
    """
    context_targets = (
        _source_citation_fragment_to_normalized_targets(
            context_source,
            default_title=None,
            default_section=None,
        )
        if context_source
        else ()
    )
    context_target = context_targets[0] if context_targets else None
    current_title = (
        context_target[1] if context_target and len(context_target) >= 3 else None
    )
    current_section = (
        context_target[2] if context_target and len(context_target) >= 3 else None
    )

    targets: list[tuple[str, ...]] = []
    seen: set[tuple[str, ...]] = set()
    previous_fragment_had_target = False
    previous_raw_fragment: str | None = None
    for raw_fragment in _SOURCE_CITATION_SEPARATOR_RE.split(source):
        fragment_targets = _source_citation_fragment_to_normalized_targets(
            raw_fragment,
            default_title=current_title,
            default_section=current_section,
        )
        if (
            fragment_targets
            and not previous_fragment_had_target
            and targets
            and _source_citation_fragment_is_bare_relative_table_label_tail(
                raw_fragment,
                previous_raw_fragment,
            )
        ):
            previous_fragment_had_target = False
            previous_raw_fragment = raw_fragment
            continue
        previous_fragment_had_target = bool(fragment_targets)
        previous_raw_fragment = raw_fragment
        for target in fragment_targets:
            if len(target) >= 3:
                current_title = target[1]
                current_section = target[2]
            if target in seen:
                continue
            seen.add(target)
            targets.append(target)
    return tuple(targets)


def _source_citation_fragment_is_bare_relative_table_label_tail(
    fragment: str,
    previous_fragment: str | None,
) -> bool:
    cleaned = _clean_source_citation_fragment(fragment)
    if not cleaned:
        return False
    if _irc_source_fragment_to_usc_citation(cleaned) is not None:
        return False
    if re.match(r"^(?:§|section|subsection)\s+", cleaned, flags=re.IGNORECASE):
        return False
    if _looks_like_absolute_usc_source_fragment(cleaned):
        return False
    if previous_fragment is None:
        return False
    previous_cleaned = _clean_source_citation_fragment(previous_fragment)
    return bool(
        re.search(
            r"^applicable\s+percentage\s+for\s+sections?\s+"
            r"[0-9A-Za-z.-]+(?:\([^)]+\))*$",
            previous_cleaned,
            flags=re.IGNORECASE,
        )
    )


def _source_citation_fragment_to_normalized_targets(
    fragment: str,
    *,
    default_title: str | None,
    default_section: str | None,
) -> tuple[tuple[str, ...], ...]:
    cleaned = _clean_source_citation_fragment(fragment)
    if not cleaned:
        return ()

    range_match = _SOURCE_CITATION_RANGE_SUFFIX_RE.search(cleaned)
    if not range_match:
        target = _single_source_citation_fragment_to_normalized_target(
            cleaned,
            default_title=default_title,
            default_section=default_section,
        )
        return (target,) if target is not None else ()

    start_fragment = _SOURCE_CITATION_RANGE_SUFFIX_RE.sub("", cleaned).strip()
    start_target = _single_source_citation_fragment_to_normalized_target(
        start_fragment,
        default_title=default_title,
        default_section=default_section,
    )
    if start_target is None:
        return ()
    endpoint_target = _range_endpoint_normalized_target(
        start_target,
        range_match.group("endpoint"),
    )
    if endpoint_target is None or endpoint_target == start_target:
        return (start_target,)
    return (start_target, endpoint_target)


def _single_source_citation_fragment_to_normalized_target(
    fragment: str,
    *,
    default_title: str | None,
    default_section: str | None,
) -> tuple[str, ...] | None:
    irc_citation = _irc_source_fragment_to_usc_citation(fragment)
    if irc_citation is not None:
        return _citation_to_normalized_target(irc_citation)

    if _looks_like_absolute_usc_source_fragment(fragment):
        target = _citation_to_normalized_target(fragment)
        if target is not None:
            return target

    relative_citation = _relative_source_fragment_to_usc_citation(
        fragment,
        default_title=default_title,
        default_section=default_section,
    )
    if relative_citation is not None:
        return _citation_to_normalized_target(relative_citation)
    return None


def _looks_like_absolute_usc_source_fragment(fragment: str) -> bool:
    return bool(
        re.match(
            r"^(?:us:statutes?/|us/statutes?/|statutes?/|\d+\s+USC\b)",
            fragment,
            flags=re.IGNORECASE,
        )
    )


def _range_endpoint_normalized_target(
    start_target: tuple[str, ...],
    endpoint: str,
) -> tuple[str, ...] | None:
    endpoint_fragments = tuple(
        fragment.lower() for fragment in re.findall(r"\(([^)]+)\)", endpoint)
    )
    if not endpoint_fragments or len(start_target) <= 3:
        return None
    prefix_length = len(start_target) - len(endpoint_fragments)
    if prefix_length < 3:
        return None
    return start_target[:prefix_length] + endpoint_fragments


def _clean_source_citation_fragment(fragment: str) -> str:
    cleaned = fragment.strip()
    cleaned = re.sub(r"^(?:and|or)\s+", "", cleaned, flags=re.IGNORECASE)
    cleaned = cleaned.rstrip(".")
    cleaned = _USC_ABBREVIATION_RE.sub("USC", cleaned)
    cleaned = _IRC_ABBREVIATION_RE.sub("IRC", cleaned)
    return cleaned.strip()


def _irc_source_fragment_to_usc_citation(fragment: str) -> str | None:
    match = re.match(
        r"^IRC\s*(?:section|sec\.?|§)?\s*"
        r"(?P<section>[0-9A-Za-z.-]+)(?P<tail>(?:\([^)]+\))*)$",
        fragment,
        flags=re.IGNORECASE,
    )
    if match:
        return f"26 USC {match.group('section')}{match.group('tail')}"

    match = re.match(
        r"^(?:the\s+)?Internal\s+Revenue\s+Code\s+"
        r"(?:section|sec\.?|§)\s*"
        r"(?P<section>[0-9A-Za-z.-]+)(?P<tail>(?:\([^)]+\))*)$",
        fragment,
        flags=re.IGNORECASE,
    )
    if match:
        return f"26 USC {match.group('section')}{match.group('tail')}"

    match = re.match(
        r"^section\s+(?P<section>[0-9A-Za-z.-]+)"
        r"(?P<tail>(?:\([^)]+\))*)\s+of\s+(?:the\s+)?"
        r"(?:Internal\s+Revenue\s+Code|IRC)$",
        fragment,
        flags=re.IGNORECASE,
    )
    if match:
        return f"26 USC {match.group('section')}{match.group('tail')}"
    return None


def _relative_source_fragment_to_usc_citation(
    fragment: str,
    *,
    default_title: str | None,
    default_section: str | None,
) -> str | None:
    if not default_title:
        return None
    fragment = re.sub(
        r"^(?:§|section)\s+",
        "",
        fragment,
        flags=re.IGNORECASE,
    ).strip()
    fragment = re.sub(
        r"^subsection\s+",
        "",
        fragment,
        flags=re.IGNORECASE,
    ).strip()

    match = re.match(
        r"^(?P<section>[0-9A-Za-z.-]+)(?P<tail>(?:\([^)]+\))*)$",
        fragment,
    )
    if match:
        return f"{default_title} USC {match.group('section')}{match.group('tail')}"

    if not default_section:
        return None
    match = re.match(r"^(?P<tail>(?:\([^)]+\))+)$", fragment)
    if match:
        return f"{default_title} USC {default_section}{match.group('tail')}"
    return None


def _source_metadata_sets_target_symbol(
    source_metadata: dict[str, object] | None, symbol_name: str
) -> bool:
    """Return whether source metadata declares a `sets` relation for the symbol."""
    if not isinstance(source_metadata, dict):
        return False
    relations = source_metadata.get("relations")
    if not isinstance(relations, list):
        return False

    for relation in relations:
        if not isinstance(relation, dict):
            continue
        if str(relation.get("relation", "")).lower() != "sets":
            continue
        target = str(relation.get("target", ""))
        _, _, target_symbol = target.partition("#")
        if target_symbol == symbol_name:
            return True
    return False


def _source_metadata_jurisdiction(
    source_metadata: dict[str, object] | None,
) -> str | None:
    """Return a jurisdiction code from source metadata when present."""
    if not isinstance(source_metadata, dict):
        return None
    relations = source_metadata.get("relations")
    if not isinstance(relations, list):
        return None

    for relation in relations:
        if not isinstance(relation, dict):
            continue
        jurisdiction = relation.get("jurisdiction")
        if jurisdiction is None:
            continue
        jurisdiction_str = str(jurisdiction).strip()
        if jurisdiction_str:
            return jurisdiction_str
    return None


def _infer_us_state_code_from_rulespec_path(
    rulespec_file: Path,
    rulespec_source_content: str = "",
) -> str | None:
    """Infer a US state code from canonical RuleSpec repo paths or legal ids."""
    path_text = rulespec_file.as_posix().lower()
    match = re.search(r"(?:^|/)rulespec-us-([a-z]{2})(?:/|$)", path_text)
    if match:
        return match.group(1).upper()

    source_text = rulespec_source_content.lower()
    match = re.search(r"\bus-([a-z]{2}):", source_text)
    if match:
        return match.group(1).upper()
    return None


def _default_snap_utility_type_for_rule(rule_name: str | None) -> str | None:
    return {
        "snap_standard_utility_allowance": "SUA",
        "snap_limited_utility_allowance": "BUA",
        "snap_individual_utility_allowance": "TUA",
    }.get(str(rule_name or ""))


def _default_snap_utility_region_for_jurisdiction(
    jurisdiction: str | None,
) -> str | None:
    if not jurisdiction:
        return None
    normalized = jurisdiction.strip().upper()
    if normalized == "NY":
        return "NY_NYC"
    return normalized


def _policyengine_us_snap_input_aliases(inputs: dict[str, Any]) -> dict[str, Any]:
    """Derive standard SNAP PE inputs from source-document input names."""

    def input_value(key: str) -> Any | None:
        if key in inputs:
            return inputs[key]
        for input_key, value in inputs.items():
            key_text = str(input_key)
            if (
                key_text.endswith(f"#input.{key}")
                or key_text.endswith(f"#{key}")
                or key_text.endswith(f".{key}")
            ):
                return value
        return None

    def nested_input_values(key: str) -> list[Any]:
        matches: list[Any] = []
        stack = list(inputs.values())
        while stack:
            value = stack.pop()
            if isinstance(value, dict):
                for nested_key, nested_value in value.items():
                    nested_key_text = str(nested_key)
                    if (
                        nested_key_text == key
                        or nested_key_text.endswith(f"#input.{key}")
                        or nested_key_text.endswith(f"#{key}")
                        or nested_key_text.endswith(f".{key}")
                    ):
                        matches.append(nested_value)
                    elif isinstance(nested_value, (dict, list)):
                        stack.append(nested_value)
            elif isinstance(value, list):
                stack.extend(value)
        return matches

    def numeric_value(key: str) -> float | None:
        value = input_value(key)
        if value is None:
            return None
        try:
            return float(value)
        except (TypeError, ValueError):
            return None

    aliases: dict[str, Any] = {}
    earned = numeric_value("employee_wages_received")
    if earned is not None:
        aliases.setdefault("snap_earned_income", earned)
        aliases.setdefault("snap_gross_income", earned)

    countable_earned = numeric_value("snap_countable_earned_income")
    countable_unearned = numeric_value("snap_countable_unearned_income")
    work_supplementation = numeric_value("work_supplementation_earned_income")
    if countable_earned is not None:
        aliases.setdefault(
            "snap_earned_income",
            max(0.0, countable_earned - (work_supplementation or 0.0)),
        )
    if countable_unearned is not None:
        aliases.setdefault("snap_unearned_income", countable_unearned)
    if countable_earned is not None or countable_unearned is not None:
        aliases.setdefault(
            "snap_gross_income",
            (countable_earned or 0.0) + (countable_unearned or 0.0),
        )

    monthly_household_income = numeric_value("snap_monthly_household_income")
    if monthly_household_income is not None:
        aliases.setdefault("snap_gross_income", monthly_household_income)

    standard_deduction = numeric_value("snap_standard_deduction")
    if standard_deduction is not None:
        aliases.setdefault("snap_standard_deduction", standard_deduction)

    elderly_or_disabled_member = input_value("snap_member_is_elderly_or_disabled")
    if elderly_or_disabled_member is None:
        nested_elderly_or_disabled = nested_input_values(
            "snap_member_is_elderly_or_disabled"
        )
        if nested_elderly_or_disabled:
            elderly_or_disabled_member = any(
                bool(item) for item in nested_elderly_or_disabled
            )
    if elderly_or_disabled_member is not None:
        aliases.setdefault(
            "snap_household_has_elderly_or_disabled_member",
            bool(elderly_or_disabled_member),
        )
        aliases.setdefault(
            "has_usda_elderly_disabled", bool(elderly_or_disabled_member)
        )

    shelter_cost = numeric_value("household_shelter_costs_incurred")
    if shelter_cost is None:
        shelter_cost = numeric_value("snap_allowable_shelter_costs")
    if shelter_cost is not None:
        aliases.setdefault("housing_cost", shelter_cost)
        aliases.setdefault("snap_utility_allowance_type", "NONE")

    deduction_aliases = {
        "dependent_care_deduction": "snap_dependent_care_deduction",
        "child_support_deduction": "snap_child_support_deduction",
        "medical_deduction": "snap_excess_medical_expense_deduction",
        "excess_shelter_deduction": "snap_excess_shelter_expense_deduction",
    }
    for source_key, alias_key in deduction_aliases.items():
        deduction_value = numeric_value(source_key)
        if deduction_value is not None:
            aliases.setdefault(alias_key, deduction_value)

    heating_or_cooling = bool(
        input_value(
            "household_incurred_or_anticipated_heating_or_cooling_costs_separate_from_rent_or_mortgage"
        )
    )
    if heating_or_cooling:
        aliases["snap_utility_allowance_type"] = "SUA"
    elif any(
        str(key).startswith("household_pays_") or "#input.household_pays_" in str(key)
        for key in inputs
    ):
        non_heating_cooling_utility_keys = (
            "household_pays_electricity_utility_cost",
            "household_pays_water_utility_cost",
            "household_pays_sewer_utility_cost",
            "household_pays_trash_utility_cost",
            "household_pays_cooking_fuel_utility_cost",
        )
        non_heating_cooling_count = sum(
            1 for key in non_heating_cooling_utility_keys if input_value(key)
        )
        aliases.setdefault(
            "snap_utility_allowance_type",
            "LUA" if non_heating_cooling_count >= 2 else "NONE",
        )

    return {key: value for key, value in aliases.items() if key not in inputs}


def _policyengine_expected_float(expected: Any) -> float:
    """Normalize RuleSpec expected values for numeric PE result comparison."""
    if isinstance(expected, str):
        normalized = expected.strip().lower()
        if normalized == "holds":
            return 1.0
        if normalized == "not_holds":
            return 0.0
    return float(expected)


def _normalize_us_tax_filing_status(value: Any) -> str:
    """Normalize Axiom/RuleSpec filing-status test inputs to PE-US enum keys."""
    numeric_statuses = {
        0: "SINGLE",
        1: "JOINT",
        2: "SEPARATE",
        3: "HEAD_OF_HOUSEHOLD",
        4: "SURVIVING_SPOUSE",
    }
    if isinstance(value, int) and not isinstance(value, bool):
        return numeric_statuses.get(value, "SINGLE")
    value_text = str(value or "SINGLE").strip().upper()
    if value_text.isdigit():
        return numeric_statuses.get(int(value_text), "SINGLE")
    aliases = {
        "MARRIED_FILING_JOINTLY": "JOINT",
        "MARRIED JOINT": "JOINT",
        "MARRIED_FILING_SEPARATELY": "SEPARATE",
        "MARRIED SEPARATE": "SEPARATE",
        "HEAD OF HOUSEHOLD": "HEAD_OF_HOUSEHOLD",
        "HOH": "HEAD_OF_HOUSEHOLD",
        "QUALIFYING_SURVIVING_SPOUSE": "SURVIVING_SPOUSE",
    }
    return aliases.get(value_text, value_text if value_text else "SINGLE")


def _tax_unit_member_aged_flags(inputs: dict[str, Any]) -> list[bool]:
    """Return explicit aged flags from a RuleSpec member_of_tax_unit input."""
    members = inputs.get("member_of_tax_unit")
    if isinstance(members, bool):
        return [members]
    if not isinstance(members, list):
        members = []
        for key, value in inputs.items():
            key_text = str(key).lower()
            if (
                "#relation." in key_text
                and key_text.rsplit("#relation.", 1)[1].endswith("member_of_tax_unit")
                and isinstance(value, list)
            ):
                members = value
                break
    if not isinstance(members, list):
        return []
    aged_flags: list[bool] = []
    for member in members:
        if isinstance(member, bool):
            aged_flags.append(member)
            continue
        if not isinstance(member, dict):
            continue
        explicit_aged = ValidatorPipeline._rulespec_test_input_value(
            member, "is_aged_65_or_over"
        )
        if explicit_aged is not None:
            aged_flags.append(bool(explicit_aged))
            continue
        age = ValidatorPipeline._rulespec_test_input_value(member, "age")
        with contextlib.suppress(TypeError, ValueError):
            aged_flags.append(int(age) >= 65)
            continue
        aged_flags.append(False)
    return aged_flags


def _policyengine_period_string(value: Any, fallback: str = "2024-01") -> str:
    """Normalize RuleSpec test period values to a PE scenario period string."""
    if isinstance(value, dict):
        start = value.get("start") or value.get("date")
        if start:
            start_text = str(start)
            if value.get("period_kind") == "month" and len(start_text) >= 7:
                return start_text[:7]
            if len(start_text) >= 4:
                return start_text[:4]
        return fallback
    if value is None:
        return fallback
    value_text = str(value)
    if not value_text:
        return fallback
    return value_text


def extract_grounding_values(content: str) -> list[tuple[int, str, float]]:
    """Extract grounded numeric values from RuleSpec definitions."""
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if (
            isinstance(payload, dict)
            and payload.get("format") == "rulespec/v1"
            and isinstance(payload.get("rules"), list)
        ):
            values: list[tuple[int, str, float]] = []
            selector_table_keys = _rulespec_index_selector_keys(payload["rules"])
            for rule in payload["rules"]:
                if not isinstance(rule, dict):
                    continue
                rule_name = str(rule.get("name") or "").strip()
                versions = rule.get("versions")
                if not isinstance(versions, list):
                    continue
                for version in versions:
                    if not isinstance(version, dict):
                        continue
                    formula = version.get("formula")
                    if isinstance(formula, (int, float)) and not isinstance(
                        formula, bool
                    ):
                        value = float(formula)
                        if value not in GROUNDING_ALLOWED_VALUES:
                            values.append((1, str(formula), value))
                    elif isinstance(formula, str):
                        values.extend(
                            _extract_formula_grounding_values(
                                1,
                                formula,
                                structural_selector_keys=(
                                    selector_table_keys.get(rule_name)
                                    if _is_structural_selector_rule(rule)
                                    else None
                                ),
                            )
                        )
                    table_values = version.get("values")
                    if isinstance(table_values, dict):
                        for table_value in table_values.values():
                            extracted = _numeric_rule_value(table_value)
                            if extracted is None:
                                continue
                            raw, value = extracted
                            if value not in GROUNDING_ALLOWED_VALUES:
                                values.append((1, raw, value))
            return values

    return []


def _numeric_rule_value(value: Any) -> tuple[str, float] | None:
    """Return a display string and numeric value for a YAML scalar."""
    if isinstance(value, bool) or value is None:
        return None
    if isinstance(value, (int, float)):
        return str(value), float(value)
    if isinstance(value, str) and _DIRECT_SCALAR_VALUE_PATTERN.fullmatch(value.strip()):
        raw = value.strip()
        return raw, float(raw.replace(",", ""))
    return None


def _extract_formula_grounding_values(
    line_number: int,
    formula_text: str,
    structural_selector_keys: set[str] | None = None,
) -> list[tuple[int, str, float]]:
    """Extract numeric literals from a formula expression or formula line."""
    cleaned = formula_text.split("#", 1)[0]
    cleaned = GROUNDING_DATE_PATTERN.sub(" ", cleaned)

    values: list[tuple[int, str, float]] = []
    for match in GROUNDING_FORMULA_NUMBER_PATTERN.finditer(cleaned):
        raw = match.group(1).replace(",", "")
        start, end = match.span(1)
        if raw == "0.5" and _is_half_up_rounding_expression(cleaned):
            continue
        if _is_structural_table_key_literal(cleaned, raw, span=(start, end)):
            continue
        if _is_structural_table_index_clamp_literal(
            cleaned,
            raw,
            span=(start, end),
        ):
            continue
        if _is_structural_mapping_key_literal(cleaned, raw, span=(start, end)):
            continue
        if _is_structural_schedule_index_literal(cleaned, raw, span=(start, end)):
            continue
        if _is_structural_enum_index_literal(cleaned, raw, span=(start, end)):
            continue
        if _is_structural_selector_result_literal(
            cleaned,
            raw,
            structural_selector_keys,
            span=(start, end),
        ):
            continue
        with contextlib.suppress(ValueError):
            value = float(raw)
            if value not in GROUNDING_ALLOWED_VALUES:
                values.append((line_number, raw, value))
    return values


def _is_structural_selector_rule(rule: dict[str, Any]) -> bool:
    if str(rule.get("dtype") or "").strip().lower() != "integer":
        return False
    name = str(rule.get("name") or "").strip().lower()
    return bool(re.search(r"(?:^|_)(?:band|bracket|tier|index)(?:_|$)", name))


def _rulespec_index_selector_keys(rules: list[Any]) -> dict[str, set[str]]:
    selector_keys: dict[str, set[str]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        index_names = _rulespec_indexed_by_names(rule.get("indexed_by"))
        if len(index_names) != 1:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        table_keys: set[str] = set()
        for version in versions:
            if not isinstance(version, dict):
                continue
            table_values = version.get("values")
            if not isinstance(table_values, dict):
                continue
            for key in table_values:
                normalized_key = _structural_integer_key(key)
                if normalized_key is not None:
                    table_keys.add(normalized_key)
        if table_keys:
            selector_name = next(iter(index_names))
            selector_keys.setdefault(selector_name, set()).update(table_keys)
    return selector_keys


def _structural_integer_key(value: Any) -> str | None:
    if isinstance(value, bool):
        return None
    if isinstance(value, int):
        return str(value)
    if isinstance(value, float) and value.is_integer():
        return str(int(value))
    if isinstance(value, str) and re.fullmatch(r"-?\d+(?:\.0+)?", value.strip()):
        numeric_value = float(value.strip())
        if numeric_value.is_integer():
            return str(int(numeric_value))
    return None


def _is_half_up_rounding_expression(expression: str) -> bool:
    """Return True when an expression uses the standard half-up rounding offset."""
    compact = re.sub(r"\s+", "", expression)
    return _call_body_contains_any(compact, "floor", ("+0.5", "0.5+")) or (
        _call_body_contains_any(compact, "ceil", ("-0.5", "0.5-"))
    )


def _is_half_up_rounding_helper_scalar(symbol_name: str, value: float) -> bool:
    """Return True when a named scalar only defines the standard half-up offset."""
    if value != 0.5:
        return False
    normalized = symbol_name.lower()
    if "half_increment" in normalized:
        return True
    return "half_up" in normalized and (
        "rounding" in normalized or "offset" in normalized
    )


def _is_structural_table_key_literal(
    expression: str,
    literal: str,
    *,
    span: tuple[int, int] | None = None,
) -> bool:
    """Return true when a small integer only selects a parameter-table row."""
    if literal in _EMBEDDED_SCALAR_ALLOWED_VALUES:
        return False
    if not re.fullmatch(r"\d+(?:\.0+)?", literal):
        return False
    with contextlib.suppress(ValueError):
        numeric_value = float(literal)
        if not numeric_value.is_integer() or not (0 <= int(numeric_value) <= 20):
            return False
    if span is not None:
        start, end = span
        left = expression[:start].rstrip(" \t")
        right = expression[end:].lstrip(" \t")
        return bool(left.endswith("[") and right.startswith("]"))
    return bool(
        re.search(
            rf"\[[ \t]*{re.escape(literal)}[ \t]*\]",
            expression,
        )
    )


def _is_structural_table_index_clamp_literal(
    expression: str,
    literal: str,
    *,
    span: tuple[int, int] | None = None,
) -> bool:
    """Return true when a small integer only clamps an indexed table lookup."""
    if not _is_small_structural_integer_literal(literal):
        return False
    if span is None:
        return bool(
            re.search(
                rf"\[[^\]]*\b(?:min|max)\s*\([^\]]*\b{re.escape(literal)}\b[^\]]*\)",
                expression,
            )
        )

    bracket_span = _enclosing_square_bracket_span(expression, span)
    if bracket_span is None:
        return False
    bracket_start, bracket_end = bracket_span
    call_name = _enclosing_function_call_name(
        expression,
        span,
        search_start=bracket_start + 1,
    )
    if call_name not in {"min", "max"}:
        return False
    start, end = span
    inner_before = expression[bracket_start + 1 : start].lower()
    inner_after = expression[end:bracket_end].lower()

    before = inner_before.rstrip()
    after = inner_after.lstrip()
    starts_argument = before.endswith((",", "("))
    ends_argument = after.startswith((",", ")"))
    return starts_argument and ends_argument


def _is_structural_mapping_key_literal(
    expression: str,
    literal: str,
    *,
    span: tuple[int, int] | None = None,
) -> bool:
    """Return true when a small integer is only a match/map arm key."""
    if not _is_small_structural_integer_literal(literal):
        return False
    if span is not None:
        _start, end = span
        return expression[end:].lstrip().startswith("=>")
    return bool(re.search(rf"\b{re.escape(literal)}\s*=>", expression))


def _is_small_structural_integer_literal(literal: str) -> bool:
    if literal in _EMBEDDED_SCALAR_ALLOWED_VALUES:
        return False
    if not re.fullmatch(r"\d+(?:\.0+)?", literal):
        return False
    with contextlib.suppress(ValueError):
        numeric_value = float(literal)
        return numeric_value.is_integer() and 0 <= int(numeric_value) <= 20
    return False


def _enclosing_square_bracket_span(
    expression: str,
    span: tuple[int, int],
) -> tuple[int, int] | None:
    start, end = span
    bracket_start = expression.rfind("[", 0, start)
    bracket_end = expression.find("]", end)
    if bracket_start == -1 or bracket_end == -1:
        return None
    if expression.rfind("]", 0, start) > bracket_start:
        return None
    if expression.find("[", end, bracket_end) != -1:
        return None
    return bracket_start, bracket_end


def _enclosing_function_call_name(
    expression: str,
    span: tuple[int, int],
    *,
    search_start: int = 0,
) -> str | None:
    start, _end = span
    stack: list[int] = []
    for index in range(search_start, start):
        char = expression[index]
        if char == "(":
            stack.append(index)
        elif char == ")" and stack:
            stack.pop()
    if not stack:
        return None
    call_start = stack[-1]
    prefix = expression[search_start:call_start]
    match = re.search(r"([A-Za-z_]\w*)\s*$", prefix)
    if match is None:
        return None
    return match.group(1).lower()


def _is_structural_selector_result_literal(
    expression: str,
    literal: str,
    selector_keys: set[str] | None,
    *,
    span: tuple[int, int] | None = None,
) -> bool:
    """Return true when an integer is only a generated table selector key."""
    if not selector_keys or literal in _EMBEDDED_SCALAR_ALLOWED_VALUES:
        return False
    if not re.fullmatch(r"\d+(?:\.0+)?", literal):
        return False
    with contextlib.suppress(ValueError):
        numeric_value = float(literal)
        if not numeric_value.is_integer() or not (0 <= int(numeric_value) <= 20):
            return False
        if str(int(numeric_value)) not in selector_keys:
            return False
    if span is not None:
        start, end = span
        before = expression[:start].rstrip()
        after = expression[end:].lstrip()
        return bool(
            before.endswith(":")
            and (not after or re.match(r"else\b", after) is not None)
        )
    normalized = re.sub(r"\s+", " ", expression)
    return bool(
        re.search(rf":\s*{re.escape(literal)}\s+(?:else\b|$)", normalized)
        or re.search(rf"(?:^|\s)else\s*:\s*{re.escape(literal)}\s*$", normalized)
    )


def _is_structural_schedule_index_literal(
    expression: str,
    literal: str,
    *,
    span: tuple[int, int] | None = None,
) -> bool:
    """Return True when a small integer only serves as a schedule index."""
    if literal in _EMBEDDED_SCALAR_ALLOWED_VALUES:
        return False
    if not re.fullmatch(r"\d+(?:\.0+)?", literal):
        return False
    with contextlib.suppress(ValueError):
        numeric_value = float(literal)
        if not numeric_value.is_integer() or not (4 <= int(numeric_value) <= 8):
            return False
    if not re.search(rf"\b{_SCHEDULE_INDEX_NAME_PATTERN}\b", expression):
        return False

    if span is not None:
        start, end = span
        before = expression[:start]
        after = expression[end:]
        return bool(
            re.search(
                rf"\b{_SCHEDULE_INDEX_NAME_PATTERN}\s*(?:==|>=|>|<=|<)\s*$",
                before,
            )
            or re.match(
                rf"\s*(?:==|>=|>|<=|<)\s*{_SCHEDULE_INDEX_NAME_PATTERN}\b",
                after,
            )
            or re.search(
                rf"(?:\(\s*)?{_SCHEDULE_INDEX_NAME_PATTERN}\s*-\s*$",
                before,
            )
            or (
                re.search(
                    rf"\bmatch\s+{_SCHEDULE_INDEX_NAME_PATTERN}\s*:",
                    expression,
                )
                and re.match(r"\s*=>", after)
            )
        )

    normalized = re.sub(r"\s+", " ", expression)
    comparison_pattern = re.compile(
        rf"\b{_SCHEDULE_INDEX_NAME_PATTERN}\s*(?:==|>=|>|<=|<)\s*{re.escape(literal)}\b"
    )
    delta_pattern = re.compile(
        rf"(?:\(\s*)?{_SCHEDULE_INDEX_NAME_PATTERN}\s*-\s*{re.escape(literal)}(?:\s*\))?"
    )
    match_arm_pattern = re.compile(rf"\b{re.escape(literal)}\s*=>")
    return bool(
        comparison_pattern.search(normalized)
        or delta_pattern.search(normalized)
        or (
            re.search(
                rf"\bmatch\s+{_SCHEDULE_INDEX_NAME_PATTERN}\s*:",
                normalized,
            )
            and match_arm_pattern.search(normalized)
        )
    )


def _is_structural_enum_index_literal(
    expression: str,
    literal: str,
    *,
    span: tuple[int, int] | None = None,
) -> bool:
    """Return True when a small integer only serves as an internal enum code."""
    if literal in _EMBEDDED_SCALAR_ALLOWED_VALUES:
        return False
    if not re.fullmatch(r"\d+(?:\.0+)?", literal):
        return False
    with contextlib.suppress(ValueError):
        numeric_value = float(literal)
        if not numeric_value.is_integer() or not (0 <= int(numeric_value) <= 20):
            return False
    if not re.search(rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\b", expression):
        return False

    if span is not None:
        start, end = span
        before = expression[:start]
        after = expression[end:]
        return bool(
            re.search(
                rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*(?:==|!=|>=|>|<=|<)\s*$",
                before,
            )
            or re.match(
                rf"\s*(?:==|!=|>=|>|<=|<)\s*{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\b",
                after,
            )
            or (
                re.search(
                    rf"\bmatch\s+{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*:",
                    expression,
                )
                and re.match(r"\s*=>", after)
            )
        )

    normalized = re.sub(r"\s+", " ", expression)
    comparison_pattern = re.compile(
        rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*(?:==|!=|>=|>|<=|<)\s*{re.escape(literal)}\b"
    )
    match_arm_pattern = re.compile(rf"\b{re.escape(literal)}\s*=>")
    return bool(
        comparison_pattern.search(normalized)
        or (
            re.search(
                rf"\bmatch\s+{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*:",
                normalized,
            )
            and match_arm_pattern.search(normalized)
        )
    )


def _is_structural_schedule_index_helper(name: str, value: float) -> bool:
    """Return True when a scalar helper only labels a schedule row index."""
    if not value.is_integer() or not (4 <= int(value) <= 8):
        return False
    normalized_name = name.lower()
    if "or_more" in normalized_name:
        return False
    if "threshold" in normalized_name and int(value) >= 5:
        return False
    index = int(value)
    word = {
        4: "four",
        5: "five",
        6: "six",
        7: "seven",
        8: "eight",
    }.get(index)
    return bool(
        re.search(rf"(?:^|_)size_{index}(?:_|$)", normalized_name)
        or re.search(rf"(?:^|_)household_size_{index}(?:_|$)", normalized_name)
        or re.search(rf"(?:^|_)unit_size_{index}(?:_|$)", normalized_name)
        or re.search(
            rf"(?:^|_){word}_person_(?:household_)?size(?:_|$)", normalized_name
        )
        or re.search(rf"(?:^|_){word}_person_unit_size(?:_|$)", normalized_name)
        or re.search(rf"(?:^|_){word}_person_spm_unit_size(?:_|$)", normalized_name)
        or re.search(rf"(?:^|_)size_row_{index}(?:_|$)", normalized_name)
        or re.search(rf"(?:^|_)household_size_row_{index}(?:_|$)", normalized_name)
        or re.search(rf"(?:^|_)unit_size_row_{index}(?:_|$)", normalized_name)
        or (
            word is not None
            and re.search(rf"(?:^|_)size_{word}(?:_|$)", normalized_name)
        )
        or (
            word is not None
            and re.search(rf"(?:^|_)household_size_{word}(?:_|$)", normalized_name)
        )
        or (
            word is not None
            and re.search(rf"(?:^|_)unit_size_{word}(?:_|$)", normalized_name)
        )
    )


def _call_body_contains_any(
    compact_expression: str,
    function_name: str,
    needles: tuple[str, ...],
) -> bool:
    token = f"{function_name}("
    search_start = 0
    while True:
        call_start = compact_expression.find(token, search_start)
        if call_start == -1:
            return False

        index = call_start + len(token)
        depth = 1
        body_chars: list[str] = []
        while index < len(compact_expression) and depth > 0:
            char = compact_expression[index]
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0:
                    break
            body_chars.append(char)
            index += 1

        if any(needle in "".join(body_chars) for needle in needles):
            return True

        search_start = call_start + 1


def extract_numbers_from_text(text: str) -> set[float]:
    """Extract numeric values from embedded statute text."""
    original_text = text
    text = _clean_source_text_for_numeric_extraction(text)
    schedule_occurrences, text = _extract_collapsed_schedule_row_occurrences(text)
    numbers = set()
    occupied_spans: list[tuple[int, int]] = []
    numbers.update(schedule_occurrences)

    for match in re.finditer(
        r"\b(?:age|aged)\s+(\d{1,3})(?=\b)", original_text, re.IGNORECASE
    ):
        with contextlib.suppress(ValueError):
            numbers.add(float(match.group(1)))

    for span, value in _iter_normalized_special_numeric_matches(text):
        numbers.add(value)
        occupied_spans.append(span)
    numbers.update(_extract_percentage_context_values(text))
    for span, value in _iter_standalone_fraction_word_matches(text):
        if _span_overlaps(span, occupied_spans):
            continue
        numbers.add(value)
        occupied_spans.append(span)
    for span, value in _iter_cardinal_word_number_matches(text):
        if _span_overlaps(span, occupied_spans):
            continue
        numbers.add(value)

    for match in SOURCE_TEXT_NUMBER_PATTERN.finditer(text):
        if _span_overlaps(match.span(1), occupied_spans):
            continue
        raw = match.group(1).replace(",", "")
        with contextlib.suppress(ValueError):
            numbers.add(float(raw))

    for match in _ORDINAL_NUMBER_PATTERN.finditer(text):
        with contextlib.suppress(ValueError):
            numbers.add(float(match.group(1)))

    for match in _ORDINAL_WORD_PATTERN.finditer(text):
        numbers.add(_ORDINAL_WORD_VALUES[match.group(1).lower()])

    for glyph, value in _UNICODE_FRACTION_VALUES.items():
        if glyph in text:
            numbers.add(value)

    text_lower = text.lower()
    for match in _CARDINAL_WORD_PATTERN.finditer(text_lower):
        numbers.add(_CARDINAL_WORD_VALUES[match.group(1)])

    return numbers


def _ordinal_is_calendar_day_reference(text: str, end_index: int, value: float) -> bool:
    """Return True when an ordinal is functioning as a calendar day before a month name."""
    if not value.is_integer() or not (1 <= value <= 31):
        return False
    trailing = text[end_index:]
    return bool(re.match(rf"\s+{_MONTH_NAME_PATTERN.pattern}", trailing, re.IGNORECASE))


def _iter_normalized_special_numeric_matches(
    text: str,
) -> list[tuple[tuple[int, int], float]]:
    """Return normalized special-case numeric matches like percentages, pence, and table values."""
    matches: list[tuple[tuple[int, int], float]] = []
    fraction_chars = "".join(re.escape(glyph) for glyph in _UNICODE_FRACTION_VALUES)

    for match in re.finditer(
        rf"\b(?:(?P<whole>{_CARDINAL_WORD_SEQUENCE})\s+and\s+)?"
        rf"(?P<fraction>{_FRACTION_WORD_PATTERN})\s+"
        r"(?:percent|per\s*cent(?:um)?)\b",
        text,
        re.IGNORECASE,
    ):
        whole = _parse_cardinal_word_sequence(match.group("whole") or "") or 0
        fraction = _parse_fraction_word(match.group("fraction"))
        if fraction is None:
            continue
        matches.append((match.span(), (whole + fraction) / 100))

    for match in re.finditer(
        rf"\b(?:(?P<whole>{_CARDINAL_WORD_SEQUENCE})\s+and\s+)?"
        rf"(?P<numerator>{_CARDINAL_WORD_SEQUENCE})\s+"
        r"one[-\s]+hundredths?\s+"
        r"(?:percent|per\s*cent(?:um)?)\b",
        text,
        re.IGNORECASE,
    ):
        whole = _parse_cardinal_word_sequence(match.group("whole") or "")
        numerator = _parse_cardinal_word_sequence(match.group("numerator"))
        if numerator is None:
            continue
        matches.append((match.span(), ((whole or 0) + numerator / 100) / 100))

    for match in re.finditer(
        rf"(-?[\d,]+)\s*([{fraction_chars}])(?:\s+|-)(?:percent|per\s*cent(?:um)?)",
        text,
        re.IGNORECASE,
    ):
        with contextlib.suppress(ValueError):
            whole = float(match.group(1).replace(",", ""))
            fraction = _UNICODE_FRACTION_VALUES[match.group(2)]
            sign = -1 if whole < 0 else 1
            matches.append((match.span(), (whole + sign * fraction) / 100))

    for match in re.finditer(
        r"(-?[\d,]+)\s+(\d+)\s*/\s*(\d+)"
        r"(?:\s+|-)(?:percent|per\s*cent(?:um)?)",
        text,
        re.IGNORECASE,
    ):
        with contextlib.suppress(ValueError, ZeroDivisionError):
            whole = float(match.group(1).replace(",", ""))
            numerator = float(match.group(2).replace(",", ""))
            denominator = float(match.group(3).replace(",", ""))
            sign = -1 if whole < 0 else 1
            matches.append(
                (match.span(), (whole + sign * numerator / denominator) / 100)
            )

    for pattern in (
        re.compile(
            r"(\d+(?:\.\d+)?)(?:\s+|-)(?:percent|per\s*cent(?:um)?)",
            re.IGNORECASE,
        ),
        re.compile(r"(\d+(?:\.\d+)?)\s*%"),
    ):
        for match in pattern.finditer(text):
            with contextlib.suppress(ValueError):
                matches.append(
                    (match.span(), float(match.group(1).replace(",", "")) / 100)
                )

    for match in _SUBPOUND_MONEY_PATTERN.finditer(text):
        with contextlib.suppress(ValueError):
            matches.append((match.span(), float(match.group(1).replace(",", "")) / 100))

    for match in SOURCE_TEXT_RATIO_NUMBER_PATTERN.finditer(text):
        for group_index in (1, 2):
            with contextlib.suppress(ValueError):
                matches.append(
                    (
                        match.span(),
                        float(match.group(group_index).replace(",", "")),
                    )
                )

    for match in re.finditer(r"(?<=[=+])\s*(-?[\d,]+(?:\.\d+)?)\b", text):
        with contextlib.suppress(ValueError):
            matches.append((match.span(1), float(match.group(1).replace(",", ""))))

    return matches


def _parse_cardinal_word_sequence(text: str) -> float | None:
    """Parse a compact English cardinal phrase up to ninety-nine."""
    words = [
        token
        for token in re.split(r"[-\s]+", text.strip().lower())
        if token and token != "and"
    ]
    if not words:
        return None
    total = 0.0
    for word in words:
        value = _CARDINAL_WORD_VALUES.get(word)
        if value is None:
            return None
        total += value
    return total


def _iter_cardinal_word_number_matches(
    text: str,
) -> list[tuple[tuple[int, int], float]]:
    """Return English cardinal number phrases such as "five hundred thousand"."""
    matches: list[tuple[tuple[int, int], float]] = []
    for match in _CARDINAL_NUMBER_WORD_PATTERN.finditer(text):
        value = _parse_cardinal_number_words(match.group(0))
        if value is None:
            continue
        matches.append((match.span(), value))
    return matches


def _parse_cardinal_number_words(text: str) -> float | None:
    """Parse an English cardinal phrase with hundred/thousand/million scales."""
    tokens = [
        token
        for token in re.split(r"[-\s]+", text.strip().lower())
        if token and token != "and"
    ]
    if not tokens:
        return None

    total = 0.0
    current = 0.0
    seen_number = False
    seen_scale = False
    for token in tokens:
        if token in _CARDINAL_WORD_VALUES:
            current += _CARDINAL_WORD_VALUES[token]
            seen_number = True
            continue
        scale = _CARDINAL_SCALE_WORD_VALUES.get(token)
        if scale is None:
            return None
        seen_scale = True
        if scale == 100:
            current = (current or 1) * scale
            seen_number = True
            continue
        total += (current or 1) * scale
        current = 0.0
        seen_number = True

    if not seen_number:
        return None
    value = total + current
    if not seen_scale and len(tokens) == 1:
        return _CARDINAL_WORD_VALUES.get(tokens[0])
    return value


def _parse_fraction_word(text: str) -> float | None:
    normalized = re.sub(r"[-\s]+", " ", text.strip().lower())
    return _FRACTION_WORD_VALUES.get(normalized)


def _iter_standalone_fraction_word_matches(
    text: str,
) -> Iterator[tuple[tuple[int, int], float]]:
    for match in _STANDALONE_FRACTION_WORD_PATTERN.finditer(text):
        value = _parse_fraction_word(match.group(1))
        if value is not None:
            yield match.span(1), value


def _extract_percentage_context_values(text: str) -> set[float]:
    """Return decimal rate equivalents for numbers in percentage table contexts."""
    values: set[float] = set()
    for match in SOURCE_TEXT_NUMBER_PATTERN.finditer(text):
        raw = match.group(1).replace(",", "")
        with contextlib.suppress(ValueError):
            value = float(raw)
            if value <= 1:
                continue
            context = text[max(0, match.start() - 500) : match.end() + 80].lower()
            if re.search(r"\bpercent(?:age|ages)?\b", context):
                values.add(value / 100)
                if value >= 100 and re.search(
                    r"\b(?:percent\s+of\s+(?:the\s+)?poverty\s+line|"
                    r"percent\s+of\s+(?:the\s+)?federal\s+poverty\s+"
                    r"(?:line|level)|fpl|income\s+tier)\b",
                    context,
                ):
                    values.add(value)
    return values


def _span_overlaps(
    span: tuple[int, int], occupied_spans: list[tuple[int, int]]
) -> bool:
    return any(
        not (span[1] <= start or span[0] >= end) for start, end in occupied_spans
    )


def _clean_source_text_for_numeric_extraction(text: str) -> str:
    """Strip structural source scaffolding before numeric extraction."""
    text = re.sub(r"\\r\\n|\\n|\\r", "\n", text)
    text = text.replace(r"\t", "\t")
    cleaned_lines: list[str] = []
    for line in text.splitlines():
        stripped = line.strip()
        structural_stripped = stripped.strip(_STRUCTURAL_SOURCE_QUOTE_CHARS)
        if _STRUCTURAL_SOURCE_LINE_PATTERN.match(structural_stripped):
            continue
        if _STRUCTURAL_SOURCE_HEADING_PATTERN.match(structural_stripped):
            continue
        if _STRUCTURAL_SOURCE_CITATION_PATTERN.match(structural_stripped):
            continue
        if _TABLE_HEADING_PATTERN.match(structural_stripped):
            continue
        if _SYNTHETIC_MODELING_INSTRUCTION_PATTERN.match(structural_stripped):
            continue
        if _SYNTHETIC_STATEWIDE_ALLOWANCE_RESTATEMENT_PATTERN.match(
            structural_stripped
        ):
            continue

        normalized_line = line.lstrip(_STRUCTURAL_SOURCE_QUOTE_CHARS)
        normalized_line = _STRUCTURAL_SOURCE_CITATION_PREFIX_PATTERN.sub(
            "", normalized_line, count=1
        )
        value_row_match = _VALUE_BEARING_TABLE_ROW_PATTERN.match(normalized_line)
        schedule_row_match = (
            _SCHEDULE_SIZE_ROW_PATTERN.fullmatch(normalized_line)
            or _SCHEDULE_PIPE_ROW_PATTERN.fullmatch(normalized_line)
            or _SCHEDULE_ARROW_ROW_PATTERN.fullmatch(normalized_line)
            or _SCHEDULE_BARE_ARROW_ROW_PATTERN.fullmatch(normalized_line)
        )
        if value_row_match and not schedule_row_match:
            normalized_line = value_row_match.group(1)
        normalized_line = _TABLE_ROW_LABEL_PATTERN.sub("size", normalized_line)
        cleaned_lines.append(_STRUCTURAL_SOURCE_PREFIX_PATTERN.sub("", normalized_line))

    cleaned = "\n".join(cleaned_lines)
    cleaned = _SOURCE_URL_PATTERN.sub(" ", cleaned)
    cleaned = re.sub(
        r"\[[^\]]*\d[^\]]*\]",
        _strip_superseded_bracketed_numeric_text,
        cleaned,
    )
    cleaned = _STRUCTURAL_SOURCE_MANUAL_NUMBER_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_MANUAL_VOLUME_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_POLICY_LABEL_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_BULLETIN_NUMBER_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_REVISION_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_REVISION_CODE_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_HANDBOOK_SECTION_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_FORM_NUMBER_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_FORM_LINE_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_CODE_CITATION_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_BARE_DOTTED_REFERENCE_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_SECTION_PATTERN.sub(" ", cleaned)
    cleaned = GROUNDING_DATE_PATTERN.sub(" ", cleaned)
    cleaned = GROUNDING_MONTH_PERIOD_PATTERN.sub(" ", cleaned)
    cleaned = _MONTH_NAME_DATE_PATTERN.sub(" ", cleaned)
    cleaned = _SLASH_DATE_PATTERN.sub(" ", cleaned)
    cleaned = _MONTH_NAME_DAY_PATTERN.sub(" ", cleaned)
    cleaned = _MONTH_DAY_OF_MONTH_PATTERN.sub(" ", cleaned)
    cleaned = _STRUCTURAL_SOURCE_SUBDIVISION_MARKER_PATTERN.sub(" ", cleaned)
    cleaned = _SCHEDULE_SIZE_CAP_RESTATEMENT_PATTERN.sub(
        lambda match: f"above {match.group(1)} use the capped household rate",
        cleaned,
    )
    cleaned = _TABLE_KEY_ASSIGNMENT_PATTERN.sub(" ", cleaned)
    for pattern in _SOURCE_REFERENCE_PATTERNS:
        cleaned = pattern.sub(" ", cleaned)
    return cleaned


def _strip_superseded_bracketed_numeric_text(match: re.Match[str]) -> str:
    """Drop superseded bracketed numerics but preserve bracketed formulas."""
    bracketed = match.group(0)
    inner = bracketed[1:-1]
    if re.search(r"[+\-−*/]", inner) or re.search(r"[A-Za-z_]", inner):
        return bracketed
    return " "


def _extract_collapsed_schedule_row_occurrences(
    text: str,
) -> tuple[list[float], str]:
    """Extract schedule row values once per contiguous value block and remove row lines."""
    occurrences: list[float] = []
    retained_lines: list[str] = []
    current_heading: str | None = None
    last_value_by_block: dict[str, float] = {}
    seen_values: set[float] = set()
    ungrouped_block = 0
    current_ungrouped_block: str | None = None

    for line in text.splitlines():
        stripped = line.strip()
        if _SCHEDULE_BLOCK_HEADING_PATTERN.fullmatch(stripped):
            current_heading = stripped
            current_ungrouped_block = None
            retained_lines.append(line)
            continue

        row_match = (
            _SCHEDULE_SIZE_ROW_PATTERN.fullmatch(stripped)
            or _SCHEDULE_PIPE_ROW_PATTERN.fullmatch(stripped)
            or _SCHEDULE_ARROW_ROW_PATTERN.fullmatch(stripped)
            or _SCHEDULE_BARE_ARROW_ROW_PATTERN.fullmatch(stripped)
        )
        if row_match:
            with contextlib.suppress(ValueError):
                value = float(row_match.group(1).replace(",", ""))
                if current_heading is not None:
                    block_key = current_heading
                else:
                    if current_ungrouped_block is None:
                        ungrouped_block += 1
                        current_ungrouped_block = f"__ungrouped_{ungrouped_block}"
                    block_key = current_ungrouped_block
                if (
                    last_value_by_block.get(block_key) != value
                    and value not in seen_values
                ):
                    occurrences.append(value)
                    last_value_by_block[block_key] = value
                    seen_values.add(value)
            continue

        if stripped:
            current_heading = None
            current_ungrouped_block = None
        retained_lines.append(line)

    return occurrences, "\n".join(retained_lines)


def extract_numeric_occurrences_from_text(text: str) -> list[float]:
    """Extract substantive numeric occurrences from source text, preserving repeats."""
    cleaned = _clean_source_text_for_numeric_extraction(text)
    collapsed_schedule_occurrences, cleaned = (
        _extract_collapsed_schedule_row_occurrences(cleaned)
    )

    occurrences: list[float] = list(collapsed_schedule_occurrences)
    spans: list[tuple[int, int]] = []

    for span, value in _iter_normalized_special_numeric_matches(cleaned):
        occurrences.append(value)
        spans.append(span)

    for span, value in _iter_standalone_fraction_word_matches(cleaned):
        if _span_overlaps(span, spans):
            continue
        occurrences.append(value)
        spans.append(span)

    for match in SOURCE_TEXT_NUMBER_PATTERN.finditer(cleaned):
        span = match.span(1)
        if _span_overlaps(span, spans):
            continue
        with contextlib.suppress(ValueError):
            value = float(match.group(1).replace(",", ""))
            if value.is_integer() and 1900 <= value <= 2100:
                continue
            occurrences.append(value)

    for match in _ORDINAL_NUMBER_PATTERN.finditer(cleaned):
        with contextlib.suppress(ValueError):
            value = float(match.group(1))
            if value.is_integer() and 1900 <= value <= 2100:
                continue
            if _ordinal_is_calendar_day_reference(cleaned, match.end(), value):
                continue
            occurrences.append(value)

    for match in _ORDINAL_WORD_PATTERN.finditer(cleaned):
        value = _ORDINAL_WORD_VALUES[match.group(1).lower()]
        if value not in GROUNDING_ALLOWED_VALUES:
            occurrences.append(value)

    for glyph, value in _UNICODE_FRACTION_VALUES.items():
        occurrences.extend(value for _ in re.finditer(re.escape(glyph), cleaned))

    for span, value in _iter_cardinal_word_number_matches(cleaned):
        if _span_overlaps(span, spans):
            continue
        if value not in GROUNDING_ALLOWED_VALUES:
            occurrences.append(value)

    occurrence_counts = Counter(occurrences)
    normalized: list[float] = []
    for value in occurrences:
        scaled = round(value * 100, 9)
        if value <= 1 and scaled in occurrence_counts:
            continue
        normalized.append(value)
    return normalized


def extract_named_scalar_occurrences(content: str) -> list[NamedScalarOccurrence]:
    """Extract direct named scalar definitions from a RuleSpec file."""
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if (
            isinstance(payload, dict)
            and payload.get("format") == "rulespec/v1"
            and isinstance(payload.get("rules"), list)
        ):
            occurrences: list[NamedScalarOccurrence] = []
            for rule in payload["rules"]:
                if not isinstance(rule, dict):
                    continue
                name = str(rule.get("name") or "").strip()
                if not name:
                    continue
                versions = rule.get("versions")
                if not isinstance(versions, list):
                    continue
                for version in versions:
                    if not isinstance(version, dict):
                        continue
                    formula = version.get("formula")
                    raw: str | None = None
                    if isinstance(formula, (int, float)) and not isinstance(
                        formula, bool
                    ):
                        raw = str(formula)
                    elif isinstance(formula, str):
                        stripped = formula.strip()
                        if _DIRECT_SCALAR_VALUE_PATTERN.fullmatch(stripped):
                            raw = stripped
                    if raw is not None:
                        with contextlib.suppress(ValueError):
                            occurrences.append(
                                NamedScalarOccurrence(
                                    line=1,
                                    name=name,
                                    value=float(raw.replace(",", "")),
                                )
                            )
                    table_values = version.get("values")
                    if isinstance(table_values, dict):
                        for key, table_value in table_values.items():
                            extracted = _numeric_rule_value(table_value)
                            if extracted is None:
                                continue
                            _, value = extracted
                            occurrences.append(
                                NamedScalarOccurrence(
                                    line=1,
                                    name=f"{name}[{key}]",
                                    value=value,
                                )
                            )
            return occurrences

    return []


def extract_embedded_source_text(content: str) -> str:
    """Extract embedded source text from RuleSpec YAML."""
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if isinstance(payload, dict) and payload.get("format") == "rulespec/v1":
            module = payload.get("module")
            if isinstance(module, dict):
                summary = module.get("summary")
                if isinstance(summary, str) and summary.strip():
                    return summary.strip()

    return ""


def find_ungrounded_numeric_issues(
    content: str,
    source_text: str | None = None,
) -> list[str]:
    """Return issues for generated numeric literals absent from source text."""
    grounding_values = extract_grounding_values(content)
    if not grounding_values:
        return []

    if source_text is not None:
        source = source_text.strip()
    else:
        source = (extract_numeric_grounding_source_text(content) or "").strip()
    if not source:
        return [
            "Numeric source required: RuleSpec defines policy numeric literals "
            "but does not provide `source_verification.corpus_citation_path` "
            "or `source_verification.corpus_citation_paths` text. "
            "`module.summary` is not accepted as source text for numeric grounding."
        ]

    source_numbers = extract_numbers_from_text(source)
    issues: list[str] = []
    for _, raw, value in grounding_values:
        if numeric_value_is_grounded(value, source_numbers):
            continue
        display = raw if raw == f"{value:g}" else f"{raw} ({value:g})"
        issues.append(
            "Ungrounded generated numeric literal: "
            f"{display} does not appear as a substantive numeric value in the source text."
        )
    return issues


def extract_numeric_grounding_source_text(content: str) -> str | None:
    """Return authoritative source text usable for numeric grounding.

    Numeric grounding must use ingested corpus source text. The human-readable
    module summary is intentionally excluded.
    """
    return _extract_source_verification_text(content)


def find_deprecated_source_url_issues(content: str) -> list[str]:
    """Reject raw source URL references in RuleSpec encodings."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []

    locations: list[str] = []
    module = payload.get("module")
    if isinstance(module, dict):
        if "source_url" in module:
            locations.append("module.source_url")
        source_verification = module.get("source_verification")
        if (
            isinstance(source_verification, dict)
            and "source_url" in source_verification
        ):
            locations.append("module.source_verification.source_url")

    source_verification = payload.get("source_verification")
    if isinstance(source_verification, dict) and "source_url" in source_verification:
        locations.append("source_verification.source_url")

    rules = payload.get("rules")
    if isinstance(rules, list):
        for index, rule in enumerate(rules):
            if isinstance(rule, dict) and "source_url" in rule:
                name = rule.get("name") or f"rules[{index}]"
                locations.append(f"rules.{name}.source_url")

    if not locations:
        return []
    return [
        "Legacy source URL metadata not allowed: "
        + ", ".join(locations[:5])
        + ("; ..." if len(locations) > 5 else "")
        + ". Use `module.source_verification.corpus_citation_path` or "
        "`module.source_verification.corpus_citation_paths`."
    ]


_SOURCE_CLAIM_ALLOWED_KINDS = frozenset(
    {
        "defines",
        "sets",
        "implements",
        "amends",
        "supersedes",
        "restates",
        "delegates",
        "applies_to",
        "requires",
        "creates_exception",
    }
)
_SOURCE_CLAIM_EXECUTABLE_KEYS = frozenset(
    {
        "formula",
        "formulas",
        "input",
        "inputs",
        "output",
        "outputs",
        "case",
        "cases",
        "test",
        "tests",
        "test_cases",
        "runtime",
        "trace",
        "traces",
        "result",
        "results",
        "eligibility",
        "benefit_amount",
        "decision",
    }
)
_SOURCE_CLAIM_ABSOLUTE_TARGET_ID = re.compile(r"^[a-z][a-z0-9_.-]*:[^\s]+$")
_SOURCE_CLAIM_FRIENDLY_CONCEPT_ID = re.compile(r"^[a-z][a-z0-9_]*(\.[a-z][a-z0-9_]*)+$")


def find_source_claim_reference_issues(content: str) -> list[str]:
    """Validate optional RuleSpec refs to accepted corpus-backed source claims."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []

    module = payload.get("module")
    if not isinstance(module, dict) or "source_claims" not in module:
        return []

    raw_refs = module.get("source_claims")
    if not isinstance(raw_refs, list) or not raw_refs:
        return [
            "Source claims malformed: `module.source_claims` must be a non-empty "
            "list of accepted claim IDs."
        ]

    source_verification = _source_verification_block(payload)
    citation_paths: tuple[str, ...] = ()
    if source_verification is not None:
        citation_paths, _ = _source_verification_source_fields(source_verification)

    issues: list[str] = []
    if not citation_paths:
        issues.append(
            "Source claims require direct source verification: "
            "`module.source_claims` may only supplement, not replace, "
            "`module.source_verification.corpus_citation_path` or "
            "`module.source_verification.corpus_citation_paths`."
        )

    claim_ids = _extract_source_claim_ids(raw_refs)
    if not claim_ids:
        issues.append(
            "Source claims malformed: `module.source_claims` must contain claim "
            "IDs as strings or `{id: ...}` mappings."
        )
        return issues

    for claim_id in claim_ids:
        claim = _fetch_local_source_claim_record(claim_id)
        if claim is None:
            issues.append(
                "Source claim missing: "
                f"`{claim_id}` was not found in local corpus claim artifacts."
            )
            continue
        issues.extend(
            _validate_source_claim_record(
                claim_id=claim_id,
                claim=claim,
                rulespec_citation_paths=citation_paths,
            )
        )

    return issues


def _extract_source_claim_ids(raw_refs: list[Any]) -> list[str]:
    claim_ids: list[str] = []
    for raw_ref in raw_refs:
        claim_id = ""
        if isinstance(raw_ref, str):
            claim_id = raw_ref.strip()
        elif isinstance(raw_ref, dict):
            claim_id = str(raw_ref.get("id") or "").strip()
        if claim_id:
            claim_ids.append(claim_id)
    return claim_ids


def _validate_source_claim_record(
    *,
    claim_id: str,
    claim: dict[str, Any],
    rulespec_citation_paths: tuple[str, ...],
) -> list[str]:
    issues: list[str] = []

    actual_id = str(claim.get("id") or "").strip()
    if actual_id != claim_id:
        issues.append(
            "Source claim ID mismatch: "
            f"`{claim_id}` resolved to a claim with id `{actual_id or '<missing>'}`."
        )

    status = str(claim.get("status") or "").strip()
    if status != "accepted":
        issues.append(
            "Source claim not accepted: "
            f"`{claim_id}` has status `{status or '<missing>'}`; RuleSpec may only "
            "reference accepted source claims."
        )

    kind = str(claim.get("kind") or "").strip()
    if kind not in _SOURCE_CLAIM_ALLOWED_KINDS:
        allowed = ", ".join(sorted(_SOURCE_CLAIM_ALLOWED_KINDS))
        issues.append(
            "Source claim kind invalid: "
            f"`{claim_id}` has kind `{kind or '<missing>'}`; allowed kinds are "
            f"{allowed}."
        )

    executable_paths = _source_claim_executable_field_paths(claim)
    if executable_paths:
        issues.append(
            "Source claim is executable: "
            f"`{claim_id}` contains execution fields "
            + ", ".join(f"`{path}`" for path in executable_paths[:5])
            + ("; ..." if len(executable_paths) > 5 else "")
            + ". Claims may assert source meaning but must not contain formulas, "
            "case inputs, outputs, tests, runtime traces, decisions, or benefit amounts."
        )

    issues.extend(_validate_source_claim_subject(claim_id=claim_id, claim=claim))

    evidence = claim.get("evidence")
    if not isinstance(evidence, list) or not evidence:
        issues.append(
            "Source claim evidence missing: "
            f"`{claim_id}` must cite at least one corpus evidence span."
        )
        return issues

    for index, evidence_item in enumerate(evidence):
        if not isinstance(evidence_item, dict):
            issues.append(
                "Source claim evidence malformed: "
                f"`{claim_id}.evidence[{index}]` must be a mapping."
            )
            continue
        evidence_path = str(evidence_item.get("corpus_citation_path") or "").strip()
        if not evidence_path:
            issues.append(
                "Source claim evidence missing corpus path: "
                f"`{claim_id}.evidence[{index}]` must declare "
                "`corpus_citation_path`."
            )
            continue
        if rulespec_citation_paths and evidence_path not in rulespec_citation_paths:
            issues.append(
                "Source claim evidence outside RuleSpec source: "
                f"`{claim_id}` cites `{evidence_path}`, but the RuleSpec verifies "
                "against "
                + _format_source_verification_paths(rulespec_citation_paths)
                + ". Add the corpus path to `module.source_verification` or split "
                "the claim reference."
            )
        quote = str(evidence_item.get("quote") or "").strip()
        if quote:
            source_text = _fetch_corpus_source_text(evidence_path)
            if source_text is not None and quote not in source_text:
                issues.append(
                    "Source claim quote not found: "
                    f"`{claim_id}.evidence[{index}].quote` does not appear in "
                    f"`{evidence_path}`."
                )

    return issues


def _validate_source_claim_subject(
    *,
    claim_id: str,
    claim: dict[str, Any],
) -> list[str]:
    subject = claim.get("subject")
    if not isinstance(subject, dict):
        return [
            "Source claim subject missing: "
            f"`{claim_id}` must declare `subject` with an absolute legal or "
            "RuleSpec target."
        ]

    subject_id = str(subject.get("id") or "").strip()
    subject_type = str(subject.get("type") or "").strip()
    issues: list[str] = []
    if not _SOURCE_CLAIM_ABSOLUTE_TARGET_ID.match(subject_id):
        issues.append(
            "Source claim subject target invalid: "
            f"`{claim_id}.subject.id` is `{subject_id or '<missing>'}`; use an "
            "absolute legal, corpus, or RuleSpec target such as "
            "`us:statutes/7/2014/e`."
        )
    if subject_type == "concept" or _SOURCE_CLAIM_FRIENDLY_CONCEPT_ID.match(subject_id):
        issues.append(
            "Source claim subject placeholder not allowed: "
            f"`{claim_id}` uses `{subject_id or '<missing>'}`; friendly concept "
            "IDs are not valid claim subjects."
        )
    return issues


def _source_claim_executable_field_paths(value: Any, prefix: str = "") -> list[str]:
    paths: list[str] = []
    if isinstance(value, dict):
        for key, child in value.items():
            key_text = str(key)
            path = f"{prefix}.{key_text}" if prefix else key_text
            if key_text in _SOURCE_CLAIM_EXECUTABLE_KEYS:
                paths.append(path)
            paths.extend(_source_claim_executable_field_paths(child, path))
    elif isinstance(value, list):
        for index, child in enumerate(value):
            paths.extend(
                _source_claim_executable_field_paths(child, f"{prefix}[{index}]")
            )
    return paths


@functools.lru_cache(maxsize=512)
def _fetch_local_source_claim_record(claim_id: str) -> dict[str, Any] | None:
    normalized_id = claim_id.strip()
    if not normalized_id:
        return None

    for claims_root in _local_corpus_claims_roots():
        for claim_file in sorted(claims_root.rglob("*.jsonl")):
            claim = _read_local_source_claim_file(claim_file, normalized_id)
            if claim is not None:
                return claim
    return None


def _read_local_source_claim_file(
    claim_file: Path,
    claim_id: str,
) -> dict[str, Any] | None:
    try:
        lines = claim_file.read_text(encoding="utf-8").splitlines()
    except OSError:
        return None
    for line in lines:
        if not line.strip():
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError:
            continue
        if not isinstance(record, dict) or record.get("id") != claim_id:
            continue
        return record
    return None


def _local_corpus_claims_roots() -> tuple[Path, ...]:
    roots: list[Path] = []
    for env_name in (
        "AXIOM_CORPUS_CLAIMS_ROOT",
        "AXIOM_CORPUS_ARTIFACT_ROOT",
        "AXIOM_CORPUS_REPO",
    ):
        raw_root = os.environ.get(env_name)
        if raw_root:
            roots.append(Path(raw_root).expanduser())

    with contextlib.suppress(OSError):
        cwd = Path.cwd().resolve()
        for base in (cwd, *cwd.parents):
            roots.extend(
                (
                    base,
                    base / "axiom-corpus",
                    base / "TheAxiomFoundation" / "axiom-corpus",
                    base.parent / "axiom-corpus",
                    base / "_axiom" / "axiom-corpus",
                )
            )

    with contextlib.suppress(RuntimeError, OSError):
        roots.append(Path.home() / "TheAxiomFoundation" / "axiom-corpus")

    claims_roots: list[Path] = []
    seen: set[Path] = set()
    for root in roots:
        for candidate in (
            root,
            root / "claims",
            root / "data" / "corpus",
            root / "data" / "corpus" / "claims",
        ):
            claims_root = (
                candidate if candidate.name == "claims" else candidate / "claims"
            )
            with contextlib.suppress(OSError):
                resolved = claims_root.resolve()
                if resolved.is_dir() and resolved not in seen:
                    seen.add(resolved)
                    claims_roots.append(resolved)
    return tuple(claims_roots)


_INTERVAL_TABLE_SELECTOR_BOUND_KIND = "selector_inline_interval_bound"
_INTERVAL_TABLE_NON_SELECTOR_BOUND_KIND = "non_selector_interval_bound_literal"
_STRUCTURED_SCALE_BRANCH_FORMULA_KIND = "branch_formula_scale"
_STRUCTURED_SCALE_MALFORMED_TABLE_KIND = "malformed_parameter_table"


def find_interval_table_reencoding_candidates(
    content: str,
    *,
    include_selector_bounds: bool = False,
) -> list[IntervalTableAuditIssue]:
    """Find generated interval-table formulas that should be re-encoded.

    Today's encoder represents source tables with interval row labels as a
    derived band selector plus indexed parameter columns. Selector predicates
    are still allowed to contain the structural row bounds. Reusing those same
    bounds in other formula arithmetic is not allowed because it bakes
    parameter-table structure into formulas and prevents clean reparameterizing.
    """
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    selector_table_keys = _rulespec_index_selector_keys(rules)
    source_text = extract_embedded_source_text(content)
    source_looks_like_table = _source_text_looks_like_table(source_text)
    if not selector_table_keys and not source_looks_like_table:
        return []

    selector_bounds: list[_IntervalSelectorBound] = []
    selector_issues: list[IntervalTableAuditIssue] = []
    seen_selector_bounds: set[tuple[str, str, float]] = set()

    for rule in rules:
        if not isinstance(rule, dict) or not _is_structural_selector_rule(rule):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip()
        if not source_looks_like_table and rule_name not in selector_table_keys:
            continue
        selector_keys = selector_table_keys.get(rule_name)
        for formula in _rulespec_rule_formula_strings(rule):
            for raw, value in _interval_table_selector_bound_literals(
                formula,
                selector_keys=selector_keys,
            ):
                selector_bounds.append(
                    _IntervalSelectorBound(
                        raw=raw,
                        value=value,
                        selector_rule=rule_name,
                        formula=formula,
                    )
                )
                seen_key = (rule_name, raw, value)
                if seen_key in seen_selector_bounds:
                    continue
                seen_selector_bounds.add(seen_key)
                if include_selector_bounds:
                    selector_issues.append(
                        IntervalTableAuditIssue(
                            kind=_INTERVAL_TABLE_SELECTOR_BOUND_KIND,
                            rule=rule_name,
                            literal=raw,
                            value=value,
                            message=(
                                "Interval table selector inventory: "
                                f"`{rule_name}` keeps source-table row bound "
                                f"`{raw}` inline in selector arithmetic. This is "
                                "currently allowed, but the file should be "
                                "re-encoded after native interval-table support "
                                "lands."
                            ),
                        )
                    )

    if not selector_bounds:
        return selector_issues

    issues: list[IntervalTableAuditIssue] = list(selector_issues)
    seen_formula_bounds: set[tuple[str, str, float]] = set()
    for rule in rules:
        if not isinstance(rule, dict) or _is_structural_selector_rule(rule):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip()
        for formula in _rulespec_rule_formula_strings(rule):
            for raw, value in _interval_table_formula_literals(
                formula,
                selector_table_keys=selector_table_keys,
            ):
                if not _numeric_matches_interval_bound(
                    raw,
                    value,
                    selector_bounds,
                    formula=formula,
                ):
                    continue
                seen_key = (rule_name, raw, value)
                if seen_key in seen_formula_bounds:
                    continue
                seen_formula_bounds.add(seen_key)
                issues.append(
                    IntervalTableAuditIssue(
                        kind=_INTERVAL_TABLE_NON_SELECTOR_BOUND_KIND,
                        rule=rule_name,
                        literal=raw,
                        value=value,
                        message=(
                            "Interval table re-encoding required: "
                            f"`{rule_name}` formula contains source-table row "
                            f"bound literal `{raw}` outside structural selector "
                            "arithmetic. Move the interval row bounds into a "
                            "native interval table/scale representation instead "
                            "of hard-coding them in derived formulas."
                        ),
                    )
                )

    return issues


def find_interval_table_reencoding_issues(content: str) -> list[str]:
    """Return CI-blocking interval-table re-encoding issues."""
    return [
        issue.message
        for issue in find_interval_table_reencoding_candidates(content)
        if issue.kind == _INTERVAL_TABLE_NON_SELECTOR_BOUND_KIND
    ]


def _rulespec_rule_formula_strings(rule: dict[str, Any]) -> list[str]:
    formulas: list[str] = []
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return formulas
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            formulas.append(formula)
    return formulas


def _interval_table_selector_bound_literals(
    formula: str,
    *,
    selector_keys: set[str] | None,
) -> list[tuple[str, float]]:
    literals: list[tuple[str, float]] = []
    cleaned = _formula_without_comments_and_dates(formula)
    for raw, value, start, end in _formula_numeric_literal_occurrences(cleaned):
        if not _formula_literal_is_comparison_bound(cleaned, raw, span=(start, end)):
            continue
        if _interval_table_literal_is_structural(
            cleaned,
            raw,
            value,
            selector_keys,
            span=(start, end),
            ignore_small_literals=True,
        ):
            continue
        literals.append((raw, value))
    return literals


def _interval_table_formula_literals(
    formula: str,
    *,
    selector_table_keys: dict[str, set[str]],
) -> list[tuple[str, float]]:
    literals: list[tuple[str, float]] = []
    cleaned = _formula_without_comments_and_dates(formula)
    for raw, value, start, end in _formula_numeric_literal_occurrences(cleaned):
        if _is_structural_selector_key_literal(cleaned, raw, selector_table_keys):
            continue
        if _interval_table_literal_is_structural(
            cleaned,
            raw,
            value,
            selector_keys=None,
            span=(start, end),
            ignore_small_literals=False,
        ):
            continue
        literals.append((raw, value))
    return literals


def _formula_without_comments_and_dates(formula: str) -> str:
    lines = [line.split("#", 1)[0] for line in formula.splitlines()]
    return GROUNDING_DATE_PATTERN.sub(" ", "\n".join(lines))


def _formula_numeric_literals(expression: str) -> list[tuple[str, float]]:
    return [
        (raw, value)
        for raw, value, _start, _end in _formula_numeric_literal_occurrences(expression)
    ]


def _formula_numeric_literal_occurrences(
    expression: str,
) -> list[tuple[str, float, int, int]]:
    literals: list[tuple[str, float, int, int]] = []
    for match in GROUNDING_FORMULA_NUMBER_PATTERN.finditer(expression):
        raw = match.group(1).replace(",", "")
        with contextlib.suppress(ValueError):
            start, end = match.span(1)
            literals.append((raw, float(raw), start, end))
    return literals


def _interval_table_literal_is_structural(
    expression: str,
    raw: str,
    value: float,
    selector_keys: set[str] | None,
    *,
    span: tuple[int, int] | None = None,
    ignore_small_literals: bool,
) -> bool:
    if ignore_small_literals and value in GROUNDING_ALLOWED_VALUES and "." not in raw:
        return True
    if raw == "0.5" and _is_half_up_rounding_expression(expression):
        return True
    return (
        _is_structural_table_key_literal(expression, raw, span=span)
        or _is_structural_table_index_clamp_literal(expression, raw, span=span)
        or _is_structural_mapping_key_literal(expression, raw, span=span)
        or _is_structural_schedule_index_literal(expression, raw, span=span)
        or _is_structural_enum_index_literal(expression, raw, span=span)
        or _is_structural_selector_result_literal(
            expression,
            raw,
            selector_keys,
            span=span,
        )
    )


def _is_structural_selector_key_literal(
    expression: str,
    raw: str,
    selector_table_keys: dict[str, set[str]],
) -> bool:
    if not selector_table_keys or not re.fullmatch(r"-?\d+(?:\.0+)?", raw):
        return False
    normalized_key = _structural_integer_key(raw)
    if normalized_key is None:
        return False
    selector_names = [
        name for name, keys in selector_table_keys.items() if normalized_key in keys
    ]
    if not selector_names:
        return False
    normalized = re.sub(r"\s+", " ", expression)
    for selector_name in selector_names:
        escaped_selector = re.escape(selector_name)
        escaped_raw = re.escape(raw)
        if re.search(
            rf"\b{escaped_selector}\s*(?:==|!=)\s*{escaped_raw}\b"
            rf"|\b{escaped_raw}\s*(?:==|!=)\s*{escaped_selector}\b",
            normalized,
        ):
            return True
    return False


def _formula_literal_is_comparison_bound(
    expression: str,
    raw: str,
    *,
    span: tuple[int, int] | None = None,
) -> bool:
    if span is not None:
        start, end = span
        before = expression[:start].rstrip()
        after = expression[end:].lstrip()
        return bool(
            re.search(r"(?:<=|>=|<|>)\s*$", before) or re.match(r"(?:<=|>=|<|>)", after)
        )
    escaped = re.escape(raw)
    return bool(
        re.search(rf"(?:<=|>=|<|>)\s*{escaped}(?![\d.])", expression)
        or re.search(rf"(?<![\d.]){escaped}\s*(?:<=|>=|<|>)", expression)
    )


def _numeric_matches_interval_bound(
    raw: str,
    value: float,
    bounds: list[_IntervalSelectorBound],
    *,
    formula: str = "",
) -> bool:
    for bound in bounds:
        if math.isclose(value, bound.value, rel_tol=0.0, abs_tol=1e-9):
            return True
        if not _percent_fraction_context_supports_conversion(formula, bound, value):
            continue
        if math.isclose(value * 100, bound.value, rel_tol=0.0, abs_tol=1e-9):
            return True
        if math.isclose(value, bound.value * 100, rel_tol=0.0, abs_tol=1e-9):
            return True
    return False


def _percent_fraction_context_supports_conversion(
    formula: str,
    bound: _IntervalSelectorBound,
    formula_value: float,
) -> bool:
    context = f"{formula}\n{bound.formula}\n{bound.selector_rule}".lower()
    if not any(
        token in context for token in ("fpl", "poverty", "percent", "percentage")
    ):
        return False
    if not any(token in context for token in ("fraction", "ratio", "share")):
        return False
    # Percent/FPL thresholds are conventionally 0-1000 percent or 0-10 as a
    # fraction. This avoids amount-like collisions such as 400 vs 40_000.
    percent_side = max(abs(bound.value), abs(formula_value))
    fraction_side = min(abs(bound.value), abs(formula_value))
    return percent_side <= 1000 and fraction_side <= 10


def find_structured_scale_parameter_issues(content: str) -> list[str]:
    """Flag source-stated numeric scales encoded as branch formulas."""
    return [
        issue.message
        for issue in find_structured_scale_parameter_issue_records(content)
    ]


def find_structured_scale_parameter_issue_records(
    content: str,
) -> list[StructuredScaleParameterIssue]:
    """Return structured records for malformed scale/table encodings."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[StructuredScaleParameterIssue] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        kind = str(rule.get("kind") or "").lower()
        if kind == "parameter":
            if rule.get("indexed_by") is None and any(
                isinstance(version, dict)
                and isinstance(version.get("values"), dict)
                and version.get("values")
                for version in rule.get("versions") or []
            ):
                name = str(rule.get("name") or "<unknown>")
                issues.append(
                    StructuredScaleParameterIssue(
                        kind=_STRUCTURED_SCALE_MALFORMED_TABLE_KIND,
                        rule=name,
                        message=(
                            "Structured parameter table malformed: "
                            f"{name} uses versioned `values` but does not "
                            "declare `indexed_by`."
                        ),
                    )
                )
            continue
        if kind != "derived":
            continue
        name = str(rule.get("name") or "<unknown>")
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            selector = _embedded_integer_scale_selector(formula)
            if selector is not None:
                issues.append(
                    StructuredScaleParameterIssue(
                        kind=_STRUCTURED_SCALE_BRANCH_FORMULA_KIND,
                        rule=name,
                        message=(
                            "Structured parameter table required: "
                            f"{name} encodes a numeric schedule keyed by {selector} "
                            "inside a derived formula; move source-stated cells to a "
                            "`kind: parameter` rule with `indexed_by` and versioned "
                            "`values`, then reference it with table lookup syntax."
                        ),
                    )
                )
                break
    return issues


def find_source_table_row_scalar_parameter_issues(content: str) -> list[str]:
    """Flag source tables exploded into scalar parameters per row/band/cell."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []

    source_text = extract_embedded_source_text(content)
    if not _source_text_looks_like_table(source_text):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    row_scalar_names: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").lower() != "parameter":
            continue
        if rule.get("indexed_by") is not None:
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        if _is_source_table_structural_scalar_name(name):
            row_scalar_names.append(name)

    if len(row_scalar_names) < 3:
        return []

    sample = ", ".join(f"`{name}`" for name in row_scalar_names[:5])
    if len(row_scalar_names) > 5:
        sample += ", ..."
    return [
        "Source table row/band scalar parameters: "
        f"{sample} encode table rows, bands, or cells as standalone public "
        "parameters. "
        "Use one `kind: parameter` rule with `indexed_by` and versioned "
        "`values` for each substantive source table column, plus a derived "
        "band/key selector when the table uses interval rows. Store structural "
        "bounds as private named numeric concepts or indexed bound columns "
        "referenced by the selector instead of exporting one public scalar per "
        "row."
    ]


def _is_source_table_structural_scalar_name(name: str) -> bool:
    return bool(
        re.search(r"(?:^|_)row_\d+(?:_|$)", name)
        or re.search(r"(?:^|_)(?:band|bracket)_\d+(?:_|$)", name)
        or _is_source_table_structural_bound_parameter_name(name)
    )


@dataclass(frozen=True)
class _SourceTableScalarBound:
    name: str
    rule: dict[str, Any]
    side: str
    row_key: int
    value: int | float | None
    alias: str | None


def repair_source_table_band_scalar_parameters(
    content: str,
    *,
    source_text: str | None = None,
) -> tuple[str, list[str]]:
    """Normalize generated source-table bound scalars into named concepts."""
    payload = _rulespec_payload(content)
    table_source_text = source_text or extract_embedded_source_text(content)
    if (
        payload is None
        or payload.get("format") != "rulespec/v1"
        or not _source_text_looks_like_table(table_source_text)
    ):
        return content, []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    bound_names: set[str] = set()
    scalar_bounds: dict[str, _SourceTableScalarBound] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        if rule.get("indexed_by") is not None:
            continue
        name = str(rule.get("name") or "").strip()
        if not _is_source_table_structural_bound_parameter_name(name):
            continue
        bound_names.add(name)
        bound = _source_table_scalar_bound(rule)
        if bound is not None:
            scalar_bounds[name] = bound

    if not bound_names:
        return content, []

    resolved_scalar_bounds = {
        name: value
        for name in scalar_bounds
        if (
            value := _resolve_source_table_scalar_bound_value(
                name,
                scalar_bounds,
            )
        )
        is not None
    }
    migratable_bound_names = set(resolved_scalar_bounds)
    selector_rule = (
        _source_table_bound_scalar_selector_rule(rules, migratable_bound_names)
        if len(migratable_bound_names) >= 3
        else None
    )
    selector_name = (
        str(selector_rule.get("name") or "").strip()
        if isinstance(selector_rule, dict)
        else ""
    )
    bound_table_names = {
        "lower": f"{selector_name}_lower_bound",
        "upper": f"{selector_name}_upper_bound",
    }
    migrated_replacements = (
        {
            name: f"{bound_table_names[scalar_bounds[name].side]}[{scalar_bounds[name].row_key}]"
            for name in migratable_bound_names
        }
        if selector_name
        else {}
    )

    referenced_bounds: set[str] = set()
    changed_rules: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip() or "<unknown>"
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            formula_bounds = {
                name
                for name in bound_names
                if _formula_references_identifier(formula, name)
            }
            if not formula_bounds:
                continue
            repaired = _repair_else_if_formula(formula)
            if migrated_replacements:
                repaired = _replace_formula_identifiers(
                    repaired,
                    {
                        name: replacement
                        for name, replacement in migrated_replacements.items()
                        if name in formula_bounds
                    },
                )
            if _formula_has_unsupported_chained_conditional(repaired):
                continue
            referenced_bounds.update(formula_bounds)
            if repaired != formula:
                version["formula"] = repaired
                changed_rules.add(rule_name)

    if not referenced_bounds:
        return content, []

    if migrated_replacements and isinstance(selector_rule, dict):
        for side in ("lower", "upper"):
            side_values = {
                scalar_bounds[name].row_key: resolved_scalar_bounds[name]
                for name in migratable_bound_names
                if scalar_bounds[name].side == side
            }
            if not side_values:
                continue
            _upsert_source_table_bound_values_rule(
                rules,
                selector_rule=selector_rule,
                table_name=bound_table_names[side],
                selector_name=selector_name,
                side=side,
                values=side_values,
                source_rules=[
                    scalar_bounds[name].rule
                    for name in migratable_bound_names
                    if scalar_bounds[name].side == side
                ],
            )
            changed_rules.add(bound_table_names[side])

        payload["rules"] = [
            rule
            for rule in rules
            if not (
                isinstance(rule, dict)
                and str(rule.get("name") or "").strip() in migratable_bound_names
            )
        ]
        changed_rules.update(migratable_bound_names)

    repaired_content = yaml.safe_dump(payload, sort_keys=False).strip() + "\n"
    return repaired_content, sorted(changed_rules)


def _source_table_scalar_bound(
    rule: dict[str, Any],
) -> _SourceTableScalarBound | None:
    name = str(rule.get("name") or "").strip()
    parsed = _parse_source_table_scalar_bound_name(name)
    if parsed is None:
        return None
    side, row_key = parsed
    value = _single_version_scalar_numeric_value(rule)
    alias = None if value is not None else _single_version_identifier_value(rule)
    return _SourceTableScalarBound(
        name=name,
        rule=rule,
        side=side,
        row_key=row_key,
        value=value,
        alias=alias,
    )


def _unreferenced_source_table_scalar_bound_names(rules: list[Any]) -> set[str]:
    candidates: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        if rule.get("indexed_by") is not None:
            continue
        name = str(rule.get("name") or "").strip()
        if _is_source_table_structural_bound_parameter_name(name):
            candidates.add(name)
    if not candidates:
        return set()

    referenced: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        if rule_name in candidates:
            continue
        for formula in _rulespec_rule_formula_strings(rule):
            referenced.update(
                name
                for name in candidates
                if _formula_references_identifier(formula, name)
            )
    return candidates - referenced


def _parse_source_table_scalar_bound_name(name: str) -> tuple[str, int] | None:
    normalized = name.strip().lower()
    patterns = (
        r"(?:^|_)(?P<side>lower|upper)_bound_"
        r"(?P<kind>row|band|bracket)_(?P<row>\d+)(?:_|$)",
        r"(?:^|_)(?P<side>lower|upper|min|max|minimum|maximum)_"
        r"(?P<kind>row|band|bracket)_(?P<row>\d+)(?:_|$)",
        r"(?:^|_)(?P<kind>row|band|bracket)_(?P<row>\d+)_"
        r"(?P<side>lower|upper|min|max|minimum|maximum)(?:_|$)",
    )
    for pattern in patterns:
        match = re.search(pattern, normalized)
        if match is None:
            continue
        side = _normalize_source_table_bound_side(match.group("side"))
        if side is None:
            continue
        return side, int(match.group("row"))
    return None


def _normalize_source_table_bound_side(raw_side: str) -> str | None:
    normalized = raw_side.strip().lower()
    if normalized in {"lower", "min", "minimum"}:
        return "lower"
    if normalized in {"upper", "max", "maximum"}:
        return "upper"
    return None


def _single_version_scalar_numeric_value(rule: dict[str, Any]) -> int | float | None:
    versions = rule.get("versions")
    if not isinstance(versions, list) or len(versions) != 1:
        return None
    version = versions[0]
    if not isinstance(version, dict):
        return None
    formula = version.get("formula")
    numeric = _numeric_rule_value(formula)
    if numeric is None:
        return None
    raw, value = numeric
    if "." not in raw and value.is_integer():
        return int(value)
    return value


def _single_version_identifier_value(rule: dict[str, Any]) -> str | None:
    versions = rule.get("versions")
    if not isinstance(versions, list) or len(versions) != 1:
        return None
    version = versions[0]
    if not isinstance(version, dict):
        return None
    formula = version.get("formula")
    if not isinstance(formula, str):
        return None
    stripped = formula.strip()
    return stripped if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", stripped) else None


def _resolve_source_table_scalar_bound_value(
    name: str,
    scalar_bounds: dict[str, _SourceTableScalarBound],
) -> int | float | None:
    seen: set[str] = set()
    current = name
    while current not in seen:
        seen.add(current)
        bound = scalar_bounds.get(current)
        if bound is None:
            return None
        if bound.value is not None:
            return bound.value
        if bound.alias is None:
            return None
        current = bound.alias
    return None


def _source_table_bound_scalar_selector_rule(
    rules: list[Any],
    bound_names: set[str],
) -> dict[str, Any] | None:
    if not bound_names:
        return None
    for rule in rules:
        if not isinstance(rule, dict) or not _is_structural_selector_rule(rule):
            continue
        for formula in _rulespec_rule_formula_strings(rule):
            if any(
                _formula_references_identifier(formula, bound_name)
                for bound_name in bound_names
            ):
                return rule
    return None


def _replace_formula_identifiers(
    formula: str,
    replacements: dict[str, str],
) -> str:
    repaired = formula
    for name in sorted(replacements, key=len, reverse=True):
        repaired = re.sub(
            rf"(?<![A-Za-z0-9_]){re.escape(name)}(?![A-Za-z0-9_])",
            replacements[name],
            repaired,
        )
    return repaired


def _upsert_source_table_bound_values_rule(
    rules: list[Any],
    *,
    selector_rule: dict[str, Any],
    table_name: str,
    selector_name: str,
    side: str,
    values: dict[int, int | float],
    source_rules: list[dict[str, Any]],
) -> None:
    sorted_values = {key: values[key] for key in sorted(values)}
    existing_rule = next(
        (
            rule
            for rule in rules
            if isinstance(rule, dict)
            and str(rule.get("name") or "").strip() == table_name
        ),
        None,
    )
    sample_rule = source_rules[0] if source_rules else selector_rule
    target_rule: dict[str, Any]
    if existing_rule is None:
        target_rule = {
            "name": table_name,
            "kind": "parameter",
            "dtype": sample_rule.get("dtype") or "Decimal",
            "indexed_by": selector_name,
            "versions": [
                {
                    "effective_from": _single_version_effective_from(sample_rule)
                    or _single_version_effective_from(selector_rule)
                    or "1900-01-01",
                    "values": sorted_values,
                }
            ],
        }
        if sample_rule.get("source") is not None:
            target_rule["source"] = sample_rule["source"]
        with contextlib.suppress(ValueError):
            rules.insert(rules.index(selector_rule), target_rule)
            return
        rules.append(target_rule)
        return

    target_rule = existing_rule
    target_rule["kind"] = "parameter"
    target_rule.setdefault("dtype", sample_rule.get("dtype") or "Decimal")
    target_rule["indexed_by"] = selector_name
    target_rule.setdefault("source", sample_rule.get("source"))
    versions = target_rule.get("versions")
    if not isinstance(versions, list) or not versions:
        target_rule["versions"] = [
            {
                "effective_from": _single_version_effective_from(sample_rule)
                or _single_version_effective_from(selector_rule)
                or "1900-01-01",
                "values": sorted_values,
            }
        ]
        return
    first_version = versions[0]
    if not isinstance(first_version, dict):
        versions[0] = {
            "effective_from": _single_version_effective_from(sample_rule)
            or _single_version_effective_from(selector_rule)
            or "1900-01-01",
            "values": sorted_values,
        }
        return
    first_version.setdefault(
        "effective_from",
        _single_version_effective_from(sample_rule)
        or _single_version_effective_from(selector_rule)
        or "1900-01-01",
    )
    first_version["values"] = sorted_values


def _single_version_effective_from(rule: dict[str, Any]) -> str | None:
    versions = rule.get("versions")
    if not isinstance(versions, list) or not versions:
        return None
    version = versions[0]
    if not isinstance(version, dict):
        return None
    effective_from = version.get("effective_from")
    return str(effective_from) if effective_from is not None else None


def repair_unsupported_chained_conditionals(content: str) -> tuple[str, list[str]]:
    """Rewrite generated multiline `elif`/`else if` formulas into expressions."""
    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return content, []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    changed_rules: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip() or "<unknown>"
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            repaired = _repair_then_conditional_formula(formula)
            repaired = _repair_python_ternary_formula(repaired)
            repaired = _repair_else_if_formula(repaired)
            if repaired == formula:
                continue
            if _formula_has_unsupported_chained_conditional(repaired):
                continue
            version["formula"] = repaired
            changed_rules.add(rule_name)

    if not changed_rules:
        return content, []

    repaired_content = yaml.safe_dump(payload, sort_keys=False).strip() + "\n"
    return repaired_content, sorted(changed_rules)


def repair_formula_let_bindings(content: str) -> tuple[str, list[str]]:
    """Inline simple generated formula-local assignments."""
    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return content, []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    changed_rules: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip() or "<unknown>"
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            repaired = _repair_formula_let_binding_text(formula)
            if repaired == formula:
                continue
            version["formula"] = repaired
            changed_rules.add(rule_name)

    if not changed_rules:
        return content, []

    repaired_content = yaml.safe_dump(payload, sort_keys=False).strip() + "\n"
    return repaired_content, sorted(changed_rules)


_FORMULA_LET_BINDING_PATTERN = re.compile(
    r"^(?P<indent>\s*)(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*=\s*(?!=)(?P<expr>.*)$"
)


def _repair_formula_let_binding_text(formula: str) -> str:
    lines = formula.splitlines()
    if not any(_FORMULA_LET_BINDING_PATTERN.match(line) for line in lines):
        return formula

    replacements: dict[str, str] = {}
    repaired_lines: list[str] = []
    changed = False
    index = 0
    while index < len(lines):
        line = lines[index]
        match = _FORMULA_LET_BINDING_PATTERN.match(line)
        if match is None:
            repaired_lines.append(
                _replace_formula_let_binding_names(line, replacements)
            )
            index += 1
            continue

        name = match.group("name")
        indent = len(match.group("indent"))
        expr_parts: list[str] = []
        inline_expr = match.group("expr").strip()
        if inline_expr:
            expr_parts.append(inline_expr)
            index += 1
        else:
            index += 1
            while index < len(lines):
                continuation = lines[index]
                if continuation.strip() == "":
                    index += 1
                    continue
                continuation_indent = len(continuation) - len(continuation.lstrip(" "))
                if continuation_indent <= indent:
                    break
                expr_parts.append(continuation.strip())
                index += 1

        if not expr_parts:
            repaired_lines.append(line)
            continue

        expression = " ".join(expr_parts)
        expression = _replace_formula_let_binding_names(expression, replacements)
        replacements[name] = f"({expression})"
        changed = True

    if not changed:
        return formula
    return "\n".join(repaired_lines)


def _replace_formula_let_binding_names(line: str, replacements: dict[str, str]) -> str:
    repaired = line
    for name, expression in replacements.items():
        repaired = re.sub(rf"\b{re.escape(name)}\b", expression, repaired)
    return repaired


def repair_source_table_open_ended_bound_sentinels(
    content: str,
    *,
    source_text: str | None = None,
) -> tuple[str, list[str]]:
    """Remove invented sentinel values for open-ended source table bounds."""
    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return content, []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    source = (
        source_text.strip()
        if source_text is not None
        else (extract_numeric_grounding_source_text(content) or "").strip()
    )
    source_numbers = extract_numbers_from_text(source) if source else set()
    changed_rules: set[str] = set()

    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        if rule.get("indexed_by") is None:
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not _looks_like_open_ended_upper_bound_parameter(rule):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            values = version.get("values")
            if not isinstance(values, dict) or len(values) < 2:
                continue
            max_key = _max_structural_integer_table_key(values)
            if max_key is None:
                continue
            numeric = _numeric_rule_value(values.get(max_key))
            if numeric is None:
                continue
            _raw, value = numeric
            if not _is_generated_open_ended_bound_sentinel(value, source_numbers):
                continue
            del values[max_key]
            changed_rules.add(rule_name or "<unknown>")

    if not changed_rules:
        return content, []

    repaired_content = yaml.safe_dump(payload, sort_keys=False).strip() + "\n"
    return repaired_content, sorted(changed_rules)


@dataclass(frozen=True)
class _IntervalSourceRow:
    lower: str | None
    upper: str | None
    outputs: tuple[str, ...]


@dataclass(frozen=True)
class _IntervalSourceTable:
    output_headers: tuple[str, ...]
    rows: tuple[_IntervalSourceRow, ...]


@dataclass(frozen=True)
class _IntervalAlignmentSpec:
    selector_name: str
    input_name: str
    rows: tuple[_IntervalSourceRow, ...]
    lower_bound_parameter_name: str | None
    upper_bound_parameter_name: str | None
    lower_bound_parameter_rule: dict[str, Any] | None
    upper_bound_parameter_rule: dict[str, Any] | None
    output_parameter_names: tuple[str, ...]
    output_parameter_rules: tuple[dict[str, Any], ...]


def repair_source_table_interval_row_alignment(
    content: str,
    *,
    source_text: str | None = None,
) -> tuple[str, list[str]]:
    """Preserve row identity for open-ended interval source tables."""
    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return content, []

    specs = _source_table_interval_alignment_specs(payload, source_text=source_text)
    if not specs:
        return content, []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    changed_rules: set[str] = set()
    selector_by_name = {
        str(rule.get("name") or "").strip(): rule
        for rule in rules
        if isinstance(rule, dict)
    }
    for spec in specs:
        selector_rule = selector_by_name.get(spec.selector_name)
        if not isinstance(selector_rule, dict):
            continue
        versions = selector_rule.get("versions")
        if not isinstance(versions, list) or not versions:
            continue
        first_version = versions[0]
        if not isinstance(first_version, dict):
            continue

        lower_bound_name, lower_bound_changed = _ensure_interval_bound_parameter_rule(
            rules,
            spec=spec,
            selector_rule=selector_rule,
            selector_version=first_version,
            side="lower",
        )
        if lower_bound_changed and lower_bound_name:
            changed_rules.add(lower_bound_name)
        upper_bound_name, upper_bound_changed = _ensure_interval_bound_parameter_rule(
            rules,
            spec=spec,
            selector_rule=selector_rule,
            selector_version=first_version,
            side="upper",
        )
        if upper_bound_changed and upper_bound_name:
            changed_rules.add(upper_bound_name)

        repaired_formula = _build_interval_selector_formula(
            input_name=spec.input_name,
            rows=spec.rows,
            lower_bound_name=lower_bound_name,
            upper_bound_name=upper_bound_name,
        )
        if not repaired_formula:
            continue
        if first_version.get("formula") != repaired_formula:
            first_version["formula"] = repaired_formula
            changed_rules.add(spec.selector_name)

        for column_index, parameter_rule in enumerate(spec.output_parameter_rules):
            parameter_name = str(parameter_rule.get("name") or "").strip()
            parameter_versions = parameter_rule.get("versions")
            if not isinstance(parameter_versions, list) or not parameter_versions:
                continue
            parameter_version = parameter_versions[0]
            if not isinstance(parameter_version, dict):
                continue
            repaired_values = {
                row_index: _coerce_interval_source_output_value(
                    row.outputs[column_index],
                    parameter_rule,
                )
                for row_index, row in enumerate(spec.rows, start=1)
            }
            if parameter_version.get("values") != repaired_values:
                parameter_version["values"] = repaired_values
                changed_rules.add(parameter_name or "<unknown>")

    removable_bound_names = _unreferenced_source_table_scalar_bound_names(rules)
    if removable_bound_names:
        payload["rules"] = [
            rule
            for rule in rules
            if not (
                isinstance(rule, dict)
                and str(rule.get("name") or "").strip() in removable_bound_names
            )
        ]
        changed_rules.update(removable_bound_names)

    if not changed_rules:
        return content, []

    repaired_content = yaml.safe_dump(payload, sort_keys=False).strip() + "\n"
    return repaired_content, sorted(changed_rules)


def repair_source_table_interval_tests(
    content: str,
    *,
    rulespec_content: str | None,
    source_text: str | None = None,
) -> tuple[str, list[str]]:
    """Repair generated tests after interval source-table row realignment."""
    if not rulespec_content:
        return content, []
    try:
        cases = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return content, []
    if not isinstance(cases, list):
        return content, []

    payload = _rulespec_payload(rulespec_content)
    if payload is None:
        return content, []
    specs = _source_table_interval_alignment_specs(payload, source_text=source_text)
    if not specs:
        return content, []

    changed_cases: list[str] = []
    for case in cases:
        if not isinstance(case, dict):
            continue
        inputs = case.get("input")
        outputs = case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        case_changed = False
        for spec in specs:
            input_value = _test_input_value_for_name(inputs, spec.input_name)
            if input_value is None:
                continue
            with contextlib.suppress(TypeError, ValueError):
                selector_key = _interval_selector_key_for_value(
                    float(input_value),
                    spec.rows,
                )
                if selector_key is None:
                    continue
                expected_outputs = _interval_expected_outputs_for_key(
                    payload,
                    spec,
                    selector_key,
                )
                for output_key in list(outputs):
                    local_name = _rulespec_test_reference_local_name(output_key)
                    if local_name not in expected_outputs:
                        continue
                    repaired_value = expected_outputs[local_name]
                    if outputs[output_key] != repaired_value:
                        outputs[output_key] = repaired_value
                        case_changed = True
        if case_changed:
            changed_cases.append(str(case.get("name") or "<unnamed>"))

    if not changed_cases:
        return content, []
    repaired_content = yaml.safe_dump(cases, sort_keys=False).strip() + "\n"
    return repaired_content, changed_cases


def repair_copied_cross_reference_summary(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path | None = None,
) -> tuple[str, list[str]]:
    """Remove copied same-section cross-reference bodies from module summaries."""
    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return content, []

    module = payload.get("module")
    if not isinstance(module, dict):
        return content, []
    summary = module.get("summary")
    if not isinstance(summary, str) or not summary.strip():
        return content, []

    statute_path = (
        _statute_path_parts_for_file(rules_file, policy_repo_path)
        if policy_repo_path is not None
        else _statute_path_parts_for_any_file(rules_file)
    )
    if statute_path is None:
        return content, []
    title, section, current_fragments = statute_path

    cited_subsections = _same_section_subsections_cited_by_summary(summary)
    if not cited_subsections:
        return content, []

    repaired_summary = summary
    repaired_imports: list[str] = []
    for subsection in cited_subsections:
        if subsection in current_fragments:
            continue
        repaired, changed = _remove_summary_subsection_body(
            repaired_summary,
            subsection=subsection,
        )
        if not changed:
            continue
        repaired_summary = repaired
        repaired_imports.append("/".join(["statutes", title, section, subsection]))

    if not repaired_imports:
        return content, []

    module["summary"] = repaired_summary.strip()
    repaired_content = yaml.safe_dump(payload, sort_keys=False).strip() + "\n"
    return repaired_content, repaired_imports


def _same_section_subsections_cited_by_summary(summary: str) -> list[str]:
    seen: set[str] = set()
    subsections: list[str] = []
    for match in re.finditer(
        r"\bsubsection\s+\((?P<subsection>[A-Za-z0-9.]+)\)"
        r"(?:\s+of\s+this\s+section)?(?=\W|$)",
        summary,
        flags=re.IGNORECASE,
    ):
        subsection = match.group("subsection")
        if subsection in seen:
            continue
        seen.add(subsection)
        subsections.append(subsection)
    return subsections


def _remove_summary_subsection_body(
    summary: str,
    *,
    subsection: str,
) -> tuple[str, bool]:
    copied_body_pattern = re.compile(
        rf"(?ms)(^|\n+)\({re.escape(subsection)}\)\s+[A-Z][\s\S]*?"
        r"(?=\n+\([A-Za-z0-9.]+\)\s+[A-Z]|\Z)"
    )

    def remove_body(match: re.Match[str]) -> str:
        prefix = match.group(1)
        return "\n\n" if "\n\n" in prefix else prefix

    repaired, count = copied_body_pattern.subn(remove_body, summary)
    if count == 0:
        return summary, False
    repaired = re.sub(r"\n{3,}", "\n\n", repaired).strip()
    return repaired, True


def _statute_path_parts_for_any_file(
    rules_file: Path,
) -> tuple[str, str, tuple[str, ...]] | None:
    parts = rules_file.resolve(strict=False).parts
    for index, part in enumerate(parts):
        if part != "statutes":
            continue
        return _statute_path_parts_from_relative_parts(tuple(parts[index:]))
    return None


def _statute_path_parts_from_relative_parts(
    relative_parts: tuple[str, ...],
) -> tuple[str, str, tuple[str, ...]] | None:
    if not relative_parts or len(relative_parts) < 4 or relative_parts[0] != "statutes":
        return None

    title = relative_parts[1]
    section = relative_parts[2]
    fragments = list(relative_parts[3:-1])
    stem = Path(relative_parts[-1]).stem
    if stem not in {"index", "__init__"}:
        fragments.append(stem)
    return title, section, tuple(fragments)


def _source_table_interval_alignment_specs(
    payload: dict[str, Any],
    *,
    source_text: str | None = None,
) -> list[_IntervalAlignmentSpec]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    source_table = _parse_interval_source_table(
        source_text or _rulespec_module_summary(payload)
    )
    if source_table is None or not source_table.rows:
        return []
    if not any(row.lower is None or row.upper is None for row in source_table.rows):
        return []

    specs: list[_IntervalAlignmentSpec] = []
    for selector_rule in rules:
        if not isinstance(selector_rule, dict) or not _is_structural_selector_rule(
            selector_rule
        ):
            continue
        if str(selector_rule.get("kind") or "").strip().lower() != "derived":
            continue
        selector_name = str(selector_rule.get("name") or "").strip()
        if not selector_name:
            continue
        selector_formula = _first_version_formula(selector_rule)
        if not selector_formula:
            continue
        bound_rules = [
            rule
            for rule in rules
            if isinstance(rule, dict)
            and selector_name in _rulespec_indexed_by_names(rule.get("indexed_by"))
            and _looks_like_interval_bound_parameter(rule)
        ]
        bound_names = frozenset(
            str(rule.get("name") or "").strip()
            for rule in bound_rules
            if str(rule.get("name") or "").strip()
        )
        lower_bound_rule = _interval_bound_parameter_rule(bound_rules, side="lower")
        upper_bound_rule = _interval_bound_parameter_rule(bound_rules, side="upper")
        lower_bound_name = _interval_bound_parameter_rule_name(
            lower_bound_rule,
            selector_name=selector_name,
            side="lower",
        )
        upper_bound_name = _interval_bound_parameter_rule_name(
            upper_bound_rule,
            selector_name=selector_name,
            side="upper",
        )

        output_rules = [
            rule
            for rule in rules
            if isinstance(rule, dict)
            and str(rule.get("kind") or "").strip().lower() == "parameter"
            and selector_name in _rulespec_indexed_by_names(rule.get("indexed_by"))
            and not _looks_like_interval_bound_parameter(rule)
        ]
        output_rules = _ordered_interval_output_parameter_rules(
            output_rules,
            source_table.output_headers,
        )
        if len(output_rules) != len(source_table.rows[0].outputs):
            continue

        input_name = _infer_interval_selector_input_name(
            selector_formula,
            selector_name,
            bound_names,
        )
        if not input_name:
            continue
        specs.append(
            _IntervalAlignmentSpec(
                selector_name=selector_name,
                input_name=input_name,
                rows=source_table.rows,
                lower_bound_parameter_name=lower_bound_name,
                upper_bound_parameter_name=upper_bound_name,
                lower_bound_parameter_rule=lower_bound_rule,
                upper_bound_parameter_rule=upper_bound_rule,
                output_parameter_names=tuple(
                    str(rule.get("name") or "").strip() for rule in output_rules
                ),
                output_parameter_rules=tuple(output_rules),
            )
        )
    return specs


def _parse_interval_source_table(text: str | None) -> _IntervalSourceTable | None:
    if not text:
        return None
    output_headers: tuple[str, ...] = ()
    rows: list[_IntervalSourceRow] = []
    for line in text.splitlines():
        cells = _source_table_cells(line)
        if not cells:
            continue
        row_key_index = _find_interval_row_key_header_index(cells)
        if row_key_index is not None and row_key_index + 2 < len(cells):
            candidate_headers = tuple(cells[row_key_index + 2 :])
            if candidate_headers and not _cells_look_like_interval_row(
                candidate_headers
            ):
                output_headers = candidate_headers
            elif candidate_headers:
                compact_headers = _compact_interval_output_headers(
                    cells,
                    row_key_index,
                )
                compact_rows = _compact_interval_rows_from_cells(
                    candidate_headers,
                    output_count=len(compact_headers) or None,
                )
                if compact_rows:
                    if compact_headers:
                        output_headers = compact_headers
                    rows.extend(compact_rows)
                    continue
        row_cells = _interval_row_cells_from_cells(cells)
        if row_cells is None:
            continue
        lower, upper, outputs = row_cells
        rows.append(_IntervalSourceRow(lower=lower, upper=upper, outputs=outputs))
    if not rows:
        return None
    output_count = len(rows[0].outputs)
    if output_count == 0 or any(len(row.outputs) != output_count for row in rows):
        return None
    if output_headers and len(output_headers) != output_count:
        output_headers = ()
    return _IntervalSourceTable(output_headers=output_headers, rows=tuple(rows))


def _source_table_cells(line: str) -> list[str]:
    if "|" not in line:
        return []
    return [cell.strip() for cell in line.split("|") if cell.strip()]


def _compact_interval_output_headers(
    cells: list[str],
    row_key_index: int,
) -> tuple[str, ...]:
    prefix = cells[:row_key_index]
    separator_index = next(
        (
            index
            for index, cell in enumerate(prefix)
            if _is_markdown_separator_cell(cell)
        ),
        None,
    )
    if separator_index is not None:
        prefix = prefix[:separator_index]
    prefix = [cell for cell in prefix if not _is_markdown_separator_cell(cell)]
    return tuple(prefix[2:]) if len(prefix) > 2 else ()


def _compact_interval_rows_from_cells(
    cells: tuple[str, ...],
    *,
    output_count: int | None,
) -> list[_IntervalSourceRow]:
    output_counts = [output_count] if output_count else list(range(1, 8))
    for candidate_output_count in output_counts:
        group_size = candidate_output_count + 2
        if group_size <= 2 or len(cells) % group_size != 0:
            continue
        rows: list[_IntervalSourceRow] = []
        valid = True
        for start in range(0, len(cells), group_size):
            group = cells[start : start + group_size]
            lower = _parse_interval_bound_cell(group[0])
            upper = _parse_interval_bound_cell(group[1])
            if lower is _UNPARSED_BOUND or upper is _UNPARSED_BOUND:
                valid = False
                break
            outputs = tuple(group[2:])
            if any(_parse_source_numeric_cell(output) is None for output in outputs):
                valid = False
                break
            rows.append(
                _IntervalSourceRow(
                    lower=lower,
                    upper=upper,
                    outputs=outputs,
                )
            )
        if valid and len(rows) > 1:
            return rows
    return []


def _is_markdown_separator_cell(cell: str) -> bool:
    return bool(re.fullmatch(r":?-{2,}:?", cell.strip()))


def _find_interval_row_key_header_index(cells: list[str]) -> int | None:
    for index in range(0, len(cells) - 1):
        if (
            _normalized_text(cells[index]) == "atleast"
            and _normalized_text(cells[index + 1]) == "butlessthan"
        ):
            return index
    return None


def _interval_row_cells_from_cells(
    cells: list[str],
) -> tuple[str | None, str | None, tuple[str, ...]] | None:
    row_key_index = _find_interval_row_key_header_index(cells)
    if row_key_index is not None:
        cells = cells[row_key_index + 2 :]
    for start in range(0, max(1, len(cells) - 2)):
        lower = _parse_interval_bound_cell(cells[start])
        upper = (
            _parse_interval_bound_cell(cells[start + 1])
            if start + 1 < len(cells)
            else _UNPARSED_BOUND
        )
        if lower is _UNPARSED_BOUND or upper is _UNPARSED_BOUND:
            continue
        outputs = tuple(
            cell
            for cell in cells[start + 2 :]
            if _parse_source_numeric_cell(cell) is not None
        )
        if outputs:
            return lower, upper, outputs
    return None


_UNPARSED_BOUND = object()


def _parse_interval_bound_cell(cell: str) -> str | None | object:
    normalized = cell.strip()
    if not normalized or re.fullmatch(r"[.\u2026]+", normalized):
        return None
    return (
        normalized
        if _parse_source_numeric_cell(normalized) is not None
        else _UNPARSED_BOUND
    )


def _parse_source_numeric_cell(cell: str) -> float | None:
    normalized = cell.strip().replace(",", "")
    if not re.fullmatch(r"-?\d+(?:\.\d+)?", normalized):
        return None
    with contextlib.suppress(ValueError):
        return float(normalized)
    return None


def _cells_look_like_interval_row(cells: tuple[str, ...]) -> bool:
    return bool(cells and _parse_interval_bound_cell(cells[0]) is not _UNPARSED_BOUND)


def _rulespec_module_summary(payload: dict[str, Any]) -> str:
    module = payload.get("module")
    if not isinstance(module, dict):
        return ""
    summary = module.get("summary")
    return summary if isinstance(summary, str) else ""


def _looks_like_interval_bound_parameter(rule: dict[str, Any]) -> bool:
    return _looks_like_interval_lower_bound_parameter(
        rule
    ) or _looks_like_open_ended_upper_bound_parameter(rule)


def _interval_bound_parameter_rule(
    bound_rules: list[dict[str, Any]],
    *,
    side: str,
) -> dict[str, Any] | None:
    predicate = (
        _looks_like_interval_lower_bound_parameter
        if side == "lower"
        else _looks_like_open_ended_upper_bound_parameter
    )
    matches = [rule for rule in bound_rules if predicate(rule)]
    return matches[0] if matches else None


def _interval_bound_parameter_rule_name(
    rule: dict[str, Any] | None,
    *,
    selector_name: str,
    side: str,
) -> str | None:
    if rule is not None:
        name = str(rule.get("name") or "").strip()
        if name:
            return name
    return f"{selector_name}_{side}_bound"


def _looks_like_interval_lower_bound_parameter(rule: dict[str, Any]) -> bool:
    name = str(rule.get("name") or "").strip().lower()
    text = _interval_parameter_text(rule)
    return bool(
        re.search(r"\bat\s+least\b", text)
        or re.search(r"(?:^|_)(?:lower|minimum|min)(?:_|$)", name)
    )


def _interval_parameter_text(rule: dict[str, Any]) -> str:
    name = str(rule.get("name") or "").strip().lower()
    text_parts = [name]
    metadata = rule.get("metadata")
    if isinstance(metadata, dict):
        proof = metadata.get("proof")
        if isinstance(proof, dict):
            atoms = proof.get("atoms")
            if isinstance(atoms, list):
                for atom in atoms:
                    if not isinstance(atom, dict):
                        continue
                    source = atom.get("source")
                    if not isinstance(source, dict):
                        continue
                    table = source.get("table")
                    if not isinstance(table, dict):
                        continue
                    for key in ("header", "row_key", "column_key"):
                        value = table.get(key)
                        if isinstance(value, str):
                            text_parts.append(value.lower())
    return " ".join(text_parts)


def _ordered_interval_output_parameter_rules(
    output_rules: list[dict[str, Any]],
    output_headers: tuple[str, ...],
) -> list[dict[str, Any]]:
    if not output_headers or len(output_headers) != len(output_rules):
        return output_rules
    indexed: list[tuple[int, dict[str, Any]]] = []
    used_indexes: set[int] = set()
    for rule in output_rules:
        rule_text = _normalized_text(_interval_parameter_text(rule))
        matches = [
            index
            for index, header in enumerate(output_headers)
            if _normalized_text(header)
            and (
                _normalized_text(header) in rule_text
                or rule_text in _normalized_text(header)
            )
        ]
        if len(matches) != 1 or matches[0] in used_indexes:
            return output_rules
        used_indexes.add(matches[0])
        indexed.append((matches[0], rule))
    return [rule for _index, rule in sorted(indexed, key=lambda item: item[0])]


def _normalized_text(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", value.lower())


def _first_version_formula(rule: dict[str, Any]) -> str | None:
    versions = rule.get("versions")
    if not isinstance(versions, list) or not versions:
        return None
    first_version = versions[0]
    if not isinstance(first_version, dict):
        return None
    formula = first_version.get("formula")
    return formula if isinstance(formula, str) else None


def _infer_interval_selector_input_name(
    formula: str,
    selector_name: str,
    bound_names: frozenset[str],
) -> str | None:
    for bound_name in sorted(bound_names, key=len, reverse=True):
        match = re.search(
            rf"\b([A-Za-z_][A-Za-z0-9_]*)\b\s*(?:[<>]=?|==)\s*{re.escape(bound_name)}\s*\[",
            formula,
        )
        if match:
            return match.group(1)
        match = re.search(
            rf"{re.escape(bound_name)}\s*\[[^\]]+\]\s*(?:[<>]=?|==)\s*\b([A-Za-z_][A-Za-z0-9_]*)\b",
            formula,
        )
        if match:
            return match.group(1)
    suffix_match = re.match(r"(.+?)_(?:band|bracket|tier|index)$", selector_name)
    return suffix_match.group(1) if suffix_match else None


def _build_interval_selector_formula(
    *,
    input_name: str,
    rows: tuple[_IntervalSourceRow, ...],
    lower_bound_name: str | None = None,
    upper_bound_name: str | None = None,
) -> str | None:
    if not rows:
        return None
    tail = "0"
    rows_to_chain = list(enumerate(rows, start=1))
    if _interval_rows_are_contiguous(rows) and rows[-1].upper is None:
        tail = str(len(rows))
        rows_to_chain = rows_to_chain[:-1]
    for row_index, row in reversed(rows_to_chain):
        condition = _interval_row_condition(
            input_name,
            row,
            row_index=row_index,
            lower_bound_name=lower_bound_name,
            upper_bound_name=upper_bound_name,
        )
        if not condition:
            tail = str(row_index)
            continue
        tail = f"if {condition}: {row_index} else: {tail}"
    return tail


def _interval_rows_are_contiguous(rows: tuple[_IntervalSourceRow, ...]) -> bool:
    if len(rows) < 2:
        return False
    for previous, current in zip(rows, rows[1:]):
        if previous.upper is None or current.lower is None:
            return False
        if not math.isclose(
            float(previous.upper),
            float(current.lower),
            rel_tol=0,
            abs_tol=1e-12,
        ):
            return False
    return True


def _interval_row_condition(
    input_name: str,
    row: _IntervalSourceRow,
    *,
    row_index: int | None = None,
    lower_bound_name: str | None = None,
    upper_bound_name: str | None = None,
) -> str | None:
    parts: list[str] = []
    if row.lower is not None:
        lower_bound = (
            f"{lower_bound_name}[{row_index}]"
            if lower_bound_name is not None and row_index is not None
            else row.lower
        )
        parts.append(f"{input_name} >= {lower_bound}")
    if row.upper is not None:
        upper_bound = (
            f"{upper_bound_name}[{row_index}]"
            if upper_bound_name is not None and row_index is not None
            else row.upper
        )
        parts.append(f"{input_name} < {upper_bound}")
    return " and ".join(parts) if parts else None


def _ensure_interval_bound_parameter_rule(
    rules: list[Any],
    *,
    spec: _IntervalAlignmentSpec,
    selector_rule: dict[str, Any],
    selector_version: dict[str, Any],
    side: str,
) -> tuple[str | None, bool]:
    values = _interval_bound_values(spec.rows, side=side)
    if not values:
        return None, False
    existing_rule = (
        spec.lower_bound_parameter_rule
        if side == "lower"
        else spec.upper_bound_parameter_rule
    )
    name = (
        spec.lower_bound_parameter_name
        if side == "lower"
        else spec.upper_bound_parameter_name
    )
    if not name:
        name = f"{spec.selector_name}_{side}_bound"

    if existing_rule is None:
        new_rule: dict[str, Any] = {
            "name": name,
            "kind": "parameter",
            "dtype": "Decimal",
            "indexed_by": spec.selector_name,
            "versions": [
                {
                    "effective_from": selector_version.get(
                        "effective_from", "1900-01-01"
                    ),
                    "values": values,
                }
            ],
        }
        if selector_rule.get("source") is not None:
            new_rule["source"] = selector_rule.get("source")
        with contextlib.suppress(ValueError):
            selector_index = rules.index(selector_rule)
            rules.insert(selector_index, new_rule)
            return name, True
        rules.append(new_rule)
        return name, True

    changed = False
    if str(existing_rule.get("kind") or "").strip().lower() != "parameter":
        existing_rule["kind"] = "parameter"
        changed = True
    if existing_rule.get("indexed_by") != spec.selector_name:
        existing_rule["indexed_by"] = spec.selector_name
        changed = True
    versions = existing_rule.get("versions")
    if not isinstance(versions, list) or not versions:
        existing_rule["versions"] = [
            {
                "effective_from": selector_version.get("effective_from", "1900-01-01"),
                "values": values,
            }
        ]
        return name, True
    first_version = versions[0]
    if not isinstance(first_version, dict):
        versions[0] = {
            "effective_from": selector_version.get("effective_from", "1900-01-01"),
            "values": values,
        }
        return name, True
    if "effective_from" not in first_version and "effective_from" in selector_version:
        first_version["effective_from"] = selector_version["effective_from"]
        changed = True
    if first_version.get("values") != values:
        first_version["values"] = values
        changed = True
    return name, changed


def _interval_bound_values(
    rows: tuple[_IntervalSourceRow, ...],
    *,
    side: str,
) -> dict[int, int | float]:
    values: dict[int, int | float] = {}
    for row_index, row in enumerate(rows, start=1):
        raw_value = row.lower if side == "lower" else row.upper
        if raw_value is None:
            continue
        coerced = _coerce_interval_source_bound_value(raw_value)
        if coerced is not None:
            values[row_index] = coerced
    return values


def _coerce_interval_source_bound_value(raw_value: str) -> int | float | None:
    normalized = raw_value.strip().replace(",", "")
    if not re.fullmatch(r"-?\d+(?:\.\d+)?", normalized):
        return None
    with contextlib.suppress(ValueError):
        if "." not in normalized:
            return int(normalized)
        return float(normalized)
    return None


def _coerce_interval_source_output_value(
    raw_value: str,
    rule: dict[str, Any],
) -> float:
    value = _parse_source_numeric_cell(raw_value)
    if value is None:
        return 0.0
    dtype = str(rule.get("dtype") or "").strip().lower()
    name = str(rule.get("name") or "").strip().lower()
    parameter_text = _interval_parameter_text(rule)
    percentage_labeled = (
        "percentage" in name
        or "percent" in name
        or re.search(r"\bpercent(?:age)?\b", parameter_text) is not None
    )
    if percentage_labeled and value != 0:
        value = value / 100
    elif dtype == "rate" and abs(value) > 1:
        value = value / 100
    return round(value, 12)


def _test_input_value_for_name(inputs: dict[Any, Any], input_name: str) -> Any:
    for key, value in inputs.items():
        key_text = str(key)
        if key_text == input_name:
            return value
        if key_text.endswith(f"#input.{input_name}") or key_text.endswith(
            f"#{input_name}"
        ):
            return value
    return None


def _interval_selector_key_for_value(
    input_value: float,
    rows: tuple[_IntervalSourceRow, ...],
) -> int | None:
    for row_index, row in enumerate(rows, start=1):
        lower_ok = row.lower is None or input_value >= float(row.lower)
        upper_ok = row.upper is None or input_value < float(row.upper)
        if lower_ok and upper_ok:
            return row_index
    return None


def _interval_expected_outputs_for_key(
    payload: dict[str, Any],
    spec: _IntervalAlignmentSpec,
    selector_key: int,
) -> dict[str, Any]:
    expected: dict[str, Any] = {spec.selector_name: selector_key}
    parameter_values = _interval_parameter_values_by_name(payload, spec)
    for parameter_name, values in parameter_values.items():
        if selector_key in values:
            expected[parameter_name] = values[selector_key]

    derived_to_parameter = _interval_derived_output_parameter_map(payload, spec)
    for derived_name, parameter_name in derived_to_parameter.items():
        values = parameter_values.get(parameter_name)
        if values and selector_key in values:
            expected[derived_name] = values[selector_key]
    return expected


def _interval_parameter_values_by_name(
    payload: dict[str, Any],
    spec: _IntervalAlignmentSpec,
) -> dict[str, dict[int, Any]]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return {}
    output_names = set(spec.output_parameter_names)
    values_by_name: dict[str, dict[int, Any]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if name not in output_names:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list) or not versions:
            continue
        version = versions[0]
        if not isinstance(version, dict) or not isinstance(version.get("values"), dict):
            continue
        values: dict[int, Any] = {}
        for key, value in version["values"].items():
            normalized_key = _structural_integer_key(key)
            if normalized_key is None:
                continue
            values[int(normalized_key)] = value
        values_by_name[name] = values
    return values_by_name


def _interval_derived_output_parameter_map(
    payload: dict[str, Any],
    spec: _IntervalAlignmentSpec,
) -> dict[str, str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return {}
    direct: dict[str, str] = {}
    aliases: dict[str, str] = {}
    output_names = set(spec.output_parameter_names)
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        name = str(rule.get("name") or "").strip()
        formula = re.sub(r"\s+", " ", (_first_version_formula(rule) or "").strip())
        lookup_pattern = (
            rf"([A-Za-z_][A-Za-z0-9_]*)\s*"
            rf"\[\s*{re.escape(spec.selector_name)}\s*\]"
        )
        lookup_match = re.fullmatch(lookup_pattern, formula)
        if lookup_match and lookup_match.group(1) in output_names:
            direct[name] = lookup_match.group(1)
            continue
        guarded_lookup_match = re.fullmatch(
            rf"if\s+{re.escape(spec.selector_name)}\s*(?:==|=)\s*0\s*:\s*"
            rf"0(?:\.0)?\s+else:\s*{lookup_pattern}",
            formula,
        )
        if guarded_lookup_match and guarded_lookup_match.group(1) in output_names:
            direct[name] = guarded_lookup_match.group(1)
            continue
        if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", formula):
            aliases[name] = formula

    changed = True
    while changed:
        changed = False
        for alias_name, target_name in aliases.items():
            target_parameter = direct.get(target_name)
            if (
                target_parameter is not None
                and direct.get(alias_name) != target_parameter
            ):
                direct[alias_name] = target_parameter
                changed = True
    return direct


def _rulespec_test_reference_local_name(key: object) -> str | None:
    if not isinstance(key, str):
        return None
    if "#" in key:
        return key.rsplit("#", 1)[1].strip() or None
    return key.strip() or None


def _looks_like_open_ended_upper_bound_parameter(rule: dict[str, Any]) -> bool:
    name = str(rule.get("name") or "").strip().lower()
    text = _interval_parameter_text(rule)
    return bool(
        re.search(r"\bbut\s+less\s+than\b", text)
        or re.search(r"\bless\s+than\b", text)
        or re.search(r"(?:^|_)(?:upper|maximum|max)(?:_|$)", name)
    )


def _max_structural_integer_table_key(values: dict[Any, Any]) -> Any | None:
    keyed: list[tuple[int, Any]] = []
    for key in values:
        normalized = _structural_integer_key(key)
        if normalized is None:
            continue
        with contextlib.suppress(ValueError):
            keyed.append((int(normalized), key))
    if not keyed:
        return None
    return max(keyed, key=lambda item: item[0])[1]


def _is_generated_open_ended_bound_sentinel(
    value: float,
    source_numbers: set[float],
) -> bool:
    if abs(value) < 1_000_000:
        return False
    if source_numbers and numeric_value_is_grounded(value, source_numbers):
        return False
    return True


def _is_source_table_structural_bound_parameter_name(name: str) -> bool:
    normalized = name.strip().lower()
    if not normalized:
        return False
    has_index = re.search(r"(?:^|_)(?:row|band|bracket)_\d+(?:_|$)", normalized)
    has_bound_word = re.search(
        r"(?:^|_)(?:lower|upper)(?:_bound|_threshold|_limit)?(?:_|$)",
        normalized,
    )
    has_structural_noun = re.search(
        r"(?:^|_)(?:bound|threshold|limit)(?:_|$)", normalized
    )
    has_adjacent_min_max = re.search(
        r"(?:^|_)(?:row|band|bracket)_\d+_(?:min|max|minimum|maximum)(?:_|$)",
        normalized,
    ) or re.search(
        r"(?:^|_)(?:min|max|minimum|maximum)_(?:row|band|bracket)_\d+(?:_|$)",
        normalized,
    )
    has_adjacent_lower_upper = re.search(
        r"(?:^|_)(?:row|band|bracket)_\d+_(?:lower|upper)(?:_|$)",
        normalized,
    ) or re.search(
        r"(?:^|_)(?:lower|upper)_(?:row|band|bracket)_\d+(?:_|$)",
        normalized,
    )
    has_named_band_bound = re.search(
        r"(?:^|_)(?:band|bracket)_(?:bound|threshold|limit)_\d",
        normalized,
    ) or re.search(
        r"(?:^|_)(?:bound|threshold|limit)_(?:band|bracket)_\d",
        normalized,
    )
    return bool(
        (
            has_index
            and (
                (has_bound_word and has_structural_noun)
                or has_adjacent_min_max
                or has_adjacent_lower_upper
            )
        )
        or has_named_band_bound
    )


def _formula_references_identifier(formula: str, identifier: str) -> bool:
    return (
        re.search(
            rf"(?<![A-Za-z0-9_]){re.escape(identifier)}(?![A-Za-z0-9_])",
            formula,
        )
        is not None
    )


def _repair_else_if_formula(formula: str) -> str:
    branches = _parse_multiline_else_if_formula(formula)
    if branches is None:
        return formula

    tail = branches[-1][1]
    for condition, result in reversed(branches[:-1]):
        tail = f"if {condition}: {result} else: {tail}"
    return tail


def _repair_then_conditional_formula(formula: str) -> str:
    compact = " ".join(line.strip() for line in formula.strip().splitlines())
    match = re.fullmatch(
        r"if\s+(?P<condition>.+?)\s+then:\s+"
        r"(?P<true_result>.+?)\s+else:\s+(?P<false_result>.+)",
        compact,
    )
    if match is None:
        return formula

    true_result = match["true_result"].strip()
    false_result = match["false_result"].strip()
    if re.match(r"(?:if|elif|else\b)", true_result) or re.match(
        r"(?:elif|else\b)", false_result
    ):
        return formula
    return f"if {match['condition'].strip()}: {true_result} else: {false_result}"


def _repair_python_ternary_formula(formula: str) -> str:
    compact = " ".join(line.strip() for line in formula.strip().splitlines())
    if compact.startswith("if "):
        return formula
    match = re.fullmatch(
        r"(?P<true_result>.+?)\s+if\s+(?P<condition>.+?)\s+else\s+"
        r"(?P<false_result>.+)",
        compact,
    )
    if match is None:
        return formula

    true_result = match["true_result"].strip()
    condition = match["condition"].strip()
    false_result = match["false_result"].strip()
    if not true_result or not condition or not false_result:
        return formula
    if re.search(r"\b(?:if|else)\b", true_result) or re.search(
        r"\b(?:if|else)\b", false_result
    ):
        return formula
    return f"if {condition}: {true_result} else: {false_result}"


def _parse_multiline_else_if_formula(
    formula: str,
) -> list[tuple[str | None, str]] | None:
    lines = [line.rstrip() for line in formula.strip().splitlines() if line.strip()]
    if len(lines) < 2:
        return None

    def collect_block_result(start: int) -> tuple[str, int] | None:
        result_lines: list[str] = []
        index = start
        while index < len(lines):
            stripped = lines[index].strip()
            if result_lines and re.fullmatch(
                r"(?:if|elif|else\s+if)\b.*|else:",
                stripped,
            ):
                break
            if not result_lines and re.match(r"(?:if|elif|else\b)", stripped):
                return None
            result_lines.append(stripped)
            index += 1

        result = " ".join(result_lines).strip()
        if not result or re.match(r"(?:if|elif|else\b)", result):
            return None
        return result, index

    branches: list[tuple[str | None, str]] = []
    index = 0
    while index < len(lines):
        collected_header = _collect_multiline_conditional_header(lines, index)
        if collected_header is None:
            return None
        header, next_index = collected_header
        inline_if_match = re.fullmatch(
            r"(?:if|elif|else\s+if)\s+(.+?):\s*(.+)",
            header,
        )
        if inline_if_match is not None:
            result = inline_if_match.group(2).strip()
            if not result or re.match(r"(?:elif|else\b)", result):
                return None
            branches.append((inline_if_match.group(1).strip(), result))
            index = next_index
            continue
        inline_else_match = re.fullmatch(r"else:\s*(.+)", header)
        if inline_else_match is not None:
            result = inline_else_match.group(1).strip()
            if not result or re.match(r"(?:if|elif|else\b)", result):
                return None
            branches.append((None, result))
            index = next_index
            break
        if_match = re.fullmatch(r"(?:if|elif|else\s+if)\s+(.+):", header)
        if if_match is not None:
            collected = collect_block_result(next_index)
            if collected is None:
                return None
            result, index = collected
            branches.append((if_match.group(1).strip(), result))
            continue
        if header == "else:":
            collected = collect_block_result(next_index)
            if collected is None:
                return None
            result, index = collected
            branches.append((None, result))
            break
        return None

    if index != len(lines):
        return None
    if len(branches) < 2 or branches[-1][0] is not None:
        return None
    if not any(condition is not None for condition, _result in branches):
        return None
    return branches


def _collect_multiline_conditional_header(
    lines: list[str],
    index: int,
) -> tuple[str, int] | None:
    header = lines[index].strip()
    if not re.match(r"(?:if|elif|else\s+if)\b", header) or ":" in header:
        return header, index + 1

    parts = [header]
    cursor = index + 1
    while cursor < len(lines):
        part = lines[cursor].strip()
        if re.match(r"(?:if|elif|else\s+if)\b|else:", part):
            return None
        parts.append(part)
        cursor += 1
        if ":" in part:
            return " ".join(parts), cursor
    return None


def _formula_has_unsupported_chained_conditional(formula: str) -> bool:
    return bool(re.search(r"(?:^|\s)(?:elif|else\s+if)\b", formula))


def _source_text_looks_like_table(source_text: str) -> bool:
    return bool(
        re.search(r"\btable\b", source_text, flags=re.IGNORECASE)
        or source_text.count("|") >= 6
        or (
            re.search(r"\bschedule\b", source_text, flags=re.IGNORECASE)
            and source_text.count("|") >= 2
        )
    )


def find_versioned_derived_formula_issues(content: str) -> list[str]:
    """Flag derived rules that rely on unsupported period-selected formulas."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        formula_versions = [
            version
            for version in versions
            if isinstance(version, dict)
            and isinstance(version.get("formula"), str)
            and version["formula"].strip()
        ]
        if len(formula_versions) <= 1:
            continue
        name = str(rule.get("name") or "<unknown>")
        issues.append(
            "Versioned derived formula unsupported: "
            f"{name} has {len(formula_versions)} formula versions. "
            "Use a single source-faithful conditional formula or resolve the "
            "currently applicable source context before encoding."
        )
    return issues


def find_upstream_placement_issues(
    content: str,
    *,
    rules_file: Path | None = None,
    source_metadata: dict[str, object] | None = None,
) -> list[str]:
    """Flag rules encoded downstream of their canonical legal authority."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    if source_metadata is None and rules_file is not None:
        source_metadata = _load_nearby_eval_source_metadata(rules_file)

    issues: list[str] = []
    issues.extend(_find_rule_metadata_schema_issues(rules))
    issues.extend(
        _find_source_metadata_upstream_issues(
            rules=rules,
            source_metadata=source_metadata,
        )
    )
    issues.extend(_find_restatement_executable_copy_issues(rules, source_metadata))
    issues.extend(
        _find_duplicate_upstream_executable_issues(
            rules=rules,
            rules_file=rules_file,
        )
    )
    return issues


_SOURCE_METADATA_RESTATEMENT_RELATIONS = {
    "restate",
    "restates",
    "restated",
    "copy",
    "copies",
    "copied",
}
_SOURCE_METADATA_DECLARATIVE_RELATIONS = {
    "sets": "sets",
    "set": "sets",
    "amends": "amends",
    "amend": "amends",
    "amended": "amends",
    "implements": "implements",
    "implement": "implements",
    "implemented": "implements",
}
_RULE_METADATA_TARGET_KEYS = ("defines", "delegates", "implements", "sets", "amends")


def _find_rule_metadata_schema_issues(rules: list[Any]) -> list[str]:
    """Reject source-relation metadata on executable RuleSpec rules."""
    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue

        metadata = rule.get("metadata")
        if metadata is None:
            continue

        rule_name = str(rule.get("name") or "<unnamed>").strip() or "<unnamed>"
        if not isinstance(metadata, dict):
            issues.append(
                f"RuleSpec relation metadata malformed: rule `{rule_name}` metadata "
                "must be a mapping."
            )
            continue

        relation_keys = [
            key
            for key in ("source_relation", *_RULE_METADATA_TARGET_KEYS)
            if key in metadata
        ]
        if relation_keys:
            keys = ", ".join(f"`metadata.{key}`" for key in relation_keys)
            issues.append(
                f"RuleSpec source-relation metadata is not allowed on executable "
                f"rule `{rule_name}`: {keys}. Encode legal/provenance edges as "
                "separate `kind: source_relation` records."
            )
            continue

        if str(metadata.get("concept_id") or "").strip():
            issues.append(
                f"RuleSpec relation metadata has placeholder target: rule "
                f"`{rule_name}` declares `metadata.concept_id`; use an absolute "
                "RuleSpec or corpus target in a separate `kind: source_relation` "
                "record instead."
            )

    return issues


def _find_source_metadata_upstream_issues(
    *,
    rules: list[Any],
    source_metadata: dict[str, object] | None,
) -> list[str]:
    """Enforce generic upstream/source relations from structured source metadata."""
    issues: list[str] = []
    for relation, target in _iter_source_metadata_target_relations(source_metadata):
        if relation in _SOURCE_METADATA_RESTATEMENT_RELATIONS:
            if _rules_include_source_relation_target(
                rules,
                target,
                relation_type="restates",
            ):
                continue
            issues.append(
                "Source metadata upstream relation requires source_relation: "
                f"source metadata says this source `{relation}` `{target}`, so "
                "encode it as `kind: source_relation` with "
                "`source_relation.type: restates` and `source_relation.target` "
                "instead of redefining executable policy locally."
            )
            continue

        metadata_key = _SOURCE_METADATA_DECLARATIVE_RELATIONS.get(relation)
        if metadata_key is None:
            continue
        if _rules_include_source_relation_target(
            rules,
            target,
            relation_type=metadata_key,
        ):
            continue
        issues.append(
            "Source metadata upstream relation not recorded: "
            f"source metadata says this source `{relation}` `{target}`, so "
            "the corresponding RuleSpec file must include a "
            f"`kind: source_relation` record with `source_relation.type: {metadata_key}` "
            f"and `source_relation.target: {target}`."
        )
    return issues


def _iter_source_metadata_target_relations(
    source_metadata: dict[str, object] | None,
) -> Iterable[tuple[str, str]]:
    if not isinstance(source_metadata, dict):
        return

    relations = source_metadata.get("relations")
    if not isinstance(relations, list):
        return

    for relation in relations:
        if not isinstance(relation, dict):
            continue
        relation_name = str(relation.get("relation") or "").strip().lower()
        target = _normalize_relation_target(relation.get("target"))
        if relation_name and target:
            yield relation_name, target


def _rules_include_source_relation_target(
    rules: list[Any],
    target: str,
    *,
    relation_type: str,
) -> bool:
    return any(
        isinstance(rule, dict)
        and str(rule.get("kind") or "").lower() == "source_relation"
        and isinstance(rule.get("source_relation"), dict)
        and str(rule["source_relation"].get("type") or "").strip().lower()
        == relation_type
        and _target_matches(
            _normalize_relation_target(rule["source_relation"].get("target")),
            target,
        )
        for rule in rules
    )


def _normalize_relation_target(value: Any) -> str | None:
    if not isinstance(value, str):
        return None
    normalized = value.strip().strip('"').strip("'")
    if not normalized:
        return None
    base, separator, symbol = normalized.partition("#")
    if base.endswith((".yaml", ".yml")):
        base = str(Path(base).with_suffix(""))
        base = str(Path(base).with_suffix(""))
    return f"{base}{separator}{symbol}" if separator else base


def _target_matches(left: str | None, right: str | None) -> bool:
    if left is None or right is None:
        return False
    return _normalize_relation_target(left) == _normalize_relation_target(right)


def _find_restatement_executable_copy_issues(
    rules: list[Any],
    source_metadata: dict[str, object] | None,
) -> list[str]:
    """Reject local executable rules that copy explicitly restated targets."""
    restated_symbols: dict[str, str] = {}
    for relation, target in _iter_source_metadata_target_relations(source_metadata):
        if relation not in _SOURCE_METADATA_RESTATEMENT_RELATIONS:
            continue
        symbol = _target_symbol(target)
        if symbol is not None:
            restated_symbols.setdefault(symbol, target)

    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        if str(source_relation.get("type") or "").strip().lower() != "restates":
            continue
        target = _normalize_relation_target(source_relation.get("target"))
        if target is None:
            continue
        symbol = _target_symbol(target)
        if symbol is not None:
            restated_symbols.setdefault(symbol, target)
        verification = rule.get("verification")
        if isinstance(verification, dict) and isinstance(
            verification.get("values"), dict
        ):
            for value_name in verification["values"]:
                restated_symbols.setdefault(str(value_name), target)

    issues: list[str] = []
    for rule in rules:
        if not _is_executable_rulespec_rule(rule):
            continue
        name = _rulespec_rule_name(rule)
        target = restated_symbols.get(name)
        if target is None:
            continue
        issues.append(
            "Restated upstream target copied as executable RuleSpec: "
            f"`{name}` duplicates `{target}`. Remove the local executable rule "
            "and keep only an import or a non-executable `kind: source_relation` "
            "record with verification if the downstream source restates it."
        )
    return issues


@dataclass(frozen=True)
class _IndexedExecutableRule:
    """Executable RuleSpec rule discovered in a local rule repository."""

    target: str
    symbol: str
    signature: str
    source_file: str


def _find_duplicate_upstream_executable_issues(
    *,
    rules: list[Any],
    rules_file: Path | None,
) -> list[str]:
    """Reject copied executable rules when an upstream RuleSpec target exists."""
    if rules_file is None:
        return []

    repo_root = _rulespec_repo_root(rules_file)
    if repo_root is None:
        return []

    prefix = _rulespec_repo_prefix(repo_root)
    current_file = Path(rules_file).resolve()
    candidate_roots = _candidate_upstream_rulespec_roots(repo_root)
    index = _rulespec_executable_index_for_roots(
        tuple(str(root.resolve()) for root in candidate_roots)
    )
    if not index:
        return []

    issues: list[str] = []
    for rule in rules:
        if not _is_executable_rulespec_rule(rule):
            continue
        signature = _rulespec_executable_signature(rule)
        if signature is None:
            continue
        name = _rulespec_rule_name(rule)
        current_target = _canonical_rulespec_target(
            prefix=prefix,
            repo_root=repo_root,
            rules_file=current_file,
            symbol=name,
        )
        for candidate in index:
            if candidate.symbol != name or candidate.signature != signature:
                continue
            if candidate.target == current_target:
                continue
            if _rulespec_targets_are_equivalent(candidate.target, current_target):
                continue
            if Path(candidate.source_file).resolve() == current_file:
                continue
            if _rulespec_target_is_descendant_of(current_target, candidate.target):
                continue
            issues.append(
                "Upstream placement violation: "
                f"executable rule `{name}` duplicates existing RuleSpec target "
                f"`{candidate.target}`. Remove the local executable copy and "
                "use an import, or encode only a non-executable "
                "`kind: source_relation` record if this source restates the "
                "upstream rule."
            )
            break
    return issues


def _rulespec_target_is_descendant_of(target: str, ancestor: str) -> bool:
    """Return whether a RuleSpec target is a more-specific path under ancestor."""
    target_base = _canonical_rulespec_target_identity_base(target)
    ancestor_base = _canonical_rulespec_target_identity_base(ancestor)
    return target_base.startswith(f"{ancestor_base}/")


def _rulespec_targets_are_equivalent(left: str, right: str) -> bool:
    return _canonical_rulespec_target_identity_base(
        left
    ) == _canonical_rulespec_target_identity_base(right) and _target_symbol(
        left
    ) == _target_symbol(right)


def _canonical_rulespec_target_identity_base(target: str) -> str:
    """Normalize country-monorepo and per-jurisdiction target prefixes.

    CI validates files in a country monorepo checkout while also loading a
    second dependency checkout named like ``rulespec-us``. The same physical
    country file can therefore be represented as either
    ``us-co:regulations/...`` or ``us:rulespec-us/us-co/regulations/...``.
    These are the same RuleSpec target for placement purposes.
    """
    base = _rulespec_target_base(target)
    prefix, separator, relative = base.partition(":")
    if not separator:
        return base
    relative = relative.strip("/")
    parts = tuple(part for part in relative.split("/") if part)
    if parts and parts[0] == f"rulespec-{prefix}":
        remainder = parts[1:]
        if remainder and remainder[0].startswith(f"{prefix}-"):
            return "/".join(remainder)
        return "/".join((prefix, *remainder))
    return "/".join((prefix, *parts))


def _rulespec_target_base(target: str) -> str:
    return target.split("#", 1)[0].strip().strip("/").strip("\"'")


def _rulespec_repo_root(rules_file: Path) -> Path | None:
    """Return the jurisdiction content root holding ``rules_file``.

    The enclosing ``rulespec-*`` checkout root in the legacy layout, or the
    first-level jurisdiction directory inside a country monorepo checkout.
    """
    return find_policy_repo_root(Path(rules_file))


def _rulespec_repo_prefix(repo_root: Path) -> str:
    return jurisdiction_prefix(repo_root)


def _candidate_upstream_rulespec_roots(repo_root: Path) -> tuple[Path, ...]:
    """Return repos that can contain canonical targets for this repo."""
    roots: list[Path] = []

    def add(candidate: Path) -> None:
        if candidate.exists() and candidate.is_dir():
            roots.append(candidate)

    add(repo_root)
    workspaces = [repo_root.parent, repo_root / "_axiom", repo_root.parent / "_axiom"]
    if repo_root.parent.name.startswith("rulespec-"):
        # A monorepo jurisdiction directory: ancestor jurisdictions live next
        # to it inside the same checkout, and sibling checkouts live next to
        # the monorepo itself.
        workspaces.extend([repo_root.parent.parent, repo_root.parent.parent / "_axiom"])
    prefix_parts = _rulespec_repo_prefix(repo_root).split("-")
    for length in range(len(prefix_parts) - 1, 0, -1):
        ancestor_prefix = "-".join(prefix_parts[:length])
        for workspace in workspaces:
            for candidate in candidate_jurisdiction_content_dirs(
                workspace, ancestor_prefix
            ):
                add(candidate)

    unique: list[Path] = []
    seen: set[Path] = set()
    for root in roots:
        resolved = root.resolve()
        if resolved in seen:
            continue
        seen.add(resolved)
        unique.append(root)
    return tuple(unique)


@functools.lru_cache(maxsize=64)
def _rulespec_executable_index_for_roots(
    root_paths: tuple[str, ...],
) -> tuple[_IndexedExecutableRule, ...]:
    records: list[_IndexedExecutableRule] = []
    for root_path in root_paths:
        root = Path(root_path)
        if not root.exists():
            continue
        prefix = _rulespec_repo_prefix(root)
        # When the root is a (partially migrated) country monorepo checkout,
        # sibling jurisdiction directories carry their own prefixes and must
        # not be indexed under this root's prefix.
        sibling_jurisdiction_dirs = jurisdiction_subdir_names(root)
        for rules_file in sorted(root.rglob("*.yaml")):
            if rules_file.name.endswith(".test.yaml"):
                continue
            relative_parts = rules_file.relative_to(root).parts
            if "_axiom" in relative_parts:
                continue
            if relative_parts and relative_parts[0] in sibling_jurisdiction_dirs:
                continue
            try:
                payload = yaml.safe_load(rules_file.read_text())
            except (OSError, yaml.YAMLError, ValueError):
                continue
            if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
                continue
            rules = payload.get("rules")
            if not isinstance(rules, list):
                continue
            for rule in rules:
                if not _is_executable_rulespec_rule(rule):
                    continue
                signature = _rulespec_executable_signature(rule)
                if signature is None:
                    continue
                symbol = _rulespec_rule_name(rule)
                records.append(
                    _IndexedExecutableRule(
                        target=_canonical_rulespec_target(
                            prefix=prefix,
                            repo_root=root,
                            rules_file=rules_file,
                            symbol=symbol,
                        ),
                        symbol=symbol,
                        signature=signature,
                        source_file=str(rules_file.resolve()),
                    )
                )
    return tuple(records)


def _is_executable_rulespec_rule(rule: Any) -> bool:
    if not isinstance(rule, dict):
        return False
    return str(rule.get("kind") or "").strip().lower() in {
        "parameter",
        "derived",
        "derived_relation",
    }


def _has_module_source_locator(payload: dict[str, Any]) -> bool:
    module = payload.get("module")
    if not isinstance(module, dict):
        return False
    source_verification = module.get("source_verification")
    if not isinstance(source_verification, dict):
        return False
    if source_verification.get("corpus_citation_path"):
        return True
    citation_paths = source_verification.get("corpus_citation_paths")
    return isinstance(citation_paths, list) and any(citation_paths)


def find_rule_source_metadata_issues(content: str) -> list[str]:
    """Require source metadata for executable RuleSpec records."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    executable_rules = [rule for rule in rules if _is_executable_rulespec_rule(rule)]
    if not executable_rules:
        return []

    issues: list[str] = []
    if not _has_module_source_locator(payload):
        issues.append(
            "Rule source locator required: module.source_verification must include "
            "`corpus_citation_path` or `corpus_citation_paths` when executable "
            "rules are present."
        )

    for rule in executable_rules:
        name = _rulespec_rule_name(rule)
        if not rule.get("source"):
            issues.append(
                "Rule source metadata required: "
                f"`{name}` is an executable rule and must include `source:` "
                "with the legal citation/span supporting it."
            )

    return issues


def _rulespec_rule_name(rule: dict[str, Any]) -> str:
    return str(rule.get("name") or "<unknown>").strip() or "<unknown>"


def _canonical_rulespec_target(
    *,
    prefix: str,
    repo_root: Path,
    rules_file: Path,
    symbol: str,
) -> str:
    relative = rules_file.resolve().relative_to(repo_root.resolve())
    if relative.suffix in {".yaml", ".yml"}:
        relative = relative.with_suffix("")
    if relative.parts and relative.parts[0] == prefix:
        relative = Path(*relative.parts[1:])
    return f"{prefix}:{relative.as_posix()}#{symbol}"


def _canonical_rulespec_file_target(
    *,
    policy_repo_path: Path | None,
    rules_file: Path,
    symbol: str,
) -> str | None:
    repo_root: Path | None
    if policy_repo_path is not None and is_jurisdiction_content_root(
        Path(policy_repo_path)
    ):
        repo_root = Path(policy_repo_path)
        # Inside a country monorepo checkout the jurisdiction directory is
        # the target anchor; prefer it when it sits under the explicit root.
        walked_root = _rulespec_repo_root(rules_file)
        if walked_root is not None:
            try:
                walked_root.relative_to(repo_root.resolve())
            except ValueError:
                pass
            else:
                repo_root = walked_root
    else:
        repo_root = _rulespec_repo_root(rules_file)
    if repo_root is None:
        return None
    try:
        return _canonical_rulespec_target(
            prefix=_rulespec_repo_prefix(repo_root),
            repo_root=repo_root,
            rules_file=rules_file,
            symbol=symbol,
        )
    except ValueError:
        return None


def _strict_rules_repo_layout_checks_enabled(
    *,
    policy_repo_path: Path | None,
    rules_file: Path,
) -> bool:
    if policy_repo_path is None:
        return False
    repo_root = Path(policy_repo_path)
    if not is_jurisdiction_content_root(repo_root):
        return False
    try:
        rules_file.resolve().relative_to(repo_root.resolve())
    except ValueError:
        return False
    return True


def find_missing_derived_companion_output_issues(
    content: str,
    cases: list[Any],
    *,
    rules_file: Path,
    policy_repo_path: Path | None = None,
) -> list[str]:
    """Require companion tests to assert every local derived output."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    covered_outputs: set[str] = set()
    for case in cases:
        if not isinstance(case, dict):
            continue
        outputs = case.get("output")
        if isinstance(outputs, dict):
            covered_outputs.update(str(name) for name in outputs)

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict) or rule.get("kind") != "derived":
            continue
        name = _rulespec_rule_name(rule)
        target = _canonical_rulespec_file_target(
            policy_repo_path=policy_repo_path,
            rules_file=rules_file,
            symbol=name,
        )
        if target is None or target in covered_outputs:
            continue
        issues.append(
            "Derived rule missing companion output coverage: "
            f"`{target}` is not asserted by the companion `.test.yaml` file."
        )

    return issues


def find_judgment_positive_companion_output_issues(
    content: str,
    cases: list[Any],
    *,
    rules_file: Path,
    policy_repo_path: Path | None = None,
) -> list[str]:
    """Require local Judgment outputs to have at least one positive case."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    positive_outputs: set[str] = set()
    positive_fragments: set[str] = set()
    for case in cases:
        if not isinstance(case, dict):
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            continue
        for key, value in outputs.items():
            if not _is_positive_judgment_value(value):
                continue
            key_text = str(key).strip()
            positive_outputs.add(key_text)
            positive_fragments.add(_test_reference_fragment(key_text))

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict) or rule.get("kind") != "derived":
            continue
        if str(rule.get("dtype") or "").strip().lower() != "judgment":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list) or not any(
            isinstance(version, dict)
            and isinstance(version.get("formula"), str)
            and version["formula"].strip()
            for version in versions
        ):
            continue
        if _rule_versions_are_constant_false(versions):
            continue
        name = _rulespec_rule_name(rule)
        target = _canonical_rulespec_file_target(
            policy_repo_path=policy_repo_path,
            rules_file=rules_file,
            symbol=name,
        )
        if target is None:
            continue
        if target in positive_outputs or name in positive_fragments:
            continue
        issues.append(
            "Judgment rule missing positive companion output coverage: "
            f"`{target}` is not asserted as `holds` by the companion "
            "`.test.yaml` file."
        )

    return issues


_SYNTHETIC_SOURCE_AUTHORIZED_INPUT_PATTERN = re.compile(
    r"(?:^|_)source_authorized(?:_|$)"
)


def find_synthetic_source_authorized_input_issues(content: str) -> list[str]:
    """Reject local inputs that let tests invent source authorization.

    These inputs usually appear when a source-stated prohibition is encoded as a
    positive entitlement gated by a caller-supplied escape hatch, e.g. a source
    says a county is not entitled to a postponement but the formula depends on
    ``county_has_source_authorized_postponement_entitlement``.
    """
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []

    local_symbols = _rulespec_executable_names_from_payload(payload)
    local_symbols.update(_rulespec_data_relation_names(payload))
    local_symbols.update(_rulespec_import_symbol_names(payload))

    issues: list[str] = []
    seen: set[tuple[str, str]] = set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return issues
    for rule in rules:
        if not isinstance(rule, dict) or rule.get("kind") != "derived":
            continue
        rule_name = _rulespec_rule_name(rule)
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            for identifier in sorted(_formula_local_identifiers(formula)):
                if identifier in local_symbols:
                    continue
                if not _SYNTHETIC_SOURCE_AUTHORIZED_INPUT_PATTERN.search(identifier):
                    continue
                key = (rule_name, identifier)
                if key in seen:
                    continue
                seen.add(key)
                issues.append(
                    "Synthetic source-authorized local input: "
                    f"`{rule_name}` depends on local input `{identifier}`. "
                    "Encode the source-stated authorization, prohibition, or "
                    "entitlement directly, or import a source-backed upstream "
                    "authorization rule; do not let tests supply a "
                    "`source_authorized` escape hatch."
                )
    return issues


def _rule_versions_are_constant_false(versions: list[Any]) -> bool:
    formulas = [
        str(version.get("formula") or "").strip().lower()
        for version in versions
        if isinstance(version, dict) and isinstance(version.get("formula"), str)
    ]
    return bool(formulas) and all(
        _formula_is_syntactically_unsatisfiable_false(formula) for formula in formulas
    )


def _formula_is_syntactically_unsatisfiable_false(formula: str) -> bool:
    normalized = re.sub(r"\s+", " ", formula.strip().lower())
    normalized = _strip_balanced_outer_parentheses(normalized)
    if normalized == "false":
        return True
    conjuncts = _split_top_level_boolean_operator(normalized, "and")
    return len(conjuncts) > 1 and any(
        _formula_is_syntactically_unsatisfiable_false(conjunct)
        for conjunct in conjuncts
    )


def _strip_balanced_outer_parentheses(expression: str) -> str:
    stripped = expression.strip()
    while stripped.startswith("(") and stripped.endswith(")"):
        depth = 0
        encloses_all = True
        for index, char in enumerate(stripped):
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0 and index != len(stripped) - 1:
                    encloses_all = False
                    break
            if depth < 0:
                encloses_all = False
                break
        if not encloses_all or depth != 0:
            break
        stripped = stripped[1:-1].strip()
    return stripped


def _split_top_level_boolean_operator(expression: str, operator: str) -> list[str]:
    parts: list[str] = []
    depth = 0
    start = 0
    index = 0
    pattern = re.compile(rf"\b{re.escape(operator)}\b")
    while index < len(expression):
        char = expression[index]
        if char == "(":
            depth += 1
            index += 1
            continue
        if char == ")":
            depth = max(depth - 1, 0)
            index += 1
            continue
        if depth == 0:
            match = pattern.match(expression, index)
            if match is not None:
                parts.append(expression[start:index].strip())
                start = match.end()
                index = match.end()
                continue
        index += 1
    parts.append(expression[start:].strip())
    return [part for part in parts if part]


def _rulespec_executable_signature(rule: dict[str, Any]) -> str | None:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return None

    normalized_versions: list[dict[str, Any]] = []
    substantive = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        normalized_version: dict[str, Any] = {}
        for key in ("effective_from", "from", "effective_to", "to"):
            if key in version:
                normalized_version[key] = _canonical_yaml_value(version.get(key))
        values = version.get("values")
        if isinstance(values, dict) and values:
            normalized_version["values"] = _canonical_yaml_value(values)
            substantive = True
        else:
            formula = version.get("formula")
            if isinstance(formula, str) and formula.strip():
                normalized_formula = _normalize_formula_signature(formula)
                normalized_version["formula"] = normalized_formula
                if _formula_signature_is_substantive(normalized_formula):
                    substantive = True
        if "values" in normalized_version or "formula" in normalized_version:
            normalized_versions.append(normalized_version)

    if not normalized_versions or not substantive:
        return None

    payload = {
        "kind": str(rule.get("kind") or "").strip().lower(),
        "dtype": str(rule.get("dtype") or "").strip(),
        "period": str(rule.get("period") or "").strip(),
        "unit": str(rule.get("unit") or "").strip(),
        "indexed_by": str(rule.get("indexed_by") or "").strip(),
        "versions": normalized_versions,
    }
    return json.dumps(payload, sort_keys=True, separators=(",", ":"))


def _normalize_formula_signature(formula: str) -> str:
    return re.sub(r"\s+", " ", formula.strip())


def _formula_signature_is_substantive(formula: str) -> bool:
    numeric = _numeric_rule_value(formula)
    if numeric is not None:
        value = numeric[1]
        return not (float(value).is_integer() and int(value) in {-1, 0, 1, 2, 3})
    if re.fullmatch(r"[A-Za-z_][\w.]*", formula):
        return False
    return True


def _canonical_yaml_value(value: Any) -> Any:
    if isinstance(value, dict):
        return {
            str(key): _canonical_yaml_value(value[key])
            for key in sorted(value, key=lambda item: str(item))
        }
    if isinstance(value, list):
        return [_canonical_yaml_value(item) for item in value]
    if isinstance(value, (str, int, float, bool)) or value is None:
        return value
    return str(value)


def _target_symbol(target: str | None) -> str | None:
    if not target:
        return None
    _, separator, symbol = target.partition("#")
    if not separator:
        return None
    symbol = symbol.strip()
    return symbol or None


def find_source_verification_issues(
    content: str,
    *,
    source_texts: dict[str, str] | None = None,
) -> list[str]:
    """Validate declared RuleSpec values against an ingested corpus source page."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []

    source_verification = _source_verification_block(payload)
    if source_verification is None:
        return []

    citation_paths, source_label = _source_verification_source_fields(
        source_verification
    )
    expected_values = source_verification.get("values")
    if not citation_paths:
        return [
            "Source verification source required: missing `corpus_citation_path`, "
            "or `corpus_citation_paths`."
        ]
    if not isinstance(expected_values, dict) or not expected_values:
        if expected_values is not None:
            return [
                "Source verification values invalid: "
                "`source_verification.values` must be a non-empty mapping when present."
            ]
        expected_values = {}

    rulespec_values, _, load_issue = _extract_rulespec_parameter_values(payload)
    if load_issue is not None:
        return [f"Source verification RuleSpec invalid: {load_issue}"]

    issues: list[str] = []
    for value_name, expected_value in expected_values.items():
        value_key = str(value_name)
        if value_key not in rulespec_values:
            issues.append(
                "Source verification RuleSpec value missing: "
                f"`{value_key}` is declared for source verification but is not "
                "defined as a scalar/table parameter."
            )
            continue
        issues.extend(
            _compare_source_verification_expected_value(
                value_name=value_key,
                expected_value=expected_value,
                rulespec_value=rulespec_values[value_key],
            )
        )

    source_text = _source_verification_text(
        citation_paths=citation_paths,
        source_label=source_label,
        source_texts=source_texts,
    )
    if source_text is None:
        issues.append(
            "Source verification source missing: "
            + f"{_format_source_verification_paths(citation_paths)} "
            "was not found in corpus.provisions."
        )
        return issues
    if not expected_values:
        return issues

    for value_name, expected_value in expected_values.items():
        value_key = str(value_name)
        issues.extend(
            _find_source_text_value_issues(
                source_label=source_label,
                source_text=source_text,
                value_name=value_key,
                expected_value=expected_value,
            )
        )

    return issues


_COST_AVAILABILITY_SOURCE_PATTERN = re.compile(
    r"\b(available|allowed|eligible|entitled)\b.{0,180}"
    r"\b(billed|cost|costs|expense|expenses|incur|incurs|incurred)\b"
    r"|"
    r"\b(billed|cost|costs|expense|expenses|incur|incurs|incurred)\b"
    r".{0,180}\b(available|allowed|eligible|entitled)\b",
    flags=re.IGNORECASE | re.DOTALL,
)


def find_source_condition_coverage_issues(
    content: str,
    *,
    source_texts: dict[str, str] | None = None,
) -> list[str]:
    """Flag eligibility formulas that collapse cost availability to only exclusions."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    source_verification = _source_verification_block(payload)
    if source_verification is None:
        return []
    citation_paths, source_label = _source_verification_source_fields(
        source_verification
    )
    source_text = extract_embedded_source_text(content) or _source_verification_text(
        citation_paths=citation_paths,
        source_label=source_label,
        source_texts=source_texts,
    )
    if not source_text or not _COST_AVAILABILITY_SOURCE_PATTERN.search(source_text):
        return []

    issues: list[str] = []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return issues
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        kind = str(rule.get("kind") or "").strip().lower()
        if kind != "derived":
            continue
        name = str(rule.get("name") or "").strip()
        normalized_name = name.lower()
        if not any(
            token in normalized_name
            for token in ("eligible", "available", "allowance", "applies")
        ):
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"judgment", "boolean", "bool"}:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            identifiers = set(_RULESPEC_IDENTIFIER.findall(formula))
            identifiers -= _RULESPEC_FORMULA_BUILTINS
            if not identifiers:
                continue
            negated = {
                match.group(1)
                for match in re.finditer(r"\bnot\s+([A-Za-z_][A-Za-z0-9_]*)\b", formula)
            }
            if identifiers and identifiers <= negated:
                issues.append(
                    "Source condition coverage missing: "
                    f"`{name}` is grounded in source text that makes cost/expense availability conditional, "
                    "but its formula only negates other predicates. Add a positive fact predicate "
                    "for the source-stated cost, billing, payment, or incurrence condition."
                )
                continue
    return issues


_ANAPHORIC_SCOPE_PHRASE_PATTERN = re.compile(
    r"\b(?P<connector>through|with\s+respect\s+to|in\s+connection\s+with|on)"
    r"\s+such\s+"
    r"(?P<object>account|accounts|instrument|instruments|payment|payments|"
    r"property|properties|contract|contracts|membership|memberships|stock|"
    r"payee|payor|broker|acquisition|transaction|transactions|plan|plans|"
    r"service|services|item|items|year|period|employee|employer|individual|"
    r"child|household|unit)\b",
    flags=re.IGNORECASE,
)
_ANAPHORIC_EVENT_STOPWORDS = frozenset(
    {
        "a",
        "an",
        "and",
        "any",
        "as",
        "be",
        "by",
        "during",
        "for",
        "if",
        "in",
        "is",
        "of",
        "or",
        "such",
        "that",
        "the",
        "to",
        "was",
        "were",
        "which",
        "with",
    }
)
_ANAPHORIC_SCOPE_STOPWORDS = frozenset(
    {
        "a",
        "an",
        "and",
        "in",
        "of",
        "such",
        "the",
        "to",
        "with",
    }
)


def find_anaphoric_scope_omission_issues(
    content: str,
    *,
    source_texts: dict[str, str] | None = None,
) -> list[str]:
    """Flag predicates that drop source-stated same-object scope.

    This catches cases like a proof excerpt for broker activity where the full
    source sentence continues with "through such account", but the generated
    predicate only says the broker acted for the payee generally.
    """
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    source_verification = _source_verification_block(payload)
    if source_verification is None:
        return []
    citation_paths, source_label = _source_verification_source_fields(
        source_verification
    )
    source_text = _source_verification_text(
        citation_paths=citation_paths,
        source_label=source_label,
        source_texts=source_texts,
    )
    if not source_text:
        return []

    issues: list[str] = []
    seen: set[tuple[str, str, str, str]] = set()
    for rule_name, kind, formula, _source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        identifiers = sorted(_formula_local_identifiers(formula))
        if not identifiers:
            continue
        for excerpt in _rule_proof_source_excerpts(rule):
            scope_phrase = _anaphoric_scope_phrase_for_excerpt(
                source_text=source_text,
                excerpt=excerpt,
            )
            if scope_phrase is None:
                continue
            excerpt_tokens = _anaphoric_event_tokens(excerpt)
            if len(excerpt_tokens) < 3:
                continue
            required_scope_tokens = _anaphoric_scope_tokens(scope_phrase)
            if not required_scope_tokens:
                continue
            required_overlap = min(4, len(excerpt_tokens))
            for identifier in identifiers:
                identifier_tokens = _anaphoric_identifier_tokens(identifier)
                if len(excerpt_tokens & identifier_tokens) < required_overlap:
                    continue
                if required_scope_tokens <= identifier_tokens:
                    continue
                issue_key = (rule_name, excerpt, scope_phrase, identifier)
                if issue_key in seen:
                    continue
                seen.add(issue_key)
                issues.append(
                    "Anaphoric scope omitted: "
                    f"`{rule_name}` uses predicate `{identifier}` for proof excerpt "
                    f"`{excerpt}`, but the supporting source states "
                    f"`{scope_phrase}`. Preserve that same-object relationship in "
                    "the predicate name/formula and companion tests instead of "
                    "broadening the condition."
                )
    return issues


def _anaphoric_scope_phrase_for_excerpt(
    *,
    source_text: str,
    excerpt: str,
) -> str | None:
    excerpt_text = _collapse_source_sentence_text(excerpt)
    if not excerpt_text:
        return None
    if excerpt_match := _ANAPHORIC_SCOPE_PHRASE_PATTERN.search(excerpt_text):
        return _collapse_source_sentence_text(excerpt_match.group(0))

    source = _collapse_source_sentence_text(source_text)
    match = re.search(re.escape(excerpt_text), source, flags=re.IGNORECASE)
    if match is None:
        return None
    tail = source[match.end() : match.end() + 240]
    scope_match = _ANAPHORIC_SCOPE_PHRASE_PATTERN.search(tail)
    if scope_match is None:
        return None

    sentence_boundary = _first_sentence_boundary_index(tail)
    if sentence_boundary is not None and scope_match.start() > sentence_boundary:
        return None
    if _anaphoric_tail_crosses_clause_boundary(tail[: scope_match.start()]):
        return None
    return _collapse_source_sentence_text(scope_match.group(0))


def _collapse_source_sentence_text(value: str) -> str:
    return re.sub(r"\s+", " ", value).strip()


def _first_sentence_boundary_index(value: str) -> int | None:
    indexes = [
        index for marker in (".", ";", "\n") if (index := value.find(marker)) != -1
    ]
    return min(indexes) if indexes else None


def _anaphoric_tail_crosses_clause_boundary(value: str) -> bool:
    return bool(
        re.search(
            r"\([A-Z0-9ivx]+\)|\b(?:then|shall|must|may)\b",
            value,
            flags=re.IGNORECASE,
        )
    )


def _anaphoric_event_tokens(value: str) -> set[str]:
    return {
        token
        for token in _anaphoric_normalized_tokens(value)
        if token not in _ANAPHORIC_EVENT_STOPWORDS and not token.isdigit()
    }


def _anaphoric_scope_tokens(value: str) -> set[str]:
    return {
        token
        for token in _anaphoric_normalized_tokens(value)
        if token not in _ANAPHORIC_SCOPE_STOPWORDS
    }


def _anaphoric_identifier_tokens(value: str) -> set[str]:
    return {
        token
        for token in _anaphoric_normalized_tokens(value)
        if token not in _ANAPHORIC_EVENT_STOPWORDS
    }


def _anaphoric_normalized_tokens(value: str) -> set[str]:
    tokens: set[str] = set()
    for raw_token in re.findall(r"[A-Za-z0-9]+", value.lower()):
        tokens.add(raw_token)
        if len(raw_token) > 4 and raw_token.endswith("ies"):
            tokens.add(raw_token[:-3] + "y")
        elif len(raw_token) > 3 and raw_token.endswith("s"):
            tokens.add(raw_token[:-1])
    return tokens


