def _rulespec_payload(content: str) -> dict[str, Any] | None:
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return None
    return payload if isinstance(payload, dict) else None


def _rulespec_rule_formula_records(
    payload: dict[str, Any],
) -> list[tuple[str, str, str, Any]]:
    """Return `(rule_name, kind, formula, source)` entries from a RuleSpec payload."""
    return [
        (name, kind, formula, source)
        for name, kind, formula, source, _rule in _rulespec_rule_formula_rule_records(
            payload
        )
    ]


def _rulespec_rule_formula_rule_records(
    payload: dict[str, Any],
) -> list[tuple[str, str, str, Any, dict[str, Any]]]:
    """Return formula records with their owning rule payload."""
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    formulas: list[tuple[str, str, str, Any, dict[str, Any]]] = []
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or f"rules[{index}]").strip()
        kind = str(rule.get("kind") or "").strip().lower()
        rule_source = rule.get("source")
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            source = version.get("source", rule_source)
            formula = version.get("formula")
            if isinstance(formula, (int, float)) and not isinstance(formula, bool):
                formulas.append((name, kind, str(formula), source, rule))
            elif isinstance(formula, str) and formula.strip():
                formulas.append((name, kind, formula, source, rule))
    return formulas


def _rulespec_rule_formulas(payload: dict[str, Any]) -> list[tuple[str, str, str]]:
    """Return `(rule_name, kind, formula)` entries from a RuleSpec payload."""
    return [
        (name, kind, formula)
        for name, kind, formula, _source in _rulespec_rule_formula_records(payload)
    ]


def find_empty_rules_module_issues(content: str) -> list[str]:
    """Reject empty RuleSpec modules that do not explicitly declare a fallback."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list) or rules:
        return []
    module = payload.get("module")
    status = ""
    if isinstance(module, dict):
        status = str(module.get("status") or "").strip().lower()
    if status in {"deferred", "entity_not_supported"}:
        return []
    return [
        "Empty RuleSpec module invalid: `rules: []` requires explicit "
        "`module.status: deferred` or `module.status: entity_not_supported`. "
        "If the source is executable, encode at least one source-backed rule; "
        "do not silently apply an empty module."
    ]


def _classify_source_scope(text: str) -> str | None:
    """Return a clear source scope, or None when the text is mixed/vague."""
    person_scoped = _PERSON_SCOPE_SOURCE_PATTERN.search(text) is not None
    unit_scoped = (
        _UNIT_SCOPE_SOURCE_PATTERN.search(text) is not None
        or _TAXPAYER_TAX_UNIT_SOURCE_PATTERN.search(text) is not None
    )
    if _HOUSEHOLD_MEMBER_MIXED_SCOPE_PATTERN.search(text):
        return None
    if person_scoped == unit_scoped:
        return None
    return _SOURCE_SCOPE_PERSON if person_scoped else _SOURCE_SCOPE_UNIT


def _classify_source_unit_entity(text: str) -> str | None:
    """Return a clear unit entity from source text, or None when generic/mixed."""
    if _TAXPAYER_TAX_UNIT_SOURCE_PATTERN.search(text):
        return "taxunit"
    matches = {
        entity
        for entity, pattern in _UNIT_SOURCE_ENTITY_PATTERNS
        if pattern.search(text)
    }
    if len(matches) != 1:
        return None
    return next(iter(matches))


def _unit_entities_are_equivalent(left: str, right: str) -> bool:
    if left == right:
        return True
    return any(
        {left, right} <= entity_set for entity_set in _UNIT_ENTITY_EQUIVALENCE_SETS
    )


def _unit_entities_are_equivalent_for_source_rule(
    left: str,
    right: str,
    *,
    rule: dict[str, Any],
    fallback_source_text: str,
) -> bool:
    if _unit_entities_are_equivalent(left, right):
        return True
    if {left, right} != {"taxunit", "household"}:
        return False
    rule_source = str(rule.get("source") or "")
    source_context = "\n".join(
        [
            fallback_source_text,
            *_rule_proof_source_excerpts(rule),
            rule_source,
        ]
    )
    if not _FEDERAL_TAX_SOURCE_CONTEXT_PATTERN.search(source_context):
        return False
    return bool(
        _FEDERAL_TAX_HOUSEHOLD_INCOME_TAXUNIT_CONTEXT_PATTERN.search(source_context)
    )


def _person_rule_can_use_unit_scoped_medicaid_magi_source(
    rule: dict[str, Any],
    *,
    fallback_source_text: str,
) -> bool:
    """Allow Medicaid MAGI individual eligibility to include household income.

    The federal MAGI groups in 42 CFR 435.110, .116, .118, and .119 define
    eligibility for individuals, while one condition is stated as household
    income against FPL. The source-scope guard should continue rejecting generic
    person rules proven only from household text, but these final Medicaid
    eligibility judgments are legitimately person-scoped.
    """
    name = str(rule.get("name") or "")
    if not _MEDICAID_MAGI_ELIGIBILITY_RULE_NAME_PATTERN.search(name):
        return False
    if _MEDICAID_MAGI_INCOME_HELPER_RULE_NAME_PATTERN.search(name):
        return False
    if str(rule.get("dtype") or "").strip().lower() != "judgment":
        return False
    if _medicaid_magi_rule_has_income_only_formula(rule):
        return False
    if not _medicaid_magi_rule_has_income_formula_reference(rule):
        return False
    proof_contexts = _rule_proof_source_contexts(rule)
    citation_context = "\n".join(
        [
            str(rule.get("source") or ""),
            *(text for _key, text in proof_contexts),
        ]
    )
    if not _MEDICAID_MAGI_RULE_CITATION_PATTERN.search(citation_context):
        return False
    proof_excerpts = [text for key, text in proof_contexts if key == "excerpt"]
    classified_texts = proof_excerpts or [fallback_source_text]
    if not any(
        re.search(r"\bhousehold\s+income\b", text, re.IGNORECASE)
        for text in classified_texts
    ):
        return False
    eligibility_context = "\n".join([*classified_texts, fallback_source_text])
    return bool(
        _MEDICAID_MAGI_PERSON_ELIGIBILITY_CONTEXT_PATTERN.search(eligibility_context)
    )


def _medicaid_magi_rule_has_income_only_formula(rule: dict[str, Any]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    formulas = [
        formula
        for version in versions
        if isinstance(version, dict)
        and isinstance((formula := version.get("formula")), str)
        and formula.strip()
    ]
    if not formulas:
        return False
    return all(
        not _FORMULA_BOOLEAN_CONNECTIVE_PATTERN.search(formula)
        and (
            _MEDICAID_MAGI_INCOME_FORMULA_PATTERN.search(formula)
            or _MEDICAID_MAGI_SINGLE_INCOME_HELPER_FORMULA_PATTERN.fullmatch(
                formula.strip()
            )
        )
        for formula in formulas
    )


def _medicaid_magi_rule_has_income_formula_reference(rule: dict[str, Any]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    formulas = [
        formula
        for version in versions
        if isinstance(version, dict)
        and isinstance((formula := version.get("formula")), str)
        and formula.strip()
    ]
    if not formulas:
        return False
    return all(
        bool(_MEDICAID_MAGI_INCOME_FORMULA_PATTERN.search(formula))
        for formula in formulas
    )


def _rule_proof_source_excerpts(rule: dict[str, Any]) -> list[str]:
    return [text for key, text in _rule_proof_source_contexts(rule) if key == "excerpt"]


def _rule_proof_source_contexts(rule: dict[str, Any]) -> list[tuple[str, str]]:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return []
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return []
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return []

    contexts: list[tuple[str, str]] = []
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        source = atom.get("source")
        if not isinstance(source, dict):
            continue
        for key in ("excerpt", "corpus_citation_path"):
            value = source.get(key)
            if isinstance(value, str) and value.strip():
                contexts.append((key, value.strip()))
        many_paths = source.get("corpus_citation_paths")
        if isinstance(many_paths, list):
            for value in many_paths:
                if isinstance(value, str) and value.strip():
                    contexts.append(("corpus_citation_paths", value.strip()))
        elif isinstance(many_paths, str) and many_paths.strip():
            contexts.append(("corpus_citation_paths", many_paths.strip()))
    return contexts


def _rule_source_scope(
    rule: dict[str, Any],
    fallback_source_text: str,
) -> tuple[str, str | None] | None:
    source_texts = _rule_proof_source_excerpts(rule)
    if not source_texts and _rule_proof_source_contexts(rule):
        # Path-only proof citations are not rule-specific source text.
        return None
    if not source_texts and fallback_source_text:
        source_texts = [fallback_source_text]

    classifications = [
        (
            scope,
            _classify_source_unit_entity(text) if scope == _SOURCE_SCOPE_UNIT else None,
        )
        for text in source_texts
        if (scope := _classify_source_scope(text)) is not None
    ]
    scopes = {scope for scope, _unit_entity in classifications}
    if len(scopes) != 1:
        return None
    scope = next(iter(scopes))
    unit_entities = {
        unit_entity
        for _scope, unit_entity in classifications
        if unit_entity is not None
    }
    if len(unit_entities) > 1:
        return None
    source_unit_entity = next(iter(unit_entities), None)
    return scope, source_unit_entity


def find_source_scope_consistency_issues(content: str) -> list[str]:
    """Flag obvious mismatches between source legal subject and rule entity.

    This is intentionally conservative: if the source appears mixed or vague,
    it returns no issue rather than guessing a legal scope.
    """
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    source_text = extract_embedded_source_text(content)

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    unit_relation_aggregate_helper_names = (
        _unit_relation_aggregate_helper_names_by_rule(payload, source_text)
    )
    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        kind = str(rule.get("kind") or "").strip().lower()
        if kind != "derived":
            continue
        name = str(rule.get("name") or "").strip()
        entity = str(rule.get("entity") or "").strip()
        normalized_entity = entity.lower()
        source_scope_record = _rule_source_scope(rule, source_text)
        if source_scope_record is None:
            continue
        source_scope, source_unit_entity = source_scope_record
        if (
            source_scope == _SOURCE_SCOPE_PERSON
            and normalized_entity in _UNIT_SCOPED_ENTITY_NAMES
        ):
            issues.append(
                "Source scope mismatch: "
                f"`{name}` is declared on `{entity}`, but the embedded source "
                "states an individual/person/member-scoped eligibility or "
                "disqualification. Encode the rule at the person/member scope "
                "or cite source text that states the unit-level test."
            )
        elif source_scope == _SOURCE_SCOPE_UNIT and normalized_entity == "person":
            if _person_rule_can_use_unit_scoped_medicaid_magi_source(
                rule,
                fallback_source_text=source_text,
            ):
                continue
            if _person_rule_can_use_unit_member_aggregate_source(
                rule,
                name=name,
                fallback_source_text=source_text,
                unit_relation_aggregate_helper_names=unit_relation_aggregate_helper_names,
            ):
                continue
            issues.append(
                "Source scope mismatch: "
                f"`{name}` is declared on `Person`, but the embedded source "
                "states a household/unit-scoped test. Encode the rule at the "
                "source-stated unit scope or cite source text that states the "
                "person-level test."
            )
        elif (
            source_scope == _SOURCE_SCOPE_UNIT
            and source_unit_entity is not None
            and normalized_entity in _UNIT_SCOPED_ENTITY_NAMES
            and not _unit_entities_are_equivalent_for_source_rule(
                normalized_entity,
                source_unit_entity,
                rule=rule,
                fallback_source_text=source_text,
            )
        ):
            issues.append(
                "Source scope mismatch: "
                f"`{name}` is declared on `{entity}`, but the embedded source "
                f"states a `{_UNIT_SCOPED_ENTITY_LABELS[source_unit_entity]}` "
                "unit-scoped test. Encode the rule at the source-stated unit "
                "scope or cite source text that states the declared unit scope."
            )
    return issues


def _unit_relation_aggregate_helper_names_by_rule(
    payload: dict[str, Any],
    fallback_source_text: str,
) -> set[str]:
    helper_names: set[str] = set()
    for _name, kind, formula, _rule_source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        entity = str(rule.get("entity") or "").strip().lower()
        if entity not in _UNIT_SCOPED_ENTITY_NAMES:
            continue
        if not _RELATION_AGGREGATE_PATTERN.search(formula):
            continue
        source_scope_record = _rule_source_scope(rule, fallback_source_text)
        if (
            source_scope_record is not None
            and source_scope_record[0] == _SOURCE_SCOPE_PERSON
        ):
            continue
        helper_names.update(_relation_aggregate_helper_identifiers(formula))
    return helper_names


_RELATION_AGGREGATE_CALL_START_PATTERN = re.compile(
    r"\b(?P<function>count_where|sum_where|len|sum)\s*\(",
    flags=re.IGNORECASE,
)


def _relation_aggregate_call_arguments(formula: str) -> Iterator[tuple[str, list[str]]]:
    for match in _RELATION_AGGREGATE_CALL_START_PATTERN.finditer(formula):
        depth = 1
        index = match.end()
        while index < len(formula):
            char = formula[index]
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0:
                    yield (
                        match.group("function").lower(),
                        _split_top_level_call_arguments(formula[match.end() : index]),
                    )
                    break
            index += 1


def _relation_aggregate_helper_identifiers(formula: str) -> set[str]:
    helper_names: set[str] = set()
    for function_name, arguments in _relation_aggregate_call_arguments(formula):
        if len(arguments) < 2:
            continue
        relation_name = arguments[0].strip()
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", relation_name):
            continue
        if function_name in {"count_where", "sum_where"}:
            for helper_argument in arguments[1:]:
                helper_names.update(_formula_local_identifiers(helper_argument))
    return helper_names


def _person_rule_can_use_unit_member_aggregate_source(
    rule: dict[str, Any],
    *,
    name: str,
    fallback_source_text: str,
    unit_relation_aggregate_helper_names: set[str],
) -> bool:
    """Allow person helpers used only to evaluate all-member unit tests."""
    if name not in unit_relation_aggregate_helper_names:
        return False
    if str(rule.get("dtype") or "").strip().lower() != "judgment":
        return False
    source_contexts = _rule_proof_source_excerpts(rule)
    if not source_contexts and fallback_source_text:
        source_contexts = [fallback_source_text]
    return any(
        _UNIT_MEMBER_AGGREGATE_HELPER_SOURCE_PATTERN.search(text)
        for text in source_contexts
    )


def _formula_or_referenced_helpers_use_relation_aggregate(
    formula: str,
    *,
    formula_by_name: dict[str, str],
    seen: set[str] | None = None,
) -> bool:
    if _RELATION_AGGREGATE_PATTERN.search(formula):
        return True
    visited = set(seen or set())
    for identifier in _formula_local_identifiers(formula):
        if identifier in visited:
            continue
        helper_formula = formula_by_name.get(identifier)
        if helper_formula is None:
            continue
        visited.add(identifier)
        if _formula_or_referenced_helpers_use_relation_aggregate(
            helper_formula,
            formula_by_name=formula_by_name,
            seen=visited,
        ):
            return True
    return False


def find_person_scoped_rate_base_unit_issues(content: str) -> list[str]:
    """Flag unit-level rate * base formulas for person-scoped legal bases."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    source_text = extract_embedded_source_text(content)
    if not source_text:
        source_text = _extract_source_verification_text(content)
    if not source_text:
        return []

    formula_records = _rulespec_rule_formula_rule_records(payload)
    formula_by_name = {
        name: formula
        for name, kind, formula, _source, _rule in formula_records
        if kind == "derived"
    }
    dtype_by_name = _rulespec_rule_dtype_by_name(payload)
    issues: list[str] = []
    for name, kind, formula, rule_source, rule in formula_records:
        if kind != "derived":
            continue
        if not _RATE_IDENTIFIER_MULTIPLICATION_PATTERN.search(formula):
            continue
        entity = str(rule.get("entity") or "").strip()
        if entity.lower() not in _UNIT_SCOPED_ENTITY_NAMES:
            continue
        if dtype_by_name.get(name) not in {"money", "decimal", "rate"}:
            continue
        scoped_source_text = " ".join(_rule_proof_source_excerpts(rule))
        if not scoped_source_text:
            scoped_source_text = _source_text_for_rule_source(source_text, rule_source)
        if not _PERSON_SCOPED_RATE_BASE_SOURCE_PATTERN.search(scoped_source_text):
            continue
        if _formula_or_referenced_helpers_use_relation_aggregate(
            formula,
            formula_by_name=formula_by_name,
        ):
            continue
        issues.append(
            "Person-scoped rate base at unit scope: "
            f"`{name}` is declared on `{entity}` and multiplies a base by a "
            "rate, but the source text states the amount or tax for each/every "
            "individual, person, member, employee, or similar lower-entity "
            "subject. Encode the rate-applied amount at that lower entity "
            "first, then aggregate through an explicit relation; do not "
            "multiply a unit-level placeholder or aggregate base by the rate."
        )
    return issues


_PERSON_SCOPED_DEFINITION_SOURCE_PATTERN = re.compile(
    r"\bterm\b[\s\S]{0,120}\bmeans\b[\s\S]{0,260}\bnet\s+earnings?\b"
    r"[\s\S]{0,180}\bderived\s+by\s+(?:an?|the|such)\s+"
    r"(?:individual|person|employee|member)\b"
    r"|"
    r"\bterm\s+[\"'“”‘’]?net\s+earnings?\b[\s\S]{0,160}\bmeans\b"
    r"[\s\S]{0,260}\bderived\s+by\s+(?:an?|the|such)\s+"
    r"(?:individual|person|employee|member)\b"
    r"|"
    r"\bearned\s+income\s+of\s+(?:an?|the|such)\s+individual\b"
    r"[\s\S]{0,220}\bcomputed\b"
    r"|"
    r"\bnet\s+earnings?\b[\s\S]{0,220}\bwages\s+paid\s+to\s+"
    r"(?:an?|the|such)\s+(?:individual|person|employee|member)\b"
    r"|"
    r"\bremuneration\b[\s\S]{0,220}\bpaid\s+to\s+"
    r"(?:an?|the|such)\s+"
    r"(?:individual|person|employee|member)\b",
    flags=re.IGNORECASE,
)

_SECTION_1402_A_12_PERSON_BASE_PATTERN = re.compile(
    r"\b(?:taxpayer'?s?\s+)?net\s+earnings?\s+from\s+self[-\s]?employment\b"
    r"[\s\S]{0,220}\bdetermined\s+without\s+regard\s+to\s+"
    r"(?:this\s+paragraph|paragraph\s*\(?12\)?)\b",
    flags=re.IGNORECASE,
)


def find_person_scoped_definition_unit_issues(content: str) -> list[str]:
    """Flag unit-level derived definitions for person-scoped legal amounts."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    source_text = extract_embedded_source_text(content)
    if not source_text:
        source_text = _extract_source_verification_text(content)
    if not source_text:
        return []

    formula_records = _rulespec_rule_formula_rule_records(payload)
    formula_by_name = {
        name: formula
        for name, kind, formula, _source, _rule in formula_records
        if kind == "derived"
    }
    issues: list[str] = []
    for name, kind, formula, rule_source, rule in formula_records:
        if kind != "derived":
            continue
        entity = str(rule.get("entity") or "").strip()
        if entity.lower() not in _UNIT_SCOPED_ENTITY_NAMES:
            continue
        scoped_source_text = " ".join(_rule_proof_source_excerpts(rule))
        if not scoped_source_text:
            scoped_source_text = _source_text_for_rule_source(source_text, rule_source)
        if (
            not _PERSON_SCOPED_DEFINITION_SOURCE_PATTERN.search(scoped_source_text)
            and not _section_1402_a_12_person_base_applies(
                scoped_source_text=scoped_source_text,
                source_text=source_text,
                rule_source=rule_source,
                rule=rule,
            )
            and _person_scoped_definition_module_fallback_applies(
                source_text=source_text,
                rule_source=rule_source,
                rule=rule,
            )
        ):
            scoped_source_text = source_text
        if not _PERSON_SCOPED_DEFINITION_SOURCE_PATTERN.search(
            scoped_source_text
        ) and not _section_1402_a_12_person_base_applies(
            scoped_source_text=scoped_source_text,
            source_text=source_text,
            rule_source=rule_source,
            rule=rule,
        ):
            continue
        if _formula_or_referenced_helpers_use_relation_aggregate(
            formula,
            formula_by_name=formula_by_name,
        ):
            continue
        issues.append(
            "Person-scoped definition at unit scope: "
            f"`{name}` is declared on `{entity}`, but the source text defines "
            "an amount, income, earnings, wage, tax, deduction, credit, or "
            "benefit for an individual, person, employee, or member. Encode "
            "that definition at the lower entity first, then aggregate only "
            "through an explicit relation when the source states a unit-level "
            "roll-up."
        )
    return issues


def find_imported_person_scoped_definition_unit_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Flag unit-scope formulas that compose stale imported person-scope definitions."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    bad_imported_symbols: dict[str, str] = {}
    for import_item in _extract_import_items_from_content(content):
        import_base, separator, imported_symbol = import_item.partition("#")
        imported_symbol = imported_symbol.strip()
        if not separator or not imported_symbol:
            continue
        import_file = _resolve_rulespec_import_file_static(
            import_base,
            rules_file=rules_file,
            policy_repo_path=policy_repo_path,
        )
        if import_file is None:
            continue
        imported_content = import_file.read_text()
        if not _imported_symbol_is_person_scoped_definition_at_unit_scope(
            imported_content,
            imported_symbol,
        ):
            continue
        bad_imported_symbols[imported_symbol] = import_item

    if not bad_imported_symbols:
        return []

    formula_records = _rulespec_rule_formula_rule_records(payload)
    formula_by_name = {
        name: formula
        for name, kind, formula, _source, _rule in formula_records
        if kind == "derived"
    }
    issues: list[str] = []
    for name, kind, formula, _rule_source, rule in formula_records:
        if kind != "derived":
            continue
        entity = str(rule.get("entity") or "").strip()
        if entity.lower() not in _UNIT_SCOPED_ENTITY_NAMES:
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"money", "decimal"}:
            continue
        imported_dependencies = sorted(
            _formula_local_identifiers(formula) & set(bad_imported_symbols)
        )
        if not imported_dependencies:
            continue
        if _formula_or_referenced_helpers_use_relation_aggregate(
            formula,
            formula_by_name=formula_by_name,
        ):
            continue
        formatted = ", ".join(
            f"`{bad_imported_symbols[symbol]}`" for symbol in imported_dependencies
        )
        issues.append(
            "Imported person-scoped definition at unit scope: "
            f"`{name}` is declared on `{entity}` and composes imported "
            f"{formatted}, whose source defines a lower-entity amount while "
            "the imported RuleSpec exports it at unit scope. Re-encode/import "
            "the upstream definition at the lower entity first, then aggregate "
            "through an explicit relation; do not build new unit-scope formulas "
            "on top of stale aggregate imports."
        )
    return issues


def _imported_symbol_is_person_scoped_definition_at_unit_scope(
    content: str,
    symbol: str,
) -> bool:
    payload = _rulespec_payload(content)
    if payload is None:
        return False
    source_text = extract_embedded_source_text(content)
    if not source_text:
        source_text = _extract_source_verification_text(content)
    if not source_text:
        return False

    for name, kind, _formula, rule_source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if name != symbol or kind != "derived":
            continue
        entity = str(rule.get("entity") or "").strip().lower()
        if entity not in _UNIT_SCOPED_ENTITY_NAMES:
            return False
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"money", "decimal"}:
            return False
        scoped_source_text = " ".join(_rule_proof_source_excerpts(rule))
        if not scoped_source_text:
            scoped_source_text = _source_text_for_rule_source(source_text, rule_source)
        if _PERSON_SCOPED_DEFINITION_SOURCE_PATTERN.search(scoped_source_text):
            return True
        return _person_scoped_definition_module_fallback_applies(
            source_text=source_text,
            rule_source=rule_source,
            rule=rule,
        )
    return False


def _person_scoped_definition_module_fallback_applies(
    *,
    source_text: str,
    rule_source: str,
    rule: Mapping[str, Any],
) -> bool:
    if not source_text:
        return False
    if not _PERSON_SCOPED_DEFINITION_SOURCE_PATTERN.search(source_text):
        return False
    if "1402(a)" not in str(rule_source).lower():
        return False
    if str(rule.get("dtype") or "").strip().lower() == "rate":
        return False
    name = str(rule.get("name") or "").lower()
    return any(
        marker in name
        for marker in (
            "net_earnings",
            "self_employment_income",
            "paragraph_12_deduction",
        )
    )


def _section_1402_a_12_person_base_applies(
    *,
    scoped_source_text: str,
    source_text: str,
    rule_source: str,
    rule: Mapping[str, Any],
) -> bool:
    source = str(rule_source).lower()
    if "1402(a)(12" not in source and "1402(a), including paragraph (12" not in source:
        return False
    if str(rule.get("dtype") or "").strip().lower() == "rate":
        return False
    name = str(rule.get("name") or "").lower()
    if not any(
        marker in name
        for marker in (
            "net_earnings",
            "self_employment",
            "deduction",
        )
    ):
        return False
    return bool(
        _SECTION_1402_A_12_PERSON_BASE_PATTERN.search(scoped_source_text)
        or _SECTION_1402_A_12_PERSON_BASE_PATTERN.search(source_text)
    )


def find_employer_scoped_entity_issues(content: str) -> list[str]:
    """Flag employer-imposed rules that are broadened to tax/business units."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    source_text = extract_embedded_source_text(content)
    if not source_text:
        source_text = _extract_source_verification_text(content)
    if not source_text:
        return []

    issues: list[str] = []
    for name, kind, _formula, rule_source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        entity = str(rule.get("entity") or "").strip()
        if entity.lower() not in _EMPLOYER_SCOPED_ENTITY_NAMES:
            continue
        scoped_source_text = " ".join(_rule_proof_source_excerpts(rule))
        if not scoped_source_text:
            scoped_source_text = _source_text_for_rule_source(source_text, rule_source)
        if not _EMPLOYER_SCOPED_SOURCE_PATTERN.search(scoped_source_text):
            continue
        issues.append(
            "Employer-scoped rule at non-employer scope: "
            f"`{name}` is declared on `{entity}`, but the source text imposes "
            "the amount, tax, credit, or limitation on an employer. Use "
            "`entity: Employer` instead of broadening it to a tax, business, "
            "or corporate unit."
        )
    return issues


def find_shared_statutory_rate_entity_suffix_name_issues(content: str) -> list[str]:
    """Flag neutral statutory rate outputs named after a consumer entity."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    source_text = extract_embedded_source_text(content)
    if not source_text:
        source_text = _extract_source_verification_text(content)
    if not source_text:
        return []
    if not _SHARED_STATUTORY_RATE_SOURCE_PATTERN.search(source_text):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        kind = str(rule.get("kind") or "").strip().lower()
        if kind not in {"derived", "parameter"}:
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"rate", "decimal"}:
            continue
        name = str(rule.get("name") or "").strip()
        suffix_match = _SHARED_STATUTORY_RATE_ENTITY_SUFFIX_PATTERN.match(name)
        section_prefix_match = _SHARED_STATUTORY_RATE_SECTION_PREFIX_PATTERN.match(name)
        if suffix_match is None and section_prefix_match is None:
            continue
        detail = (
            "is framed as a section-prefixed local cross-reference name"
            if section_prefix_match is not None
            else ""
        )
        if suffix_match is not None:
            entity = suffix_match.group("entity").lower()
            entity_label = entity.replace("_", " ")
            if re.search(
                rf"\b{re.escape(entity_label)}s?\b", source_text, re.IGNORECASE
            ):
                continue
            detail = f"ends with `_for_{entity}`"
        issues.append(
            "Shared statutory rate name should use source-stated application: "
            f"`{name}` {detail}, but the source names a "
            "statutory rate or percentage by section rather than by that "
            "local consumer or cross-reference. Name the output after the source-stated legal "
            "application, such as `applicable_percentage_for_section_...` or "
            "`applicable_percentage_for_sections_...`."
        )
    return issues


def find_filtered_entity_dependency_issues(content: str) -> list[str]:
    """Reject rules scoped to filtered entities without a declaration/import."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    declared_entities: set[str] = set()
    filtered_entity_rules: list[tuple[str, str]] = []
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or f"rules[{index}]").strip()
        kind = str(rule.get("kind") or "").strip().lower()
        if kind == "derived_relation":
            derived_relation = rule.get("derived_relation")
            if isinstance(derived_relation, dict):
                entity = str(derived_relation.get("entity") or "").strip()
                if entity in _FILTERED_ENTITY_DECLARATION_IMPORTS:
                    declared_entities.add(entity)
            continue
        entity = str(rule.get("entity") or "").strip()
        if entity in _FILTERED_ENTITY_DECLARATION_IMPORTS:
            filtered_entity_rules.append((name, entity))

    if not filtered_entity_rules:
        return []

    imported_symbols = _rulespec_import_fragment_names(payload.get("imports"))
    imported_entities = {
        entity
        for entity, symbols in _FILTERED_ENTITY_DECLARATION_IMPORTS.items()
        if imported_symbols & symbols
    }
    available_entities = declared_entities | imported_entities

    issues: list[str] = []
    for name, entity in filtered_entity_rules:
        if entity in available_entities:
            continue
        required_symbols = ", ".join(
            f"`{symbol}`"
            for symbol in sorted(_FILTERED_ENTITY_DECLARATION_IMPORTS[entity])
        )
        issues.append(
            "Filtered entity dependency missing: "
            f"`{name}` uses `entity: {entity}`, but this RuleSpec file does "
            f"not declare `{entity}` with a `kind: derived_relation` rule or "
            f"import its declaring relation ({required_symbols})."
        )
    return issues


def find_tax_filing_status_surviving_spouse_issues(content: str) -> list[str]:
    """Flag filing-status branches that omit surviving spouse when source groups it."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    module_source_text = (
        _extract_source_verification_text(content)
        or extract_embedded_source_text(content)
        or content
    )
    issues: list[str] = []
    for name, kind, formula, source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived" or not _US_TAX_FILING_STATUS_NAME_PATTERN.search(formula):
            continue
        source_context = _filing_status_rule_source_context(
            content=content,
            module_source_text=module_source_text,
            rule=rule,
            source=source,
        )
        joint_only_issue = _filing_status_joint_only_any_other_case_branch_issue(
            name, formula, source_context
        )
        if joint_only_issue is not None:
            issues.append(joint_only_issue)
            continue
        if not _US_TAX_JOINT_SURVIVING_SPOUSE_GROUP_TEXT_PATTERN.search(source_context):
            continue
        branch_issue = _filing_status_surviving_spouse_branch_issue(name, formula)
        if branch_issue is not None:
            issues.append(branch_issue)
    return issues


def _filing_status_rule_source_context(
    *,
    content: str,
    module_source_text: str,
    rule: dict[str, Any],
    source: Any,
) -> str:
    """Return the source text relevant to one filing-status formula."""
    candidates: list[str] = []
    if module_source_text:
        scoped = _source_text_for_rule_source(module_source_text, source)
        if scoped:
            candidates.append(scoped)
    candidates.extend(_rule_proof_source_texts(rule))
    candidates.extend(_source_field_texts(source))
    return "\n".join(item for item in candidates if item.strip()) or content


def _rule_proof_source_texts(rule: dict[str, Any]) -> list[str]:
    proof = _rule_proof_payload(rule)
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if not isinstance(atoms, list):
        return []

    texts: list[str] = []
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        source = atom.get("source")
        if isinstance(source, dict):
            for key in ("text", "quote", "excerpt", "span"):
                value = source.get(key)
                if isinstance(value, str) and value.strip():
                    texts.append(value.strip())
        elif isinstance(source, str) and source.strip():
            texts.append(source.strip())
    return texts


def _source_field_texts(source: Any) -> list[str]:
    if isinstance(source, dict):
        return [
            value.strip()
            for value in source.values()
            if isinstance(value, str) and value.strip()
        ]
    if isinstance(source, str) and source.strip():
        return [source.strip()]
    return []


_FILING_STATUS_STRING_VALUE_PATTERN = re.compile(
    rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*(?:==|!=)\s*['\"][^'\"]+['\"]"
    rf"|['\"][^'\"]+['\"]\s*(?:==|!=)\s*{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}",
    flags=re.IGNORECASE,
)
_FILING_STATUS_NAMED_VALUE_ALTERNATIVES = (
    r"single|joint|joint_return|married_filing_jointly|"
    r"married_filing_separately|separate|head_of_household|surviving_spouse|"
    r"qualifying_widow(?:er)?"
)
_FILING_STATUS_NAMED_VALUE_PATTERN = re.compile(
    rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*(?:==|!=)\s*"
    rf"(?:{_FILING_STATUS_NAMED_VALUE_ALTERNATIVES})\b",
    flags=re.IGNORECASE,
)
_FILING_STATUS_MATCH_NAMED_ARM_PATTERN = re.compile(
    rf"^\s*['\"]?(?:{_FILING_STATUS_NAMED_VALUE_ALTERNATIVES})['\"]?\s*=>",
    flags=re.IGNORECASE | re.MULTILINE,
)


def find_tax_filing_status_enum_representation_issues(content: str) -> list[str]:
    """Reject string/boolean encodings of the structural US filing-status enum."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    issues: list[str] = []
    for name, kind, formula in _rulespec_rule_formulas(payload):
        if kind != "derived" or not _US_TAX_FILING_STATUS_NAME_PATTERN.search(formula):
            continue
        if (
            _FILING_STATUS_STRING_VALUE_PATTERN.search(formula)
            or _FILING_STATUS_NAMED_VALUE_PATTERN.search(formula)
            or _filing_status_match_has_named_arms(formula)
        ):
            issues.append(
                "Filing status must use numeric enum: "
                f"`{name}` compares `filing_status` to string/named status values. "
                "Use numeric codes directly: 0 single, 1 joint return, 2 married "
                "filing separately, 3 head of household, 4 surviving spouse / "
                "qualifying widow(er)."
            )
    return issues


def find_tax_filing_status_local_input_issues(
    content: str,
    test_cases: Any | None = None,
) -> list[str]:
    """Reject generated RuleSpec that treats US tax filing status as a fact input."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    protected_names = {"filing_status", "tax_filing_status"}
    available_symbols = _rulespec_executable_names_from_payload(payload)
    available_symbols.update(_rulespec_import_symbol_names(payload))

    issues: list[str] = []
    for name, _kind, formula in _rulespec_rule_formulas(payload):
        for identifier in sorted(_formula_local_identifiers(formula) & protected_names):
            if identifier in available_symbols:
                continue
            issues.append(
                "Filing status is a derived legal classification, not a factual "
                f"input: `{name}` references `{identifier}` without defining or "
                "importing an absolute upstream filing-status RuleSpec output. "
                "Encode/import the upstream filing-status rule and set its leaf "
                f"facts; do not create local `#input.{identifier}` facts."
            )

    for rule in payload.get("rules") or []:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "<unnamed>").strip() or "<unnamed>"
        for index_name in _rulespec_indexed_by_names(rule.get("indexed_by")):
            if index_name not in protected_names or index_name in available_symbols:
                continue
            issues.append(
                "Filing status is a derived legal classification, not a factual "
                f"input: `{name}` indexes by `{index_name}` without defining or "
                "importing an absolute upstream filing-status RuleSpec output. "
                "Encode/import the upstream filing-status rule and set its leaf "
                f"facts; do not create local `#input.{index_name}` facts."
            )

    if isinstance(test_cases, list):
        for test_case in test_cases:
            if not isinstance(test_case, dict):
                continue
            test_name = str(test_case.get("name") or "<unnamed>").strip() or "<unnamed>"
            inputs = test_case.get("input")
            if not isinstance(inputs, dict):
                continue
            for key, value in inputs.items():
                fragment = _test_reference_fragment(key)
                if (
                    fragment == "input.filing_status"
                    and _is_numeric_filing_status_fixture(value)
                ):
                    continue
                if fragment not in {"input.filing_status", "input.tax_filing_status"}:
                    continue
                issues.append(
                    "Filing status is a derived legal classification, not a factual "
                    f"input: test case `{test_name}` assigns filing status as a "
                    f"local input via `{key}`. Set the upstream filing-status leaf "
                    "facts instead."
                )

    return issues


_US_TAX_STATUS_COMPONENT_NAMES = {
    "surviving_spouse",
    "taxpayer_is_surviving_spouse",
    "individual_is_surviving_spouse",
    "head_of_household",
    "taxpayer_is_head_of_household",
    "individual_is_head_of_household",
}
_US_TAX_STATUS_COMPONENT_FRAGMENT_PATTERN = re.compile(
    r"(?:^|_)("
    r"surviving_spouse|"
    r"head_of_household|"
    r"qualifying_widow(?:er)?|"
    r"married_filing|"
    r"filing_jointly|"
    r"filing_separately|"
    r"joint_return|"
    r"not_married|"
    r"unmarried|"
    r"is_married"
    r")(?:_|$)",
    flags=re.IGNORECASE,
)


def find_tax_status_component_local_input_issues(content: str) -> list[str]:
    """Reject local inputs for legal filing-status component classifications.

    Scope: U.S. tax code (Title 26). Other titles use \"surviving spouse\"
    and similar terms in non-tax-status legal contexts — e.g. 7 USC 2012(j)
    defines a SNAP \"elderly or disabled member\" partly by reference to a
    person who is the surviving spouse of a veteran with specified Title 38
    disability status. That is a SNAP demographic predicate, not a tax
    filing status; the validator must not block it.
    """
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    if not _module_source_is_us_tax_code(payload):
        return []

    module_source_text = extract_embedded_source_text(content) or content
    available_symbols = _rulespec_executable_names_from_payload(payload)
    available_symbols.update(_rulespec_import_symbol_names(payload))

    issues: list[str] = []
    for name, _kind, formula, source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        protected_identifiers = {
            identifier
            for identifier in _formula_local_identifiers(formula)
            if identifier in _US_TAX_STATUS_COMPONENT_NAMES
            or _US_TAX_STATUS_COMPONENT_FRAGMENT_PATTERN.search(identifier)
        }
        source_context = _filing_status_rule_source_context(
            content=content,
            module_source_text=module_source_text,
            rule=rule,
            source=source,
        )
        for identifier in sorted(protected_identifiers):
            if identifier in available_symbols:
                continue
            if _source_context_allows_local_tax_status_component(
                identifier, source_context
            ):
                continue
            issues.append(
                "Tax filing-status component is a derived legal classification, "
                f"not a local factual input: `{name}` references `{identifier}` "
                "without defining or importing its absolute upstream RuleSpec "
                "output. Encode/import the upstream status source or defer the "
                "affected output."
            )

    return issues


def _module_source_is_us_tax_code(payload: dict[str, Any]) -> bool:
    """True iff the RuleSpec module's corpus citation lives in US Title 26 (IRC).

    Filing-status component checks are IRC-specific; SNAP (Title 7), labor
    (Title 29), and similar codes use overlapping vocabulary (\"surviving
    spouse\", etc.) in unrelated legal senses. Restricting the validator
    to Title 26 avoids the cross-title false positive that surfaced on
    7 USC 2012(j) (SNAP elderly/disabled member, encoded 2026-05-28).
    """
    module = payload.get("module") if isinstance(payload, dict) else None
    if not isinstance(module, dict):
        # No module block: legacy/test content; run the validator
        # unconditionally to preserve historical behavior.
        return True
    sv = module.get("source_verification")
    if not isinstance(sv, dict):
        return True
    paths: list[str] = []
    single = sv.get("corpus_citation_path")
    if isinstance(single, str):
        paths.append(single)
    plural = sv.get("corpus_citation_paths")
    if isinstance(plural, list):
        paths.extend(p for p in plural if isinstance(p, str))
    if not paths:
        return True
    return any(_is_us_tax_code_path(path) for path in paths)


def _is_us_tax_code_path(path: str) -> bool:
    """True for paths anchored in U.S. tax-code material (IRC + Treasury regs
    + IRS guidance). Excludes SNAP (Title 7), labor (Title 29), SSA, USDA,
    and other non-tax titles where overlapping vocabulary like \"surviving
    spouse\" appears in unrelated legal senses."""
    p = path.strip().lower()
    return (
        p.startswith("us/statute/26/")
        or p.startswith("us/regulation/26/")
        or p.startswith("us/guidance/irs/")
    )


def _source_context_allows_local_tax_status_component(
    identifier: str, source_context: str
) -> bool:
    """Allow non-tax-status uses of words that overlap filing-status vocabulary."""
    if "surviving_spouse" not in identifier.lower():
        return False

    return bool(
        re.search(
            r"\bemployer\s+is\s+a\s+surviving\s+spouse\s+or\s+a\s+divorced\s+individual\b",
            source_context,
            flags=re.IGNORECASE,
        )
        and re.search(r"\bdomestic\s+service\b", source_context, flags=re.IGNORECASE)
        and re.search(r"\bhas\s+not\s+remarried\b", source_context, flags=re.IGNORECASE)
    )


_MODIFIER_PARAMETER_SOURCE_PATTERN = re.compile(
    r"\b("
    r"substitut(?:e|es|ed|ing)|"
    r"higher\s+amount|"
    r"increas(?:e|es|ed|ing)|"
    r"decreas(?:e|es|ed|ing)|"
    r"replac(?:e|es|ed|ing)|"
    r"in\s+lieu\s+of|"
    r"reduc(?:e|es|ed|ing)\s+by|"
    r"capp(?:ed|ing)\s+at"
    r")\b",
    flags=re.IGNORECASE,
)
_NUMERIC_DERIVED_OUTPUT_NAME_PATTERN = re.compile(
    r"(?:amount|deduction|credit|limit|threshold|income|tax|benefit|allowance|rate)",
    flags=re.IGNORECASE,
)
_NUMERIC_DERIVED_DTYPES = {
    "decimal",
    "integer",
    "money",
    "number",
    "rate",
}


def find_deferred_output_issues(content: str) -> list[str]:
    """Validate explicit non-executable deferred output provenance."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    module = payload.get("module")
    if not isinstance(module, dict) or "deferred_outputs" not in module:
        return []

    deferred_outputs = module.get("deferred_outputs")
    if not isinstance(deferred_outputs, list):
        return ["`module.deferred_outputs` must be a list of deferred output records."]

    issues: list[str] = []
    for index, record in enumerate(deferred_outputs):
        label = f"module.deferred_outputs[{index}]"
        if not isinstance(record, dict):
            issues.append(f"{label} must be a mapping.")
            continue

        output = str(record.get("output") or "").strip()
        output_ref = _parse_rulespec_target(output) if output else None
        if output_ref is None or output_ref.symbol is None:
            issues.append(
                f"{label}.output must use an absolute RuleSpec output target "
                "such as `us:statutes/26/63/f#additional_amount`."
            )

        reason = str(record.get("reason") or "").strip()
        if not reason:
            issues.append(f"{label}.reason is required.")

        blocked_by = record.get("blocked_by")
        if blocked_by is not None and not isinstance(blocked_by, list):
            issues.append(
                f"{label}.blocked_by must be a list of absolute RuleSpec "
                "targets when exact blockers are known."
            )
        elif isinstance(blocked_by, list):
            for blocker in blocked_by:
                blocker_text = str(blocker or "").strip()
                blocker_ref = (
                    _parse_rulespec_target(blocker_text) if blocker_text else None
                )
                if blocker_ref is None or blocker_ref.symbol is None:
                    issues.append(
                        f"{label}.blocked_by entry `{blocker_text}` must be an "
                        "absolute RuleSpec target with a rule fragment."
                    )
                elif _target_path_embeds_jurisdiction(blocker_ref):
                    issues.append(
                        f"{label}.blocked_by entry `{blocker_text}` embeds a "
                        "jurisdiction in the path; use the target jurisdiction "
                        "prefix instead."
                    )

        source_values = record.get("source_values")
        if source_values is not None:
            if not isinstance(source_values, list) or not source_values:
                issues.append(
                    f"{label}.source_values must list absolute RuleSpec targets "
                    "for source-stated values retained for the deferred output."
                )
                continue
            for value in source_values:
                value_text = str(value or "").strip()
                value_ref = _parse_rulespec_target(value_text) if value_text else None
                if value_ref is None or value_ref.symbol is None:
                    issues.append(
                        f"{label}.source_values entry `{value_text}` must be an "
                        "absolute RuleSpec target with a rule fragment."
                    )

    return issues


def find_source_subparagraph_coverage_issues(
    content: str,
    *,
    rules_file: Path | None = None,
    source_texts: dict[str, str] | None = None,
    requested_source: str | None = None,
) -> list[str]:
    """Require high-signal source children to be encoded or explicitly deferred.

    ``requested_source`` lets the caller declare which subsection the encoder
    was *asked* to produce, even when the corpus served a parent-fallback
    source slice. Without it, a benchmark targeting `us/statute/7/2014/e/2/B`
    that gets served the whole § 2014 text triggers spurious "missing
    coverage" errors for every sibling subparagraph — the encoder was only
    responsible for (e)(2)(B). The pipeline reads this from the nearby eval
    workspace's ``source-metadata.json``; tests can pass it directly.
    """
    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return []

    source_verification = _source_verification_block(payload)
    if source_verification is None:
        return []
    citation_paths, source_label = _source_verification_source_fields(
        source_verification
    )
    if len(citation_paths) != 1:
        return []

    citation_path = citation_paths[0]
    source_text = _source_verification_text(
        citation_paths=citation_paths,
        source_label=source_label,
        source_texts=source_texts,
    ) or extract_embedded_source_text(content)
    if not source_text:
        return []
    if _empty_deferred_editorial_source_slice(payload, content):
        return []

    source_children = _high_signal_top_level_subparagraphs(source_text)
    # The requested-source scope takes precedence over the rules_file-derived
    # one because it captures encoder intent precisely; the rules_file path
    # only tells us where the artifact landed (which can collapse to the
    # parent under corpus fallback, see issue #71).
    coverage_scope_prefix = _scope_prefix_from_requested_source(
        citation_path, requested_source
    ) or _source_subparagraph_coverage_scope_prefix(
        citation_path,
        rules_file=rules_file,
    )
    if coverage_scope_prefix:
        coverage_scope_top_level = _top_level_subparagraph_path(coverage_scope_prefix)
        source_children = [
            (label, text)
            for label, text in source_children
            if (label,) == coverage_scope_top_level
        ]
    if not source_children:
        return []

    covered_children = _rule_source_covered_subparagraphs(payload, citation_path)
    covered_children.update(
        _source_relation_covered_subparagraphs(payload, citation_path)
    )
    covered_children.update(
        _deferred_output_covered_subparagraphs(payload, citation_path)
    )

    issues: list[str] = []
    for label, text in source_children:
        if (label,) in covered_children:
            continue
        citation = _format_source_subparagraph_citation(citation_path, label)
        excerpt = _compact_source_excerpt(text, limit=120)
        issues.append(
            "Source sub-paragraph coverage missing: "
            f"{citation} ('{excerpt}') has no rule citing it and no entry in "
            "`module.deferred_outputs`. Either encode a rule with "
            f"`source: {citation}` or add a deferred_outputs entry naming the blocker."
        )
    return issues


def find_out_of_scope_rule_source_issues(
    content: str,
    *,
    requested_source: str | None,
) -> list[str]:
    """Flag executable rules sourced to sibling provisions of the encode target."""
    if not requested_source:
        return []
    requested_targets = _source_citation_to_normalized_targets(requested_source)
    requested_target = requested_targets[0] if requested_targets else None
    if requested_target is None or len(requested_target) < 3:
        return []

    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        if not _is_executable_rulespec_rule(rule):
            continue
        source = rule.get("source")
        if not isinstance(source, str) or not source.strip():
            continue
        source_targets = _source_citation_to_normalized_targets(
            source,
            context_source=requested_source,
        )
        if not source_targets:
            continue
        if all(
            _normalized_target_within(source_target, requested_target)
            for source_target in source_targets
        ):
            continue
        name = str(rule.get("name") or f"rules[{index}]")
        issues.append(
            f"`{name}` source `{source.strip()}` is outside requested source "
            f"`{requested_source}`. Encode only the requested citation subtree; "
            "defer or separately encode sibling provisions."
        )
    return issues


def _normalized_target_within(
    candidate: tuple[str, ...],
    anchor: tuple[str, ...],
) -> bool:
    return candidate == anchor or candidate[: len(anchor)] == anchor


def _empty_deferred_editorial_source_slice(
    payload: dict[str, Any],
    content: str,
) -> bool:
    """Allow explicitly deferred empty modules for repealed/editorial slices."""
    rules = payload.get("rules")
    if not isinstance(rules, list) or rules:
        return False
    module = payload.get("module")
    if not isinstance(module, dict):
        return False
    status = str(module.get("status") or "").strip().lower()
    if status not in {"deferred", "entity_not_supported"}:
        return False
    summary = extract_embedded_source_text(content)
    return _source_slice_is_editorial_omission(summary)


def _source_slice_is_editorial_omission(source_text: str) -> bool:
    normalized = re.sub(r"\s+", " ", source_text).strip()
    if not normalized:
        return False
    if re.match(r"^\([A-Za-z0-9]+\)\s+Repealed\b", normalized):
        return True
    if re.fullmatch(r"\(?[A-Za-z0-9]+\)?\s*(?:\[?\s*)?\.{3,}(?:\s*\]?)?", normalized):
        return True
    return False


def _high_signal_top_level_subparagraphs(source_text: str) -> list[tuple[str, str]]:
    return [
        (label, text)
        for label, text in _top_level_source_subparagraph_segments(source_text)
        if _HIGH_SIGNAL_SUBPARAGRAPH_PATTERN.search(text)
    ]


def _top_level_source_subparagraph_segments(
    source_text: str,
) -> list[tuple[str, str]]:
    matches = list(_TOP_LEVEL_SOURCE_SUBPARAGRAPH_PATTERN.finditer(source_text))
    children: list[tuple[str, str]] = []
    for index, match in enumerate(matches):
        label = match.group("label").lower()
        start = match.start("text")
        end = (
            matches[index + 1].start() if index + 1 < len(matches) else len(source_text)
        )
        text = source_text[start:end].strip()
        children.append((label, text))
    return children


def _rule_source_covered_subparagraphs(
    payload: dict[str, Any],
    citation_path: str,
) -> set[tuple[str, ...]]:
    return {
        _top_level_subparagraph_path(path)
        for path in _rule_source_subparagraph_paths(payload, citation_path)
        if path
    }


def _rule_source_subparagraph_paths(
    payload: dict[str, Any],
    citation_path: str,
) -> set[tuple[str, ...]]:
    paths: set[tuple[str, ...]] = set()
    for _name, _kind, _formula, source, _rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if isinstance(source, str):
            paths.update(_source_citation_subparagraph_paths(source, citation_path))
    return paths


def _source_relation_covered_subparagraphs(
    payload: dict[str, Any],
    citation_path: str,
) -> set[tuple[str, ...]]:
    return {
        _top_level_subparagraph_path(path)
        for path in _source_relation_subparagraph_paths(payload, citation_path)
        if path
    }


def _source_relation_subparagraph_paths(
    payload: dict[str, Any],
    citation_path: str,
) -> set[tuple[str, ...]]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()

    paths: set[tuple[str, ...]] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source = rule.get("source")
        if isinstance(source, str):
            paths.update(_source_citation_subparagraph_paths(source, citation_path))
    return paths


def _deferred_output_covered_subparagraphs(
    payload: dict[str, Any],
    citation_path: str,
) -> set[tuple[str, ...]]:
    return {
        _top_level_subparagraph_path(path)
        for path in _deferred_output_subparagraph_paths(payload, citation_path)
        if path
    }


def _deferred_output_subparagraph_paths(
    payload: dict[str, Any],
    citation_path: str,
) -> set[tuple[str, ...]]:
    module = payload.get("module")
    if not isinstance(module, dict):
        return set()
    deferred_outputs = module.get("deferred_outputs")
    if not isinstance(deferred_outputs, list):
        return set()

    base_parts = _rulespec_base_parts_for_corpus_path(citation_path)
    if not base_parts:
        return set()

    paths: set[tuple[str, ...]] = set()
    for record in deferred_outputs:
        if not isinstance(record, dict):
            continue
        output = str(record.get("output") or "").strip()
        target_ref = _parse_rulespec_target(output) if output else None
        if target_ref is None:
            continue
        target_parts = _rulespec_relative_path_parts(target_ref.relative_path)
        if (
            len(target_parts) <= len(base_parts)
            or target_parts[: len(base_parts)] != base_parts
        ):
            continue
        paths.add(tuple(part.lower() for part in target_parts[len(base_parts) :]))
    return paths


def _source_subparagraph_coverage_scope_prefix(
    citation_path: str,
    *,
    rules_file: Path | None,
) -> tuple[str, ...]:
    return _rulespec_file_subparagraph_scope(citation_path, rules_file)


def _normalize_requested_source_to_corpus_path(requested_source: str) -> str:
    """Return a corpus-path form for a requested_source string.

    The eval workspace stores requested_source as the raw caller input —
    typically the human USC citation (``7 USC 2014(c)``). Subparagraph-scope
    matching needs the corpus-path form (``us/statute/7/2014/c``). If parsing
    fails the input is returned unchanged so corpus-path inputs pass through.
    """
    candidate = requested_source.strip()
    if not candidate:
        return candidate
    target_ref = _parse_rulespec_target(candidate)
    if target_ref is not None:
        target_parts = target_ref.relative_path.with_suffix("").parts
        if len(target_parts) >= 3 and target_parts[0] == "statutes":
            return "/".join((target_ref.prefix, "statute", *target_parts[1:]))
        if len(target_parts) >= 4 and target_parts[0] == "regulations":
            title = target_parts[1].removesuffix("-cfr")
            return "/".join((target_ref.prefix, "regulation", title, *target_parts[2:]))
    if candidate.startswith(("us/", "us-")):
        return candidate
    try:
        parts = parse_usc_citation(candidate)
    except (ValueError, Exception):
        return candidate
    if parts is None:
        return candidate
    try:
        return citation_to_citation_path(parts)
    except (ValueError, Exception):
        return candidate


def _scope_prefix_from_requested_source(
    citation_path: str, requested_source: str | None
) -> tuple[str, ...]:
    """Derive a subparagraph scope from a requested source vs the resolved
    citation_path. When the corpus serves a parent-fallback slice, the
    citation_path collapses to the parent while the requested source still
    names the encoder's actual target. The difference is the scope.

    `requested_source` may be either a corpus-path form
    (``us/statute/7/2014/e/2/B``) or the human USC form (``7 USC 2014(e)(2)(B)``)
    — the eval workspace stores it as the raw caller input, which is usually
    human form. Normalize both to corpus paths before comparing.

    Examples (citation_path → requested_source → scope):
      us/statute/7/2014 → us/statute/7/2014/e/2/B → ('e', '2', 'b')
      us/statute/7/2014 → 7 USC 2014(e)(2)(B)    → ('e', '2', 'b')
      us/statute/7/2014 → us/statute/7/2014       → ()
      us/statute/7/2014 → us/statute/26/63        → ()  (unrelated)
    """
    if not requested_source:
        return ()
    normalized_request = _normalize_requested_source_to_corpus_path(requested_source)
    citation_parts = tuple(part for part in citation_path.strip("/").split("/") if part)
    requested_parts = tuple(
        part for part in normalized_request.strip("/").split("/") if part
    )
    if not citation_parts or len(requested_parts) <= len(citation_parts):
        return ()
    if requested_parts[: len(citation_parts)] != citation_parts:
        return ()
    return tuple(part.lower() for part in requested_parts[len(citation_parts) :])


def _rulespec_file_subparagraph_scope(
    citation_path: str,
    rules_file: Path | None,
) -> tuple[str, ...]:
    if rules_file is None:
        return ()
    base_parts = _rulespec_base_parts_for_corpus_path(citation_path)
    if not base_parts:
        return ()

    file_parts = list(rules_file.with_suffix("").parts)
    for index in range(0, len(file_parts) - len(base_parts) + 1):
        if tuple(file_parts[index : index + len(base_parts)]) != base_parts:
            continue
        return tuple(
            part.lower() for part in file_parts[index + len(base_parts) :] if part
        )
    return ()


def _source_citation_subparagraph_paths(
    source: str,
    citation_path: str,
) -> set[tuple[str, ...]]:
    pattern = _source_subparagraph_citation_pattern(citation_path)
    if pattern is None:
        return set()
    paths: set[tuple[str, ...]] = set()
    for match in pattern.finditer(source):
        suffix = match.group("suffix")
        parts = tuple(
            part.lower() for part in re.findall(r"\(([A-Za-z0-9]+)\)", suffix) if part
        )
        if parts:
            paths.add(parts)
    return paths


def _source_subparagraph_citation_pattern(citation_path: str) -> re.Pattern[str] | None:
    parts = citation_path.strip("/").split("/")
    exact_corpus_path = re.escape(citation_path.strip("/"))
    if len(parts) >= 4 and parts[:2] == ["us", "statute"]:
        title = re.escape(parts[2])
        section = re.escape(parts[3])
        citation_prefixes = [
            exact_corpus_path,
            rf"{title}\s+(?:U\.?\s*S\.?\s*C\.?|USC)\s+{section}",
        ]
        if parts[2] == "26":
            citation_prefixes.append(rf"I\.?\s*R\.?\s*C\.?\s+section\s+{section}")
            citation_prefixes.append(rf"IRC\s+section\s+{section}")
        return re.compile(
            rf"\b(?:{'|'.join(citation_prefixes)})"
            r"(?P<suffix>(?:\([A-Za-z0-9]+\))+)",
            flags=re.IGNORECASE,
        )
    if len(parts) >= 4 and parts[0].startswith("us-") and parts[1] == "statute":
        section = re.escape(parts[3])
        return re.compile(
            rf"(?<![\w.-])(?:{exact_corpus_path}|{section}|C\.?\s*R\.?\s*S\.?\s*{section})"
            r"(?P<suffix>(?:\([A-Za-z0-9]+\))+)",
            flags=re.IGNORECASE,
        )
    if len(parts) >= 5 and parts[:2] == ["us", "regulation"]:
        title = re.escape(parts[2])
        section = re.escape(f"{parts[3]}.{parts[4]}")
        return re.compile(
            rf"(?:\b{title}\s+(?:C\.?\s*F\.?\s*R\.?|CFR)\s+{section}|{exact_corpus_path})"
            r"(?P<suffix>(?:\([A-Za-z0-9]+\))+)",
            flags=re.IGNORECASE,
        )
    if len(parts) >= 3 and parts[0].startswith("us-") and parts[1] == "regulation":
        return re.compile(
            rf"(?<![\w.-]){exact_corpus_path}"
            r"(?P<suffix>(?:\([A-Za-z0-9]+\))+)",
            flags=re.IGNORECASE,
        )
    if (
        len(parts) >= 3
        and parts[0].startswith("us-")
        and parts[1] in _RULESPEC_DOCUMENT_CLASS_DIRS
    ):
        return re.compile(
            rf"(?<![\w.-]){exact_corpus_path}"
            r"(?P<suffix>(?:\([A-Za-z0-9]+\))+)",
            flags=re.IGNORECASE,
        )
    return None


_RULESPEC_DOCUMENT_CLASS_DIRS = {
    "form": "forms",
    "forms": "forms",
    "guidance": "guidance",
    "manual": "manuals",
    "manuals": "manuals",
    "policies": "policies",
    "policy": "policies",
}


def _rulespec_base_parts_for_corpus_path(citation_path: str) -> tuple[str, ...]:
    parts = citation_path.strip("/").split("/")
    if (
        len(parts) >= 4
        and parts[1] == "statute"
        and (parts[0] == "us" or parts[0].startswith("us-"))
    ):
        return ("statutes", parts[2], parts[3])
    if len(parts) >= 5 and parts[:2] == ["us", "regulation"]:
        return ("regulations", f"{parts[2]}-cfr", parts[3], parts[4])
    if len(parts) >= 3 and parts[0].startswith("us-") and parts[1] == "regulation":
        return ("regulations", *parts[2:])
    if (
        len(parts) >= 3
        and parts[0].startswith("us-")
        and parts[1] in _RULESPEC_DOCUMENT_CLASS_DIRS
    ):
        return (_RULESPEC_DOCUMENT_CLASS_DIRS[parts[1]], *parts[2:])
    return ()


def _rulespec_relative_path_parts(path: Path) -> tuple[str, ...]:
    parts = list(path.parts)
    if parts:
        last = parts[-1]
        for suffix in (".yaml", ".yml"):
            if last.endswith(suffix):
                parts[-1] = last[: -len(suffix)]
                break
    return tuple(parts)


def _top_level_subparagraph_path(path: tuple[str, ...]) -> tuple[str, ...]:
    return (path[0].lower(),) if path else ()


def _format_source_subparagraph_citation(citation_path: str, label: str) -> str:
    parts = citation_path.strip("/").split("/")
    if len(parts) >= 4 and parts[:2] == ["us", "statute"]:
        return f"{parts[2]} USC {parts[3]}({label})"
    if len(parts) >= 4 and parts[0].startswith("us-") and parts[1] == "statute":
        return f"{parts[3]}({label})"
    if len(parts) >= 5 and parts[:2] == ["us", "regulation"]:
        return f"{parts[2]} CFR {parts[3]}.{parts[4]}({label})"
    return f"{citation_path}({label})"


def _compact_source_excerpt(text: str, *, limit: int) -> str:
    excerpt = re.sub(r"\s+", " ", text).strip()
    if len(excerpt) <= limit:
        return excerpt
    return excerpt[: limit - 3].rstrip() + "..."


def _deferred_output_source_value_symbols(payload: dict[str, Any]) -> set[str]:
    module = payload.get("module")
    if not isinstance(module, dict):
        return set()
    deferred_outputs = module.get("deferred_outputs")
    if not isinstance(deferred_outputs, list):
        return set()

    symbols: set[str] = set()
    for record in deferred_outputs:
        if not isinstance(record, dict):
            continue
        source_values = record.get("source_values")
        if not isinstance(source_values, list):
            continue
        for value in source_values:
            value_text = str(value or "").strip()
            value_ref = _parse_rulespec_target(value_text) if value_text else None
            if value_ref is not None and value_ref.symbol is not None:
                symbols.add(value_ref.symbol)
    return symbols


def find_unused_modifier_parameter_issues(content: str) -> list[str]:
    """Reject monetary formulas that ignore source-stated modifier parameters."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    module = payload.get("module")
    if isinstance(module, dict) and str(module.get("status") or "").strip() in {
        "deferred",
        "entity_not_supported",
    }:
        return []

    modifier_parameters: list[str] = []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        source_context = "\n".join(
            [
                *_source_field_texts(rule.get("source")),
                *_rule_proof_source_texts(rule),
            ]
        )
        if _MODIFIER_PARAMETER_SOURCE_PATTERN.search(source_context):
            modifier_parameters.append(name)

    if not modifier_parameters:
        return []

    deferred_source_value_symbols = _deferred_output_source_value_symbols(payload)
    numeric_derived_formulas: dict[str, str] = {}
    for name, kind, formula, _source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype in {"bool", "boolean", "judgment"}:
            continue
        unit = str(rule.get("unit") or "").strip()
        if (
            dtype in _NUMERIC_DERIVED_DTYPES
            or unit
            or _NUMERIC_DERIVED_OUTPUT_NAME_PATTERN.search(name)
        ):
            numeric_derived_formulas[name] = formula

    issues: list[str] = []
    if not numeric_derived_formulas:
        for parameter_name in sorted(set(modifier_parameters)):
            if parameter_name in deferred_source_value_symbols:
                continue
            issues.append(
                "Source-stated modifier parameter has no affected numeric "
                f"derived output: `{parameter_name}` appears to encode a "
                "substitution/modification amount, but the module has no "
                "numeric derived output that can apply it. Encode the affected "
                "numeric output using the modifier, or defer that affected "
                "output and list this source value under "
                "`module.deferred_outputs[].source_values` until the upstream "
                "branching condition is encoded."
            )
        return issues

    for parameter_name in sorted(set(modifier_parameters)):
        if any(
            parameter_name in _formula_local_identifiers(formula)
            for formula in numeric_derived_formulas.values()
        ):
            continue
        if parameter_name in deferred_source_value_symbols:
            continue
        derived_names = ", ".join(
            f"`{name}`" for name in sorted(numeric_derived_formulas)
        )
        issues.append(
            "Source-stated modifier parameter is not used by any numeric "
            f"derived output: `{parameter_name}` appears to encode a "
            f"substitution/modification amount, but {derived_names} ignores it. "
            "Use the modifier in the affected formula or defer the affected "
            "output until the upstream branching condition is encoded and list "
            "this source value under `module.deferred_outputs[].source_values`."
        )

    return issues


def _rulespec_import_symbol_names(payload: dict[str, Any]) -> set[str]:
    """Return explicit local symbols exposed by imports in a RuleSpec payload."""
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return set()

    names: set[str] = set()
    for item in imports:
        if isinstance(item, str):
            names.update(_rulespec_import_item_symbol_names(item))
        elif isinstance(item, dict):
            for alias, target in item.items():
                alias_text = str(alias or "").strip()
                if re.fullmatch(r"[A-Za-z_]\w*", alias_text):
                    names.add(alias_text)
                if isinstance(target, str):
                    names.update(_rulespec_import_item_symbol_names(target))
    return names


def _rulespec_import_item_symbol_names(import_item: str) -> set[str]:
    """Return the symbol fragment imported by an import item, if explicit."""
    if "#" not in import_item:
        return set()
    fragment = import_item.split("#", 1)[1].strip().strip("'\"")
    if not re.fullmatch(r"[A-Za-z_]\w*", fragment):
        return set()
    return {fragment}


def _rulespec_indexed_by_names(indexed_by: Any) -> set[str]:
    if isinstance(indexed_by, str):
        return {indexed_by.strip()} if indexed_by.strip() else set()
    if isinstance(indexed_by, list):
        return {
            str(item).strip()
            for item in indexed_by
            if isinstance(item, str) and str(item).strip()
        }
    return set()


def _filing_status_match_has_named_arms(formula: str) -> bool:
    lines = formula.splitlines()
    for index, line in enumerate(lines):
        match = re.match(
            rf"^(\s*)match\s+{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*:\s*(.*)$",
            line,
            flags=re.IGNORECASE,
        )
        if match is None:
            continue
        if _match_fragment_has_named_arm(match.group(2)):
            return True
        base_indent = len(match.group(1))
        for branch_line in lines[index + 1 :]:
            if not branch_line.strip():
                continue
            branch_indent = len(branch_line) - len(branch_line.lstrip())
            if branch_indent <= base_indent:
                break
            if _match_fragment_has_named_arm(branch_line):
                return True
    return False


def _match_fragment_has_named_arm(fragment: str) -> bool:
    return any(
        _FILING_STATUS_MATCH_NAMED_ARM_PATTERN.match(part)
        for part in re.split(r";", fragment)
        if part.strip()
    )


def find_tax_filing_status_test_input_issues(test_cases: Any) -> list[str]:
    """Reject non-enum `#input.filing_status` and local alias test assignments."""
    if not isinstance(test_cases, list):
        return []

    issues: list[str] = []
    for test_case in test_cases:
        if not isinstance(test_case, dict):
            continue
        test_name = str(test_case.get("name") or "<unnamed>").strip() or "<unnamed>"
        inputs = test_case.get("input")
        if not isinstance(inputs, dict):
            continue
        for key, value in inputs.items():
            fragment = _test_reference_fragment(key)
            if fragment == "input.filing_status" and _is_numeric_filing_status_fixture(
                value
            ):
                continue
            if fragment not in {"input.filing_status", "input.tax_filing_status"}:
                continue
            issues.append(
                "Filing status is a derived legal classification, not a factual "
                f"input: test case `{test_name}` assigns filing status via "
                f"`{key}`. Set the upstream filing-status leaf facts instead."
            )
    return issues


def _is_numeric_filing_status_fixture(value: Any) -> bool:
    numeric = _numeric_rule_value(value)
    if numeric is None:
        return False
    _, number = numeric
    with contextlib.suppress(TypeError, ValueError):
        numeric_int = int(number)
        return number == numeric_int and 0 <= numeric_int <= 4
    return False


def _filing_status_surviving_spouse_branch_issue(
    rule_name: str,
    formula: str,
) -> str | None:
    match_blocks = _filing_status_match_blocks(formula)
    for arms in match_blocks:
        if 1 not in arms:
            continue
        if 4 not in arms:
            return (
                "Filing status branch missing surviving spouse: "
                f"`{rule_name}` handles joint-return status code 1 while this source "
                "mentions surviving spouse or qualifying widow(er), but the formula "
                "does not handle status code 4 in the same filing-status branch. "
                "Include code 4 when the source groups surviving spouse with joint "
                "return, or encode a separate explicit branch."
            )
        if _normalize_branch_result(arms[1]) != _normalize_branch_result(arms[4]):
            return (
                "Filing status branch routes surviving spouse to a different result: "
                f"`{rule_name}` handles joint-return status code 1 and surviving-spouse "
                "status code 4 with different branch results, but this source groups "
                "surviving spouse with joint return."
            )
    if match_blocks:
        return None

    conditional_results = _filing_status_conditional_branch_results(formula)
    if conditional_results:
        if 1 in conditional_results and 4 not in conditional_results:
            return (
                "Filing status branch missing surviving spouse: "
                f"`{rule_name}` handles joint-return status code 1 while this source "
                "mentions surviving spouse or qualifying widow(er), but the formula "
                "does not handle status code 4 in the same filing-status branch. "
                "Include code 4 when the source groups surviving spouse with joint "
                "return, or encode a separate explicit branch."
            )
        if (
            1 in conditional_results
            and 4 in conditional_results
            and (conditional_results[1] != conditional_results[4])
        ):
            return (
                "Filing status branch routes surviving spouse to a different result: "
                f"`{rule_name}` handles joint-return status code 1 and surviving-spouse "
                "status code 4 with different branch results, but this source groups "
                "surviving spouse with joint return."
            )

    if _filing_status_has_code_equality(formula, 1) and not (
        _filing_status_has_grouped_joint_surviving_spouse_condition(formula)
        or _filing_status_has_code_equality(formula, 4)
    ):
        return (
            "Filing status branch missing surviving spouse: "
            f"`{rule_name}` handles joint-return status code 1 while this source "
            "mentions surviving spouse or qualifying widow(er), but the formula "
            "does not handle status code 4. Include code 4 when the source groups "
            "surviving spouse with joint return, or encode a separate explicit branch."
        )
    return None


def _filing_status_joint_only_any_other_case_branch_issue(
    rule_name: str,
    formula: str,
    source_context: str,
) -> str | None:
    if _US_TAX_JOINT_SURVIVING_SPOUSE_GROUP_TEXT_PATTERN.search(source_context):
        return None
    if not _US_TAX_JOINT_ONLY_ANY_OTHER_CASE_TEXT_PATTERN.search(source_context):
        return None

    match_blocks = _filing_status_match_blocks(formula)
    for arms in match_blocks:
        if 1 not in arms or 4 not in arms:
            continue
        if _normalize_branch_result(arms[1]) == _normalize_branch_result(arms[4]):
            return (
                "Filing status branch incorrectly treats surviving spouse as joint "
                "return: "
                f"`{rule_name}` routes status code 4 to the same result as "
                "joint-return status code 1, but this source states a joint-return "
                "branch and an any-other-case branch without grouping surviving "
                "spouse or qualifying widow(er) with joint returns. Route status "
                "code 4 through the any-other-case branch unless the source "
                "explicitly states otherwise."
            )

    conditional_results = _filing_status_conditional_branch_results(formula)
    if (
        1 in conditional_results
        and 4 in conditional_results
        and conditional_results[1] == conditional_results[4]
    ) or _filing_status_has_grouped_joint_surviving_spouse_condition(formula):
        return (
            "Filing status branch incorrectly treats surviving spouse as joint "
            "return: "
            f"`{rule_name}` groups status code 4 with joint-return status code 1, "
            "but this source states a joint-return branch and an any-other-case "
            "branch without grouping surviving spouse or qualifying widow(er) with "
            "joint returns. Route status code 4 through the any-other-case branch "
            "unless the source explicitly states otherwise."
        )
    return None


def _filing_status_match_blocks(formula: str) -> list[dict[int, str]]:
    blocks: list[dict[int, str]] = []
    lines = formula.splitlines()
    for index, line in enumerate(lines):
        match = re.match(
            rf"^(\s*)match\s+{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*:\s*$",
            line,
            flags=re.IGNORECASE,
        )
        if match is None:
            continue
        base_indent = len(match.group(1))
        arms: dict[int, str] = {}
        for branch_line in lines[index + 1 :]:
            if not branch_line.strip():
                continue
            branch_indent = len(branch_line) - len(branch_line.lstrip())
            if branch_indent <= base_indent:
                break
            branch_match = re.match(r"^\s*(\d+)\s*=>\s*(.+?)\s*$", branch_line)
            if branch_match is None:
                continue
            with contextlib.suppress(ValueError):
                arms[int(branch_match.group(1))] = branch_match.group(2)
        blocks.append(arms)
    return blocks


def _filing_status_conditional_branch_results(formula: str) -> dict[int, set[str]]:
    results: dict[int, set[str]] = {}
    for raw_line in formula.splitlines():
        line = raw_line.strip()
        if not line:
            continue
        branch = re.match(r"^(?:if|elif)\s+(.+?)\s*:\s*(.+)$", line)
        if branch is None:
            continue
        condition = branch.group(1)
        expression = re.split(
            r"\s+else\s*:",
            branch.group(2).strip(),
            maxsplit=1,
            flags=re.IGNORECASE,
        )[0].strip()
        if not expression:
            continue
        for code in _filing_status_equality_codes_in_condition(condition):
            results.setdefault(code, set()).add(_normalize_branch_result(expression))
    return results


def _filing_status_equality_codes_in_condition(condition: str) -> set[int]:
    codes: set[int] = set()
    for pattern in (
        rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*==\s*(\d+)\b",
        rf"\b(\d+)\s*==\s*{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\b",
    ):
        for match in re.finditer(pattern, condition, flags=re.IGNORECASE):
            with contextlib.suppress(ValueError):
                codes.add(int(match.group(1)))
    return codes


def _normalize_branch_result(result: str) -> str:
    return re.sub(r"\s+", "", result.strip().rstrip(",")).lower()


def _filing_status_has_code_equality(formula: str, code: int) -> bool:
    return bool(
        re.search(
            rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*==\s*{code}\b"
            rf"|\b{code}\s*==\s*{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\b",
            formula,
            flags=re.IGNORECASE,
        )
    )


def _filing_status_has_grouped_joint_surviving_spouse_condition(formula: str) -> bool:
    compact = re.sub(r"\s+", "", formula).lower()
    for name in ("filing_status", "tax_filing_status"):
        if re.search(rf"\b{name}in[\[\(\{{]1,4[\]\)\}}]", compact):
            return True
        if re.search(rf"\b{name}in[\[\(\{{]4,1[\]\)\}}]", compact):
            return True
        if f"{name}==1or{name}==4" in compact:
            return True
        if f"{name}==4or{name}==1" in compact:
            return True
        if f"1=={name}or4=={name}" in compact:
            return True
        if f"4=={name}or1=={name}" in compact:
            return True
    return False


def _filing_status_codes_in_formula(formula: str) -> set[int]:
    codes: set[int] = set()
    normalized = re.sub(r"\s+", " ", formula)
    for match in re.finditer(
        rf"\b{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*(?:==|!=|>=|>|<=|<)\s*(\d+)\b",
        normalized,
        flags=re.IGNORECASE,
    ):
        with contextlib.suppress(ValueError):
            codes.add(int(match.group(1)))
    if re.search(
        rf"\bmatch\s+{_STRUCTURAL_ENUM_INDEX_NAME_PATTERN}\s*:",
        normalized,
        flags=re.IGNORECASE,
    ):
        for block in _filing_status_match_blocks(formula):
            codes.update(block)
    return codes


def find_nonnegative_amount_reduction_issues(content: str) -> list[str]:
    """Flag benefit-style reductions that can fall below zero."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"money", "currency", "decimal", "integer", "number"}:
            continue
        name = str(rule.get("name") or "").strip()
        is_taxable_income = bool(
            _NONNEGATIVE_TAXABLE_INCOME_NAME_PATTERN.fullmatch(name)
        )
        if (
            not is_taxable_income
            and not _NONNEGATIVE_REDUCTION_AMOUNT_NAME_PATTERN.search(name)
        ):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            if is_taxable_income:
                if not _taxable_income_formula_has_zero_floor(formula):
                    issues.append(
                        "Nonnegative taxable income missing floor: "
                        f"`{name}` can return a negative amount. Taxable income "
                        "outputs used for current-law tax calculations must floor "
                        "the selected branch at zero."
                    )
                continue
            result_expressions = _formula_result_expressions(formula)
            unfloored_expressions = [
                expression
                for expression in result_expressions
                if _NONNEGATIVE_REDUCTION_FORMULA_PATTERN.search(expression)
                and not _final_expression_has_zero_floor(expression)
            ]
            if not unfloored_expressions:
                unfloored_income_base_expressions = [
                    expression
                    for expression in result_expressions
                    if _nonnegative_income_base_missing_zero_floor(expression)
                ]
                if not unfloored_income_base_expressions:
                    continue
                issues.append(
                    "Nonnegative amount income base missing floor: "
                    f"`{name}` uses an income, earnings, or wages base inside "
                    "`min(...)` without flooring that base at zero. Benefit, "
                    "allotment, credit, deduction, allowance, and subsidy outputs "
                    "must use `max(0, income)` when a negative income input could "
                    "otherwise produce a negative amount."
                )
            else:
                issues.append(
                    "Nonnegative amount reduction missing floor: "
                    f"`{name}` subtracts an income/contribution-style reduction from a "
                    "maximum amount but does not floor the result at zero. Benefit, "
                    "allotment, credit, deduction, allowance, and subsidy outputs must "
                    "use `max(0, ...)` before downstream minimums or eligibility branches."
                )
    return issues


def _nonnegative_income_base_missing_zero_floor(expression: str) -> bool:
    if _final_expression_has_zero_floor(expression):
        return False
    if not _NONNEGATIVE_INCOME_BASE_FORMULA_PATTERN.search(expression):
        return False
    return not _ZERO_FLOORED_INCOME_BASE_PATTERN.search(expression)


def repair_nonnegative_amount_reductions(content: str) -> tuple[str, list[str]]:
    """Mechanically floor supported nonnegative amount reduction formulas."""
    payload = _rulespec_payload(content)
    if payload is None:
        return content, []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    repaired_content = content
    repaired_rules: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"money", "currency", "decimal", "integer", "number"}:
            continue
        name = str(rule.get("name") or "").strip()
        is_taxable_income = bool(
            _NONNEGATIVE_TAXABLE_INCOME_NAME_PATTERN.fullmatch(name)
        )
        if (
            not is_taxable_income
            and not _NONNEGATIVE_REDUCTION_AMOUNT_NAME_PATTERN.search(name)
        ):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            repaired_formula = (
                _repair_nonnegative_taxable_income_formula(formula)
                if is_taxable_income
                else _repair_nonnegative_amount_reduction_formula(formula)
            )
            if repaired_formula == formula:
                continue
            updated_content = _replace_formula_text_once(
                repaired_content,
                formula,
                repaired_formula,
            )
            if updated_content == repaired_content:
                continue
            repaired_content = updated_content
            repaired_rules.append(name or "<unknown>")
    return repaired_content, repaired_rules


def _taxable_income_formula_has_zero_floor(formula: str) -> bool:
    expressions = _formula_result_expressions(formula)
    return bool(expressions) and all(
        _taxable_income_expression_has_zero_floor(expression)
        for expression in expressions
    )


def _repair_nonnegative_taxable_income_formula(formula: str) -> str:
    return _repair_nonnegative_taxable_income_expression(formula.strip())


def _repair_nonnegative_taxable_income_expression(expression: str) -> str:
    if not expression or _taxable_income_expression_has_zero_floor(expression):
        return expression
    conditional = re.match(
        r"^(?P<head>if\b.+?)\s*:\s*(?P<then>.+?)\s+else\s*:\s*(?P<else>.+)$",
        expression,
        flags=re.IGNORECASE,
    )
    if conditional is not None:
        then_expr = _repair_nonnegative_taxable_income_expression(
            conditional.group("then").strip()
        )
        else_expr = _repair_nonnegative_taxable_income_expression(
            conditional.group("else").strip()
        )
        return f"{conditional.group('head')}: {then_expr} else: {else_expr}"
    return f"max(0, {expression})"


def _taxable_income_expression_has_zero_floor(expression: str) -> bool:
    expression = expression.strip()
    if _ZERO_LITERAL_PATTERN.fullmatch(expression):
        return True
    return any(
        start == 0 and end == len(expression)
        for start, end, _argument in _zero_floor_call_spans(expression)
    )


def _repair_nonnegative_amount_reduction_formula(formula: str) -> str:
    if _nonnegative_income_base_missing_zero_floor(formula):
        repaired_formula = _repair_nonnegative_income_base_expression(formula.strip())
        if repaired_formula != formula.strip():
            return repaired_formula

    repaired_lines: list[str] = []
    changed = False
    for line in formula.splitlines() or [formula]:
        repaired_line = _repair_nonnegative_amount_reduction_expression(line.strip())
        if repaired_line != line.strip():
            changed = True
            prefix = line[: len(line) - len(line.lstrip())]
            repaired_lines.append(f"{prefix}{repaired_line}")
        else:
            repaired_lines.append(line)
    return "\n".join(repaired_lines) if changed else formula


def _repair_nonnegative_amount_reduction_expression(expression: str) -> str:
    if not expression:
        return expression
    conditional = re.match(
        r"^(?P<head>if\b.+?)\s*:\s*(?P<then>.+?)\s+else\s*:\s*(?P<else>.+)$",
        expression,
        flags=re.IGNORECASE,
    )
    if conditional is not None:
        then_expr = _repair_nonnegative_amount_reduction_expression(
            conditional.group("then").strip()
        )
        else_expr = _repair_nonnegative_amount_reduction_expression(
            conditional.group("else").strip()
        )
        return f"{conditional.group('head')}: {then_expr} else: {else_expr}"
    if _nonnegative_income_base_missing_zero_floor(expression):
        return _repair_nonnegative_income_base_expression(expression)
    if not (
        _NONNEGATIVE_REDUCTION_FORMULA_PATTERN.search(expression)
        or _ZERO_FLOOR_REDUCTION_ARGUMENT_PATTERN.search(expression)
    ):
        return expression
    if _final_expression_has_zero_floor(expression):
        return expression
    return f"max(0, {expression})"


def _repair_nonnegative_income_base_expression(expression: str) -> str:
    for start, end, arguments in _min_call_spans(expression):
        repaired_arguments = [argument.strip() for argument in arguments]
        for index, argument in enumerate(arguments):
            stripped_argument = argument.strip()
            if not _INCOME_BASE_IDENTIFIER_PATTERN.search(stripped_argument):
                continue
            if _ZERO_FLOORED_INCOME_BASE_PATTERN.search(stripped_argument):
                continue
            repaired_arguments[index] = f"max(0, {stripped_argument})"
            return (
                f"{expression[:start]}min({', '.join(repaired_arguments)})"
                f"{expression[end:]}"
            )
    return expression


def _min_call_spans(expression: str) -> list[tuple[int, int, list[str]]]:
    spans: list[tuple[int, int, list[str]]] = []
    for match in _MIN_FUNCTION_CALL_PATTERN.finditer(expression):
        open_index = match.end() - 1
        depth = 0
        for index in range(open_index, len(expression)):
            char = expression[index]
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0:
                    arguments = _split_top_level_call_arguments(
                        expression[open_index + 1 : index]
                    )
                    spans.append((match.start(), index + 1, arguments))
                    break
    return spans


@dataclass(frozen=True)
class _ImportedRulespecExport:
    name: str
    target: str
    file: Path


def find_current_year_final_amount_table_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path | None = None,
) -> list[str]:
    """Flag formulas that recompute a final rounded table exported upstream."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    imported_exports = _imported_rulespec_exports(
        payload,
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )
    if not imported_exports:
        return []

    issues: list[str] = []
    for name, kind, formula, _source, _rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        if not _CURRENT_YEAR_FINAL_AMOUNT_RULE_PATTERN.search(name):
            continue
        if not _CURRENT_YEAR_FINAL_AMOUNT_RECOMPUTE_PATTERN.search(formula):
            continue
        final_export = _matching_final_amount_export(name, imported_exports)
        if final_export is None:
            continue
        issues.append(
            "Current-year final amount table ignored: "
            f"`{name}` recomputes a maximum amount from a rate and amount even "
            f"though imported RuleSpec `{final_export.target}` exports a final "
            "rounded amount table. Select the imported table instead of "
            "recomputing a rounded current-year value."
        )
    return issues


def repair_current_year_final_amount_tables(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path | None = None,
) -> tuple[str, list[str]]:
    """Mechanically select supported imported final amount tables."""
    payload = _rulespec_payload(content)
    if payload is None:
        return content, []

    rule_names = _rulespec_rule_names(payload)
    imported_exports = _imported_rulespec_exports(
        payload,
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )

    repaired = content
    repaired_rules: list[str] = []
    for name, kind, formula, _source, _rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        phased_in_repair = _current_year_phased_in_cap_repair(
            name=name,
            formula=formula,
            rule_names=rule_names,
        )
        if phased_in_repair is not None:
            repaired = _replace_formula_text_once(repaired, formula, phased_in_repair)
            repaired_rules.append(name)
            continue
        if not imported_exports:
            continue
        if not _CURRENT_YEAR_FINAL_AMOUNT_RULE_PATTERN.search(name):
            continue
        if not _CURRENT_YEAR_FINAL_AMOUNT_RECOMPUTE_PATTERN.search(formula):
            continue
        final_export = _matching_final_amount_export(name, imported_exports)
        if final_export is None:
            continue
        index_rule = _final_amount_index_rule_name(name, rule_names)
        if index_rule is None:
            continue
        keys = _parameter_table_keys(final_export.file, final_export.name)
        if not keys:
            continue
        replacement = _final_amount_table_match_formula(
            table_name=final_export.name,
            index_rule=index_rule,
            keys=keys,
        )
        repaired = _replace_formula_text_once(repaired, formula, replacement)
        import_hash = f"sha256:{_file_sha256(final_export.file)}"
        repaired = _insert_rule_proof_import_atom(
            repaired,
            rule_name=name,
            target=final_export.target,
            output=final_export.name,
            import_hash=import_hash,
        )
        repaired_rules.append(name)

    return repaired, repaired_rules


def _current_year_phased_in_cap_repair(
    *,
    name: str,
    formula: str,
    rule_names: set[str],
) -> str | None:
    if not name.endswith("_phased_in"):
        return None
    prefix = name.removesuffix("_phased_in")
    maximum_name = f"{prefix}_maximum"
    if maximum_name not in rule_names:
        return None
    stripped = formula.strip()
    if stripped.startswith("if earned_income >= eitc_earned_income_amount:"):
        return None
    if "phase_in_rate" not in stripped or "earned_income_amount" not in stripped:
        return None
    raw_formula = re.sub(
        rf"^min\s*\(\s*{re.escape(maximum_name)}\s*,\s*(?P<body>.*)\)\s*$",
        r"\g<body>",
        stripped,
        count=1,
    )
    return f"if earned_income >= eitc_earned_income_amount: {maximum_name} else: {raw_formula}"


def _rulespec_rule_names(payload: dict[str, Any]) -> set[str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    return {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }


def _imported_rulespec_exports(
    payload: dict[str, Any],
    *,
    rules_file: Path,
    policy_repo_path: Path | None,
) -> dict[str, _ImportedRulespecExport]:
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return {}

    exports: dict[str, _ImportedRulespecExport] = {}
    for raw_import in imports:
        if not isinstance(raw_import, str):
            continue
        target = raw_import.split("#", 1)[0].strip().strip("/")
        target_ref = _parse_rulespec_target(target)
        if target_ref is None:
            continue
        target_file = _resolve_rulespec_target_file(
            target_ref,
            policy_repo_path or _rulespec_repo_root(Path(rules_file).resolve()),
        )
        if target_file is None or not target_file.exists():
            continue
        target_payload = _rulespec_payload_from_file(target_file)
        if target_payload is None:
            continue
        for rule_name in _rulespec_rule_names(target_payload):
            exports.setdefault(
                rule_name,
                _ImportedRulespecExport(
                    name=rule_name,
                    target=f"{target}#{rule_name}",
                    file=target_file,
                ),
            )
    return exports


def _matching_final_amount_export(
    rule_name: str,
    imported_exports: dict[str, _ImportedRulespecExport],
) -> _ImportedRulespecExport | None:
    for candidate in _final_amount_export_candidates(rule_name):
        export = imported_exports.get(candidate)
        if export is not None:
            return export
    return None


def _final_amount_export_candidates(rule_name: str) -> tuple[str, ...]:
    candidates = [
        f"{rule_name}_amounts",
        f"{rule_name}_credit_amounts",
    ]
    if rule_name.endswith("_maximum"):
        prefix = rule_name.removesuffix("_maximum")
        if prefix:
            candidates.append(f"{prefix}_maximum_credit_amounts")
    return tuple(dict.fromkeys(candidates))


def _final_amount_index_rule_name(
    rule_name: str,
    rule_names: set[str],
) -> str | None:
    prefixes = [rule_name]
    if rule_name.endswith("_maximum"):
        prefixes.append(rule_name.removesuffix("_maximum"))
    for prefix in prefixes:
        for candidate in (
            f"{prefix}_capped_child_count",
            f"{prefix}_child_count",
            f"{prefix}_capped_count",
        ):
            if candidate in rule_names:
                return candidate
    return None


def _parameter_table_keys(target_file: Path, rule_name: str) -> list[str]:
    payload = _rulespec_payload_from_file(target_file)
    if payload is None:
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("name") or "").strip() != rule_name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list) or not versions:
            return []
        first_version = versions[0]
        if not isinstance(first_version, dict):
            return []
        values = first_version.get("values")
        if not isinstance(values, dict):
            return []
        return [str(key) for key in values]
    return []


def _final_amount_table_match_formula(
    *,
    table_name: str,
    index_rule: str,
    keys: list[str],
) -> str:
    sorted_keys = sorted(keys, key=lambda key: int(key) if key.isdigit() else key)
    lines = [f"match {index_rule}:"]
    lines.extend(f"    {key} => {table_name}[{key}]" for key in sorted_keys)
    return "\n".join(lines)


def _insert_rule_proof_import_atom(
    content: str,
    *,
    rule_name: str,
    target: str,
    output: str,
    import_hash: str,
) -> str:
    if f"target: {target}" in content:
        return content

    lines = content.splitlines(keepends=True)
    rule_starts = [
        index for index, line in enumerate(lines) if re.match(r"^  - name:\s*", line)
    ]
    for rule_start, next_rule_start in zip(
        rule_starts,
        rule_starts[1:] + [len(lines)],
        strict=False,
    ):
        name_match = re.match(r"^  - name:\s*(.+?)\s*$", lines[rule_start])
        if name_match is None or name_match.group(1).strip() != rule_name:
            continue
        atom_index = next(
            (
                index
                for index in range(rule_start, next_rule_start)
                if re.match(r"^        atoms:\s*$", lines[index])
            ),
            None,
        )
        if atom_index is None:
            return content
        inserted = [
            "          - path: versions[0].formula\n",
            "            kind: import\n",
            "            import:\n",
            f"              target: {target}\n",
            f"              output: {output}\n",
            f"              hash: {import_hash}\n",
        ]
        return "".join(lines[: atom_index + 1] + inserted + lines[atom_index + 1 :])
    return content


def _replace_formula_text_once(content: str, old: str, new: str) -> str:
    if old in content:
        replacement = new
        if "\n" in new:
            start = content.index(old)
            line_start = content.rfind("\n", 0, start) + 1
            prefix_match = re.match(r"[ \t]*", content[line_start:start])
            prefix = prefix_match.group(0) if prefix_match is not None else ""
            replacement = new.replace("\n", f"\n{prefix}")
        return content.replace(old, replacement, 1)
    replaced_block = _replace_indented_block_text_once(content, old, new)
    if replaced_block != content:
        return replaced_block
    replaced_folded_scalar = _replace_folded_formula_scalar_text_once(content, old, new)
    if replaced_folded_scalar != content:
        return replaced_folded_scalar
    updated = content
    for old_line, new_line in zip(old.splitlines(), new.splitlines(), strict=False):
        if old_line == new_line:
            continue
        old_stripped = old_line.strip()
        if not old_stripped:
            continue
        lines = updated.splitlines(keepends=True)
        for index, line in enumerate(lines):
            line_end = "\n" if line.endswith("\n") else ""
            body = line[:-1] if line_end else line
            if body.strip() != old_stripped:
                continue
            indent = body[: len(body) - len(body.lstrip())]
            lines[index] = f"{indent}{new_line.strip()}{line_end}"
            updated = "".join(lines)
            break
    return updated


def _replace_folded_formula_scalar_text_once(content: str, old: str, new: str) -> str:
    old_normalized = _normalize_yaml_folded_scalar_text(old)
    if not old_normalized:
        return content
    formula_scalar_pattern = re.compile(
        r"formula:\s*(?P<quote>['\"])(?P<body>.*?)(?P=quote)",
        flags=re.DOTALL,
    )
    for match in formula_scalar_pattern.finditer(content):
        body = match.group("body")
        if _normalize_yaml_folded_scalar_text(body) != old_normalized:
            continue
        line_start = content.rfind("\n", 0, match.start()) + 1
        indent_match = re.match(r"[ \t]*", content[line_start : match.start()])
        indent = indent_match.group(0) if indent_match is not None else ""
        replacement_lines = [f"{indent}  {line}" for line in new.splitlines()]
        replacement = "formula: |-\n" + "\n".join(replacement_lines)
        return content[: match.start()] + replacement + content[match.end() :]
    return content


def _normalize_yaml_folded_scalar_text(value: str) -> str:
    return " ".join(value.split())


def _replace_indented_block_text_once(content: str, old: str, new: str) -> str:
    old_lines = old.splitlines()
    if not old_lines:
        return content
    content_lines = content.splitlines(keepends=True)
    for start in range(0, len(content_lines) - len(old_lines) + 1):
        first_body = content_lines[start].removesuffix("\n")
        indent = first_body[: len(first_body) - len(first_body.lstrip())]
        if first_body[len(indent) :] != old_lines[0]:
            continue
        for offset, old_line in enumerate(old_lines):
            body = content_lines[start + offset].removesuffix("\n")
            if not body.startswith(indent):
                break
            if body[len(indent) :] != old_line:
                break
        else:
            replacement = [
                f"{indent}{new_line}{_line_ending(content_lines[start])}"
                for new_line in new.splitlines()
            ]
            return "".join(
                content_lines[:start]
                + replacement
                + content_lines[start + len(old_lines) :]
            )
    return content


def _line_ending(line: str) -> str:
    return "\n" if line.endswith("\n") else ""


def find_formula_date_literal_issues(content: str) -> list[str]:
    """Flag ISO date literals in executable formulas."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "parameter",
            "derived",
            "derived_relation",
        }:
            continue
        name = str(rule.get("name") or "").strip()
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            match = _FORMULA_ISO_DATE_LITERAL_PATTERN.search(formula)
            if match is None:
                continue
            issues.append(
                "Formula date literal unsupported: "
                f"`{name}` uses `{match.group(0)}` inside an executable formula. "
                "Axiom formula syntax has no date literal type; encode effective "
                "windows with `effective_from` metadata or source-stated boolean "
                "predicates such as `taxable_year_begins_after_termination_date`."
            )
    return issues


_TEMPORAL_VALUE_FACT_YEAR_PATTERN = re.compile(r"(?:^|_)(?:19|20)\d{2}(?:_|$)")


def find_temporal_value_fact_name_issues(content: str) -> list[str]:
    """Reject runtime date predicates that embed the legal date value in the name."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    defined_symbols = _defined_rulespec_symbols(rules)
    issues: list[str] = []
    seen: set[tuple[str, str]] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        rule_name = str(rule.get("name") or "").strip()
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            for identifier in sorted(_formula_local_identifiers(formula)):
                if identifier in defined_symbols:
                    continue
                if not identifier.startswith("taxable_year"):
                    continue
                if _TEMPORAL_VALUE_FACT_YEAR_PATTERN.search(identifier) is None:
                    continue
                key = (rule_name, identifier)
                if key in seen:
                    continue
                seen.add(key)
                issues.append(
                    "Temporal fact name embeds legal date value: "
                    f"`{rule_name}` references local fact `{identifier}`. "
                    "Do not put source date or year values in runtime fact names; "
                    "use a semantic predicate such as "
                    "`taxable_year_begins_after_termination_date` or "
                    "`taxable_year_is_in_temporary_effective_window`."
                )
    return issues


_DEFINED_TERM_HEADING_PATTERN = re.compile(
    r"\([a-z0-9]+\)\s+Definition of\s+(?P<term>[A-Za-z][A-Za-z\s-]*?)(?:\s+\(|\s+For\b|$)"
)


def find_helper_only_definition_issues(content: str) -> list[str]:
    """Reject definition slices that expose helpers but not the defined term."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    module = payload.get("module")
    if not isinstance(module, dict):
        return []

    summary = str(module.get("summary") or "")
    if not summary:
        return []

    rules = payload.get("rules")
    has_rules = isinstance(rules, list) and any(
        isinstance(rule, dict) for rule in rules
    )
    if not has_rules:
        return []

    issues: list[str] = []
    if re.search(r"\bfinal\b.{0,120}\bnot encoded\b", summary, flags=re.IGNORECASE):
        issues.append(
            "Definition provision is helper-only: module summary says the final "
            "defined status is not encoded while executable helper rules are "
            "present. Either encode the final source-defined term or mark the "
            "module deferred with no executable rules."
        )

    rule_names = _rulespec_rule_names(payload)
    for match in _DEFINED_TERM_HEADING_PATTERN.finditer(summary):
        term = " ".join(match.group("term").split()).lower()
        if not term:
            continue
        term_slug = re.sub(r"[^a-z0-9]+", "_", term).strip("_")
        if not term_slug:
            continue
        allowed_names = {
            term_slug,
            f"taxpayer_is_{term_slug}",
            f"individual_is_{term_slug}",
        }
        if rule_names & allowed_names:
            continue
        issues.append(
            "Definition provision missing final defined term: "
            f"`Definition of {term}` must expose `{term_slug}` as the final "
            "source-backed output, not only helper, limitation, or prerequisite "
            "predicates."
        )

    return issues


def find_judgment_conditional_formula_issues(content: str) -> list[str]:
    """Flag Judgment formulas that branch between judgment expressions."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        if str(rule.get("dtype") or "").strip().lower() != "judgment":
            continue
        name = str(rule.get("name") or "").strip()
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            if _FORMULA_AXIOM_CONDITIONAL_PATTERN.search(formula):
                issues.append(
                    "Judgment conditional formula unsupported: "
                    f"`{name}` uses `if ... else ...` in a Judgment formula. "
                    "Judgment formulas must be boolean expressions using `and`, "
                    "`or`, `not`, comparisons, and parentheses; rewrite branch "
                    "logic as equivalent boolean logic instead of returning one "
                    "judgment expression or another."
                )
    return issues


def _formula_result_expressions(formula: str) -> list[str]:
    expressions: list[str] = []
    for raw_line in formula.splitlines():
        line = raw_line.strip()
        if not line:
            continue
        if _inline_conditional_result_parts(line) is not None:
            expressions.extend(_split_inline_conditional_result_expressions(line))
            continue
        match_arm = re.match(r"^(?:\d+|default|otherwise|_)\s*=>\s*(.+)$", line)
        if match_arm is not None:
            expressions.extend(
                _split_inline_conditional_result_expressions(match_arm.group(1))
            )
            continue
        branch = re.match(r"^(?:if\b.+|elif\b.+|else)\s*:\s*(.+)$", line)
        if branch is not None:
            expression = _branch_result_expression(branch.group(1).strip())
            expressions.extend(_split_inline_conditional_result_expressions(expression))
    if not expressions:
        expressions.extend(_indented_conditional_result_expressions(formula))
    if not expressions and formula.strip():
        expressions.append(formula.strip())
    return expressions


_INDENTED_CONDITIONAL_CONTROL_LINE_PATTERN = re.compile(
    r"^\s*(?:if\b.+|elif\b.+|else)\s*:\s*$",
    flags=re.IGNORECASE,
)
_EXPRESSION_CONTINUATION_PREFIX_PATTERN = re.compile(
    r"^(?:and|or|[+*/%<>=!&|])\b|^[-+*/%)]"
)
_EXPRESSION_CONTINUATION_SUFFIX_PATTERN = re.compile(
    r"(?:[+\-*/%<>=!&|]|\b(?:and|or)\b|[,([{])$",
    flags=re.IGNORECASE,
)


def _indented_conditional_result_expressions(formula: str) -> list[str]:
    """Return leaf expressions from an indented Rulespec conditional block."""
    lines = formula.splitlines()
    if not any(
        _INDENTED_CONDITIONAL_CONTROL_LINE_PATTERN.match(line) for line in lines
    ):
        return []

    expressions: list[str] = []
    index = 0
    while index < len(lines):
        raw_line = lines[index]
        line = raw_line.strip()
        if not line or _INDENTED_CONDITIONAL_CONTROL_LINE_PATTERN.match(raw_line):
            index += 1
            continue

        expression_lines = [line]
        depth = _formula_bracket_depth_delta(line)
        index += 1
        while index < len(lines):
            next_raw = lines[index]
            next_line = next_raw.strip()
            if not next_line:
                index += 1
                continue
            if depth <= 0 and _INDENTED_CONDITIONAL_CONTROL_LINE_PATTERN.match(
                next_raw
            ):
                break
            if depth <= 0 and not _formula_line_continues_expression(
                expression_lines[-1],
                next_line,
            ):
                break
            expression_lines.append(next_line)
            depth += _formula_bracket_depth_delta(next_line)
            index += 1

        expression = "\n".join(expression_lines).strip()
        expressions.extend(_split_inline_conditional_result_expressions(expression))

    return expressions


def _formula_line_continues_expression(previous_line: str, next_line: str) -> bool:
    return bool(
        _EXPRESSION_CONTINUATION_SUFFIX_PATTERN.search(previous_line.strip())
        or _EXPRESSION_CONTINUATION_PREFIX_PATTERN.search(next_line.strip())
    )


def _formula_bracket_depth_delta(expression: str) -> int:
    depth = 0
    quote: str | None = None
    escaped = False
    for char in expression:
        if quote is not None:
            if escaped:
                escaped = False
            elif char == "\\":
                escaped = True
            elif char == quote:
                quote = None
            continue
        if char in {"'", '"'}:
            quote = char
        elif char in "([{":
            depth += 1
        elif char in ")]}" and depth:
            depth -= 1
    return depth


_INLINE_CONDITIONAL_START_PATTERN = re.compile(r"^(?:if|elif)\b", flags=re.IGNORECASE)


def _branch_result_expression(branch_tail: str) -> str:
    if _inline_conditional_result_parts(branch_tail) is not None:
        return branch_tail
    top_level_else = _top_level_else_bounds(branch_tail)
    if top_level_else is None:
        return branch_tail.strip()
    else_start, _else_end = top_level_else
    return branch_tail[:else_start].strip()


def _split_inline_conditional_result_expressions(expression: str) -> list[str]:
    expression = expression.strip()
    if not expression:
        return []
    inline_conditional = _inline_conditional_result_parts(expression)
    if inline_conditional is None:
        return [expression]
    then_expression, else_expression = inline_conditional
    return [
        *(_split_inline_conditional_result_expressions(then_expression)),
        *(_split_inline_conditional_result_expressions(else_expression)),
    ]


def _inline_conditional_result_parts(expression: str) -> tuple[str, str] | None:
    expression = expression.strip()
    if _INLINE_CONDITIONAL_START_PATTERN.match(expression) is None:
        return None

    colon_index = _top_level_conditional_colon_index(expression)
    if colon_index is None:
        return None
    top_level_else = _top_level_else_bounds(expression[colon_index + 1 :])
    if top_level_else is None:
        return None

    else_start, else_end = top_level_else
    then_expression = expression[colon_index + 1 : colon_index + 1 + else_start]
    else_expression = expression[colon_index + 1 + else_end :]
    return then_expression.strip(), else_expression.strip()


def _top_level_conditional_colon_index(expression: str) -> int | None:
    for index, char, depth in _formula_scan_chars(expression):
        if char == ":" and depth == 0:
            return index
    return None


def _top_level_else_bounds(expression: str) -> tuple[int, int] | None:
    for index, char, depth in _formula_scan_chars(expression):
        if depth != 0 or char.lower() != "e":
            continue
        prefix_ok = index == 0 or expression[index - 1].isspace()
        if not prefix_ok:
            continue
        match = re.match(r"else\s*:", expression[index:], flags=re.IGNORECASE)
        if match is not None:
            return index, index + match.end()
    return None


def _formula_scan_chars(expression: str) -> Iterable[tuple[int, str, int]]:
    depth = 0
    quote: str | None = None
    escaped = False
    for index, char in enumerate(expression):
        if quote is not None:
            if escaped:
                escaped = False
            elif char == "\\":
                escaped = True
            elif char == quote:
                quote = None
            yield index, char, depth
            continue
        if char in {"'", '"'}:
            quote = char
        elif char in "([{":
            depth += 1
        elif char in ")]}" and depth:
            depth -= 1
        yield index, char, depth


def _final_expression_has_zero_floor(expression: str) -> bool:
    without_zero_floor_calls = _expression_without_zero_floor_calls(expression)
    return not _NONNEGATIVE_REDUCTION_FORMULA_PATTERN.search(
        without_zero_floor_calls
    ) and any(
        _NONNEGATIVE_REDUCTION_FORMULA_PATTERN.search(argument)
        or _ZERO_FLOOR_REDUCTION_ARGUMENT_PATTERN.search(argument)
        for argument in _zero_floor_argument_expressions(expression)
    )


_MAX_CALL_PATTERN = re.compile(r"\bmax\s*\(", flags=re.IGNORECASE)
_ZERO_LITERAL_PATTERN = re.compile(r"0(?:\.0+)?$")


def _zero_floor_argument_expressions(expression: str) -> list[str]:
    argument_expressions: list[str] = []
    for _start, _end, argument in _zero_floor_call_spans(expression):
        argument_expressions.append(argument)
    return argument_expressions


def _expression_without_zero_floor_calls(expression: str) -> str:
    chunks: list[str] = []
    last_end = 0
    for start, end, _argument in _zero_floor_call_spans(expression):
        if start < last_end:
            continue
        chunks.append(expression[last_end:start])
        chunks.append(" zero_floor_result ")
        last_end = end
    chunks.append(expression[last_end:])
    return "".join(chunks)


def _zero_floor_call_spans(expression: str) -> list[tuple[int, int, str]]:
    spans: list[tuple[int, int, str]] = []
    for match in _MAX_CALL_PATTERN.finditer(expression):
        depth = 1
        index = match.end()
        while index < len(expression):
            char = expression[index]
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0:
                    arguments = _split_top_level_call_arguments(
                        expression[match.end() : index]
                    )
                    if len(arguments) >= 2:
                        first = arguments[0].strip()
                        second = arguments[1].strip()
                        if _ZERO_LITERAL_PATTERN.fullmatch(first):
                            spans.append((match.start(), index + 1, second))
                        elif _ZERO_LITERAL_PATTERN.fullmatch(second):
                            spans.append((match.start(), index + 1, first))
                    break
            index += 1
    return spans


def _split_top_level_call_arguments(arguments: str) -> list[str]:
    parts: list[str] = []
    depth = 0
    start = 0
    for index, char in enumerate(arguments):
        if char == "(":
            depth += 1
        elif char == ")" and depth > 0:
            depth -= 1
        elif char == "," and depth == 0:
            parts.append(arguments[start:index])
            start = index + 1
    parts.append(arguments[start:])
    return parts


def find_zero_branch_test_coverage_issues(
    content: str,
    test_cases: Any,
) -> list[str]:
    """Require a companion assertion for source-stated zero amount branches."""
    if not isinstance(test_cases, list):
        return []
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype in {"judgment", "boolean", "bool"}:
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        if not any(
            isinstance(version, dict)
            and isinstance(version.get("formula"), str)
            and _ZERO_AMOUNT_BRANCH_PATTERN.search(version["formula"])
            for version in versions
        ):
            continue
        if _has_zero_output_test(test_cases, name):
            continue
        issues.append(
            "Zero branch test coverage missing: "
            f"`{name}` has a formula branch that returns 0, but no companion test "
            "asserts that output is zero. Add a case that exercises the zero branch "
            "rather than only above-threshold positive cases."
        )
    return issues


def _has_zero_output_test(test_cases: list[Any], rule_name: str) -> bool:
    for test_case in test_cases:
        if not isinstance(test_case, dict):
            continue
        outputs = test_case.get("output")
        if not isinstance(outputs, dict):
            continue
        for key, value in outputs.items():
            if _test_reference_fragment(key) == rule_name and _is_zero_expected_value(
                value
            ):
                return True
    return False


def _is_zero_expected_value(value: Any) -> bool:
    if isinstance(value, bool) or value is None:
        return False
    if isinstance(value, list | tuple):
        return any(_is_zero_expected_value(item) for item in value)
    if isinstance(value, (int, float)):
        return float(value) == 0.0
    if isinstance(value, str):
        with contextlib.suppress(ValueError):
            return float(value.strip()) == 0.0
    if isinstance(value, dict):
        raw_value = value.get("value")
        if isinstance(raw_value, dict):
            return _is_zero_expected_value(raw_value.get("value"))
        return _is_zero_expected_value(raw_value)
    return False


def find_proof_import_hash_consistency_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path | None = None,
) -> list[str]:
    """Validate proof import hashes against resolved RuleSpec source files."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    current_file = Path(rules_file).resolve()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip() or "<unknown>"
        proof = _rule_proof_payload(rule)
        atoms = proof.get("atoms") if isinstance(proof, dict) else None
        if not isinstance(atoms, list):
            continue
        for atom_index, atom in enumerate(atoms):
            if not isinstance(atom, dict) or not isinstance(atom.get("import"), dict):
                continue
            raw_import = atom["import"]
            target = str(raw_import.get("target") or "").strip()
            hash_value = str(raw_import.get("hash") or "").strip()
            target_ref = _parse_rulespec_target(target)
            if target_ref is None:
                continue
            target_file = _resolve_rulespec_target_file(
                target_ref,
                policy_repo_path or _rulespec_repo_root(current_file),
            )
            if target_file is None or not target_file.exists():
                continue
            expected_hash = (
                "sha256:local"
                if target_file.resolve() == current_file
                or _rulespec_file_matches_target_ref(current_file, target_ref)
                else f"sha256:{_file_sha256(target_file)}"
            )
            if hash_value == expected_hash:
                continue
            issues.append(
                "Proof import hash mismatch: "
                f"`{rule_name}` proof atom {atom_index} imports `{target}` with "
                f"`hash: {hash_value or '<missing>'}`, expected `{expected_hash}`."
            )
    return issues


def _rule_proof_payload(rule: dict[str, Any]) -> dict[str, Any] | None:
    metadata = rule.get("metadata")
    if isinstance(metadata, dict) and isinstance(metadata.get("proof"), dict):
        return metadata["proof"]
    proof = rule.get("proof")
    return proof if isinstance(proof, dict) else None


def _file_sha256(path: Path) -> str:
    return hashlib.sha256(path.read_bytes()).hexdigest()


def _rulespec_file_matches_target_ref(
    rules_file: Path,
    target_ref: "_RuleSpecTargetRef",
) -> bool:
    """Return whether a file path carries the canonical target path suffix.

    Generated candidates are often validated outside a `rulespec-*` checkout,
    for example under `/tmp/.../statutes/26/63/f.yaml`. A proof import pointing
    to `us:statutes/26/63/f#symbol` is still a same-file import in that context.
    """
    path_parts = Path(rules_file).resolve().parts
    target_parts = target_ref.relative_path.parts
    if len(path_parts) < len(target_parts):
        return False
    return path_parts[-len(target_parts) :] == target_parts


def _rulespec_data_relation_names(payload: dict[str, Any]) -> set[str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    return {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("kind") or "").strip().lower() == "data_relation"
        and str(rule.get("name") or "").strip()
    }


def _source_limitation_subject_slugs(source_text: str) -> set[str]:
    slugs: set[str] = set()
    for match in _LIMITATION_ON_SUBJECT_PATTERN.finditer(source_text):
        slug = re.sub(r"[^a-z0-9]+", "_", match.group(1).lower()).strip("_")
        if slug:
            slugs.add(slug)
    return slugs


def _rule_source_subsection_tokens(source: Any) -> tuple[str, ...]:
    if isinstance(source, dict):
        source_text = " ".join(
            str(value) for value in source.values() if isinstance(value, str)
        )
    elif isinstance(source, str):
        source_text = source
    else:
        return ()
    return tuple(
        token
        for token in re.findall(r"\(([A-Za-z0-9]+)\)", source_text)
        if 1 <= len(token) <= 4
    )


def _rule_source_subsection_selectors(
    source: Any,
) -> tuple[tuple[str, str | None], ...]:
    if isinstance(source, dict):
        source_text = " ".join(
            str(value) for value in source.values() if isinstance(value, str)
        )
    elif isinstance(source, str):
        source_text = source
    else:
        return ()

    selectors: list[tuple[str, str | None]] = []
    for match in re.finditer(
        r"\(([A-Za-z0-9]+)\)"
        r"(?:\s*(?:-|\u2013|\u2014|to)\s*\(([A-Za-z0-9]+)\))?",
        source_text,
    ):
        start = match.group(1)
        end = match.group(2)
        if not 1 <= len(start) <= 4:
            continue
        if end is not None and not 1 <= len(end) <= 4:
            continue
        selectors.append((start, end))
    return tuple(selectors)


def _slice_source_text_at_marker(source_text: str, token: str) -> str:
    marker_flags = 0 if token.isalpha() else re.IGNORECASE
    marker = re.compile(rf"\({re.escape(token)}\)", flags=marker_flags)
    match = marker.search(source_text)
    if match is None:
        return ""

    if token.isdigit():
        next_token = str(int(token) + 1)
    elif len(token) == 1 and token.isalpha():
        next_token = chr(ord(token) + 1)
    else:
        next_token = ""
    if not next_token:
        return source_text[match.start() :].strip()
    next_marker_pattern = rf"\({re.escape(next_token)}\)"
    next_match = re.search(
        next_marker_pattern,
        source_text[match.end() :],
        flags=marker_flags,
    )
    if next_match is None:
        if token.isdigit():
            for sibling_match in re.finditer(
                r"\((\d+)\)",
                source_text[match.end() :],
                flags=marker_flags,
            ):
                if int(sibling_match.group(1)) > int(token):
                    next_match = sibling_match
                    break
        elif len(token) == 1 and token.isalpha():
            sibling_marker_pattern = (
                r"\(([a-z])\)" if token.islower() else r"\(([A-Z])\)"
            )
            for sibling_match in re.finditer(
                sibling_marker_pattern,
                source_text[match.end() :],
                flags=marker_flags,
            ):
                if ord(sibling_match.group(1)) > ord(token):
                    next_match = sibling_match
                    break
    if next_match is None:
        return source_text[match.start() :].strip()
    return source_text[match.start() : match.end() + next_match.start()].strip()


def _slice_source_text_at_marker_range(
    source_text: str,
    start_token: str,
    end_token: str,
) -> str:
    start_flags = 0 if start_token.isalpha() else re.IGNORECASE
    start_marker = re.compile(rf"\({re.escape(start_token)}\)", flags=start_flags)
    start_match = start_marker.search(source_text)
    if start_match is None:
        return ""

    end_flags = 0 if end_token.isalpha() else re.IGNORECASE
    end_marker = re.compile(rf"\({re.escape(end_token)}\)", flags=end_flags)
    end_match = end_marker.search(source_text, start_match.end())
    if end_match is None:
        return _slice_source_text_at_marker(source_text, start_token)

    end_segment = _slice_source_text_at_marker(
        source_text[end_match.start() :], end_token
    )
    if not end_segment:
        return _slice_source_text_at_marker(source_text, start_token)
    return source_text[
        start_match.start() : end_match.start() + len(end_segment)
    ].strip()


def _source_text_for_rule_source(source_text: str, source: Any) -> str:
    scoped_source = source_text
    for start_token, end_token in _rule_source_subsection_selectors(source):
        if end_token is None:
            next_scoped_source = _slice_source_text_at_marker(
                scoped_source, start_token
            )
        else:
            next_scoped_source = _slice_source_text_at_marker_range(
                scoped_source,
                start_token,
                end_token,
            )
        if not next_scoped_source:
            return scoped_source
        scoped_source = next_scoped_source
    return scoped_source


def _formula_implements_limitation(formula: str, source_text: str) -> bool:
    if _LIMITATION_IMPLEMENTATION_PATTERN.search(formula):
        return True
    return bool(
        _CONDITIONAL_SOURCE_LIMITATION_PATTERN.search(source_text)
        and _CONDITIONAL_FORMULA_PATTERN.search(formula)
    )


def _source_supports_structural_relation_container(
    source_text: str, relation_name: str
) -> bool:
    normalized_source = source_text.lower()
    normalized_relation = relation_name.lower()
    if re.search(r"\b(?:all|each|every)\s+(?:member|members)\b", normalized_source):
        return True
    relation_container_terms = (
        ("member_of_household", "household"),
        ("household_member", "household"),
        ("member_of_family", "family"),
        ("family_member", "family"),
        ("member_of_filing_unit", "filing unit"),
        ("filing_unit_member", "filing unit"),
        ("member_of_tax_unit", "tax unit"),
        ("tax_unit_member", "tax unit"),
    )
    return any(
        relation_token in normalized_relation and source_term in normalized_source
        for relation_token, source_term in relation_container_terms
    )


@dataclass(frozen=True)
class _SourceLimitPair:
    tokens: frozenset[str]
    phrases: frozenset[str]
    amount_tokens: frozenset[str]
    amount_phrases: frozenset[str]
    cap_tokens: frozenset[str]
    cap_phrases: frozenset[str]
    has_standalone_reduction: bool = False


@dataclass(frozen=True)
class _SourceLimitRelevance:
    tokens: frozenset[str]
    phrases: frozenset[str]
    amount_tokens: frozenset[str]
    amount_phrases: frozenset[str]
    cap_tokens: frozenset[str]
    cap_phrases: frozenset[str]
    filter_tokens: frozenset[str]
    filter_phrases: frozenset[str]
    has_standalone_reduction: bool
    filter_allows_negated_identifiers: bool
    limit_pairs: tuple[_SourceLimitPair, ...]


def _limit_relevance_tokens(text: str) -> set[str]:
    tokens: set[str] = set()
    for raw_word in _LIMIT_RELEVANCE_WORD_PATTERN.findall(text):
        for token in raw_word.lower().split("_"):
            if len(token) < 3 or token in _LIMIT_RELEVANCE_TOKEN_STOPWORDS:
                continue
            tokens.add(token)
    return tokens


def _limit_relevance_phrase_words(text: str) -> list[str]:
    words: list[str] = []
    for raw_word in _LIMIT_RELEVANCE_WORD_PATTERN.findall(text):
        for token in raw_word.lower().split("_"):
            if len(token) < 3 or token in _LIMIT_RELEVANCE_PHRASE_STOPWORDS:
                continue
            words.append(token)
    return words


def _limit_relevance_phrases(text: str) -> set[str]:
    phrases: set[str] = set()
    phrase_words = _limit_relevance_phrase_words(text)
    for ngram_size in range(2, 5):
        for index in range(0, len(phrase_words) - ngram_size + 1):
            phrases.add("_".join(phrase_words[index : index + ngram_size]))
    return phrases


def _phrase_is_amount_side(
    phrase: str,
    *,
    amount_words: set[str],
    amount_phrases: set[str],
) -> bool:
    phrase_words = set(phrase.split("_"))
    return phrase_words <= amount_words or any(
        amount_phrase in phrase for amount_phrase in amount_phrases
    )


_LESSER_GREATER_OF_PATTERN = re.compile(
    r"\b(?:lesser|greater)\s+of\b",
    flags=re.IGNORECASE,
)


def _source_limit_lesser_greater_operands(
    text: str,
    *,
    already_after_phrase: bool = False,
) -> tuple[str, str] | None:
    operand_text = text
    if not already_after_phrase:
        match = _LESSER_GREATER_OF_PATTERN.search(text)
        if match is None:
            return None
        operand_text = text[match.end() :]
    operand_text = re.sub(r"^\s*(?:the\s+)?", "", operand_text.strip(), flags=re.I)
    parts = re.split(r"\s+(?:and|or)\s+", operand_text, maxsplit=1, flags=re.I)
    if len(parts) < 2:
        return None
    return parts[0].strip(" ,.;:"), parts[1].strip(" ,.;:")


def _source_limit_pair(
    *,
    segment_text: str,
    amount_text: str,
    cap_text: str,
    has_standalone_reduction: bool = False,
) -> _SourceLimitPair | None:
    amount_tokens = _limit_relevance_tokens(amount_text)
    amount_phrases = _limit_relevance_phrases(amount_text)
    cap_tokens = _limit_relevance_tokens(cap_text) - amount_tokens
    cap_phrases = {
        phrase
        for phrase in _limit_relevance_phrases(cap_text)
        if not _phrase_is_amount_side(
            phrase,
            amount_words=amount_tokens,
            amount_phrases=amount_phrases,
        )
    }
    if (not amount_tokens and not amount_phrases) or (
        not cap_tokens and not cap_phrases
    ):
        return None
    return _SourceLimitPair(
        tokens=frozenset(_limit_relevance_tokens(segment_text)),
        phrases=frozenset(_limit_relevance_phrases(segment_text)),
        amount_tokens=frozenset(amount_tokens),
        amount_phrases=frozenset(amount_phrases),
        cap_tokens=frozenset(cap_tokens),
        cap_phrases=frozenset(cap_phrases),
        has_standalone_reduction=has_standalone_reduction,
    )


def _operand_matches_amount_side(
    operand_text: str,
    *,
    amount_tokens: set[str],
    amount_phrases: set[str],
) -> bool:
    if not amount_tokens and not amount_phrases:
        return False
    operand_tokens = _limit_relevance_tokens(operand_text)
    operand_phrases = _limit_relevance_phrases(operand_text)
    return bool(
        operand_tokens & amount_tokens
        or operand_phrases & amount_phrases
        or any(
            _phrase_is_amount_side(
                phrase,
                amount_words=amount_tokens,
                amount_phrases=amount_phrases,
            )
            for phrase in operand_phrases
        )
    )


def _source_limit_pairs_from_segment(segment: str) -> list[_SourceLimitPair]:
    match = _LIMITATION_PHRASE_PATTERN.search(segment)
    if match is None:
        return []
    has_standalone_reduction = bool(
        re.fullmatch(r"reduced\s+by", match.group(0), flags=re.I)
    )
    amount_side_text = _source_limit_amount_side_text(segment)
    operands = _source_limit_lesser_greater_operands(
        segment[match.end() :],
        already_after_phrase=bool(
            re.fullmatch(r"(?:lesser|greater)\s+of", match.group(0), flags=re.I)
        ),
    )
    candidate_texts: list[tuple[str, str]]
    if operands is None:
        candidate_texts = [(amount_side_text, _source_limit_cap_side_text(segment))]
    else:
        left_operand, right_operand = operands
        amount_side_tokens = _limit_relevance_tokens(amount_side_text)
        amount_side_phrases = _limit_relevance_phrases(amount_side_text)
        left_matches_amount = _operand_matches_amount_side(
            left_operand,
            amount_tokens=amount_side_tokens,
            amount_phrases=amount_side_phrases,
        )
        right_matches_amount = _operand_matches_amount_side(
            right_operand,
            amount_tokens=amount_side_tokens,
            amount_phrases=amount_side_phrases,
        )
        if left_matches_amount and not right_matches_amount:
            candidate_texts = [(f"{amount_side_text} {left_operand}", right_operand)]
        elif right_matches_amount and not left_matches_amount:
            candidate_texts = [(f"{amount_side_text} {right_operand}", left_operand)]
        else:
            candidate_texts = [
                (f"{amount_side_text} {left_operand}", right_operand),
                (f"{amount_side_text} {right_operand}", left_operand),
            ]
    pairs: list[_SourceLimitPair] = []
    seen: set[tuple[frozenset[str], frozenset[str], frozenset[str], frozenset[str]]] = (
        set()
    )
    for amount_text, cap_text in candidate_texts:
        pair = _source_limit_pair(
            segment_text=segment,
            amount_text=amount_text,
            cap_text=cap_text,
            has_standalone_reduction=has_standalone_reduction,
        )
        if pair is None:
            continue
        key = (
            pair.amount_tokens,
            pair.amount_phrases,
            pair.cap_tokens,
            pair.cap_phrases,
        )
        if key in seen:
            continue
        seen.add(key)
        pairs.append(pair)
    return pairs


def _source_filter_allows_negated_identifiers(
    phrase_text: str,
    filter_side_text: str,
) -> bool:
    return bool(
        _FILTER_NEGATION_SOURCE_PATTERN.search(f"{phrase_text} {filter_side_text}")
    )


def _source_limit_relevance(source_text: str) -> _SourceLimitRelevance:
    tokens: set[str] = set()
    phrases: set[str] = set()
    amount_tokens: set[str] = set()
    amount_phrases: set[str] = set()
    cap_tokens: set[str] = set()
    cap_phrases: set[str] = set()
    filter_tokens: set[str] = set()
    filter_phrases: set[str] = set()
    limit_pairs: list[_SourceLimitPair] = []
    has_standalone_reduction = False
    filter_allows_negated_identifiers = False
    for segment, _terms in _source_lower_entity_limitation_records(source_text):
        tokens.update(_limit_relevance_tokens(segment))
        phrases.update(_limit_relevance_phrases(segment))
        limitation_match = _LIMITATION_PHRASE_PATTERN.search(segment)
        filter_match = _FILTER_LIMITATION_PHRASE_PATTERN.search(segment)
        if filter_match is not None and limitation_match is None:
            amount_side_text = segment[: filter_match.start()]
            amount_tokens.update(_limit_relevance_tokens(amount_side_text))
            amount_phrases.update(_limit_relevance_phrases(amount_side_text))
            filter_side_text = segment[filter_match.end() :]
            filter_tokens.update(_limit_relevance_tokens(filter_side_text))
            filter_phrases.update(_limit_relevance_phrases(filter_side_text))
            filter_allows_negated_identifiers = (
                filter_allows_negated_identifiers
                or _source_filter_allows_negated_identifiers(
                    filter_match.group(0),
                    filter_side_text,
                )
            )
            continue
        segment_pairs = _source_limit_pairs_from_segment(segment)
        limit_pairs.extend(segment_pairs)
        for pair in segment_pairs:
            amount_tokens.update(pair.amount_tokens)
            amount_phrases.update(pair.amount_phrases)
            cap_tokens.update(pair.cap_tokens)
            cap_phrases.update(pair.cap_phrases)
            has_standalone_reduction = (
                has_standalone_reduction or pair.has_standalone_reduction
            )
    return _SourceLimitRelevance(
        tokens=frozenset(tokens),
        phrases=frozenset(phrases),
        amount_tokens=frozenset(amount_tokens),
        amount_phrases=frozenset(amount_phrases),
        cap_tokens=frozenset(cap_tokens),
        cap_phrases=frozenset(cap_phrases),
        filter_tokens=frozenset(filter_tokens),
        filter_phrases=frozenset(filter_phrases),
        has_standalone_reduction=has_standalone_reduction,
        filter_allows_negated_identifiers=filter_allows_negated_identifiers,
        limit_pairs=tuple(limit_pairs),
    )


def _source_limit_cap_side_text(segment: str) -> str:
    match = _LIMITATION_PHRASE_PATTERN.search(segment)
    if match is None:
        return segment
    tail = segment[match.end() :]
    operands = _source_limit_lesser_greater_operands(
        tail,
        already_after_phrase=bool(
            re.fullmatch(r"(?:lesser|greater)\s+of", match.group(0), flags=re.I)
        ),
    )
    return operands[1] if operands is not None else tail


def _source_limit_amount_side_text(segment: str) -> str:
    match = _LIMITATION_PHRASE_PATTERN.search(segment)
    return segment[: match.start()] if match else ""


def _source_limit_lesser_greater_amount_side_text(segment: str) -> str:
    match = _LIMITATION_PHRASE_PATTERN.search(segment)
    if match is None:
        return ""
    operands = _source_limit_lesser_greater_operands(
        segment[match.end() :],
        already_after_phrase=bool(
            re.fullmatch(r"(?:lesser|greater)\s+of", match.group(0), flags=re.I)
        ),
    )
    return operands[0] if operands is not None else ""


def _text_matches_source_cap_relevance(
    text: str,
    source_limit_relevance: _SourceLimitRelevance | _SourceLimitPair,
) -> bool:
    if not source_limit_relevance.cap_tokens and not source_limit_relevance.cap_phrases:
        return False
    identifiers = {
        raw_word.lower() for raw_word in _LIMIT_RELEVANCE_WORD_PATTERN.findall(text)
    }
    if any(
        _identifier_matches_source_cap_phrase(
            identifier,
            source_limit_relevance.cap_phrases,
        )
        for identifier in identifiers
        if "_" in identifier
    ):
        return True
    if any("_" in identifier for identifier in identifiers):
        return False
    return bool(_limit_relevance_tokens(text) & source_limit_relevance.cap_tokens)


def _text_matches_source_amount_relevance(
    text: str,
    source_limit_relevance: _SourceLimitRelevance | _SourceLimitPair,
) -> bool:
    if (
        not source_limit_relevance.amount_tokens
        and not source_limit_relevance.amount_phrases
    ):
        return False
    identifiers = {
        raw_word.lower() for raw_word in _LIMIT_RELEVANCE_WORD_PATTERN.findall(text)
    }
    if any(
        identifier in source_limit_relevance.amount_phrases
        for identifier in identifiers
        if "_" in identifier
    ):
        return True
    return bool(_limit_relevance_tokens(text) & source_limit_relevance.amount_tokens)


def _text_matches_source_filter_relevance(
    text: str,
    source_limit_relevance: _SourceLimitRelevance,
) -> bool:
    if (
        not source_limit_relevance.filter_tokens
        and not source_limit_relevance.filter_phrases
    ):
        return False
    if (
        _expression_has_negated_filter_identifier(text)
        and not source_limit_relevance.filter_allows_negated_identifiers
    ):
        return False
    identifiers = {
        raw_word.lower() for raw_word in _LIMIT_RELEVANCE_WORD_PATTERN.findall(text)
    }
    if any(
        _identifier_matches_source_filter_phrase(
            identifier,
            source_limit_relevance.filter_phrases,
        )
        for identifier in identifiers
        if "_" in identifier
    ):
        return True
    return bool(_limit_relevance_tokens(text) & source_limit_relevance.filter_tokens)


def _identifier_has_negated_filter(identifier: str) -> bool:
    return bool(set(identifier.lower().split("_")) & _FILTER_NEGATION_IDENTIFIER_WORDS)


def _expression_has_negated_filter_identifier(expression: str) -> bool:
    if _NEGATED_IDENTIFIER_PATTERN.search(expression):
        return True
    return any(
        _identifier_has_negated_filter(raw_word)
        for raw_word in _LIMIT_RELEVANCE_WORD_PATTERN.findall(expression)
    )


def _identifier_matches_source_cap_phrase(
    identifier: str,
    cap_phrases: frozenset[str],
) -> bool:
    if identifier in cap_phrases:
        return True
    for suffix in (
        "_amount",
        "_cap",
        "_ceiling",
        "_limit",
        "_limitation",
        "_maximum",
        "_value",
    ):
        if identifier.endswith(suffix) and identifier[: -len(suffix)] in cap_phrases:
            return True
    return False


def _identifier_matches_source_filter_phrase(
    identifier: str,
    filter_phrases: frozenset[str],
) -> bool:
    if identifier in filter_phrases:
        return True
    identifier_words = [
        word
        for word in identifier.split("_")
        if word and word not in _LIMIT_RELEVANCE_PHRASE_STOPWORDS
    ]
    normalized_identifier = "_".join(identifier_words)
    return any(
        phrase in normalized_identifier
        or set(phrase.split("_")) <= set(identifier_words)
        for phrase in filter_phrases
    )


def _aggregate_tail_arguments(tail: str) -> list[str]:
    tail_after_relation = re.sub(r"^\s*,\s*", "", tail, count=1)
    return [
        argument.strip()
        for argument in _split_top_level_call_arguments(tail_after_relation)
        if argument.strip()
    ]


def _aggregate_amount_argument(function_name: str, tail: str) -> str:
    if function_name.lower() == "sum_where":
        parts = _aggregate_tail_arguments(tail)
        return parts[0] if parts else ""
    if function_name.lower() == "sum":
        field_match = re.match(r"\s*\.\s*([A-Za-z_][A-Za-z0-9_]*)", tail)
        return field_match.group(1) if field_match else ""
    return ""


def _aggregate_predicate_argument(function_name: str, tail: str) -> str:
    if function_name.lower() != "sum_where":
        return ""
    parts = _aggregate_tail_arguments(tail)
    return parts[1] if len(parts) >= 2 else ""


def _aggregate_uses_pre_limited_amount(
    function_name: str,
    tail: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
) -> bool:
    predicate_arg = _aggregate_predicate_argument(function_name, tail)
    if predicate_arg and _expression_or_referenced_helpers_match_source_filter(
        predicate_arg,
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=set(),
    ):
        return True
    amount_arg = _aggregate_amount_argument(function_name, tail)
    helper_formula = formula_by_name.get(amount_arg)
    if helper_formula is None:
        return False
    return _formula_or_referenced_helpers_implement_entity_limit(
        helper_formula,
        formula_by_name=formula_by_name,
        current_name=amount_arg,
        source_limit_relevance=source_limit_relevance,
    )


def _aggregate_amount_matches_source_limit(
    function_name: str,
    tail: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
) -> bool:
    amount_arg = _aggregate_amount_argument(function_name, tail)
    if _text_matches_source_amount_relevance(amount_arg, source_limit_relevance):
        return True
    helper_formula = formula_by_name.get(amount_arg)
    return bool(
        helper_formula is not None
        and _text_matches_source_amount_relevance(
            helper_formula,
            source_limit_relevance,
        )
    )


def _uncapped_broad_relation_aggregates_in_formula(
    formula: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
    require_source_amount_match: bool = False,
) -> set[str]:
    relations: set[str] = set()
    for match in _RELATION_AMOUNT_AGGREGATE_CALL_PATTERN.finditer(formula):
        relation_name = match.group("relation")
        if not _BROAD_STRUCTURAL_RELATION_PATTERN.search(relation_name):
            continue
        function_name = match.group("function")
        tail = match.group("tail") or ""
        if _aggregate_uses_pre_limited_amount(
            function_name,
            tail,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
        ):
            continue
        if require_source_amount_match and not _text_matches_source_amount_relevance(
            _aggregate_amount_argument(function_name, tail),
            source_limit_relevance,
        ):
            if not _aggregate_amount_matches_source_limit(
                function_name,
                tail,
                formula_by_name=formula_by_name,
                source_limit_relevance=source_limit_relevance,
            ):
                continue
        relations.add(relation_name)
    return relations


def _aggregate_relations_referenced_by_formula(
    formula: str,
    *,
    aggregate_relations_by_name: dict[str, set[str]],
    formula_by_name: dict[str, str],
    seen: set[str] | None = None,
) -> set[str]:
    relations: set[str] = set()
    visited = set(seen or set())
    for identifier in _formula_local_identifiers(formula):
        if identifier in visited:
            continue
        if identifier in aggregate_relations_by_name:
            relations.update(aggregate_relations_by_name[identifier])
        helper_formula = formula_by_name.get(identifier)
        if helper_formula is None:
            continue
        visited.add(identifier)
        relations.update(
            _aggregate_relations_referenced_by_formula(
                helper_formula,
                aggregate_relations_by_name=aggregate_relations_by_name,
                formula_by_name=formula_by_name,
                seen=visited,
            )
        )
    return relations


def _formula_limiting_expressions(formula: str) -> list[str]:
    expressions: list[str] = []
    for match in _LIMITING_FUNCTION_CALL_PATTERN.finditer(formula):
        start = match.start()
        open_index = match.end() - 1
        depth = 0
        for index in range(open_index, len(formula)):
            char = formula[index]
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0:
                    expressions.append(formula[start : index + 1])
                    break
    for match in _LIMITING_CONDITIONAL_PATTERN.finditer(formula):
        condition = match.group("condition")
        if _FORMULA_LIMIT_COMPARISON_PATTERN.search(condition):
            expressions.append(condition)
    return expressions


def _formula_min_limit_side_expressions(formula: str) -> list[str]:
    expressions: list[str] = []
    for arguments in _formula_min_argument_sets(formula):
        expressions.extend(arguments)
    return expressions


def _formula_min_argument_sets(formula: str) -> list[list[str]]:
    argument_sets: list[list[str]] = []
    for match in _MIN_FUNCTION_CALL_PATTERN.finditer(formula):
        open_index = match.end() - 1
        depth = 0
        for index in range(open_index, len(formula)):
            char = formula[index]
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0:
                    arguments = _split_top_level_call_arguments(
                        formula[open_index + 1 : index]
                    )
                    argument_sets.append([argument.strip() for argument in arguments])
                    break
    return argument_sets


def _formula_has_source_relevant_comparison(
    formula: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance | _SourceLimitPair,
    seen: set[str],
) -> bool:
    return bool(
        _FORMULA_LIMIT_COMPARISON_PATTERN.search(formula)
        and _expression_or_referenced_helpers_match_source_amount(
            formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
        and _expression_or_referenced_helpers_match_source_cap(
            formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
    )


def _clean_comparison_operand(operand: str) -> str:
    return re.sub(
        r"^\s*(?:if|elif|return)\s+",
        "",
        operand.strip().strip("() "),
        flags=re.I,
    ).strip()


def _source_relevant_comparison_direction(
    expression: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance | _SourceLimitPair,
    seen: set[str],
) -> str | None:
    for match in _SOURCE_RELEVANT_COMPARISON_PATTERN.finditer(expression):
        left = _clean_comparison_operand(match.group("left"))
        right = _clean_comparison_operand(match.group("right"))
        op = match.group("op")
        left_amount = _expression_or_referenced_helpers_match_source_amount(
            left,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
        right_amount = _expression_or_referenced_helpers_match_source_amount(
            right,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
        left_cap = _expression_or_referenced_helpers_match_source_cap(
            left,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
        right_cap = _expression_or_referenced_helpers_match_source_cap(
            right,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
        if left_amount and right_cap:
            return "amount_gt_cap" if op in {">", ">="} else "amount_lt_cap"
        if left_cap and right_amount:
            return "amount_gt_cap" if op in {"<", "<="} else "amount_lt_cap"

    for match in _NEGATED_IDENTIFIER_PATTERN.finditer(expression):
        identifier = match.group(1)
        if identifier in seen:
            continue
        helper_formula = formula_by_name.get(identifier)
        if helper_formula is None:
            continue
        visited = set(seen)
        visited.add(identifier)
        direction = _source_relevant_comparison_direction(
            helper_formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        )
        if direction == "amount_gt_cap":
            return "amount_lt_cap"
        if direction == "amount_lt_cap":
            return "amount_gt_cap"

    for identifier in _formula_local_identifiers(expression):
        if identifier in seen:
            continue
        helper_formula = formula_by_name.get(identifier)
        if helper_formula is None:
            continue
        visited = set(seen)
        visited.add(identifier)
        direction = _source_relevant_comparison_direction(
            helper_formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        )
        if direction is not None:
            return direction
    return None


def _expression_or_referenced_helpers_match_source_filter(
    expression: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
    seen: set[str],
) -> bool:
    if _text_matches_source_filter_relevance(expression, source_limit_relevance):
        return True
    for identifier in _formula_local_identifiers(expression):
        if identifier in seen:
            continue
        helper_formula = formula_by_name.get(identifier)
        if helper_formula is None:
            continue
        visited = set(seen)
        visited.add(identifier)
        if _expression_or_referenced_helpers_match_source_filter(
            helper_formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        ):
            return True
    return False


def _expression_or_referenced_helpers_match_source_amount(
    expression: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance | _SourceLimitPair,
    seen: set[str],
) -> bool:
    if _text_matches_source_amount_relevance(expression, source_limit_relevance):
        return True
    for identifier in _formula_local_identifiers(expression):
        if identifier in seen:
            continue
        helper_formula = formula_by_name.get(identifier)
        if helper_formula is None:
            continue
        visited = set(seen)
        visited.add(identifier)
        if _expression_or_referenced_helpers_match_source_amount(
            helper_formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        ):
            return True
    return False


def _expression_or_referenced_helpers_match_source_cap(
    expression: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance | _SourceLimitPair,
    seen: set[str],
) -> bool:
    if _text_matches_source_cap_relevance(expression, source_limit_relevance):
        return True
    for identifier in _formula_local_identifiers(expression):
        if identifier in seen:
            continue
        helper_formula = formula_by_name.get(identifier)
        if helper_formula is None:
            continue
        visited = set(seen)
        visited.add(identifier)
        if _expression_or_referenced_helpers_match_source_cap(
            helper_formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        ):
            return True
    return False


def _conditional_branch_texts(
    formula: str, condition_match: re.Match[str]
) -> list[str]:
    body = formula[condition_match.end() :]
    else_match = re.search(r"(?m)^\s*else\s*:\s*", body)
    if else_match is None:
        return [body.strip()]
    return [
        body[: else_match.start()].strip(),
        body[else_match.end() :].strip(),
    ]


def _conditional_implements_source_relevant_limit(
    formula: str,
    condition_match: re.Match[str],
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
    seen: set[str],
) -> bool:
    branch_texts = _conditional_branch_texts(formula, condition_match)
    if len(branch_texts) < 2:
        return False
    then_branch, else_branch = branch_texts[0], branch_texts[1]
    direction = _source_relevant_comparison_direction(
        condition_match.group("condition"),
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=seen,
    )
    if direction is None:
        return False
    then_matches_amount = _expression_or_referenced_helpers_match_source_amount(
        then_branch,
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=seen,
    )
    else_matches_amount = _expression_or_referenced_helpers_match_source_amount(
        else_branch,
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=seen,
    )
    then_matches_cap = _expression_or_referenced_helpers_match_source_cap(
        then_branch,
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=seen,
    )
    else_matches_cap = _expression_or_referenced_helpers_match_source_cap(
        else_branch,
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=seen,
    )
    if direction == "amount_gt_cap":
        return then_matches_cap and else_matches_amount
    return then_matches_amount and else_matches_cap


def _min_arguments_implement_source_limit(
    arguments: list[str],
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
    seen: set[str],
) -> bool:
    amount_indexes = {
        index
        for index, argument in enumerate(arguments)
        if _expression_or_referenced_helpers_match_source_amount(
            argument,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
    }
    cap_indexes = {
        index
        for index, argument in enumerate(arguments)
        if _expression_or_referenced_helpers_match_source_cap(
            argument,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
    }
    return any(
        amount_index != cap_index
        for amount_index in amount_indexes
        for cap_index in cap_indexes
    )


def _formula_has_source_relevant_reduction(
    formula: str,
    *,
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
    seen: set[str],
) -> bool:
    return bool(
        source_limit_relevance.has_standalone_reduction
        and "-" in formula
        and _expression_or_referenced_helpers_match_source_amount(
            formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
        and _expression_or_referenced_helpers_match_source_cap(
            formula,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=seen,
        )
    )


def _formula_or_referenced_helpers_implement_entity_limit(
    formula: str,
    *,
    formula_by_name: dict[str, str],
    current_name: str,
    source_limit_relevance: _SourceLimitRelevance,
    seen: set[str] | None = None,
) -> bool:
    visited = set(seen or set())
    visited.add(current_name)
    for arguments in _formula_min_argument_sets(formula):
        if _min_arguments_implement_source_limit(
            arguments,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        ):
            return True
    for match in _LIMITING_CONDITIONAL_PATTERN.finditer(formula):
        if _conditional_implements_source_relevant_limit(
            formula,
            match,
            formula_by_name=formula_by_name,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        ):
            return True
    if _formula_has_source_relevant_reduction(
        formula,
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=visited,
    ):
        return True
    if not _LIMITING_CONDITIONAL_PATTERN.search(
        formula
    ) and _formula_has_source_relevant_comparison(
        formula,
        formula_by_name=formula_by_name,
        source_limit_relevance=source_limit_relevance,
        seen=visited,
    ):
        return True
    for identifier in _formula_local_identifiers(formula):
        if identifier in visited or identifier not in formula_by_name:
            continue
        if _formula_or_referenced_helpers_implement_entity_limit(
            formula_by_name[identifier],
            formula_by_name=formula_by_name,
            current_name=identifier,
            source_limit_relevance=source_limit_relevance,
            seen=visited,
        ):
            return True
    return False


def _limited_aggregate_relations_in_formula(
    formula: str,
    *,
    aggregate_relations_by_name: dict[str, set[str]],
    formula_by_name: dict[str, str],
    source_limit_relevance: _SourceLimitRelevance,
) -> set[str]:
    relations: set[str] = set()
    for expression in _formula_limiting_expressions(formula):
        relations.update(
            _uncapped_broad_relation_aggregates_in_formula(
                expression,
                formula_by_name=formula_by_name,
                source_limit_relevance=source_limit_relevance,
                require_source_amount_match=True,
            )
        )
        relations.update(
            _aggregate_relations_referenced_by_formula(
                expression,
                aggregate_relations_by_name=aggregate_relations_by_name,
                formula_by_name=formula_by_name,
            )
        )
    return relations


def _source_lower_entity_limitation_terms(source_text: str) -> set[str]:
    terms: set[str] = set()
    for _segment, segment_terms in _source_lower_entity_limitation_records(source_text):
        terms.update(segment_terms)
    return terms


def _source_lower_entity_limitation_records(
    source_text: str,
) -> list[tuple[str, set[str]]]:
    records: list[tuple[str, set[str]]] = []
    previous_lower_terms: set[str] = set()
    previous_context_segment = ""
    for raw_segment in _SOURCE_LIMIT_SEGMENT_SPLIT_PATTERN.split(source_text):
        for segment in _source_limit_clauses(raw_segment):
            if not segment.strip():
                continue
            segment_lower_terms = _source_lower_entity_terms_before_limitation(segment)
            if not _SOURCE_LIMITATION_PATTERN.search(segment):
                if _LOWER_ENTITY_CONTEXTUAL_AMOUNT_PATTERN.search(segment):
                    previous_lower_terms = segment_lower_terms
                    previous_context_segment = segment
                continue
            if _source_limitation_subject_is_aggregate_unit(segment):
                previous_lower_terms = set()
                previous_context_segment = ""
                continue
            if segment_lower_terms:
                records.append((segment, segment_lower_terms))
                previous_lower_terms = segment_lower_terms
                previous_context_segment = segment
                continue
            if previous_lower_terms and _ANAPHORIC_AMOUNT_PATTERN.search(segment):
                records.append(
                    (
                        f"{previous_context_segment} {segment}".strip(),
                        previous_lower_terms,
                    )
                )
                continue
            later_terms = {
                match.group(0).lower()
                for match in _LOWER_ENTITY_LIMITED_SOURCE_PATTERN.finditer(segment)
            }
            if later_terms:
                records.append((segment, later_terms))
    return records


def _source_limit_clauses(segment: str) -> list[str]:
    clauses = [
        clause.strip(" ,;")
        for clause in _SOURCE_LIMIT_CLAUSE_SPLIT_PATTERN.split(segment)
    ]
    return [clause for clause in clauses if clause]


def _source_lower_entity_terms_before_limitation(segment: str) -> set[str]:
    match = _LIMITATION_PHRASE_PATTERN.search(segment)
    search_text = segment[: match.start()] if match else segment
    return {
        term_match.group(0).lower()
        for term_match in _LOWER_ENTITY_LIMITED_SOURCE_PATTERN.finditer(search_text)
    }


def _source_limitation_subject_is_aggregate_unit(segment: str) -> bool:
    match = _LIMITATION_PHRASE_PATTERN.search(segment)
    if match is None:
        return False
    subject = segment[max(0, match.start() - 120) : match.start()]
    return bool(_AGGREGATE_UNIT_SUBJECT_PATTERN.search(subject))


def find_relation_aggregate_syntax_issues(content: str) -> list[str]:
    """Reject relation aggregation forms that the runtime does not support."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    relation_names = _rulespec_data_relation_names(payload)
    executable_names = _rulespec_executable_names_from_payload(payload)
    issues: list[str] = []
    for name, _kind, formula in _rulespec_rule_formulas(payload):
        for match in _UNSUPPORTED_RELATION_SUM_PATTERN.finditer(formula):
            relation_name = match.group(1)
            if (
                relation_name not in relation_names
                and not _BROAD_STRUCTURAL_RELATION_PATTERN.search(relation_name)
            ):
                continue
            issues.append(
                "Unsupported relation aggregate syntax: "
                f"`{name}` uses `sum({relation_name}, ...)`. RuleSpec supports "
                "`sum(relation.amount_fact)` and "
                "`sum_where(relation, amount_fact_or_derived, predicate_fact)`; "
                "move arithmetic into named facts/derived rules before aggregating."
            )
        for match in _RELATION_FIELD_SUM_PATTERN.finditer(formula):
            relation_name = match.group(1)
            field_name = match.group(2)
            if (
                relation_name not in relation_names
                and not _BROAD_STRUCTURAL_RELATION_PATTERN.search(relation_name)
            ):
                continue
            if field_name not in executable_names:
                continue
            issues.append(
                "Unsupported relation aggregate syntax: "
                f"`{name}` uses `sum({relation_name}.{field_name})`, but "
                f"`{field_name}` is a local executable output. RuleSpec treats "
                "`sum(relation.amount_fact)` as summing a raw relation-row fact. "
                "Use "
                f"`sum_where({relation_name}, {field_name}, predicate_fact)` "
                "for per-related-entity derived outputs, or remove the local "
                "executable rule and model the value as a direct relation-row "
                "fact only if the source defines that row fact directly."
            )
    return issues


def find_role_limited_relation_scope_issues(content: str) -> list[str]:
    """Flag broad container relations used where the source names narrower roles."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    if not source_text or not _ROLE_LIMITED_SOURCE_PATTERN.search(source_text):
        return []

    relation_names = _rulespec_data_relation_names(payload)
    broad_relations = {
        relation_name
        for relation_name in relation_names
        if _BROAD_STRUCTURAL_RELATION_PATTERN.search(relation_name)
    }
    if not broad_relations:
        return []

    role_terms = sorted(
        {
            match.group(0).lower()
            for match in _ROLE_LIMITED_SOURCE_PATTERN.finditer(source_text)
        }
    )
    role_detail = ", ".join(role_terms[:4])
    issues: list[str] = []
    reported: set[tuple[str, str]] = set()
    for name, kind, formula in _rulespec_rule_formulas(payload):
        if kind != "derived":
            continue
        for match in _RELATION_AGGREGATE_PATTERN.finditer(formula):
            relation_name = match.group(1)
            if relation_name not in broad_relations:
                continue
            if _source_supports_structural_relation_container(
                source_text, relation_name
            ):
                continue
            key = (name, relation_name)
            if key in reported:
                continue
            reported.add(key)
            issues.append(
                "Role-limited relation scope: "
                f"`{name}` aggregates `{relation_name}`, but the source text "
                f"states narrower legal role(s) ({role_detail}). Define or use "
                "a relation/fact scoped to the exact roles counted by the source; "
                "do not count every member of a broader container unless the "
                "source says every member counts."
            )
    return issues


def find_entity_limited_aggregation_order_issues(content: str) -> list[str]:
    """Flag lower-entity caps applied after aggregating a broad relation."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    source_entity_terms = (
        _source_lower_entity_limitation_terms(source_text) if source_text else set()
    )
    source_limit_relevance = (
        _source_limit_relevance(source_text) if source_text else None
    )
    if (
        not source_text
        or not _SOURCE_LIMITATION_PATTERN.search(source_text)
        or not source_entity_terms
        or source_limit_relevance is None
    ):
        return []

    formula_records = _rulespec_rule_formula_records(payload)
    formula_by_name = {
        name: formula
        for name, kind, formula, _source in formula_records
        if kind == "derived"
    }
    aggregate_relations_by_name = {
        name: relations
        for name, formula in formula_by_name.items()
        if (
            relations := _uncapped_broad_relation_aggregates_in_formula(
                formula,
                formula_by_name=formula_by_name,
                source_limit_relevance=source_limit_relevance,
                require_source_amount_match=True,
            )
        )
    }
    if not aggregate_relations_by_name:
        return []

    dtype_by_name = _rulespec_rule_dtype_by_name(payload)
    entity_detail = ", ".join(sorted(source_entity_terms)[:4])
    issues: list[str] = []
    reported: set[tuple[str, str]] = set()
    for name, kind, formula, rule_source in formula_records:
        if kind != "derived":
            continue
        if dtype_by_name.get(name) in {"judgment", "boolean", "bool", "count"}:
            continue
        scoped_source_text = _source_text_for_rule_source(source_text, rule_source)
        scoped_entity_terms = _source_lower_entity_limitation_terms(scoped_source_text)
        if not _SOURCE_LIMITATION_PATTERN.search(scoped_source_text):
            continue
        if not scoped_entity_terms:
            continue
        scoped_limit_relevance = _source_limit_relevance(scoped_source_text)
        relations = _limited_aggregate_relations_in_formula(
            formula,
            aggregate_relations_by_name=aggregate_relations_by_name,
            formula_by_name=formula_by_name,
            source_limit_relevance=scoped_limit_relevance,
        )
        relations.update(
            _uncapped_broad_relation_aggregates_in_formula(
                formula,
                formula_by_name=formula_by_name,
                source_limit_relevance=scoped_limit_relevance,
                require_source_amount_match=True,
            )
        )
        scoped_entity_detail = ", ".join(sorted(scoped_entity_terms)[:4])
        for relation_name in sorted(relations):
            key = (name, relation_name)
            if key in reported:
                continue
            reported.add(key)
            issues.append(
                "Entity-limited aggregation order: "
                f"`{name}` applies a limitation/cap/reduction to an aggregate "
                f"over `{relation_name}`, while the source text states "
                "lower-entity legal subject(s) "
                f"({scoped_entity_detail or entity_detail}). Apply the "
                "limit at the source-stated lower entity first, then aggregate; "
                "do not aggregate before capping unless the source says the cap "
                "applies to the aggregate unit."
            )
    return issues


def find_source_limitation_application_issues(content: str) -> list[str]:
    """Flag final amount formulas that ignore a same-source cap or limitation."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    if not source_text or not _SOURCE_LIMITATION_PATTERN.search(source_text):
        return []

    formula_records = _rulespec_rule_formula_records(payload)
    dtype_by_name = _rulespec_rule_dtype_by_name(payload)
    formula_by_name = {
        name: formula
        for name, kind, formula, _source in formula_records
        if kind == "derived"
    }
    issues: list[str] = []
    for name, kind, formula, rule_source in formula_records:
        if kind != "derived":
            continue
        if dtype_by_name.get(name) in {"judgment", "boolean", "bool"}:
            continue
        if not _FINAL_AMOUNT_NAME_PATTERN.search(name):
            continue
        scoped_source_text = _source_text_for_rule_source(source_text, rule_source)
        if not _SOURCE_LIMITATION_PATTERN.search(scoped_source_text):
            continue
        limitation_subject_slugs = _source_limitation_subject_slugs(scoped_source_text)
        candidate_text = f"{name} {formula}".lower()
        if limitation_subject_slugs and not any(
            slug in candidate_text for slug in limitation_subject_slugs
        ):
            continue
        if _formula_implements_limitation(formula, scoped_source_text):
            continue
        if _formula_or_referenced_helpers_implement_limitation(
            formula,
            formula_by_name=formula_by_name,
            current_name=name,
            source_text=scoped_source_text,
        ):
            continue
        if _formula_is_referenced_by_limited_downstream_formula(
            name,
            formula_by_name=formula_by_name,
            source_text=scoped_source_text,
        ):
            continue
        if _formula_aggregates_limited_local_amount(
            formula,
            formula_by_name=formula_by_name,
            current_name=name,
            source_text=scoped_source_text,
        ):
            continue
        issues.append(
            "Source limitation not applied: "
            f"`{name}` is a final amount-style output, but the same source text "
            "contains a limitation, cap, exception, or not-exceed rule that the "
            "formula does not reference. Import or encode the limiting rule and "
            "compose it into the final exported amount."
        )
    return issues


_PARTIAL_EXTENT_SOURCE_PATTERN = re.compile(r"\bto\s+the\s+extent\b", re.IGNORECASE)
_PARTIAL_EXTENT_ZEROING_PATTERN = re.compile(
    r"\bif\s+(?P<condition>[^:\n]+?)\s*:\s*0(?:\.0+)?\s+else\s*:\s*(?P<else>[^\n]+)",
    flags=re.IGNORECASE,
)
_PARTIAL_EXTENT_EXEMPTION_CONDITION_PATTERN = re.compile(
    r"(?:exempt|exemption|excluded|exclusion|disallow|disallowed)",
    flags=re.IGNORECASE,
)


def find_partial_extent_zeroing_issues(content: str) -> list[str]:
    """Reject all-or-nothing zeroing for source-stated partial extent rules."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    if not source_text or not _PARTIAL_EXTENT_SOURCE_PATTERN.search(source_text):
        return []

    issues: list[str] = []
    for name, kind, formula in _rulespec_rule_formulas(payload):
        if kind != "derived":
            continue
        dtype = _rulespec_rule_dtype_by_name(payload).get(name, "")
        if dtype not in {"money", "currency", "decimal", "integer", "number"}:
            continue
        for match in _PARTIAL_EXTENT_ZEROING_PATTERN.finditer(formula):
            condition = match.group("condition")
            if not _PARTIAL_EXTENT_EXEMPTION_CONDITION_PATTERN.search(condition):
                continue
            issues.append(
                "Partial extent exemption collapsed: "
                f"`{name}` returns zero whenever `{condition.strip()}` holds, "
                "but the source uses `to the extent`, which makes the exemption "
                "partial. Subtract or apportion the exempt amount, or mark the "
                "artifact unsupported if the current executable schema cannot "
                "wire the adjusted basis into imported child calculations."
            )
            break
    return issues


_SCOPED_EXCEPTION_CATEGORY_PATTERN = re.compile(
    r"\b(?:does\s+not\s+apply\s+to|shall\s+not\s+apply\s+to|except(?:\s+that)?|other\s+than)\b"
    r"[^.;]{0,180}?\b(?:a|an|any|the)?\s*"
    r"(?:payment|amount|expense|benefit|item|income|compensation|wages?)\s+for\s+"
    r"(?P<category>[a-z0-9][a-z0-9\s'/-]{2,100}?)"
    r"(?:\s+to\s+the\s+extent|\s+which\b|\s+that\b|[,.;]|$)",
    flags=re.IGNORECASE,
)
_SCOPED_EXCEPTION_TOKEN_STOPWORDS = {
    "a",
    "an",
    "and",
    "any",
    "for",
    "in",
    "of",
    "or",
    "the",
    "to",
}
_SCOPED_EXCEPTION_AMOUNT_TOKENS = {
    "amount",
    "amounts",
    "benefit",
    "benefits",
    "compensation",
    "cost",
    "costs",
    "expense",
    "expenses",
    "income",
    "includable",
    "included",
    "includible",
    "payment",
    "payments",
    "value",
    "wage",
    "wages",
}
_SCOPED_EXCEPTION_PREDICATE_TOKENS = {
    "applies",
    "apply",
    "category",
    "condition",
    "eligible",
    "for",
    "is",
    "kind",
    "qualified",
    "qualifies",
    "status",
    "type",
}
_SCOPED_EXCEPTION_PREDICATE_BLOCKING_AMOUNT_TOKENS = _SCOPED_EXCEPTION_AMOUNT_TOKENS - {
    "payment",
    "payments",
}
_SCOPED_EXCEPTION_FOR_PREDICATE_SUBJECT_TOKENS = {
    "item",
    "items",
    "payment",
    "payments",
}
_SCOPED_EXCEPTION_NONPREDICATE_QUANTITY_TOKENS = {
    "base",
    "bases",
    "cap",
    "caps",
    "ceiling",
    "ceilings",
    "count",
    "counts",
    "dollar",
    "dollars",
    "fraction",
    "fractions",
    "limit",
    "limits",
    "number",
    "numbers",
    "percent",
    "percentage",
    "percentages",
    "percents",
    "quantity",
    "quantities",
    "rate",
    "rates",
    "ratio",
    "ratios",
    "share",
    "shares",
    "sum",
    "sums",
    "threshold",
    "thresholds",
    "total",
    "totals",
    "usd",
}
_SCOPED_EXCEPTION_STRONG_PREDICATE_TOKENS = {
    "applies",
    "apply",
    "category",
    "condition",
    "eligible",
    "is",
    "kind",
    "qualifies",
    "status",
    "type",
}


def find_scoped_exception_category_gate_issues(content: str) -> list[str]:
    """Require source-scoped exception amounts to be gated by category predicates."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    formula_records = _rulespec_rule_formula_rule_records(payload)
    formula_by_name = {
        name: formula
        for name, kind, formula, _source, _rule in formula_records
        if kind == "derived" and name
    }
    issues: list[str] = []
    for name, kind, formula, _source, rule in formula_records:
        if kind != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype in {"judgment", "boolean", "bool"}:
            continue
        categories = _rule_scoped_exception_categories(rule)
        if not categories:
            continue
        for category in categories:
            category_tokens = _scoped_exception_category_tokens(category)
            if not category_tokens:
                continue
            if not _formula_or_referenced_helpers_have_ungated_category_amount(
                formula,
                category_tokens=category_tokens,
                formula_by_name=formula_by_name,
                current_name=name,
            ):
                continue
            issues.append(
                "Scoped exception category not gated: "
                f"`{name}` applies the `{category}` exception amount without a "
                "category predicate. Add a source-stated predicate such as "
                f"`*_is_for_{_normalize_identifier(category)}` and gate the "
                "carve-out through that predicate so non-excepted qualifying "
                "items are not reduced by a positive exception amount."
            )
    return issues


_CURRENT_PURPOSE_PLACEHOLDER_PATTERN = re.compile(
    r"(?:^|_)current_(?:purpose|use|context)(?:_|$)|"
    r"(?:^|_)(?:for|under)_current_(?:purpose|use|context)(?:_|$)",
    flags=re.IGNORECASE,
)
_PURPOSE_SPECIFIC_NAME_MARKER_PATTERN = re.compile(
    r"(?:^|_)(?:for|under|with_respect_to|in_case_of)_"
    r"(?:section|subsection|paragraph|clause|tax|rate|purpose|portion|category|use|case)"
    r"(?:_|$)|(?:^|_)hospital_insurance(?:_|$)|(?:^|_)rate_portion(?:_|$)|"
    r"(?:^|_)tier_[0-9]+(?:_|$)",
    flags=re.IGNORECASE,
)
_DEFERRED_PURPOSE_LIMITATION_REASON_PATTERN = re.compile(
    r"\b(?:shall\s+not\s+apply|does\s+not\s+apply|except(?:ion)?|carve-?out|"
    r"purpose-specific|rate\s+portion|for\s+purposes\s+of|for\s+the\s+tax\s+imposed\s+by)\b",
    flags=re.IGNORECASE,
)
_PURPOSE_SPLIT_PATTERN = re.compile(
    r"_(?:for|under|with_respect_to|in_case_of)_(?:section|subsection|paragraph|"
    r"clause|tax|rate|purpose|portion|category|use|case)",
    flags=re.IGNORECASE,
)
_PURPOSE_TOKEN_STOPWORDS = {
    "a",
    "after",
    "and",
    "any",
    "applicable",
    "before",
    "by",
    "current",
    "for",
    "from",
    "in",
    "of",
    "or",
    "purpose",
    "the",
    "to",
    "under",
    "with",
}
_PURPOSE_AMOUNT_TOKENS = {
    "amount",
    "base",
    "benefit",
    "compensation",
    "credit",
    "deduction",
    "earnings",
    "excess",
    "exclusion",
    "inclusion",
    "income",
    "rate",
    "tax",
    "wage",
    "wages",
}


def find_current_purpose_placeholder_issues(content: str) -> list[str]:
    """Reject broad current-purpose placeholders in executable formulas."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    issues: list[str] = []
    for name, kind, formula in _rulespec_rule_formulas(payload):
        if kind != "derived":
            continue
        for identifier in sorted(_formula_local_identifiers(formula)):
            if not _CURRENT_PURPOSE_PLACEHOLDER_PATTERN.search(identifier):
                continue
            issues.append(
                "Current-purpose placeholder input: "
                f"`{name}` references `{identifier}`. Do not make callers supply "
                "a broad current-purpose/current-context base; encode concrete "
                "purpose-specific outputs or defer the affected executable surface."
            )
    return issues


def find_deferred_purpose_specific_limitation_issues(content: str) -> list[str]:
    """Reject generic executable outputs when purpose-specific limitations defer."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    deferred_prefix_tokens: list[tuple[str, set[str]]] = []
    module = payload.get("module")
    deferred_outputs = (
        module.get("deferred_outputs") if isinstance(module, dict) else None
    )
    if not isinstance(deferred_outputs, list):
        return []
    for record in deferred_outputs:
        if not isinstance(record, dict):
            continue
        output = str(record.get("output") or "").strip()
        reason = str(record.get("reason") or "").strip()
        if not output or "#" not in output:
            continue
        symbol = output.rsplit("#", 1)[1]
        if not (
            _PURPOSE_SPECIFIC_NAME_MARKER_PATTERN.search(symbol)
            or _DEFERRED_PURPOSE_LIMITATION_REASON_PATTERN.search(reason)
        ):
            continue
        if not _DEFERRED_PURPOSE_LIMITATION_REASON_PATTERN.search(reason):
            continue
        prefix = _purpose_specific_prefix(symbol)
        tokens = _purpose_surface_tokens(prefix)
        if len(tokens) < 2:
            continue
        deferred_prefix_tokens.append((symbol, tokens))
    if not deferred_prefix_tokens:
        return []

    issues: list[str] = []
    for name, kind, _formula, _source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype in {"judgment", "boolean", "bool"}:
            continue
        if _PURPOSE_SPECIFIC_NAME_MARKER_PATTERN.search(name):
            continue
        rule_tokens = _purpose_surface_tokens(name)
        if not rule_tokens or not rule_tokens.intersection(_PURPOSE_AMOUNT_TOKENS):
            continue
        for deferred_symbol, deferred_tokens in deferred_prefix_tokens:
            overlap = rule_tokens & deferred_tokens
            if len(overlap) < 3:
                continue
            overlap_hint = ", ".join(f"`{token}`" for token in sorted(overlap)[:4])
            issues.append(
                "Generic output with deferred purpose-specific limitation: "
                f"`{name}` overlaps deferred purpose-specific output "
                f"`{deferred_symbol}` on {overlap_hint}. Do not export a broad "
                "amount/base/inclusion/exclusion that applies the non-excepted "
                "rule to every purpose while a source-stated purpose-specific "
                "carve-out is deferred; rename/split into concrete "
                "purpose-specific outputs or defer the generic surface."
            )
            break
    return issues


def find_imported_deferred_branch_composition_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Reject final outputs that compose one child branch while another is deferred."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    deferred_by_imported_symbol: dict[str, list[tuple[str, set[str], set[str]]]] = {}
    for import_item in _extract_import_items_from_content(content):
        import_base, separator, imported_symbol = import_item.partition("#")
        imported_symbol = imported_symbol.strip()
        if not separator or not imported_symbol:
            continue
        import_file = _resolve_rulespec_import_file_static(
            import_base,
            rules_file=rules_file,
            policy_repo_path=policy_repo_path,
        )
        if import_file is None:
            continue
        with contextlib.suppress(OSError, yaml.YAMLError, TypeError, ValueError):
            imported_payload = yaml.safe_load(import_file.read_text()) or {}
            module = (
                imported_payload.get("module")
                if isinstance(imported_payload, dict)
                else None
            )
            deferred_outputs = (
                module.get("deferred_outputs") if isinstance(module, dict) else None
            )
            if not isinstance(deferred_outputs, list):
                continue
            imported_tokens = _purpose_surface_tokens(imported_symbol)
            if len(imported_tokens) < 2:
                continue
            for record in deferred_outputs:
                output = (
                    str(record.get("output") or "").strip()
                    if isinstance(record, dict)
                    else str(record or "").strip()
                )
                if not output or "#" not in output:
                    continue
                deferred_symbol = output.rsplit("#", 1)[1].strip()
                if not deferred_symbol or deferred_symbol == imported_symbol:
                    continue
                deferred_tokens = _purpose_surface_tokens(deferred_symbol)
                if len(imported_tokens & deferred_tokens) < 2:
                    continue
                if not deferred_tokens.intersection(_PURPOSE_AMOUNT_TOKENS):
                    continue
                deferred_by_imported_symbol.setdefault(imported_symbol, []).append(
                    (deferred_symbol, deferred_tokens, imported_tokens)
                )
    if not deferred_by_imported_symbol:
        return []

    issues: list[str] = []
    for name, kind, formula, _source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype in {"judgment", "boolean", "bool"}:
            continue
        if _PURPOSE_SPECIFIC_NAME_MARKER_PATTERN.search(name):
            continue
        identifiers = _formula_local_identifiers(formula)
        rule_tokens = _purpose_surface_tokens(name)
        if len(rule_tokens) < 2:
            continue
        for imported_symbol in sorted(identifiers):
            for (
                deferred_symbol,
                deferred_tokens,
                imported_tokens,
            ) in deferred_by_imported_symbol.get(imported_symbol, []):
                if imported_tokens.issubset(rule_tokens):
                    continue
                overlap = rule_tokens & deferred_tokens
                if len(overlap) < 3:
                    continue
                overlap_hint = ", ".join(f"`{token}`" for token in sorted(overlap)[:4])
                issues.append(
                    "Generic output with deferred purpose-specific limitation: "
                    f"`{name}` composes imported child/sibling output "
                    f"`{imported_symbol}` while overlapping deferred output "
                    f"`{deferred_symbol}` remains unresolved on {overlap_hint}. "
                    "Do not treat the deferred branch as zero; split the "
                    "branch-specific output or defer the generic surface."
                )
                break
            else:
                continue
            break
    return issues


def _purpose_specific_prefix(symbol: str) -> str:
    match = _PURPOSE_SPLIT_PATTERN.search(symbol)
    if match:
        return symbol[: match.start()]
    return symbol


def _purpose_surface_tokens(name: str) -> set[str]:
    tokens = {
        _normalize_purpose_token(token)
        for token in _normalize_identifier(name).split("_")
        if token and token not in _PURPOSE_TOKEN_STOPWORDS
    }
    return {token for token in tokens if token}


def _normalize_purpose_token(token: str) -> str:
    if token in {"exclude", "excluded", "excludes", "excluding"}:
        return "exclusion"
    if token in {"include", "included", "includes", "including", "includable"}:
        return "inclusion"
    if token in {"earning"}:
        return "earnings"
    return token


def _rule_scoped_exception_categories(rule: dict[str, Any]) -> list[str]:
    proof = _rule_proof_payload(rule)
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if not isinstance(atoms, list):
        return []
    categories: list[str] = []
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        if str(atom.get("kind") or "").strip().lower() != "exception":
            continue
        source = atom.get("source")
        excerpt = ""
        if isinstance(source, dict):
            excerpt = str(source.get("excerpt") or "").strip()
        if not excerpt:
            continue
        for match in _SCOPED_EXCEPTION_CATEGORY_PATTERN.finditer(excerpt):
            category = " ".join(match.group("category").split())
            if category and category not in categories:
                categories.append(category)
    return categories


def _scoped_exception_category_tokens(category: str) -> tuple[str, ...]:
    tokens = [
        token
        for token in re.findall(r"[a-z0-9]+", category.lower())
        if len(token) > 1 and token not in _SCOPED_EXCEPTION_TOKEN_STOPWORDS
    ]
    return tuple(tokens)


def _identifier_contains_category(
    identifier: str, category_tokens: tuple[str, ...]
) -> bool:
    if not category_tokens:
        return False
    identifier_tokens = set(re.findall(r"[a-z0-9]+", identifier.lower()))
    return all(token in identifier_tokens for token in category_tokens)


def _identifier_is_scoped_exception_amount(
    identifier: str,
    category_tokens: tuple[str, ...],
) -> bool:
    if not _identifier_contains_category(identifier, category_tokens):
        return False
    identifier_tokens = set(re.findall(r"[a-z0-9]+", identifier.lower()))
    return bool(identifier_tokens & _SCOPED_EXCEPTION_AMOUNT_TOKENS)


def _identifier_is_scoped_exception_predicate(
    identifier: str,
    category_tokens: tuple[str, ...],
) -> bool:
    if not _identifier_contains_category(identifier, category_tokens):
        return False
    identifier_tokens = set(re.findall(r"[a-z0-9]+", identifier.lower()))
    predicate_tokens = identifier_tokens & _SCOPED_EXCEPTION_PREDICATE_TOKENS
    if not predicate_tokens:
        return False
    if (
        identifier_tokens & _SCOPED_EXCEPTION_PREDICATE_BLOCKING_AMOUNT_TOKENS
    ) and not (identifier_tokens & _SCOPED_EXCEPTION_STRONG_PREDICATE_TOKENS):
        return False
    if predicate_tokens == {"for"} and not (
        identifier_tokens & _SCOPED_EXCEPTION_FOR_PREDICATE_SUBJECT_TOKENS
    ):
        return False
    if identifier_tokens & _SCOPED_EXCEPTION_NONPREDICATE_QUANTITY_TOKENS:
        return False
    return True


def _formula_or_referenced_helpers_have_ungated_category_amount(
    formula: str,
    *,
    category_tokens: tuple[str, ...],
    formula_by_name: dict[str, str],
    current_name: str,
    gate_context: bool = False,
    seen: set[str] | None = None,
) -> bool:
    visited = set(seen or set())
    visited.add(current_name)

    conditional_spans = _rulespec_inline_conditional_spans(formula)
    if conditional_spans:
        remaining_formula = formula
        for start, end, condition, then_formula, else_formula in reversed(
            conditional_spans
        ):
            then_has_category_gate, else_has_category_gate = (
                _formula_category_branch_gates(
                    condition,
                    category_tokens=category_tokens,
                )
            )
            if _formula_or_referenced_helpers_have_ungated_category_amount(
                then_formula,
                category_tokens=category_tokens,
                formula_by_name=formula_by_name,
                current_name=current_name,
                gate_context=gate_context or then_has_category_gate,
                seen=visited,
            ) or _formula_or_referenced_helpers_have_ungated_category_amount(
                else_formula,
                category_tokens=category_tokens,
                formula_by_name=formula_by_name,
                current_name=current_name,
                gate_context=gate_context or else_has_category_gate,
                seen=visited,
            ):
                return True
            remaining_formula = (
                f"{remaining_formula[:start]} 0 {remaining_formula[end:]}"
            )
        formula = remaining_formula

    conditional = _split_rulespec_inline_conditional(formula)
    if conditional is not None:
        condition, then_formula, else_formula = conditional
        then_has_category_gate, else_has_category_gate = _formula_category_branch_gates(
            condition,
            category_tokens=category_tokens,
        )
        return _formula_or_referenced_helpers_have_ungated_category_amount(
            then_formula,
            category_tokens=category_tokens,
            formula_by_name=formula_by_name,
            current_name=current_name,
            gate_context=gate_context or then_has_category_gate,
            seen=visited,
        ) or _formula_or_referenced_helpers_have_ungated_category_amount(
            else_formula,
            category_tokens=category_tokens,
            formula_by_name=formula_by_name,
            current_name=current_name,
            gate_context=gate_context or else_has_category_gate,
            seen=visited,
        )

    for identifier in _formula_local_identifiers(formula):
        is_category_amount = _identifier_is_scoped_exception_amount(
            identifier,
            category_tokens,
        )
        if identifier in formula_by_name and identifier not in visited:
            helper_formula = formula_by_name[identifier]
            if is_category_amount:
                if gate_context or _formula_expression_is_category_gated(
                    helper_formula,
                    category_tokens=category_tokens,
                    formula_by_name=formula_by_name,
                    current_name=identifier,
                    seen=visited,
                ):
                    continue
                return True
            if _formula_or_referenced_helpers_have_ungated_category_amount(
                helper_formula,
                category_tokens=category_tokens,
                formula_by_name=formula_by_name,
                current_name=identifier,
                gate_context=gate_context,
                seen=visited,
            ):
                return True
            continue
        if is_category_amount and not gate_context:
            return True
    return False


def _formula_expression_is_category_gated(
    formula: str,
    *,
    category_tokens: tuple[str, ...],
    formula_by_name: dict[str, str],
    current_name: str,
    seen: set[str] | None = None,
) -> bool:
    visited = set(seen or set())
    visited.add(current_name)
    if _formula_output_is_category_gated(
        formula,
        category_tokens=category_tokens,
    ):
        return True
    remaining_formula = formula
    for _start, _end, condition, then_formula, else_formula in reversed(
        _rulespec_inline_conditional_spans(formula)
    ):
        then_has_category_gate, else_has_category_gate = _formula_category_branch_gates(
            condition,
            category_tokens=category_tokens,
        )
        if then_has_category_gate and _formula_expression_is_zero(else_formula):
            remaining_formula = (
                f"{remaining_formula[:_start]} 0 {remaining_formula[_end:]}"
            )
            continue
        if else_has_category_gate and _formula_expression_is_zero(then_formula):
            remaining_formula = (
                f"{remaining_formula[:_start]} 0 {remaining_formula[_end:]}"
            )
            continue

    for identifier in sorted(
        _formula_local_identifiers(remaining_formula),
        key=len,
        reverse=True,
    ):
        if identifier in visited or identifier not in formula_by_name:
            continue
        if _formula_expression_is_category_gated(
            formula_by_name[identifier],
            category_tokens=category_tokens,
            formula_by_name=formula_by_name,
            current_name=identifier,
            seen=visited,
        ):
            remaining_formula = re.sub(
                rf"\b{re.escape(identifier)}\b",
                "0",
                remaining_formula,
            )
    return _formula_expression_is_zero(remaining_formula)


def _formula_expression_is_zero(formula: str) -> bool:
    stripped = formula.strip()
    if re.fullmatch(r"0(?:\.0+)?", stripped):
        return True
    return _formula_expression_is_statically_zero(stripped)


def _formula_expression_is_statically_zero(formula: str) -> bool:
    try:
        expression = ast.parse(formula, mode="eval")
    except SyntaxError:
        return False
    return _formula_ast_node_is_zero(expression.body)


def _formula_ast_node_is_zero(node: ast.AST) -> bool:
    if isinstance(node, ast.Constant) and isinstance(node.value, int | float):
        return float(node.value) == 0
    if isinstance(node, ast.UnaryOp):
        return _formula_ast_node_is_zero(node.operand)
    if isinstance(node, ast.BinOp):
        if isinstance(node.op, ast.Add | ast.Sub):
            return _formula_ast_node_is_zero(node.left) and _formula_ast_node_is_zero(
                node.right
            )
        if isinstance(node.op, ast.Mult):
            return _formula_ast_node_is_zero(node.left) or _formula_ast_node_is_zero(
                node.right
            )
        if isinstance(node.op, ast.Div | ast.FloorDiv):
            return _formula_ast_node_is_zero(node.left)
    if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
        function_name = node.func.id.lower()
        if function_name in {"abs", "ceil", "floor", "round"} and len(node.args) == 1:
            return _formula_ast_node_is_zero(node.args[0])
        if function_name == "max":
            return bool(node.args) and all(
                _formula_ast_node_is_zero(argument) for argument in node.args
            )
        if function_name == "min":
            return bool(node.args) and (
                all(_formula_ast_node_is_zero(argument) for argument in node.args)
                or (
                    any(_formula_ast_node_is_zero(argument) for argument in node.args)
                    and all(
                        _formula_ast_node_is_nonnegative(argument)
                        for argument in node.args
                    )
                )
            )
    return False


def _formula_ast_node_is_nonnegative(node: ast.AST) -> bool:
    if isinstance(node, ast.Constant) and isinstance(node.value, int | float):
        return float(node.value) >= 0
    if isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.USub):
        return False
    if _formula_ast_node_is_zero(node):
        return True
    if isinstance(node, ast.BinOp):
        if isinstance(node.op, ast.Add):
            return _formula_ast_node_is_nonnegative(
                node.left
            ) and _formula_ast_node_is_nonnegative(node.right)
        if isinstance(node.op, ast.Mult):
            return _formula_ast_node_is_nonnegative(
                node.left
            ) and _formula_ast_node_is_nonnegative(node.right)
    if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
        function_name = node.func.id.lower()
        if function_name == "abs":
            return True
        if function_name == "max":
            return any(_formula_ast_node_is_zero(argument) for argument in node.args)
        if function_name == "min":
            return bool(node.args) and all(
                _formula_ast_node_is_nonnegative(argument) for argument in node.args
            )
    return False


def _formula_output_is_category_gated(
    formula: str,
    *,
    category_tokens: tuple[str, ...],
) -> bool:
    stripped = formula.strip()
    if not stripped:
        return False
    if re.fullmatch(r"0(?:\.0+)?", stripped):
        return True

    conditional = _split_rulespec_inline_conditional(stripped)
    if conditional is None:
        return False

    condition, then_formula, else_formula = conditional
    then_has_category_gate, else_has_category_gate = _formula_category_branch_gates(
        condition,
        category_tokens=category_tokens,
    )
    return (
        then_has_category_gate
        or _formula_output_is_category_gated(
            then_formula,
            category_tokens=category_tokens,
        )
    ) and (
        else_has_category_gate
        or _formula_output_is_category_gated(
            else_formula,
            category_tokens=category_tokens,
        )
    )


def _formula_category_branch_gates(
    formula: str,
    *,
    category_tokens: tuple[str, ...],
) -> tuple[bool, bool]:
    occurrences = _formula_category_predicate_occurrences(
        formula,
        category_tokens=category_tokens,
    )
    has_positive = any(not negated for _identifier, negated in occurrences)
    has_negative = any(negated for _identifier, negated in occurrences)
    if has_positive == has_negative:
        return False, False
    return has_positive, has_negative


def _formula_category_predicate_occurrences(
    formula: str,
    *,
    category_tokens: tuple[str, ...],
) -> list[tuple[str, bool]]:
    occurrences: list[tuple[str, bool]] = []
    for match in _RULESPEC_IDENTIFIER.finditer(formula):
        identifier = match.group(0)
        if identifier in _RULESPEC_FORMULA_BUILTINS:
            continue
        if not _identifier_is_scoped_exception_predicate(
            identifier,
            category_tokens,
        ):
            continue
        occurrences.append(
            (
                identifier,
                _formula_identifier_reference_is_negated(formula, match),
            )
        )
    return occurrences


def _formula_identifier_reference_is_negated(
    formula: str,
    match: re.Match[str],
) -> bool:
    prefix = formula[: match.start()].rstrip()
    if re.search(r"(?:^|[^A-Za-z0-9_])not\s*$", prefix, flags=re.IGNORECASE):
        return True
    suffix = formula[match.end() :].lstrip().lower()
    return suffix.startswith("== false") or suffix.startswith("!= true")


def _split_rulespec_inline_conditional(formula: str) -> tuple[str, str, str] | None:
    text = formula.strip()
    span = _split_rulespec_inline_conditional_at(text, 0)
    if span is None or span[1] != len(text):
        return None
    _start, _end, condition, then_formula, else_formula = span
    return condition, then_formula, else_formula


def _rulespec_inline_conditional_spans(
    formula: str,
) -> list[tuple[int, int, str, str, str]]:
    spans: list[tuple[int, int, str, str, str]] = []
    index = 0
    while index < len(formula):
        if not (
            _rulespec_word_at(formula, index, "if")
            or _rulespec_word_at(formula, index, "elif")
        ):
            index += 1
            continue
        span = _split_rulespec_inline_conditional_at(formula, index)
        if span is not None:
            spans.append(span)
            index = span[1]
            continue
        index += 1
    return spans


def _split_rulespec_inline_conditional_at(
    text: str,
    start: int,
) -> tuple[int, int, str, str, str] | None:
    head = re.match(r"(?:if|elif)\b", text[start:], flags=re.IGNORECASE)
    if head is None:
        return None

    base_depth = _rulespec_bracket_depth_before(text, start)
    head_end = start + head.end()
    colon_index = _find_rulespec_top_level_colon(
        text,
        head_end,
        base_depth=base_depth,
    )
    if colon_index is None:
        return None

    else_match = _find_rulespec_top_level_else(
        text,
        colon_index + 1,
        base_depth=base_depth,
    )
    if else_match is None:
        return None
    else_index, else_colon_index = else_match
    end = _find_rulespec_conditional_end(
        text,
        else_colon_index + 1,
        base_depth=base_depth,
    )
    condition = text[head_end:colon_index].strip()
    then_formula = text[colon_index + 1 : else_index].strip()
    else_formula = text[else_colon_index + 1 : end].strip()
    return start, end, condition, then_formula, else_formula


def _find_rulespec_top_level_colon(
    text: str,
    start: int,
    *,
    base_depth: int = 0,
) -> int | None:
    depth = base_depth
    quote: str | None = None
    index = start
    while index < len(text):
        char = text[index]
        if quote is not None:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
        elif char in "([{":
            depth += 1
        elif char in ")]}" and depth:
            depth -= 1
        elif char == ":" and depth == base_depth:
            return index
        index += 1
    return None


def _find_rulespec_top_level_else(
    text: str,
    start: int,
    *,
    base_depth: int = 0,
) -> tuple[int, int] | None:
    depth = base_depth
    quote: str | None = None
    nested_conditionals = 0
    index = start
    while index < len(text):
        char = text[index]
        if quote is not None:
            if char == quote and text[index - 1] != "\\":
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth != base_depth:
            index += 1
            continue
        if _rulespec_word_at(text, index, "if"):
            nested_conditionals += 1
            index += 2
            continue
        if _rulespec_word_at(text, index, "elif"):
            nested_conditionals += 1
            index += 4
            continue
        if _rulespec_word_at(text, index, "else"):
            colon_index = _find_rulespec_else_colon(text, index + len("else"))
            if colon_index is None:
                index += 1
                continue
            if nested_conditionals:
                nested_conditionals -= 1
                index = colon_index + 1
                continue
            return index, colon_index
        index += 1
    return None


def _find_rulespec_conditional_end(
    text: str,
    start: int,
    *,
    base_depth: int,
) -> int:
    depth = base_depth
    quote: str | None = None
    index = start
    while index < len(text):
        char = text[index]
        if quote is not None:
            if char == quote and text[index - 1] != "\\":
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth == base_depth:
                return index
            depth -= 1
            index += 1
            continue
        if char == "," and depth == base_depth:
            return index
        index += 1
    return len(text)


def _rulespec_bracket_depth_before(text: str, end: int) -> int:
    depth = 0
    quote: str | None = None
    index = 0
    while index < min(end, len(text)):
        char = text[index]
        if quote is not None:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
        elif char in "([{":
            depth += 1
        elif char in ")]}" and depth:
            depth -= 1
        index += 1
    return depth


def _rulespec_word_at(text: str, index: int, word: str) -> bool:
    end = index + len(word)
    if text[index:end].lower() != word:
        return False
    before = text[index - 1] if index > 0 else ""
    after = text[end] if end < len(text) else ""
    return not (
        (before and re.match(r"[A-Za-z0-9_]", before))
        or (after and re.match(r"[A-Za-z0-9_]", after))
    )


def _find_rulespec_else_colon(text: str, start: int) -> int | None:
    index = start
    while index < len(text) and text[index].isspace():
        index += 1
    if index < len(text) and text[index] == ":":
        return index
    return None


def _rulespec_rule_dtype_by_name(payload: dict[str, Any]) -> dict[str, str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return {}
    dtype_by_name: dict[str, str] = {}
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or f"rules[{index}]").strip()
        dtype = str(rule.get("dtype") or "").strip().lower()
        if name and dtype:
            dtype_by_name[name] = dtype
    return dtype_by_name


def _formula_or_referenced_helpers_implement_limitation(
    formula: str,
    *,
    formula_by_name: dict[str, str],
    current_name: str,
    source_text: str,
    seen: set[str] | None = None,
) -> bool:
    if _formula_implements_limitation(formula, source_text):
        return True
    visited = set(seen or set())
    visited.add(current_name)
    for identifier in _formula_local_identifiers(formula):
        if identifier in visited or identifier not in formula_by_name:
            continue
        if _formula_or_referenced_helpers_implement_limitation(
            formula_by_name[identifier],
            formula_by_name=formula_by_name,
            current_name=identifier,
            source_text=source_text,
            seen=visited,
        ):
            return True
    return False


def _formula_is_referenced_by_limited_downstream_formula(
    name: str,
    *,
    formula_by_name: dict[str, str],
    source_text: str,
) -> bool:
    """Return true when `name` is an intermediate used by a limited output."""
    for downstream_name, downstream_formula in formula_by_name.items():
        if downstream_name == name:
            continue
        if name not in _formula_local_identifiers(downstream_formula):
            continue
        if _formula_or_referenced_helpers_implement_limitation(
            downstream_formula,
            formula_by_name=formula_by_name,
            current_name=downstream_name,
            source_text=source_text,
        ):
            return True
    return False


def _formula_aggregates_limited_local_amount(
    formula: str,
    *,
    formula_by_name: dict[str, str],
    current_name: str,
    source_text: str,
) -> bool:
    """Return true when an aggregate sums local amounts that apply a limit."""
    if not re.search(r"\bsum(?:_where)?\s*\(", formula):
        return False
    normalized_formula = f"_{_normalize_identifier(formula)}_"
    for helper_name, helper_formula in formula_by_name.items():
        if helper_name == current_name:
            continue
        normalized_helper = _normalize_identifier(helper_name)
        if not normalized_helper:
            continue
        if f"_{normalized_helper}_" not in normalized_formula:
            continue
        if _formula_or_referenced_helpers_implement_limitation(
            helper_formula,
            formula_by_name=formula_by_name,
            current_name=helper_name,
            source_text=source_text,
        ):
            return True
    return False


_BROAD_APPLICATION_FURNISHING_SOURCE_PATTERN = re.compile(
    r"\b(?:shall|must|may)\s+(?:be\s+)?"
    r"(?:furnished|provided|paid|made\s+available|granted|issued)\b"
    r"(?:(?!\n\n).){0,240}\b(?:eligible|eligibility)\b"
    r"(?:(?!\n\n).){0,160}\b(?:application|applicant|apply|applies)\b",
    flags=re.IGNORECASE | re.DOTALL,
)


def find_broad_application_passthrough_issues(content: str) -> list[str]:
    """Flag administrative furnishing/application clauses encoded as outputs."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    if not source_text or not _BROAD_APPLICATION_FURNISHING_SOURCE_PATTERN.search(
        source_text
    ):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        if not re.search(
            r"\b(?:furnish|provid|paid|grant|issue|assistance|entitle|participat)",
            name.replace("_", " "),
            flags=re.IGNORECASE,
        ):
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"judgment", "boolean", "bool"}:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            identifiers = _formula_local_identifiers(formula)
            if not identifiers or len(identifiers) > 3:
                continue
            if not any("eligib" in identifier for identifier in identifiers):
                continue
            if not any(
                re.search(r"applic|applicant|apply|applies", identifier)
                for identifier in identifiers
            ):
                continue
            issues.append(
                "Broad application pass-through: "
                f"`{name}` encodes an administrative furnishing/application clause as "
                "a generic executable output. Keep that clause in `module.summary`; "
                "encode only source-specific eligibility conditions, exceptions, "
                "parameters, or source relations."
            )
            break
    return issues


def find_copied_cross_reference_source_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Reject copying cited same-section subsection bodies into this module."""
    source_text = extract_embedded_source_text(content)
    if not source_text:
        return []

    statute_path = _statute_path_parts_for_file(rules_file, policy_repo_path)
    if statute_path is None:
        return []
    title, section, current_fragments = statute_path

    issues: list[str] = []
    seen: set[str] = set()
    for match in re.finditer(
        r"\bsubsection\s+\((?P<subsection>[A-Za-z0-9]+)\)"
        r"(?:\s+of\s+this\s+section)?(?=\W|$)",
        source_text,
        flags=re.IGNORECASE,
    ):
        subsection = match.group("subsection")
        if subsection in current_fragments:
            continue
        if subsection in seen:
            continue
        copied_body_pattern = re.compile(
            rf"(?:^|\s)\({re.escape(subsection)}\)\s+[A-Z][A-Za-z]"
        )
        if not copied_body_pattern.search(source_text):
            continue
        seen.add(subsection)
        import_base = "/".join(["statutes", title, section, subsection])
        issues.append(
            "Copied cross-reference source: "
            f"`{rules_file.name}` embeds the body of cited subsection "
            f"`{import_base}` in its own source summary. Encode/import that "
            "subsection separately instead of re-encoding it locally."
        )
    return issues


def find_missing_same_section_subsection_import_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Require imports for cited same-section subsections used as carve-outs."""
    source_text = extract_embedded_source_text(content)
    if not source_text or not re.search(
        r"\b(?:except|unless)\b",
        source_text,
        flags=re.IGNORECASE,
    ):
        return []

    statute_path = _statute_path_parts_for_file(rules_file, policy_repo_path)
    if statute_path is None:
        return []
    title, section, current_fragments = statute_path
    import_items = _extract_import_items_from_content(content)
    imports = {
        _normalize_rulespec_import_path_static(import_path)
        for import_path in import_items
    }

    issues: list[str] = []
    seen: set[str] = set()
    for match in re.finditer(
        r"\bsubsection\s+\((?P<subsection>[A-Za-z0-9]+)\)"
        r"(?:\s+of\s+this\s+section)?(?=\W|$)",
        source_text,
        flags=re.IGNORECASE,
    ):
        if not _same_section_subsection_citation_requires_import(source_text, match):
            continue
        subsection = match.group("subsection")
        if subsection in current_fragments or subsection in seen:
            continue
        import_base = "/".join(["statutes", title, section, subsection])
        if not _rulespec_path_or_child_exists_static(policy_repo_path, import_base):
            continue
        if _imports_cover_path_static(
            imports,
            import_base,
        ) or _transitive_imports_cover_path_static(
            imports,
            import_base,
            rules_file=rules_file,
            policy_repo_path=policy_repo_path,
        ):
            continue
        seen.add(subsection)
        issues.append(
            "Same-section subsection import missing: "
            f"source text cites subsection `{import_base}` in an exception/cross-reference "
            "clause, but the file does not import it. Encode/import the cited "
            "subsection instead of modeling its requirements as a local fact."
        )
    return issues


def _same_section_subsection_citation_requires_import(
    source_text: str,
    match: re.Match[str],
) -> bool:
    """Return whether a same-section citation is locally an exception dependency."""
    sentence_start = max(
        source_text.rfind(".", 0, match.start()),
        source_text.rfind(";", 0, match.start()),
    )
    prefix = source_text[sentence_start + 1 : match.start()]
    triggers = list(
        re.finditer(
            r"\b(?:except|unless|notwithstanding)\b",
            prefix,
            flags=re.IGNORECASE,
        )
    )
    if not triggers:
        return False
    return triggers[-1].group(0).lower() in {"except", "unless"}


def _rulespec_path_or_child_exists_static(
    policy_repo_path: Path,
    import_base: str,
) -> bool:
    """Return whether a cited same-section RuleSpec source exists locally."""
    relative = Path(import_base)
    return (policy_repo_path / relative.with_suffix(".yaml")).exists() or (
        policy_repo_path / relative
    ).is_dir()


def find_rule_name_path_suffix_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Reject rule names that append the file's legal path fragments."""
    statute_path = _statute_path_parts_for_file(rules_file, policy_repo_path)
    if statute_path is None:
        return []
    _title, section, fragments = statute_path
    if not fragments:
        return []

    suffixes = _path_suffix_tokens_for_rule_name(section, fragments)
    if not suffixes:
        return []

    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if not isinstance(payload, dict):
            return []
        rules = payload.get("rules")
        if not isinstance(rules, list):
            return []

        issues: list[str] = []
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            name = str(rule.get("name") or "").strip()
            if not name:
                continue
            normalized = name.lower()
            for suffix in suffixes:
                if normalized.endswith(f"_{suffix}"):
                    issues.append(
                        "Rule name includes citation suffix: "
                        f"rule `{name}` ends with `_{suffix}`. The file path is "
                        "the legal ID; use a semantic rule name without path "
                        "fragments."
                    )
                    break
        return issues
    return []


def find_mixed_case_rule_name_token_issues(content: str) -> list[str]:
    """Reject accidental mixed-case word tokens in exported rule names."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        for token in name.split("_"):
            if any(ch.islower() for ch in token) and any(ch.isupper() for ch in token):
                issues.append(
                    "Rule name token uses accidental mixed case: "
                    f"rule `{name}` contains token `{token}`. Use lowercase "
                    "semantic acronyms such as `ipv`; reserve uppercase for "
                    "source-stated legal fragments like `D`, `7C`, or `7527A`."
                )
                break
    return issues


def _path_suffix_tokens_for_rule_name(
    section: str,
    fragments: tuple[str, ...],
) -> set[str]:
    """Return path-fragment suffixes specific enough to avoid common words."""
    normalized_fragments = tuple(
        _normalize_rule_name_suffix_token(item) for item in fragments
    )
    normalized_fragments = tuple(item for item in normalized_fragments if item)
    if not normalized_fragments:
        return set()

    suffixes: set[str] = set()
    section_token = _normalize_rule_name_suffix_token(section)
    if section_token:
        suffixes.add("_".join((section_token, *normalized_fragments)))
    if len(normalized_fragments) >= 2:
        suffixes.add("_".join(normalized_fragments))
        suffixes.add("_".join(normalized_fragments[-2:]))
    return {suffix for suffix in suffixes if suffix}


def _normalize_rule_name_suffix_token(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", "_", value.lower()).strip("_")


def find_sibling_rule_name_collision_issues(
    content: str, rules_file: Path
) -> list[str]:
    """Reject exported rule names that collide with sibling child fragments."""
    current_names = _rulespec_rule_names_from_content(content)
    if not current_names:
        return []

    issues: list[str] = []
    current_path = rules_file.resolve()
    sibling_names: dict[str, Path] = {}
    for sibling in sorted(rules_file.parent.glob("*.yaml")):
        if sibling.name.endswith(".test.yaml") or sibling.resolve() == current_path:
            continue
        for name in _rulespec_rule_names_from_file(sibling):
            sibling_names.setdefault(name, sibling)

    for name in sorted(current_names & sibling_names.keys()):
        sibling = sibling_names[name]
        issues.append(
            "Sibling rule name collision: "
            f"rule `{name}` is also exported by sibling `{sibling.name}`. "
            "Use semantic branch-specific names so aggregate parent provisions "
            "can import sibling outputs without ambiguity."
        )
    return issues


def _rulespec_executable_names_from_payload(payload: Any) -> set[str]:
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    names: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "parameter",
            "derived",
        }:
            continue
        name = str(rule.get("name") or "").strip()
        if name:
            names.add(name)
    return names


def _rulespec_executable_names_in_order_from_payload(payload: Any) -> list[str]:
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    names: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "parameter",
            "derived",
        }:
            continue
        name = str(rule.get("name") or "").strip()
        if name:
            names.append(name)
    return names


def _rulespec_terminal_executable_names_from_payload(payload: Any) -> list[str]:
    """Return executable exports that other local executable rules do not consume."""
    names = _rulespec_executable_names_in_order_from_payload(payload)
    if not names or not isinstance(payload, dict):
        return names

    name_set = set(names)
    referenced: set[str] = set()
    for owner, _kind, formula in _rulespec_rule_formulas(payload):
        referenced.update(
            identifier
            for identifier in _formula_local_identifiers(formula)
            if identifier in name_set and identifier != owner
        )
    terminal = [name for name in names if name not in referenced]
    return terminal or names


def _rulespec_child_export_targets(
    names: Iterable[str],
    *,
    child_import_base: str,
    policy_repo_path: Path,
) -> list[str]:
    prefix = jurisdiction_prefix(policy_repo_path)
    return [f"{prefix}:{child_import_base}#{name}" for name in names]


def _format_child_export_hint(targets: list[str]) -> str:
    if not targets:
        return "from that child"
    formatted = ", ".join(f"`{target}`" for target in targets[:3])
    if len(targets) > 3:
        formatted += ", ..."
    noun = "output" if len(targets) == 1 else "outputs"
    return f"{noun} {formatted}"


def _rulespec_payload_from_file(path: Path) -> dict[str, Any] | None:
    try:
        payload = yaml.safe_load(path.read_text())
    except (OSError, yaml.YAMLError, ValueError):
        return None
    return payload if isinstance(payload, dict) else None


def _rulespec_import_export_names(
    imports: set[str],
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> set[str]:
    names: set[str] = set()
    for import_path in imports:
        import_file = _resolve_rulespec_import_file_static(
            import_path,
            rules_file=rules_file,
            policy_repo_path=policy_repo_path,
        )
        if import_file is None:
            continue
        payload = _rulespec_payload_from_file(import_file)
        names.update(_rulespec_executable_names_from_payload(payload))
    return names


def _rulespec_import_fragment_names(imports: Any) -> set[str]:
    if not isinstance(imports, list):
        return set()
    names: set[str] = set()
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        fragment = raw_import.rsplit("#", 1)[1].strip()
        if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", fragment):
            names.add(fragment)
    return names


def _rulespec_local_input_slots(
    payload: dict[str, Any],
    *,
    imports: set[str],
    rules_file: Path,
    policy_repo_path: Path,
) -> set[str]:
    local_symbols = _rulespec_executable_names_from_payload(payload)
    local_symbols.update(_rulespec_data_relation_names(payload))
    imported_symbols = _rulespec_import_export_names(
        imports,
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )
    return _rulespec_formula_identifiers(payload) - local_symbols - imported_symbols


def _rulespec_executable_numeric_values_by_name(
    payload: Any,
) -> dict[str, set[float]]:
    if not isinstance(payload, dict):
        return {}
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return {}

    values_by_name: dict[str, set[float]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "parameter",
            "derived",
        }:
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue

        values: set[float] = set()
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, (int, float)) and not isinstance(formula, bool):
                extracted = _numeric_rule_value(formula)
                if extracted is not None:
                    values.add(extracted[1])
            elif isinstance(formula, str) and formula.strip():
                values.update(
                    value
                    for _line_number, _raw, value in _extract_formula_grounding_values(
                        1,
                        formula,
                    )
                )

            table_values = version.get("values")
            if isinstance(table_values, dict):
                for table_value in table_values.values():
                    extracted = _numeric_rule_value(table_value)
                    if extracted is not None:
                        values.add(extracted[1])
        if values:
            values_by_name[name] = values
    return values_by_name


def _rule_formula_numeric_values_by_name_for_child_source(
    payload: dict[str, Any],
    *,
    title: str,
    section: str,
    fragments: tuple[str, ...],
) -> dict[str, set[float]]:
    values_by_name: dict[str, set[float]] = {}
    for name, kind, formula, source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind not in {"parameter", "derived", "derived_relation"}:
            continue
        context = "\n".join(
            [
                *_source_field_texts(source),
                *_rule_proof_source_texts(rule),
            ]
        )
        if not _source_context_mentions_statute_fragment(
            context,
            title=title,
            section=section,
            fragments=fragments,
        ):
            continue
        values = {
            value
            for _line_number, _raw, value in _extract_formula_grounding_values(
                1,
                formula,
            )
        }
        if values:
            values_by_name.setdefault(name, set()).update(values)
    return values_by_name


def _source_context_mentions_statute_fragment(
    context: str,
    *,
    title: str,
    section: str,
    fragments: tuple[str, ...],
) -> bool:
    if not context.strip() or not fragments:
        return False

    fragment_pattern = "".join(
        rf"\s*\(\s*{re.escape(fragment)}\s*\)" for fragment in fragments
    )
    section_fragment_pattern = re.compile(
        rf"\b(?:{re.escape(title)}\s+U\.?S\.?C\.?\s+)?"
        rf"{re.escape(section)}{fragment_pattern}",
        flags=re.IGNORECASE,
    )
    if section_fragment_pattern.search(context):
        return True

    first_fragment = re.escape(fragments[0])
    subsection_pattern = re.compile(
        rf"\bsubsection\s+\(\s*{first_fragment}\s*\)",
        flags=re.IGNORECASE,
    )
    return bool(subsection_pattern.search(context))


def _child_numeric_output_reencoding_issues(
    *,
    parent_payload: dict[str, Any],
    child_payload: dict[str, Any],
    child_display_path: str,
    rules_file: Path,
    child: Path,
    policy_repo_path: Path,
) -> list[str]:
    statute_path = _statute_path_parts_for_file(child, policy_repo_path)
    if statute_path is None:
        return []
    title, section, child_fragments = statute_path

    child_values_by_name = _rulespec_executable_numeric_values_by_name(child_payload)
    if not child_values_by_name:
        return []

    parent_values_by_name = _rule_formula_numeric_values_by_name_for_child_source(
        parent_payload,
        title=title,
        section=section,
        fragments=child_fragments,
    )
    if not parent_values_by_name:
        return []

    value_to_child_names: dict[float, list[str]] = {}
    for child_name, child_values in child_values_by_name.items():
        for value in child_values:
            value_to_child_names.setdefault(value, []).append(child_name)

    matches: list[tuple[float, list[str], list[str]]] = []
    for value in sorted(set(value_to_child_names)):
        parent_names = sorted(
            name
            for name, parent_values in parent_values_by_name.items()
            if value in parent_values
        )
        if not parent_names:
            continue
        matches.append((value, sorted(value_to_child_names[value]), parent_names))
    if not matches:
        return []

    copied_values = ", ".join(
        f"`{_format_numeric_literal(value)}`" for value, _, _ in matches[:4]
    )
    if len(matches) > 4:
        copied_values += ", ..."
    parent_rules = sorted(
        {name for _value, _child_names, names in matches for name in names}
    )
    parent_hint = ", ".join(f"`{name}`" for name in parent_rules[:4])
    if len(parent_rules) > 4:
        parent_hint += ", ..."
    child_import_base = (
        child.resolve().relative_to(policy_repo_path).with_suffix("").as_posix()
    )
    child_exports = _rulespec_child_export_targets(
        sorted({name for _value, names, _parent_names in matches for name in names}),
        child_import_base=child_import_base,
        policy_repo_path=policy_repo_path,
    )
    export_hint = _format_child_export_hint(child_exports)
    return [
        "Child fragment numeric output re-encoded: "
        f"`{rules_file.name}` copies numeric literal(s) {copied_values} from child "
        f"`{child_display_path}` in rule(s) {parent_hint}. Import and reference "
        f"the child {export_hint} instead of copying the child value into "
        "the parent formula."
    ]


def _format_numeric_literal(value: float) -> str:
    if value.is_integer():
        return str(int(value))
    return str(value)


def find_child_fragment_reencoding_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Reject parent files that re-encode factual inputs owned by child fragments."""
    payload = _rulespec_payload(content)
    if payload is None:
        return []

    child_dir = rules_file.with_suffix("")
    if not child_dir.is_dir():
        return []

    try:
        policy_repo_path = policy_repo_path.resolve()
        rules_file.resolve().relative_to(policy_repo_path)
    except ValueError:
        return []

    import_items = _extract_import_items_from_content(content)
    imports = {
        _normalize_rulespec_import_path_static(import_path)
        for import_path in import_items
    }
    parent_inputs = _rulespec_local_input_slots(
        payload,
        imports=imports,
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )
    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    has_partial_extent_source = bool(
        source_text and _PARTIAL_EXTENT_SOURCE_PATTERN.search(source_text)
    )
    partial_extent_guidance = (
        " Because the source uses `to the extent`, do not recompute child "
        "branches with a locally adjusted basis when the current executable "
        "schema cannot pass that adjusted basis into imported child outputs; "
        "emit `module.status: entity_not_supported` or `deferred` instead of "
        "an approximate executable formula."
        if has_partial_extent_source
        else ""
    )

    issues: list[str] = []
    for child in sorted(child_dir.rglob("*.yaml")):
        if child.name.endswith(".test.yaml"):
            continue
        try:
            child_import_base = (
                child.resolve().relative_to(policy_repo_path).with_suffix("").as_posix()
            )
            child_display_path = (
                child.resolve().relative_to(policy_repo_path).as_posix()
            )
        except ValueError:
            continue

        child_payload = _rulespec_payload_from_file(child)
        if child_payload is None:
            continue
        child_imports = {
            _normalize_rulespec_import_path_static(import_path)
            for import_path in _extract_import_paths_from_content(child.read_text())
        }
        child_inputs = _rulespec_local_input_slots(
            child_payload,
            imports=child_imports,
            rules_file=child,
            policy_repo_path=policy_repo_path,
        )
        if parent_inputs:
            shared_inputs = sorted(parent_inputs & child_inputs)
            if shared_inputs:
                if _rulespec_has_same_section_displacement_boundary(payload):
                    continue
                terminal_child_names = _rulespec_terminal_executable_names_from_payload(
                    child_payload
                )
                child_imports_terminal_output = (
                    _imports_include_child_terminal_output_static(
                        import_items,
                        child_import_base=child_import_base,
                        terminal_names=terminal_child_names,
                    )
                )
                if child_imports_terminal_output:
                    continue
                child_exports = _rulespec_child_export_targets(
                    terminal_child_names,
                    child_import_base=child_import_base,
                    policy_repo_path=policy_repo_path,
                )
                export_hint = _format_child_export_hint(child_exports)
                shared = ", ".join(f"`{name}`" for name in shared_inputs[:4])
                if len(shared_inputs) > 4:
                    shared += ", ..."
                issues.append(
                    "Child fragment re-encoded: "
                    f"`{rules_file.name}` uses child-local input(s) {shared} also used by "
                    f"`{child_display_path}` without importing a terminal child output. "
                    f"Import and compose the child {export_hint} "
                    "instead of copying the child formula or factual inputs into the parent."
                    f"{partial_extent_guidance}"
                )
        issues.extend(
            _child_numeric_output_reencoding_issues(
                parent_payload=payload,
                child_payload=child_payload,
                child_display_path=child_display_path,
                rules_file=rules_file,
                child=child,
                policy_repo_path=policy_repo_path,
            )
        )
    return issues


def _rulespec_has_same_section_displacement_boundary(payload: dict[str, Any]) -> bool:
    """Return whether formulas gate the parent rule on a child displacement fact."""
    for _name, _kind, formula in _rulespec_rule_formulas(payload):
        for identifier in _formula_local_identifiers(formula):
            normalized = identifier.lower()
            if (
                "does_not_displace_this_subsection" in normalized
                or "does_not_displace_this_section" in normalized
            ):
                return True
    return False


_FORMULA_ABSOLUTE_REFERENCE_PATTERN = re.compile(
    r"\b[a-z][a-z0-9-]*:[A-Za-z0-9_./-]+#[A-Za-z_][A-Za-z0-9_]*\b"
)


def find_formula_absolute_reference_issues(content: str) -> list[str]:
    """Reject absolute RuleSpec import references inside formula text."""
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if not isinstance(payload, dict):
            return []
        rules = payload.get("rules")
        if not isinstance(rules, list):
            return []

        issues: list[str] = []
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            name = str(rule.get("name") or "").strip()
            if not name:
                continue
            versions = rule.get("versions")
            if not isinstance(versions, list):
                continue
            seen: set[str] = set()
            for version in versions:
                if not isinstance(version, dict):
                    continue
                formula = version.get("formula")
                if not isinstance(formula, str):
                    continue
                for match in _FORMULA_ABSOLUTE_REFERENCE_PATTERN.finditer(formula):
                    target = match.group(0)
                    if target in seen:
                        continue
                    seen.add(target)
                    issues.append(
                        "Formula absolute import reference: "
                        f"`{name}` contains `{target}` inside a formula. Add "
                        "that target to `imports:` and reference the imported "
                        "rule by bare local name in formula text."
                    )
        return issues
    return []


def find_unused_import_issues(content: str) -> list[str]:
    """Reject imported executable symbols that are not consumed by the module."""
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if not isinstance(payload, dict):
            return []
        imports = payload.get("imports")
        if not isinstance(imports, list):
            return []

        formula_text = "\n".join(_rulespec_formula_texts(payload))
        proof_import_targets = _rulespec_proof_import_targets(payload)
        issues: list[str] = []
        for raw_item in imports:
            if not isinstance(raw_item, str):
                continue
            import_item = raw_item.strip()
            if "#" not in import_item:
                continue
            symbol = import_item.rsplit("#", 1)[1].strip()
            if not symbol:
                continue
            if _formula_references_symbol(formula_text, symbol):
                continue
            if import_item in proof_import_targets:
                continue
            issues.append(
                f"Unused import `{import_item}`: imported symbol `{symbol}` is "
                "not referenced by any formula or proof import."
            )
        return issues
    return []


def find_proof_import_reference_issues(content: str) -> list[str]:
    """Reject proof import atoms whose imported symbol is absent from the formula."""
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if not isinstance(payload, dict):
            return []
        rules = payload.get("rules")
        if not isinstance(rules, list):
            return []

        issues: list[str] = []
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            rule_name = str(rule.get("name") or "<unknown>").strip() or "<unknown>"
            formula_text = "\n".join(_rulespec_rule_formula_texts(rule))
            proof = _rule_proof_payload(rule)
            atoms = proof.get("atoms") if isinstance(proof, dict) else None
            if not isinstance(atoms, list):
                continue
            for atom in atoms:
                if not isinstance(atom, dict):
                    continue
                import_payload = atom.get("import")
                if not isinstance(import_payload, dict):
                    continue
                symbol = str(import_payload.get("output") or "").strip()
                if not symbol:
                    target = str(import_payload.get("target") or "").strip()
                    if "#" in target:
                        symbol = target.rsplit("#", 1)[1].strip()
                if not symbol or _formula_references_symbol(formula_text, symbol):
                    continue
                issues.append(
                    "Proof import not referenced: "
                    f"`{rule_name}` proof imports `{symbol}`, but the rule "
                    "formula does not reference that imported symbol."
                )
        return issues
    return []


def find_import_shape_issues(content: str) -> list[str]:
    """Reject non-string top-level RuleSpec imports."""
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if not isinstance(payload, dict):
            return []
        imports = payload.get("imports")
        if imports is None:
            return []
        if not isinstance(imports, list):
            return [
                "Import shape invalid: top-level `imports:` must be a YAML list "
                "of scalar strings."
            ]

        issues: list[str] = []
        for index, raw_item in enumerate(imports):
            if isinstance(raw_item, str):
                import_item = raw_item.strip().strip("\"'")
                import_base = import_item.split("#", 1)[0].strip()
                if import_base and ":" not in import_base:
                    issues.append(
                        "Import target invalid: "
                        f"`imports[{index}]` uses `{raw_item}`. Imports must use "
                        "absolute RuleSpec targets like "
                        "`us:statutes/26/45A/a#base_year_1993_indian_employment_costs`."
                    )
                continue
            issues.append(
                "Import shape invalid: "
                f"`imports[{index}]` must be a scalar string like "
                "`us:statutes/26/45A/a#base_year_1993_indian_employment_costs`, "
                "not a map with `target`/`symbols` or any other object shape."
            )
        return issues
    return []


def _rulespec_formula_texts(payload: dict[str, Any]) -> list[str]:
    formulas: list[str] = []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return formulas
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        formulas.extend(_rulespec_rule_formula_texts(rule))
    return formulas


def _rulespec_rule_formula_texts(rule: dict[str, Any]) -> list[str]:
    formulas: list[str] = []
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return formulas
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            formulas.append(formula)
        elif isinstance(formula, (int, float)) and not isinstance(formula, bool):
            formulas.append(str(formula))
    return formulas


def _rulespec_proof_import_targets(payload: dict[str, Any]) -> set[str]:
    targets: set[str] = set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return targets
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        proof = _rule_proof_payload(rule)
        atoms = proof.get("atoms") if isinstance(proof, dict) else None
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            import_payload = atom.get("import")
            if not isinstance(import_payload, dict):
                continue
            target = str(import_payload.get("target") or "").strip()
            if target:
                targets.add(target)
    return targets


def _formula_references_symbol(formula_text: str, symbol: str) -> bool:
    return (
        re.search(
            rf"(?<![A-Za-z0-9_]){re.escape(symbol)}(?![A-Za-z0-9_])",
            formula_text,
        )
        is not None
    )


def _rulespec_rule_names_from_file(path: Path) -> set[str]:
    try:
        stat = path.stat()
        cache_path = path.resolve()
    except OSError:
        return set()
    return _rulespec_rule_names_from_file_cached(
        cache_path,
        stat.st_mtime_ns,
        stat.st_size,
    )


@functools.lru_cache(maxsize=8192)
def _rulespec_rule_names_from_file_cached(
    path: Path,
    _mtime_ns: int,
    _size: int,
) -> set[str]:
    with contextlib.suppress(OSError):
        return _rulespec_rule_names_from_content(path.read_text())
    return set()


def _rulespec_rule_names_from_content(content: str) -> set[str]:
    with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
        payload = yaml.safe_load(content)
        if not isinstance(payload, dict):
            return set()
        rules = payload.get("rules")
        if not isinstance(rules, list):
            return set()
        return {
            name
            for rule in rules
            if isinstance(rule, dict)
            for name in [str(rule.get("name") or "").strip()]
            if name
        }
    return set()


def _statute_path_parts_for_file(
    rules_file: Path,
    policy_repo_path: Path,
) -> tuple[str, str, tuple[str, ...]] | None:
    """Return title, section, and subsection fragments for a statute RuleSpec file."""
    resolved_file = rules_file.resolve()
    resolved_root = policy_repo_path.resolve()
    relative_parts: tuple[str, ...] | None = None
    with contextlib.suppress(ValueError):
        relative_parts = resolved_file.relative_to(resolved_root).parts
    if relative_parts is None:
        parts = resolved_file.parts
        with contextlib.suppress(ValueError):
            statutes_index = parts.index("statutes")
            relative_parts = tuple(parts[statutes_index:])
    if relative_parts is None:
        return None
    return _statute_path_parts_from_relative_parts(relative_parts)


def _extract_import_items_from_content(content: str) -> list[str]:
    """Extract raw import references from an imports block."""
    items: list[str] = []
    in_imports = False
    imports_indent = 0

    for line in content.splitlines():
        imports_match = re.match(r"^(\s*)imports:\s*$", line)
        if imports_match:
            in_imports = True
            imports_indent = len(imports_match.group(1))
            continue

        if not in_imports:
            continue

        if not line.strip():
            continue

        indent = len(line) - len(line.lstrip())
        top_level_sequence_item = (
            indent == imports_indent and IMPORT_ITEM_PATTERN.match(line)
        )
        if indent <= imports_indent and not top_level_sequence_item:
            in_imports = False
            continue

        item_match = IMPORT_ITEM_PATTERN.match(line)
        if item_match:
            item = item_match.group(2).strip()
        else:
            mapping_match = IMPORT_MAPPING_PATTERN.match(line)
            if not mapping_match:
                continue
            item = mapping_match.group(2).strip()
        item = item.strip().strip("\"'")
        if item:
            items.append(item)

    return items


def _extract_import_paths_from_content(content: str) -> list[str]:
    """Extract import file references from an imports block."""
    paths: list[str] = []
    for item in _extract_import_items_from_content(content):
        import_target = item.split("#", 1)[0].strip()
        if import_target:
            paths.append(import_target)

    return paths


def _normalize_rulespec_import_path_static(import_path: str) -> str:
    normalized = import_path.split("#", 1)[0].strip().strip("\"'")
    if ":" in normalized:
        _, tail = normalized.split(":", 1)
        normalized = tail
    return normalized.strip("/")


_RULESPEC_IMPORT_SOURCE_ROOTS = {"policies", "regulations", "statutes"}


def _rulespec_import_path_aliases_static(import_path: str) -> set[str]:
    normalized = _normalize_rulespec_import_path_static(import_path)
    aliases = {normalized} if normalized else set()
    head, separator, tail = normalized.partition("/")
    if separator and head in _RULESPEC_IMPORT_SOURCE_ROOTS:
        aliases.add(tail)
    return aliases


def _imports_cover_path_static(imports: set[str], expected_path: str) -> bool:
    for import_path in imports:
        if _rulespec_import_path_matches_static(import_path, expected_path):
            return True
    return False


def _rulespec_import_path_matches_static(
    import_path: str,
    expected_path: str,
) -> bool:
    expected_aliases = _rulespec_import_path_aliases_static(expected_path)
    for import_alias in _rulespec_import_path_aliases_static(import_path):
        for expected in expected_aliases:
            if import_alias == expected:
                return True
            if import_alias.startswith(expected + "/"):
                return True
            if expected.startswith(import_alias + "/"):
                return True
    return False


def _imports_include_child_terminal_output_static(
    import_items: list[str],
    *,
    child_import_base: str,
    terminal_names: list[str],
) -> bool:
    """Return true when imports include at least one terminal export from a child."""
    terminal_set = {name for name in terminal_names if name}
    if not terminal_set:
        return False
    for item in import_items:
        import_base, separator, symbol = item.partition("#")
        if not _rulespec_import_path_matches_static(import_base, child_import_base):
            continue
        if not separator:
            return True
        if symbol.strip() in terminal_set:
            return True
    return False


def _transitive_imports_cover_path_static(
    imports: set[str],
    expected_path: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> bool:
    """Return whether imported RuleSpecs import an expected path."""
    for import_path in imports:
        import_file = _resolve_rulespec_import_file_static(
            import_path,
            rules_file=rules_file,
            policy_repo_path=policy_repo_path,
        )
        if import_file is None:
            continue
        with contextlib.suppress(OSError):
            nested_imports = {
                _normalize_rulespec_import_path_static(path)
                for path in _extract_import_paths_from_content(import_file.read_text())
            }
            if _imports_cover_path_static(nested_imports, expected_path):
                return True
    return False


def _resolve_rulespec_import_file_static(
    import_path: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> Path | None:
    """Resolve a normalized import path to a local RuleSpec file."""
    normalized = _normalize_rulespec_import_path_static(import_path)
    if not normalized:
        return None
    candidate = policy_repo_path / f"{normalized}.yaml"
    if candidate.exists():
        return candidate

    repo_prefix = _rulespec_import_prefix_static(import_path)
    if repo_prefix:
        candidate = (
            policy_repo_path.parent / f"rulespec-{repo_prefix}" / f"{normalized}.yaml"
        )
        if candidate.exists():
            return candidate

    with contextlib.suppress(ValueError):
        relative_parent = rules_file.parent.resolve().relative_to(
            policy_repo_path.resolve()
        )
        candidate = policy_repo_path / relative_parent / f"{normalized}.yaml"
        if candidate.exists():
            return candidate
    return None


def _rulespec_import_prefix_static(import_path: str) -> str | None:
    normalized = import_path.split("#", 1)[0].strip().strip("\"'")
    if ":" not in normalized:
        return None
    prefix, tail = normalized.split(":", 1)
    if re.fullmatch(r"[a-z][a-z0-9-]*", prefix) and tail:
        return prefix
    return None


def _formula_local_identifiers(formula: str) -> set[str]:
    """Return non-builtin identifiers referenced by a RuleSpec formula."""
    scrubbed = _QUOTED_STRING_PATTERN.sub(" ", formula)
    return set(_RULESPEC_IDENTIFIER.findall(scrubbed)) - _RULESPEC_FORMULA_BUILTINS


def _normalize_identifier(value: str) -> str:
    """Normalize source phrases and symbols for loose identifier matching."""
    normalized = re.sub(r"[^a-z0-9]+", "_", value.lower())
    return re.sub(r"_+", "_", normalized).strip("_")


_SAME_SECTION_TERM_STOPWORDS = frozenset(
    {
        "amount",
        "amounts",
        "and",
        "applicable",
        "base",
        "cap",
        "component",
        "credit",
        "credits",
        "for",
        "in",
        "limit",
        "limitation",
        "of",
        "or",
        "rate",
        "section",
        "tax",
        "taxes",
        "the",
        "to",
        "under",
    }
)


def _same_section_term_is_specific(identifier: str) -> bool:
    """Return whether a symbol is specific enough to guard against drift."""
    tokens = [
        token
        for token in _normalize_identifier(identifier).split("_")
        if token and token not in _SAME_SECTION_TERM_STOPWORDS
    ]
    return len(tokens) >= 2


def _identifier_phrase_occurs(term: str, identifier: str) -> bool:
    """Return whether `term` appears as an underscore-delimited phrase."""
    normalized_term = _normalize_identifier(term)
    normalized_identifier = _normalize_identifier(identifier)
    if not normalized_term or not normalized_identifier:
        return False
    return f"_{normalized_term}_" in f"_{normalized_identifier}_"


def _same_section_term_overlap_is_rate_import(
    local_term: str,
    imported_symbol: str,
    import_item: str,
) -> bool:
    """Return whether a term overlap is a cited rate, not a stand-in amount."""
    normalized_local = _normalize_identifier(local_term)
    normalized_symbol = _normalize_identifier(imported_symbol)
    if not normalized_local or not normalized_symbol:
        return False
    if normalized_local.endswith(("_rate", "_tax_rate")):
        return False
    if not normalized_symbol.endswith(("_rate", "_tax_rate")):
        return False
    if normalized_symbol not in {
        f"{normalized_local}_rate",
        f"{normalized_local}_tax_rate",
    }:
        return False
    import_path = import_item.split("#", 1)[0]
    import_path_tokens = {
        token for token in re.split(r"[^a-z0-9]+", import_path.lower()) if token
    }
    return "rate" in import_path_tokens or "rates" in import_path_tokens


def _imported_rate_source_is_thresholded(content: str, rate_name: str) -> bool:
    """Return whether an imported rate file also encodes limited rate mechanics."""
    if rate_name not in _formula_local_identifiers(content):
        return False
    normalized = _normalize_identifier(content)
    return any(
        token in normalized
        for token in (
            "threshold",
            "excess",
            "cap",
            "capped",
            "ceiling",
            "limit",
            "limited",
            "above",
            "below",
        )
    )


_SOURCE_STATED_COMPOSITE_RATE_PATTERN = re.compile(
    r"\b(?:one-half|half|sum)\b[\s\S]{0,160}\b"
    r"rates?\s+imposed\s+by\b"
    r"|"
    r"\brates?\s+imposed\s+by\b[\s\S]{0,160}\b(?:one-half|half|sum)\b",
    flags=re.IGNORECASE,
)


def _block_is_source_stated_composite_rate(
    block: Mapping[str, object],
    source_text: str,
) -> bool:
    """Allow Rate rules when the source itself asks for a sum of imported rates."""
    if str(block.get("dtype") or "").strip().lower() != "rate":
        return False
    proof_excerpts = block.get("proof_excerpts")
    scoped_text = (
        " ".join(str(item) for item in proof_excerpts)
        if isinstance(proof_excerpts, list)
        else ""
    ).strip()
    if not scoped_text:
        scoped_text = str(block.get("source") or "")
    if not scoped_text:
        scoped_text = source_text
    return bool(_SOURCE_STATED_COMPOSITE_RATE_PATTERN.search(scoped_text))


def _formula_preserves_thresholded_rate_mechanics(formula: str) -> bool:
    """Return whether a local formula appears to preserve limited-rate mechanics."""
    normalized = _normalize_identifier(formula)
    if any(
        token in normalized
        for token in (
            "threshold",
            "excess",
            "cap",
            "capped",
            "ceiling",
            "limit",
            "limited",
        )
    ):
        return True
    return bool(re.search(r"\bmin\s*\(", formula))


@dataclass(frozen=True)
class _CrossReferenceBaseObligation:
    section: str
    subsections: str
    affected_children: tuple[str, ...]


def _extract_cross_reference_base_obligations(
    source_text: str,
) -> list[_CrossReferenceBaseObligation]:
    """Return cited base-mechanics sections that must affect local amount rules."""
    obligations: list[_CrossReferenceBaseObligation] = []
    seen: set[tuple[str, str, tuple[str, ...]]] = set()
    pattern = re.compile(
        r"\bFor\s+application\s+of\s+"
        r"(?P<description>.{0,220}?\b(?:base|bases|cap|caps|limit|limits)"
        r".{0,220}?)"
        r"\s+(?:with\s+respect\s+to|to|for)\s+"
        r"(?P<target>.{0,220}?)"
        r"\bsee\s+section\s+(?P<section>[0-9][A-Za-z0-9.-]*)"
        r"(?P<subsections>(?:\([A-Za-z0-9]+\))+)?",
        flags=re.IGNORECASE | re.DOTALL,
    )
    for match in pattern.finditer(source_text):
        description = match.group("description") or ""
        target = match.group("target") or ""
        if not re.search(
            r"\b(?:compensation|contribution|wage|remuneration|payment|taxable)\b",
            description,
            flags=re.IGNORECASE,
        ):
            continue
        if not re.search(r"\b(?:tax|taxes|amount|rate|rates)\b", target, re.I):
            continue
        affected_children = _extract_referenced_source_children(target)
        section = str(match.group("section") or "").strip()
        subsections = str(match.group("subsections") or "").strip()
        key = (section, subsections, affected_children)
        if not section or key in seen:
            continue
        seen.add(key)
        obligations.append(
            _CrossReferenceBaseObligation(
                section=section,
                subsections=subsections,
                affected_children=affected_children,
            )
        )
    return obligations


def _extract_referenced_source_children(text: str) -> tuple[str, ...]:
    """Extract top-level source children from phrases like ``subsections (a) and (b)``."""
    children: list[str] = []
    for match in re.finditer(
        r"\bsubsections?\s+((?:\([A-Za-z0-9]+\)"
        r"(?:\s*(?:,|and|or)\s*)?)+)",
        text,
        flags=re.IGNORECASE,
    ):
        children.extend(re.findall(r"\(([A-Za-z0-9]+)\)", match.group(1)))
    return tuple(dict.fromkeys(child.lower() for child in children if child))


def _formula_uses_raw_compensation_base(identifiers: set[str]) -> bool:
    """Return whether a formula appears to use a raw payroll-style amount base."""
    raw_base_tokens = {
        "compensation",
        "wage",
        "wages",
        "remuneration",
        "payment",
        "payments",
        "paid",
        "pay",
        "salary",
    }
    for identifier in identifiers:
        tokens = set(_normalize_identifier(identifier).split("_"))
        if tokens.intersection(raw_base_tokens):
            return True
    return False


def _formula_uses_cross_reference_base_mechanics(
    identifiers: set[str],
    *,
    imports_by_fragment: dict[str, str],
    section: str,
) -> bool:
    """Return whether a formula imports or references cited base mechanics."""
    normalized_section = _normalize_identifier(section)
    mechanics_tokens = {
        "base",
        "bases",
        "cap",
        "capped",
        "ceiling",
        "contribution",
        "excess",
        "exclude",
        "excluded",
        "exclusion",
        "limit",
        "limited",
        "remaining",
    }
    for identifier in identifiers:
        import_item = imports_by_fragment.get(identifier)
        if import_item and f"/{section}" in import_item:
            return True
        normalized = _normalize_identifier(identifier)
        tokens = set(normalized.split("_"))
        if normalized_section and normalized_section in tokens:
            return True
        if tokens.intersection(mechanics_tokens) and "base" in tokens:
            return True
        if tokens.intersection({"excess", "excluded", "remaining", "limit"}):
            return True
    return False


def find_test_input_assignment_issues(
    content: str,
    test_cases: Any,
) -> list[str]:
    """Require tests to assign every local factual input used by formulas."""
    if not isinstance(test_cases, list):
        return []
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    module = payload.get("module")
    proof_validation = (
        module.get("proof_validation") if isinstance(module, dict) else {}
    )
    if not (
        isinstance(proof_validation, dict) and proof_validation.get("required") is True
    ):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    defined_symbols = _defined_rulespec_symbols(rules)
    imported_symbols = _rulespec_import_fragment_names(payload.get("imports"))
    symbol_inputs: dict[str, set[str]] = {}
    symbol_dependencies: dict[str, set[str]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not rule_name:
            continue
        if str(rule.get("kind") or "").strip().lower() == "parameter":
            index_names = _indexed_by_input_names(rule.get("indexed_by"))
            symbol_inputs[rule_name] = index_names - defined_symbols - imported_symbols
            symbol_dependencies[rule_name] = index_names & defined_symbols
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        formula_identifiers: set[str] = set()
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            formula_identifiers.update(_formula_local_identifiers(formula))
        symbol_inputs[rule_name] = (
            formula_identifiers - defined_symbols - imported_symbols
        )
        symbol_dependencies[rule_name] = formula_identifiers & defined_symbols

    if not symbol_inputs:
        return []

    imports_present = bool(payload.get("imports"))
    assigned_input_names = _all_test_input_names(test_cases)
    globally_local_inputs = (
        set().union(*symbol_inputs.values()) if symbol_inputs else set()
    )
    if imports_present:
        globally_local_inputs &= assigned_input_names
    if not globally_local_inputs:
        return []

    issues: list[str] = []
    for index, test_case in enumerate(test_cases, start=1):
        if not isinstance(test_case, dict):
            continue
        test_name = str(test_case.get("name") or f"case {index}").strip()
        required_inputs = _required_inputs_for_test_outputs(
            test_case.get("output"),
            symbol_inputs=symbol_inputs,
            symbol_dependencies=symbol_dependencies,
        )
        local_inputs = required_inputs & globally_local_inputs
        if not local_inputs:
            continue
        inputs = test_case.get("input")
        assigned = set()
        if isinstance(inputs, dict):
            assigned.update(_input_names_from_mapping(inputs))
        assigned.update(_table_input_names(test_case.get("tables")))
        if not assigned:
            issues.append(
                "Test input assignment missing: "
                f"`{test_name}` must provide `input` facts or `tables` rows "
                "assigning every local factual `#input.<fact>` referenced by "
                "this module's formulas."
            )
            continue
        missing = sorted(local_inputs - assigned)
        if not missing:
            continue
        missing_display = ", ".join(f"#input.{name}" for name in missing[:8])
        if len(missing) > 8:
            missing_display += f", and {len(missing) - 8} more"
        issues.append(
            "Test input assignment missing: "
            f"`{test_name}` does not assign {missing_display}. Every test for a "
            "proof-required RuleSpec module must set all local factual inputs, "
            "including false facts, so tests cannot pass through implicit defaults."
        )
    return issues


def _defined_rulespec_symbols(rules: list[Any]) -> set[str]:
    return {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }


def _indexed_by_input_names(value: Any) -> set[str]:
    if isinstance(value, str):
        return {value.strip()} if value.strip() else set()
    if isinstance(value, list):
        return {str(item).strip() for item in value if str(item).strip()}
    return set()


def _required_inputs_for_test_outputs(
    outputs: Any,
    *,
    symbol_inputs: dict[str, set[str]],
    symbol_dependencies: dict[str, set[str]],
) -> set[str]:
    if not isinstance(outputs, dict):
        return set().union(*symbol_inputs.values()) if symbol_inputs else set()

    required: set[str] = set()
    for output_name in outputs:
        fragment = _test_reference_fragment(output_name)
        if fragment in symbol_inputs:
            required.update(
                _required_inputs_for_symbol(
                    fragment,
                    symbol_inputs=symbol_inputs,
                    symbol_dependencies=symbol_dependencies,
                    seen=set(),
                )
            )
    return required


def _required_inputs_for_symbol(
    symbol: str,
    *,
    symbol_inputs: dict[str, set[str]],
    symbol_dependencies: dict[str, set[str]],
    seen: set[str],
) -> set[str]:
    if symbol in seen:
        return set()
    seen.add(symbol)
    required = set(symbol_inputs.get(symbol, set()))
    for dependency in symbol_dependencies.get(symbol, set()):
        required.update(
            _required_inputs_for_symbol(
                dependency,
                symbol_inputs=symbol_inputs,
                symbol_dependencies=symbol_dependencies,
                seen=seen,
            )
        )
    return required


def _all_test_input_names(test_cases: list[Any]) -> set[str]:
    names: set[str] = set()
    for test_case in test_cases:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if isinstance(inputs, dict):
            names.update(_input_names_from_mapping(inputs))
        names.update(_table_input_names(test_case.get("tables")))
    return names


def _table_input_names(tables: Any) -> set[str]:
    names: set[str] = set()
    if not isinstance(tables, dict):
        return names
    for rows in tables.values():
        if not isinstance(rows, list):
            continue
        for row in rows:
            if isinstance(row, dict):
                names.update(_input_names_from_mapping(row))
    return names


def _test_case_assignment_keys(test_case: dict[str, Any]) -> list[str]:
    keys: list[str] = []
    inputs = test_case.get("input")
    if isinstance(inputs, dict):
        keys.extend(_assignment_keys_from_mapping(inputs))
    tables = test_case.get("tables")
    if isinstance(tables, dict):
        for rows in tables.values():
            if not isinstance(rows, list):
                continue
            for row in rows:
                if isinstance(row, dict):
                    keys.extend(_assignment_keys_from_mapping(row))
    return keys


def _assignment_keys_from_mapping(inputs: dict[Any, Any]) -> list[str]:
    keys: list[str] = []
    for key, value in inputs.items():
        key_text = str(key)
        if key_text not in {"id", "entity_id"} and not key_text.endswith("_id"):
            keys.append(key_text)
        if isinstance(value, list):
            for item in value:
                if isinstance(item, dict):
                    keys.extend(_assignment_keys_from_mapping(item))
    return keys


def _input_names_from_mapping(inputs: dict[Any, Any]) -> set[str]:
    names: set[str] = set()
    for key, value in inputs.items():
        fragment = _test_reference_fragment(key)
        if fragment.startswith("input."):
            names.add(fragment.removeprefix("input."))
        if isinstance(value, list):
            for item in value:
                if isinstance(item, dict):
                    names.update(_input_names_from_mapping(item))
    return names


def find_exception_test_coverage_issues(
    content: str,
    test_cases: Any,
) -> list[str]:
    """Require each encoded exception predicate to have a blocking test."""
    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    if not source_text or not re.search(
        r"\b(?:except|unless|notwithstanding)\b"
        r"|\bshall\s+not\s+include\b"
        r"|\bnot\s+(?:be\s+)?treated\b",
        source_text,
        flags=re.IGNORECASE,
    ):
        return []

    if not isinstance(test_cases, list):
        return []
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    defined_symbols = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    imported_symbol_bases = _imported_symbol_bases_by_name(content)
    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in {"judgment", "boolean", "bool"}:
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not rule_name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        exception_inputs: set[str] = set()
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            exception_inputs.update(
                _exception_formula_inputs(formula) - defined_symbols
            )
        for exception_input in sorted(exception_inputs):
            if _has_exception_blocking_test(
                test_cases,
                rule_name=rule_name,
                exception_input=exception_input,
                exception_import_base=imported_symbol_bases.get(exception_input),
            ):
                continue
            issues.append(
                "Exception test coverage missing: "
                f"`{rule_name}` negates `{exception_input}`, but no companion test "
                f"sets `#input.{exception_input}` true and expects `{rule_name}` "
                "to be not_holds while an otherwise identical positive companion "
                "sets that exception false and expects holds."
            )
    return issues


def find_aggregate_exception_predicate_issues(content: str) -> list[str]:
    """Flag source exception lists collapsed into one factual predicate."""
    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    if not source_text or not re.search(
        r"\b(?:except|unless|notwithstanding)\b",
        source_text,
        flags=re.IGNORECASE,
    ):
        return []

    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    defined_symbols = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip() or "<unnamed>"
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            for identifier in sorted(_formula_local_identifiers(formula)):
                if identifier in defined_symbols:
                    continue
                if not _is_aggregate_exception_identifier(identifier):
                    continue
                issues.append(
                    "Aggregate exception predicate: "
                    f"`{rule_name}` references `{identifier}`, which collapses "
                    "multiple cited exception/cross-reference carve-outs into one "
                    "factual input. Encode or import each cited exception separately "
                    "so each one can be tested independently."
                )
    return issues


def find_unconsumed_local_exception_output_issues(content: str) -> list[str]:
    """Require local exception outputs to block matching exported apply rules."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    formulas_by_name: dict[str, list[str]] = {}
    imported_outputs_by_name: dict[str, set[str]] = {}
    dtypes_by_name: dict[str, str] = {}
    exception_names: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype:
            dtypes_by_name[name] = dtype
        formulas = _rule_formula_texts(rule)
        if formulas:
            formulas_by_name[name] = formulas
        imported_outputs_by_name[name] = _rule_imported_outputs(rule)
        if _is_exception_identifier(name) and _rule_has_shall_not_apply_exception_atom(
            rule
        ):
            exception_names.append(name)

    if not exception_names:
        return []

    issues: list[str] = []
    for exception_name in exception_names:
        target_fragments = _exception_output_target_fragments(exception_name)
        for rule_name, formulas in sorted(formulas_by_name.items()):
            if rule_name == exception_name:
                continue
            imports_exception = exception_name in imported_outputs_by_name.get(
                rule_name,
                set(),
            )
            name_matches_exception_target = bool(
                target_fragments
                and rule_name.endswith("_applies")
                and _exception_fragments_match_rule_name(
                    target_fragments,
                    rule_name,
                )
            )
            if not imports_exception and not name_matches_exception_target:
                continue
            target_is_judgment_exception_output = dtypes_by_name.get(
                rule_name
            ) == "judgment" and _is_exception_identifier(rule_name)
            if (
                any(
                    _formula_negates_identifier(formula, exception_name)
                    for formula in formulas
                )
                and not target_is_judgment_exception_output
            ):
                continue
            if _is_positive_excluded_amount_output(
                rule_name,
                dtype=dtypes_by_name.get(rule_name),
            ) and any(
                _formula_uses_identifier_as_positive_exclusion_amount(
                    formula,
                    exception_name,
                )
                for formula in formulas
            ):
                continue
            if target_is_judgment_exception_output and any(
                _formula_uses_identifier_as_positive_exception_component(
                    formula,
                    exception_name,
                )
                for formula in formulas
            ):
                continue
            issues.append(
                "Unconsumed local exception output: "
                f"`{exception_name}` appears to carve out `{rule_name}`, but "
                f"`{rule_name}` does not negate it. Compose the exception into "
                "the affected exported rule instead of exposing both outputs "
                "independently."
            )
    return issues


def _rule_formula_texts(rule: dict[Any, Any]) -> list[str]:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return []
    formulas: list[str] = []
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            formulas.append(formula)
    return formulas


def _rule_imported_outputs(rule: dict[Any, Any]) -> set[str]:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return set()
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return set()
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return set()

    outputs: set[str] = set()
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        imported = atom.get("import")
        if not isinstance(imported, dict):
            continue
        output = str(imported.get("output") or "").strip()
        if output:
            outputs.add(output)
    return outputs


def _rule_has_shall_not_apply_exception_atom(rule: dict[Any, Any]) -> bool:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return False
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return False
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return False
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        if str(atom.get("kind") or "").strip().lower() != "exception":
            continue
        source = atom.get("source")
        if not isinstance(source, dict):
            continue
        excerpt = str(source.get("excerpt") or "")
        if re.search(
            r"\b(?:shall|does)\s+not\s+(?:be\s+)?appl(?:y|icable)\b",
            excerpt,
            flags=re.IGNORECASE,
        ):
            return True
    return False


def _exception_output_target_fragments(exception_name: str) -> list[set[str]]:
    _, _, suffix = exception_name.partition("_exception_to_")
    if not suffix:
        return []
    fragments: list[set[str]] = []
    for raw_fragment in suffix.split("_and_"):
        fragment = re.sub(
            r"^(?:subsection|section|paragraph|subparagraph|clause)_",
            "",
            raw_fragment,
            flags=re.IGNORECASE,
        )
        tokens = _identifier_token_set(fragment)
        if len(tokens) >= 2:
            fragments.append(tokens)
    return fragments


def _exception_fragments_match_rule_name(
    target_fragments: list[set[str]],
    rule_name: str,
) -> bool:
    rule_tokens = _identifier_token_set(rule_name)
    return any(fragment <= rule_tokens for fragment in target_fragments)


def _identifier_token_set(identifier: str) -> set[str]:
    return {token.lower() for token in re.findall(r"[A-Za-z0-9]+", identifier) if token}


def _formula_negates_identifier(formula: str, identifier: str) -> bool:
    return bool(
        re.search(
            rf"\bnot\s+(?:\(\s*)?{re.escape(identifier)}\b",
            formula,
        )
    )


def _is_positive_excluded_amount_output(
    rule_name: str,
    *,
    dtype: str | None,
) -> bool:
    return dtype in {"decimal", "integer", "money", "number"} and (
        "_excluded_from_" in rule_name or "_disregarded_for_" in rule_name
    )


def _formula_uses_identifier_as_positive_exclusion_amount(
    formula: str,
    identifier: str,
) -> bool:
    normalized = " ".join(formula.split())
    match = re.fullmatch(
        r"if\s+(?P<condition>.+?)\s*:\s*(?P<positive>.+?)\s+else\s*:\s*0(?:\.0+)?",
        normalized,
    )
    if match is None:
        return False
    condition = _strip_wrapping_parentheses(match.group("condition").strip())
    return condition == identifier


def _formula_uses_identifier_as_positive_exception_component(
    formula: str,
    identifier: str,
) -> bool:
    normalized = _strip_wrapping_parentheses(" ".join(formula.split()))
    or_terms = _split_top_level_or_terms(normalized)
    if len(or_terms) < 2:
        return False
    return any(_strip_wrapping_parentheses(term) == identifier for term in or_terms)


def _split_top_level_or_terms(expression: str) -> list[str]:
    terms: list[str] = []
    start = 0
    depth = 0
    quote: str | None = None
    i = 0
    while i < len(expression):
        character = expression[i]
        if quote is not None:
            if character == quote:
                quote = None
            i += 1
            continue
        if character in {"'", '"'}:
            quote = character
            i += 1
            continue
        if character == "(":
            depth += 1
            i += 1
            continue
        if character == ")":
            depth = max(0, depth - 1)
            i += 1
            continue
        if depth == 0 and expression[i : i + 4].lower() == " or ":
            terms.append(expression[start:i].strip())
            i += 4
            start = i
            continue
        i += 1
    terms.append(expression[start:].strip())
    return terms


def _strip_wrapping_parentheses(text: str) -> str:
    while text.startswith("(") and text.endswith(")"):
        inner = text[1:-1].strip()
        if not inner or not _parentheses_balanced(inner):
            break
        text = inner
    return text


def _parentheses_balanced(text: str) -> bool:
    depth = 0
    for character in text:
        if character == "(":
            depth += 1
        elif character == ")":
            depth -= 1
            if depth < 0:
                return False
    return depth == 0


def find_missing_child_exception_import_issues(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Require parent exception-list slices to import existing child exceptions."""
    source_text = extract_embedded_source_text(
        content
    ) or _extract_source_verification_text(content)
    if not source_text or not _source_text_opens_exception_list(source_text):
        return []

    child_root = rules_file.with_suffix("")
    if not child_root.is_dir():
        return []

    child_exports: list[tuple[str, str]] = []
    for child_file in sorted(child_root.rglob("*.yaml")):
        if child_file.name.endswith(".test.yaml"):
            continue
        for export in _rulespec_file_exception_exports(child_file):
            with contextlib.suppress(ValueError):
                child_rel = child_file.resolve().relative_to(policy_repo_path.resolve())
                child_target = child_rel.with_suffix("").as_posix()
                child_exports.append((child_target, export))
    if not child_exports:
        return []

    formula_identifiers = _rulespec_content_formula_identifiers(content)
    if not formula_identifiers:
        return []

    imports = {
        _normalize_rulespec_import_path_static(import_path)
        for import_path in _extract_import_paths_from_content(content)
    }
    missing_refs: list[str] = []
    prefix = _rulespec_repo_prefix(policy_repo_path)
    for child_target, export in child_exports:
        if _imports_cover_path_static(imports, child_target) and (
            export in formula_identifiers
        ):
            continue
        missing_refs.append(f"{prefix}:{child_target}#{export}")

    if not missing_refs:
        return []
    visible = ", ".join(f"`{ref}`" for ref in missing_refs[:8])
    if len(missing_refs) > 8:
        visible += ", ..."
    return [
        "Parent exception-list child import missing: "
        "source text opens an exception/exclusion list, but the parent formula "
        f"does not import and use existing child exception outputs {visible}. "
        "Import each child exception output and negate it in the affected "
        "definition instead of leaving only the positive definition conditions."
    ]


def _source_text_opens_exception_list(source_text: str) -> bool:
    normalized = " ".join(source_text.split())
    return bool(
        re.search(
            r"\b(?:exceptions?|exclusions?)\b[^.:\n]{0,180}\b(?:following|below)\b\s*:?"
            r"|\b(?:such\s+term\s+)?shall\s+not\s+include\b[^.:\n]{0,220}\b(?:following|below)\b\s*:?"
            r"|\bnot\s+(?:be\s+)?treated\b[^.:\n]{0,220}\b(?:unless|following|below)\b\s*:?",
            normalized,
            flags=re.IGNORECASE,
        )
    )


def _rulespec_file_exception_exports(rules_file: Path) -> list[str]:
    try:
        payload = yaml.safe_load(rules_file.read_text())
    except (OSError, yaml.YAMLError, TypeError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    terminal_exports = set(_rulespec_file_terminal_exports(payload))
    exports: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if not name or name not in terminal_exports:
            continue
        if _is_exception_identifier(name):
            exports.append(name)
    return exports


def _rulespec_file_terminal_exports(payload: dict[Any, Any]) -> list[str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    exports: list[str] = []
    formulas: list[tuple[str, str]] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "parameter",
            "derived",
        }:
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        exports.append(name)
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, (int, float)) and not isinstance(formula, bool):
                formulas.append((name, str(formula)))
            elif isinstance(formula, str) and formula.strip():
                formulas.append((name, formula))
    if not exports:
        return []
    export_names = set(exports)
    referenced: set[str] = set()
    for owner, formula in formulas:
        referenced.update(
            identifier
            for identifier in _formula_local_identifiers(formula)
            if identifier in export_names and identifier != owner
        )
    terminal = [name for name in exports if name not in referenced]
    return terminal or exports


def _rule_has_exception_proof(rule: dict[str, Any]) -> bool:
    try:
        atoms = rule["metadata"]["proof"]["atoms"]
    except (KeyError, TypeError):
        return False
    if not isinstance(atoms, list):
        return False
    return any(
        isinstance(atom, dict)
        and str(atom.get("kind") or "").strip().lower() in {"exception", "exclusion"}
        for atom in atoms
    )


def _rulespec_content_formula_identifiers(content: str) -> set[str]:
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, TypeError, ValueError):
        return set()
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    identifiers: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, str):
                identifiers.update(_formula_local_identifiers(formula))
    return identifiers


def _is_aggregate_exception_identifier(identifier: str) -> bool:
    normalized = identifier.lower()
    if "_and_" not in normalized:
        return False
    if "section" not in normalized and "subsection" not in normalized:
        return False
    return any(
        token in normalized
        for token in ("exception", "except", "preclude", "displace", "carve")
    )


def _exception_formula_inputs(formula: str) -> set[str]:
    return {
        match.group(1)
        for match in re.finditer(r"\bnot\s+([A-Za-z_][A-Za-z0-9_]*)\b", formula)
        if _is_exception_identifier(match.group(1))
    }


def _title_qualified_reference_for_section(
    section: str,
    source_text: str,
) -> str | None:
    """Return the USC title when source says `section X of title Y`."""
    match = re.search(
        rf"\bsection\s+{re.escape(section)}(?:\([^)]+\))*\s+of\s+title\s+"
        r"(?P<title>[0-9]+)\b",
        source_text,
        flags=re.IGNORECASE,
    )
    if match:
        return match.group("title")
    return None


def _section_reference_to_named_act_without_title(
    section: str,
    source_text: str,
    *,
    identifier: str | None = None,
) -> bool:
    """Return whether source cites `section X of the Some Act` without USC title."""
    named_acts = _named_act_references_for_section(section, source_text)
    if not named_acts:
        return False
    if (
        _title_qualified_reference_for_section(section, source_text)
        and identifier is not None
    ):
        return any(
            _identifier_mentions_named_act(identifier, named_act)
            for named_act in named_acts
        )
    if _title_qualified_reference_for_section(section, source_text):
        return False
    return True


def _named_act_references_for_section(section: str, source_text: str) -> list[str]:
    """Return named acts cited with `section X` without a USC title."""
    names: list[str] = []
    for match in re.finditer(
        rf"\bsection\s+{re.escape(section)}(?:\([^)]+\))*\s+of\s+"
        r"(?:the\s+)?(?!title\s+\d+\b)"
        r"(?P<act>[A-Z][A-Za-z0-9'&.-]*(?:\s+[A-Z][A-Za-z0-9'&.-]*){0,8}\s+Act)\b",
        source_text,
        flags=re.IGNORECASE,
    ):
        names.append(match.group("act"))
    for match in re.finditer(
        r"\b(?P<act>[A-Z][A-Za-z0-9'&.-]*(?:\s+[A-Z][A-Za-z0-9'&.-]*){0,8}\s+Act)"
        rf"\s+section\s+{re.escape(section)}(?:\([^)]+\))*\b",
        source_text,
        flags=re.IGNORECASE,
    ):
        names.append(match.group("act"))
    return names


def _identifier_mentions_named_act(identifier: str, named_act: str) -> bool:
    identifier_tokens = set(re.findall(r"[a-z0-9]+", identifier.lower()))
    act_tokens = [
        token
        for token in re.findall(r"[a-z0-9]+", named_act.lower())
        if token not in {"a", "act", "an", "by", "of", "the", "to"}
    ]
    for start in range(len(act_tokens)):
        suffix = act_tokens[start:]
        if len(suffix) >= 2 and all(token in identifier_tokens for token in suffix):
            return True
    return bool(act_tokens) and all(token in identifier_tokens for token in act_tokens)


def _is_exception_identifier(identifier: str) -> bool:
    normalized = identifier.lower()
    return any(
        token in normalized
        for token in ("exception", "except", "exclusion", "carve_out", "displace")
    )


def _has_exception_blocking_test(
    test_cases: list[Any],
    *,
    rule_name: str,
    exception_input: str,
    exception_import_base: str | None = None,
) -> bool:
    for test_case in test_cases:
        if not isinstance(test_case, dict):
            continue
        inputs = _test_case_input_assignments(test_case)
        outputs = test_case.get("output")
        if not inputs or not isinstance(outputs, dict):
            continue
        has_direct_exception_toggle = any(
            _test_assignment_targets_exception(key, exception_input)
            and _is_truthy_fact_value(value)
            for key, value in inputs
        )
        has_imported_exception_inputs = bool(
            exception_import_base
            and any(
                _test_assignment_in_import_base(key, exception_import_base)
                for key, _ in inputs
            )
        )
        if not has_direct_exception_toggle and not has_imported_exception_inputs:
            continue
        if not any(
            _test_reference_fragment(key) == rule_name
            and _is_negative_judgment_value(value)
            for key, value in outputs.items()
        ):
            continue
        if _has_exception_positive_companion_test(
            test_cases,
            rule_name=rule_name,
            exception_input=exception_input,
            exception_import_base=exception_import_base,
            negative_inputs=inputs,
        ):
            return True
    return False


def _has_exception_positive_companion_test(
    test_cases: list[Any],
    *,
    rule_name: str,
    exception_input: str,
    exception_import_base: str | None,
    negative_inputs: list[tuple[Any, Any]],
) -> bool:
    """Return true when a positive case proves the exception flips the outcome."""
    expected_inputs = _normalized_test_inputs(
        negative_inputs,
        exclude_input=exception_input,
        exclude_import_base=exception_import_base,
    )
    for test_case in test_cases:
        if not isinstance(test_case, dict):
            continue
        inputs = _test_case_input_assignments(test_case)
        outputs = test_case.get("output")
        if not inputs or not isinstance(outputs, dict):
            continue
        has_direct_exception_toggle = any(
            _test_assignment_targets_exception(key, exception_input)
            and not _is_truthy_fact_value(value)
            for key, value in inputs
        )
        has_imported_exception_inputs = bool(
            exception_import_base
            and any(
                _test_assignment_in_import_base(key, exception_import_base)
                for key, _ in inputs
            )
        )
        if not has_direct_exception_toggle and not has_imported_exception_inputs:
            continue
        if not any(
            _test_reference_fragment(key) == rule_name
            and _is_positive_judgment_value(value)
            for key, value in outputs.items()
        ):
            continue
        if (
            _normalized_test_inputs(
                inputs,
                exclude_input=exception_input,
                exclude_import_base=exception_import_base,
            )
            == expected_inputs
        ):
            return True
    return False


def _normalized_test_inputs(
    inputs: list[tuple[Any, Any]],
    *,
    exclude_input: str,
    exclude_import_base: str | None = None,
) -> dict[str, str]:
    normalized: dict[str, str] = {}
    for key, value in inputs:
        fragment = _test_reference_fragment(key)
        if _test_assignment_targets_exception(key, exclude_input):
            continue
        if exclude_import_base and _test_assignment_in_import_base(
            key, exclude_import_base
        ):
            continue
        normalized[fragment] = _normalized_test_value(value)
    return normalized


def _test_case_input_assignments(test_case: dict[Any, Any]) -> list[tuple[Any, Any]]:
    assignments: list[tuple[Any, Any]] = []
    inputs = test_case.get("input")
    if isinstance(inputs, dict):
        assignments.extend(_iter_test_assignment_items(inputs))
    tables = test_case.get("tables")
    if isinstance(tables, dict):
        assignments.extend(_iter_test_assignment_items(tables))
    return assignments


def _iter_test_assignment_items(value: Any) -> list[tuple[Any, Any]]:
    assignments: list[tuple[Any, Any]] = []
    if isinstance(value, dict):
        for key, item in value.items():
            if isinstance(item, (dict, list)):
                assignments.extend(_iter_test_assignment_items(item))
            else:
                assignments.append((key, item))
    elif isinstance(value, list):
        for item in value:
            assignments.extend(_iter_test_assignment_items(item))
    return assignments


def _test_assignment_targets_exception(key: Any, exception_input: str) -> bool:
    fragment = _test_reference_fragment(key)
    return fragment in {f"input.{exception_input}", exception_input}


def _test_assignment_in_import_base(key: Any, import_base: str) -> bool:
    key_text = str(key).strip()
    if "#" not in key_text:
        return False
    key_base = _normalize_rulespec_import_path_static(key_text.split("#", 1)[0])
    normalized_base = _normalize_rulespec_import_path_static(import_base)
    return key_base == normalized_base


def _imported_symbol_bases_by_name(content: str) -> dict[str, str]:
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, TypeError, ValueError):
        return {}
    if not isinstance(payload, dict):
        return {}
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return {}
    mapping: dict[str, str] = {}
    for item in imports:
        if not isinstance(item, str) or "#" not in item:
            continue
        base, symbol = item.split("#", 1)
        symbol = symbol.strip()
        if symbol:
            mapping[symbol] = base.strip()
    return mapping


def _normalized_test_value(value: Any) -> str:
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, (int, float, str)) or value is None:
        return str(value).strip().lower()
    try:
        return json.dumps(value, sort_keys=True)
    except TypeError:
        return str(value).strip()


def _test_reference_fragment(key: Any) -> str:
    key_text = str(key).strip()
    return key_text.split("#", 1)[1].strip() if "#" in key_text else key_text


def _is_truthy_fact_value(value: Any) -> bool:
    if isinstance(value, list):
        return any(_is_truthy_fact_value(item) for item in value)
    if isinstance(value, bool):
        return value
    return str(value).strip().lower() in {"true", "holds", "yes", "1"}


def _is_positive_judgment_value(value: Any) -> bool:
    if isinstance(value, list):
        return any(_is_positive_judgment_value(item) for item in value)
    return str(value).strip().lower().replace("-", "_") == "holds"


def _is_negative_judgment_value(value: Any) -> bool:
    if isinstance(value, list):
        return any(_is_negative_judgment_value(item) for item in value)
    if isinstance(value, bool):
        return not value
    return str(value).strip().lower() in {"not_holds", "false", "no", "0"}


def _source_verification_block(payload: dict[str, Any]) -> dict[str, Any] | None:
    module = payload.get("module")
    if isinstance(module, dict) and isinstance(module.get("source_verification"), dict):
        return module["source_verification"]
    source_verification = payload.get("source_verification")
    if isinstance(source_verification, dict):
        return source_verification
    return None


def _source_verification_source_fields(
    source_verification: dict[str, Any],
) -> tuple[tuple[str, ...], str]:
    citation_paths: list[str] = []
    raw_citation_path = str(
        source_verification.get("corpus_citation_path") or ""
    ).strip()
    if raw_citation_path:
        citation_paths.append(raw_citation_path)
    raw_citation_paths = source_verification.get("corpus_citation_paths")
    if isinstance(raw_citation_paths, list):
        for raw_path in raw_citation_paths:
            if not isinstance(raw_path, str):
                continue
            citation_path = raw_path.strip()
            if citation_path:
                citation_paths.append(citation_path)
    citation_path_tuple = tuple(dict.fromkeys(citation_paths))
    return citation_path_tuple, ", ".join(citation_path_tuple)


def _source_verification_text(
    *,
    citation_paths: tuple[str, ...],
    source_label: str,
    source_texts: dict[str, str] | None = None,
) -> str | None:
    if source_texts is not None:
        source_text = source_texts.get(source_label)
        if source_text is not None:
            return source_text
    if citation_paths:
        source_text_values: list[str] = []
        for citation_path in citation_paths:
            source_text = (
                source_texts.get(citation_path) if source_texts is not None else None
            )
            if source_text is None:
                source_text = _fetch_corpus_source_text(citation_path)
            if source_text is None:
                return None
            source_text_values.append(source_text)
        return "\n\n".join(source_text_values)
    return None


def _extract_source_verification_text(content: str) -> str | None:
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return None
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return None
    source_verification = _source_verification_block(payload)
    if source_verification is None:
        return None
    citation_paths, source_label = _source_verification_source_fields(
        source_verification
    )
    if not source_label:
        return None
    return _source_verification_text(
        citation_paths=citation_paths,
        source_label=source_label,
    )


def _format_source_verification_paths(citation_paths: tuple[str, ...]) -> str:
    if len(citation_paths) == 1:
        return f"`{citation_paths[0]}`"
    return (
        "`"
        + "`, `".join(citation_paths[:3])
        + ("`, ..." if len(citation_paths) > 3 else "`")
    )


def _compare_source_verification_expected_value(
    *,
    value_name: str,
    expected_value: Any,
    rulespec_value: Any,
) -> list[str]:
    """Check the verification block agrees with the RuleSpec parameter values."""
    if isinstance(expected_value, dict):
        if not isinstance(rulespec_value, dict):
            return [
                "Source verification RuleSpec mismatch: "
                f"`{value_name}` is declared as a table but the RuleSpec value is scalar."
            ]
        issues: list[str] = []
        for raw_key, expected_cell in expected_value.items():
            cell_key = str(raw_key)
            if cell_key not in rulespec_value:
                issues.append(
                    "Source verification RuleSpec value missing: "
                    f"`{value_name}[{cell_key}]` is declared but not defined."
                )
                continue
            actual_cell = rulespec_value[cell_key]
            if not _verification_values_equal(expected_cell, actual_cell):
                issues.append(
                    "Source verification RuleSpec mismatch: "
                    f"`{value_name}[{cell_key}]` declares "
                    f"{_format_verification_value(expected_cell)}, but RuleSpec has "
                    f"{_format_verification_value(actual_cell)}."
                )
        return issues

    if isinstance(rulespec_value, dict):
        return [
            "Source verification RuleSpec mismatch: "
            f"`{value_name}` is declared as a scalar but the RuleSpec value is a table."
        ]
    if _verification_values_equal(expected_value, rulespec_value):
        return []
    return [
        "Source verification RuleSpec mismatch: "
        f"`{value_name}` declares {_format_verification_value(expected_value)}, "
        f"but RuleSpec has {_format_verification_value(rulespec_value)}."
    ]


def _find_source_text_value_issues(
    *,
    source_label: str,
    source_text: str,
    value_name: str,
    expected_value: Any,
) -> list[str]:
    """Check expected values are present in the ingested source page text."""
    normalized_text = _normalize_source_verification_text(source_text)
    if isinstance(expected_value, dict):
        issues: list[str] = []
        for raw_key, expected_cell in expected_value.items():
            cell_key = str(raw_key)
            if not _source_text_contains_indexed_value(
                normalized_text,
                index=cell_key,
                value=expected_cell,
            ):
                issues.append(
                    "Source verification value missing: "
                    f"`{source_label}` does not contain `{value_name}[{cell_key}]` = "
                    f"{_format_verification_value(expected_cell)}."
                )
        if issues and _source_text_contains_table_value_multiset(
            normalized_text,
            expected_value.values(),
        ):
            return []
        return issues

    if _source_text_contains_scalar_value(normalized_text, expected_value):
        return []
    return [
        "Source verification value missing: "
        f"`{source_label}` does not contain `{value_name}` = "
        f"{_format_verification_value(expected_value)}."
    ]


@functools.lru_cache(maxsize=512)
def _fetch_corpus_source_text(citation_path: str) -> str | None:
    """Fetch a corpus.provisions body by citation path.

    Local corpus artifacts are preferred so encoder and CI runs verify against
    normalized source text without re-reading original PDFs or HTML pages.
    Supabase is the network fallback for environments without local artifacts.
    """
    local_text = _fetch_local_corpus_source_text(citation_path)
    if local_text is not None:
        return local_text
    for candidate_path in _candidate_corpus_source_paths(citation_path):
        source_text = _fetch_supabase_corpus_source_text(candidate_path)
        if source_text is not None:
            return source_text
    return None


@functools.lru_cache(maxsize=512)
def _fetch_local_corpus_source_text(citation_path: str) -> str | None:
    normalized_path = citation_path.strip().strip("/")
    if not normalized_path:
        return None

    for provisions_root in _local_corpus_provisions_roots():
        for candidate_path in _candidate_corpus_source_paths(normalized_path):
            exact_records: list[dict[str, Any]] = []
            for provision_file in _candidate_local_corpus_provision_files(
                provisions_root,
                candidate_path,
            ):
                exact_records.extend(
                    _read_local_corpus_provision_records(
                        provision_file,
                        candidate_path,
                    )
                )
            source_text = _select_local_corpus_record_body(exact_records)
            if source_text is not None:
                return source_text

            for provision_file in _candidate_local_corpus_provision_files(
                provisions_root,
                candidate_path,
            ):
                source_text = _read_local_corpus_descendant_text(
                    provision_file,
                    candidate_path,
                )
                if source_text is not None:
                    return source_text
    return None


def _candidate_corpus_source_paths(citation_path: str) -> tuple[str, ...]:
    normalized_path = citation_path.strip().strip("/")
    if not normalized_path:
        return ()

    candidates = [normalized_path]
    candidates.extend(_uk_legislation_gov_source_path_aliases(normalized_path))
    return tuple(dict.fromkeys(candidates))


def _uk_legislation_gov_source_path_aliases(citation_path: str) -> tuple[str, ...]:
    parts = citation_path.split("/")
    if (
        len(parts) >= 6
        and parts[0] == "uk"
        and parts[1] == "statute"
        and parts[2] != "legislation.gov.uk"
    ):
        source_type, year, chapter, *section_parts = parts[2:]
        prefix = (
            "uk",
            "statute",
            "legislation.gov.uk",
            source_type,
            year,
            chapter,
            "section",
        )
        candidates = [
            "/".join(
                (
                    *prefix,
                    *section_parts,
                )
            )
        ]
        lower_section_parts = [part.lower() for part in section_parts]
        if lower_section_parts != section_parts:
            candidates.append(
                "/".join(
                    (
                        *prefix,
                        *lower_section_parts,
                    )
                )
            )
        return tuple(candidates)
    return ()


def _local_corpus_provisions_roots() -> tuple[Path, ...]:
    roots: list[Path] = []
    cwd: Path | None = None
    with contextlib.suppress(OSError):
        cwd = Path.cwd().resolve()
        roots.append(cwd)

    for env_name in (
        "AXIOM_CORPUS_ARTIFACT_ROOT",
        "AXIOM_CORPUS_LOCAL_ROOT",
        "AXIOM_CORPUS_REPO",
    ):
        raw_root = os.environ.get(env_name)
        if raw_root:
            roots.append(Path(raw_root).expanduser())

    if cwd is not None:
        for base in (cwd, *cwd.parents):
            roots.extend(
                (
                    base / "axiom-corpus",
                    base / "TheAxiomFoundation" / "axiom-corpus",
                    base.parent / "axiom-corpus",
                )
            )

    with contextlib.suppress(RuntimeError, OSError):
        roots.append(Path.home() / "TheAxiomFoundation" / "axiom-corpus")

    provisions_roots: list[Path] = []
    seen: set[Path] = set()
    for root in roots:
        for candidate in (
            root,
            root / "provisions",
            root / "data" / "corpus",
            root / "data" / "corpus" / "provisions",
        ):
            provisions_root = (
                candidate
                if candidate.name == "provisions"
                else candidate / "provisions"
            )
            with contextlib.suppress(OSError):
                resolved = provisions_root.resolve()
                if resolved.is_dir() and resolved not in seen:
                    seen.add(resolved)
                    provisions_roots.append(resolved)
    return tuple(provisions_roots)


def _candidate_local_corpus_provision_files(
    provisions_root: Path,
    citation_path: str,
) -> tuple[Path, ...]:
    parts = citation_path.split("/")
    candidates: list[Path] = []
    seen: set[Path] = set()

    def add_files(base: Path) -> None:
        for path in sorted(base.glob("*.jsonl")):
            with contextlib.suppress(OSError):
                resolved = path.resolve()
                if resolved not in seen:
                    seen.add(resolved)
                    candidates.append(resolved)

    if len(parts) >= 2:
        add_files(provisions_root / parts[0] / parts[1])
    if not candidates:
        for path in sorted(provisions_root.rglob("*.jsonl")):
            with contextlib.suppress(OSError):
                resolved = path.resolve()
                if resolved not in seen:
                    seen.add(resolved)
                    candidates.append(resolved)
    return tuple(candidates)


def _read_local_corpus_provision_records(
    provision_file: Path,
    citation_path: str,
) -> list[dict[str, Any]]:
    try:
        lines = provision_file.read_text(encoding="utf-8").splitlines()
    except OSError:
        return []
    records: list[dict[str, Any]] = []
    for line in lines:
        if not line.strip():
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError:
            continue
        if not isinstance(record, dict) or record.get("citation_path") != citation_path:
            continue
        records.append(record)
    return records


def _read_local_corpus_provision_file(
    provision_file: Path,
    citation_path: str,
) -> str | None:
    records = _read_local_corpus_provision_records(provision_file, citation_path)
    return _select_local_corpus_record_body(records)


def _select_local_corpus_record_body(records: list[dict[str, Any]]) -> str | None:
    """Select the best body when local corpus files contain duplicate citations."""
    body_records = [record for record in records if record.get("body") is not None]
    if not body_records:
        return None

    def record_key(record: dict[str, Any]) -> tuple[str, int, str]:
        source_as_of = str(record.get("source_as_of") or "")
        source_format = str(record.get("source_format") or "")
        official_source = 1 if source_format == "legislation.gov.uk-clml" else 0
        version = str(record.get("version") or "")
        return (source_as_of, official_source, version)

    selected = max(body_records, key=record_key)
    return str(selected["body"])


def _read_local_corpus_descendant_text(
    provision_file: Path,
    citation_path: str,
) -> str | None:
    """Read body-bearing child provisions for a metadata-only source document."""
    try:
        lines = provision_file.read_text(encoding="utf-8").splitlines()
    except OSError:
        return None

    descendants: list[tuple[int, int, str | None, str]] = []
    child_prefix = f"{citation_path}/"
    for line in lines:
        if not line.strip():
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError:
            continue
        if not isinstance(record, dict):
            continue
        record_path = str(record.get("citation_path") or "")
        if not record_path.startswith(child_prefix):
            continue
        body = record.get("body")
        if body is None:
            continue
        descendants.append(
            (
                int(record.get("level") or 0),
                int(record.get("ordinal") or 0),
                str(record.get("heading") or "") or None,
                str(body),
            )
        )

    if not descendants:
        return None
    chunks: list[str] = []
    for _, _, heading, body in sorted(descendants):
        if heading:
            chunks.append(f"{heading}\n\n{body}")
        else:
            chunks.append(body)
    return "\n\n".join(chunks)


@functools.lru_cache(maxsize=512)
def _fetch_supabase_corpus_source_text(citation_path: str) -> str | None:
    """Fetch current corpus source text by exact citation path from Supabase."""
    supabase_url = os.environ.get(
        "AXIOM_SUPABASE_URL", DEFAULT_AXIOM_SUPABASE_URL
    ).rstrip("/")
    anon_key = (
        os.environ.get("SUPABASE_ANON_KEY")
        or os.environ.get("NEXT_PUBLIC_SUPABASE_ANON_KEY")
        or DEFAULT_AXIOM_SUPABASE_ANON_KEY
    )
    params = urllib.parse.urlencode(
        {
            "select": "body",
            "citation_path": f"eq.{citation_path}",
            "limit": "1",
        }
    )
    request = urllib.request.Request(
        f"{supabase_url}/rest/v1/current_provisions?{params}",
        headers={
            "apikey": anon_key,
            "Authorization": f"Bearer {anon_key}",
            "Accept-Profile": "corpus",
        },
    )
    try:
        with urllib.request.urlopen(request, timeout=20) as response:
            data = json.loads(response.read())
    except (
        TimeoutError,
        urllib.error.HTTPError,
        urllib.error.URLError,
        json.JSONDecodeError,
    ):
        return None
    if not isinstance(data, list) or not data:
        return None
    body = data[0].get("body") if isinstance(data[0], dict) else None
    return str(body) if body is not None else None


def _normalize_source_verification_text(text: str) -> str:
    return re.sub(r"\s+", " ", text.replace(",", "")).strip()


def _source_text_contains_indexed_value(text: str, *, index: str, value: Any) -> bool:
    value_texts = _source_verification_numeric_texts(value)
    if not value_texts:
        return False
    index_text = re.escape(str(index).replace(",", ""))
    return any(
        re.search(
            rf"(?<!\d){index_text}\s+\$?{re.escape(value_text)}(?!\d)",
            text,
            re.IGNORECASE,
        )
        for value_text in value_texts
    )


def _source_text_contains_scalar_value(text: str, value: Any) -> bool:
    value_texts = _source_verification_numeric_texts(value)
    if not value_texts:
        return str(value).strip() in text
    return any(
        re.search(
            rf"(?:\$|\+)?{re.escape(value_text)}(?!\d)",
            text,
            re.IGNORECASE,
        )
        for value_text in value_texts
    )


def _source_text_contains_table_value_multiset(
    text: str,
    values: Iterable[Any],
) -> bool:
    expected_counts: Counter[str] = Counter()
    for value in values:
        value_texts = _source_verification_numeric_texts(value)
        if not value_texts:
            return False
        expected_counts["\0".join(value_texts)] += 1

    return all(
        max(
            _source_text_value_occurrence_count(text, value_text)
            for value_text in value_texts_key.split("\0")
        )
        >= expected_count
        for value_texts_key, expected_count in expected_counts.items()
    )


def _source_text_value_occurrence_count(text: str, value_text: str) -> int:
    value_pattern = re.escape(value_text)
    return len(re.findall(rf"(?:\$|\+)?{value_pattern}(?!\d)", text, re.IGNORECASE))


def _source_verification_numeric_text(value: Any) -> str | None:
    texts = _source_verification_numeric_texts(value)
    return texts[0] if texts else None


def _source_verification_numeric_texts(value: Any) -> tuple[str, ...]:
    numeric = _numeric_rule_value(value)
    if numeric is None:
        return ()
    raw, number = numeric
    texts: list[str] = []
    if float(number).is_integer():
        texts.append(str(int(number)))
    else:
        texts.append(raw.replace(",", ""))
    with contextlib.suppress(TypeError, ValueError):
        numeric_float = float(number)
        if 0 < abs(numeric_float) <= 1:
            percent = numeric_float * 100
            percent_text = (
                str(int(percent)) if float(percent).is_integer() else f"{percent:g}"
            )
            texts.append(percent_text)
            texts.append(f"{percent_text}%")
            texts.append(f"{percent_text} percent")
            texts.append(f"{percent_text}-percent")
            texts.append(f"{percent_text} per cent")
            if float(percent).is_integer():
                percent_word = _CARDINAL_VALUE_WORDS.get(int(percent))
                if percent_word:
                    texts.append(f"{percent_word} percent")
                    texts.append(f"{percent_word} per cent")
    return tuple(dict.fromkeys(texts))


@dataclass(frozen=True)
class _RuleSpecTargetRef:
    """Parsed canonical RuleSpec target reference."""

    prefix: str
    repo_name: str
    relative_path: Path
    symbol: str | None


@dataclass(frozen=True)
class _DelegatedPolicySettingTarget:
    """Canonical target for a delegated downstream policy setting."""

    label: str
    target: str
    rule_name_patterns: tuple[str, ...]


_US_STATE_RULESPEC_PATH_PART = re.compile(r"(?:rulespec-)?us-[a-z]{2}(?:-[a-z0-9]+)*")
_SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS = (
    _DelegatedPolicySettingTarget(
        label="standard utility allowance",
        target=(
            "us:regulations/7-cfr/273/9#snap_standard_utility_allowance_state_option"
        ),
        rule_name_patterns=(
            r"^snap_standard_utility_allowance(?:_amount)?$",
            r"^.*heating_cooling_standard_utility_allowance.*$",
            r"^.*standard_utility_allowance.*$",
        ),
    ),
    _DelegatedPolicySettingTarget(
        label="limited utility allowance",
        target=(
            "us:regulations/7-cfr/273/9#snap_limited_utility_allowance_state_option"
        ),
        rule_name_patterns=(
            r"^snap_limited_utility_allowance(?:_amount)?$",
            r"^.*basic_utility_allowance.*$",
            r"^.*limited_utility_allowance.*$",
        ),
    ),
    _DelegatedPolicySettingTarget(
        label="individual utility allowance",
        target=(
            "us:regulations/7-cfr/273/9#snap_individual_utility_allowance_state_option"
        ),
        rule_name_patterns=(
            r"^snap_individual_utility_allowance(?:_amount)?$",
            r"^.*telephone_utility_allowance.*$",
            r"^.*telephone_standard.*$",
            r"^.*one_utility_allowance.*$",
        ),
    ),
)
_DELEGATED_SETTING_AMOUNT_DTYPES = {"money"}


def find_source_relation_issues(
    content: str,
    *,
    policy_repo_path: Path | None = None,
) -> list[str]:
    """Validate non-executable source-relation records."""
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").lower() != "source_relation":
            continue
        name = str(rule.get("name") or "<unknown>")
        source_relation = rule.get("source_relation")
        target = ""
        target_ref: _RuleSpecTargetRef | None = None
        relation_type = ""
        if isinstance(source_relation, dict):
            relation_type = str(source_relation.get("type") or "").strip().lower()
        if relation_type not in {
            "amends",
            "delegates",
            "implements",
            "restates",
            "sets",
        }:
            continue
        if (
            not isinstance(source_relation, dict)
            or not str(source_relation.get("target") or "").strip()
        ):
            issues.append(
                "Source relation target required: "
                f"{name} must declare `source_relation.target` pointing to the canonical RuleSpec rule."
            )
        else:
            target = str(source_relation.get("target") or "").strip()
            target_ref = _parse_rulespec_target(target)
            if target_ref is None:
                issues.append(
                    "Source relation target invalid: "
                    f"{name} uses `{target}`, expected `<jurisdiction>:<path>#<rule>`."
                )
            elif target_ref.symbol is None and relation_type in {"restates", "sets"}:
                issues.append(
                    "Source relation target rule required: "
                    f"{name} must point to a specific RuleSpec rule with `#rule_name`."
                )
        if rule.get("versions"):
            issues.append(
                "Source relation must be non-executable: "
                f"{name} should not declare `versions`; use the canonical target for formulas and values."
            )
        if relation_type == "sets":
            value = (
                source_relation.get("value")
                if isinstance(source_relation, dict)
                else None
            )
            if value is None or (isinstance(value, str) and not value.strip()):
                issues.append(
                    "Source relation setting value required: "
                    f"{name} uses `source_relation.type: sets` and must declare "
                    "`source_relation.value` pointing to the local value or formula "
                    "that fills the delegated slot."
                )
            basis = (
                source_relation.get("basis")
                if isinstance(source_relation, dict)
                else None
            )
            delegation = basis.get("delegation") if isinstance(basis, dict) else None
            if not isinstance(delegation, str) or not delegation.strip():
                issues.append(
                    "Source relation delegation basis required: "
                    f"{name} uses `source_relation.type: sets` and must declare "
                    "`source_relation.basis.delegation` pointing to the upstream "
                    "delegation authority."
                )
        verification = rule.get("verification")
        if (
            relation_type == "restates"
            and target
            and target_ref is not None
            and target_ref.symbol is not None
            and isinstance(verification, dict)
            and isinstance(verification.get("values"), dict)
        ):
            issues.extend(
                _find_source_relation_value_verification_issues(
                    name=name,
                    target=target,
                    target_ref=target_ref,
                    expected_values=verification["values"],
                    policy_repo_path=policy_repo_path,
                )
            )
    return issues


def find_delegated_policy_setting_issues(
    content: str,
    *,
    rules_file: Path | None = None,
) -> list[str]:
    """Require downstream state settings to use the canonical delegated hook."""
    payload = _rulespec_payload(content)
    if payload is None or payload.get("format") != "rulespec/v1":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list) or not _is_us_state_rulespec_path(rules_file):
        return []
    if not _looks_like_snap_utility_allowance_module(payload, rules_file=rules_file):
        return []

    issues: list[str] = []
    for setting_target in _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS:
        local_rule_names = _matching_delegated_setting_rule_names(
            rules,
            setting_target.rule_name_patterns,
        )
        if not local_rule_names:
            continue
        if _rules_include_source_relation_target(
            rules,
            setting_target.target,
            relation_type="sets",
        ):
            continue
        wrong_relations = _source_relation_sets_rules_for_local_values(
            rules,
            local_rule_names,
        )
        if wrong_relations:
            for relation_name, target in wrong_relations:
                issues.append(
                    "Delegated policy setting wrong source_relation target: "
                    f"`{relation_name}` points a state-set SNAP {setting_target.label} "
                    f"to `{target}`. The canonical target is "
                    f"`{setting_target.target}`; `source_relation.value` should "
                    "point to the local setting and `source_relation.basis.delegation` "
                    "should point to the upstream delegation authority."
                )
            continue
        local_list = ", ".join(f"`{name}`" for name in local_rule_names)
        issues.append(
            "Delegated policy setting missing source_relation: "
            f"{local_list} encodes a state-set SNAP {setting_target.label}. "
            "The canonical encoding is a non-executable `kind: source_relation` "
            "record with `source_relation.type: sets`, "
            f"`source_relation.target: {setting_target.target}`, "
            "`source_relation.value` pointing to the local setting, and "
            "`source_relation.basis.delegation` pointing to the upstream "
            "delegation authority. Executable formulas should consume the "
            "federal delegated hook rather than a state-specific local output."
        )
    return issues


def _source_relation_sets_rules_for_local_values(
    rules: list[Any],
    local_rule_names: list[str],
) -> list[tuple[str, str]]:
    local_names = set(local_rule_names)
    matches: list[tuple[str, str]] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        if str(source_relation.get("type") or "").strip().lower() != "sets":
            continue
        value = _normalize_relation_target(source_relation.get("value"))
        if not value:
            continue
        value_name = value.rsplit("#", 1)[-1] if "#" in value else value
        if value_name not in local_names:
            continue
        target = _normalize_relation_target(source_relation.get("target"))
        if not target:
            continue
        matches.append((_rulespec_rule_name(rule), target))
    return matches


def _is_us_state_rulespec_path(rules_file: Path | None) -> bool:
    if rules_file is None:
        return False
    return any(
        _US_STATE_RULESPEC_PATH_PART.fullmatch(part) is not None
        for part in rules_file.parts
    )


def _looks_like_snap_utility_allowance_module(
    payload: dict[str, Any],
    *,
    rules_file: Path | None,
) -> bool:
    text_parts: list[str] = []
    if rules_file is not None:
        text_parts.extend(part.lower() for part in rules_file.parts)
    module = payload.get("module")
    if isinstance(module, dict):
        summary = module.get("summary")
        if isinstance(summary, str):
            text_parts.append(summary.lower())
    rules = payload.get("rules")
    if isinstance(rules, list):
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            text_parts.append(str(rule.get("name") or "").lower())
            source = rule.get("source")
            if isinstance(source, str):
                text_parts.append(source.lower())
    text = "\n".join(text_parts)
    return (
        "snap" in text
        or "supplemental nutrition" in text
        or "food and nutrition" in text
        or re.search(r"(?:^|[/_\-\s])fns(?:$|[/_\-\s])", text) is not None
    )


def _matching_delegated_setting_rule_names(
    rules: list[Any],
    patterns: tuple[str, ...],
) -> list[str]:
    compiled_patterns = tuple(re.compile(pattern) for pattern in patterns)
    matches: list[str] = []
    for rule in rules:
        if not _is_executable_rulespec_rule(rule):
            continue
        assert isinstance(rule, dict)
        dtype = str(rule.get("dtype") or "").strip().lower()
        if dtype not in _DELEGATED_SETTING_AMOUNT_DTYPES:
            continue
        name = _rulespec_rule_name(rule)
        normalized_name = name.lower()
        if any(pattern.fullmatch(normalized_name) for pattern in compiled_patterns):
            matches.append(name)
    return sorted(dict.fromkeys(matches))


def _find_source_relation_value_verification_issues(
    *,
    name: str,
    target: str,
    target_ref: _RuleSpecTargetRef,
    expected_values: dict[Any, Any],
    policy_repo_path: Path | None,
) -> list[str]:
    """Compare a source relation's expected values against its canonical target file."""
    target_file = _resolve_rulespec_target_file(target_ref, policy_repo_path)
    if target_file is None:
        return [
            "Source relation verification target unavailable: "
            f"{name} points to `{target}`, but repository `{target_ref.repo_name}` "
            "was not found."
        ]

    target_values, target_symbols, load_issue = _extract_source_relation_target_values(
        target_file
    )
    if load_issue is not None:
        return [
            "Source relation verification target invalid: "
            f"{name} points to `{target}`, but {load_issue}"
        ]

    issues: list[str] = []
    if target_ref.symbol and target_ref.symbol not in target_symbols:
        issues.append(
            "Source relation target rule missing: "
            f"{name} points to `{target}`, but `{target_ref.symbol}` is not defined "
            f"in {target_ref.relative_path}."
        )

    for value_name, expected_value in expected_values.items():
        value_key = str(value_name)
        if value_key not in target_values:
            issues.append(
                "Source relation verification target missing value: "
                f"{name} expects `{value_key}` but `{target}` does not define it."
            )
            continue
        actual_value = target_values[value_key]
        issues.extend(
            _compare_source_relation_verification_value(
                name=name,
                target=target,
                value_name=value_key,
                expected_value=expected_value,
                actual_value=actual_value,
            )
        )

    return issues


def _parse_rulespec_target(target: str) -> _RuleSpecTargetRef | None:
    """Parse `us:policies/foo#rule` into a target repo and relative file path."""
    normalized = target.strip().strip("'\"")
    match = re.match(
        r"^(?P<prefix>[a-z][a-z0-9_-]*):(?P<path>[^#]+)(?:#(?P<symbol>[^#]+))?$",
        normalized,
    )
    if match is None:
        return None

    path_text = match.group("path").strip().strip("/")
    if not path_text:
        return None
    relative_path = Path(path_text)
    if relative_path.is_absolute() or any(
        part in {"", ".", ".."} for part in relative_path.parts
    ):
        return None
    if not path_text.endswith((".yaml", ".yml")):
        relative_path = Path(f"{path_text}.yaml")

    prefix = match.group("prefix")
    symbol = match.group("symbol")
    return _RuleSpecTargetRef(
        prefix=prefix,
        repo_name=f"rulespec-{prefix}",
        relative_path=relative_path,
        symbol=symbol.strip() if symbol and symbol.strip() else None,
    )


def _target_path_embeds_jurisdiction(target_ref: _RuleSpecTargetRef) -> bool:
    """Return whether a RuleSpec path repeats a jurisdiction after the kind."""
    parts = target_ref.relative_path.with_suffix("").parts
    if len(parts) < 2 or parts[0] not in {"policies", "regulations", "statutes"}:
        return False
    embedded = parts[1]
    return (
        embedded == target_ref.prefix
        or re.match(r"^[a-z]{2}-[a-z0-9_-]+$", embedded) is not None
    )


def _resolve_rulespec_target_file(
    target_ref: _RuleSpecTargetRef,
    policy_repo_path: Path | None,
) -> Path | None:
    """Resolve a canonical RuleSpec target file across sibling/CI checkouts."""
    for root in _candidate_rulespec_repo_roots(
        target_ref.repo_name,
        policy_repo_path,
        prefix=target_ref.prefix,
    ):
        target_file = root / target_ref.relative_path
        if target_file.exists():
            return target_file
    return None


def _candidate_rulespec_repo_roots(
    repo_name: str,
    policy_repo_path: Path | None,
    prefix: str | None = None,
) -> list[Path]:
    """Return possible local content roots for a canonical rules repository.

    Each base location yields its candidates in monorepo-first order
    (``<base>/rulespec-<country>/<prefix>``, then ``<base>/rulespec-<prefix>``);
    bases that are themselves the jurisdiction's checkout (by name or Git
    origin) resolve to the jurisdiction's content root in either layout.
    """
    candidates: list[Path] = []
    jurisdiction = prefix or repo_name.removeprefix("rulespec-")

    def add(base: Path | None) -> None:
        if base is None:
            return
        candidates.extend(
            candidate_jurisdiction_content_dirs(base.expanduser(), jurisdiction)
        )

    if policy_repo_path is not None:
        policy_root = Path(policy_repo_path).resolve()
        add(policy_root)
        add(policy_root / "_axiom")

    env_roots = os.environ.get("AXIOM_RULESPEC_REPO_ROOTS", "")
    for raw_root in env_roots.split(os.pathsep):
        if raw_root.strip():
            add(Path(raw_root.strip()))

    if policy_repo_path is not None:
        policy_root = Path(policy_repo_path).resolve()
        add(policy_root.parent)
        add(policy_root.parent / "_axiom")
        if policy_root.parent.name.startswith("rulespec-"):
            # A monorepo jurisdiction directory: sibling checkouts live next
            # to the monorepo itself.
            add(policy_root.parent.parent)
            add(policy_root.parent.parent / "_axiom")

    cwd = Path.cwd()
    add(cwd)
    add(cwd / "_axiom")

    unique: list[Path] = []
    seen: set[Path] = set()
    for candidate in candidates:
        resolved = candidate.resolve() if candidate.exists() else candidate
        if resolved in seen:
            continue
        seen.add(resolved)
        unique.append(candidate)
    return unique


def _rulespec_repo_alias_parent(policy_repo_path: Path) -> Path | None:
    """Expose a temp checkout under its canonical `rulespec-*` repo name."""
    canonical_name = canonical_rulespec_repo_name(policy_repo_path)
    return _rulespec_repo_alias_parent_for_root(policy_repo_path, canonical_name)


def _monorepo_rulespec_repo_alias(
    policy_repo_path: Path,
) -> tuple[Path, str] | None:
    """Expose a country monorepo root when validating one jurisdiction subdir."""
    policy_root = Path(policy_repo_path).resolve()
    monorepo_root = policy_root.parent
    if not monorepo_root.name.startswith("rulespec-"):
        return None
    if policy_root.name not in jurisdiction_subdir_names(monorepo_root):
        return None
    canonical_name = canonical_rulespec_repo_name(monorepo_root)
    alias_parent = _rulespec_repo_alias_parent_for_root(monorepo_root, canonical_name)
    if alias_parent is None or canonical_name is None:
        return None
    return alias_parent, canonical_name


def _rulespec_repo_alias_parent_for_root(
    rulespec_root: Path,
    canonical_name: str | None,
) -> Path | None:
    """Expose a checkout root under a canonical `rulespec-*` repo name."""
    if not canonical_name or Path(rulespec_root).name == canonical_name:
        return None

    resolved_repo = Path(rulespec_root).resolve()
    digest = hashlib.sha256(str(resolved_repo).encode()).hexdigest()[:16]
    alias_parent = Path(tempfile.gettempdir()) / "axiom-rulespec-repo-aliases" / digest
    alias_parent.mkdir(parents=True, exist_ok=True)
    alias = alias_parent / canonical_name
    if alias.exists() or alias.is_symlink():
        with contextlib.suppress(OSError, RuntimeError):
            if alias.resolve() == resolved_repo:
                return alias_parent
        if alias.is_symlink() or alias.is_file():
            alias.unlink()
        else:
            shutil.rmtree(alias)
    alias.symlink_to(resolved_repo, target_is_directory=True)
    return alias_parent


def _canonical_rulespec_compile_path(
    rules_file: Path,
    policy_repo_path: Path,
) -> Path:
    """Return a compile path under the canonical repo alias when needed."""
    monorepo_alias = _monorepo_rulespec_repo_alias(policy_repo_path)
    if monorepo_alias is not None:
        monorepo_alias_parent, monorepo_canonical_name = monorepo_alias
        try:
            relative = rules_file.resolve().relative_to(
                Path(policy_repo_path).resolve().parent
            )
        except ValueError:
            return rules_file
        return monorepo_alias_parent / monorepo_canonical_name / relative

    alias_parent = _rulespec_repo_alias_parent(policy_repo_path)
    canonical_name = canonical_rulespec_repo_name(policy_repo_path)
    if alias_parent is None or canonical_name is None:
        return rules_file
    try:
        relative = rules_file.resolve().relative_to(policy_repo_path.resolve())
    except ValueError:
        return rules_file
    return alias_parent / canonical_name / relative


def _extract_source_relation_target_values(
    target_file: Path,
) -> tuple[dict[str, Any], set[str], str | None]:
    """Extract scalar/table parameter values from a canonical RuleSpec file."""
    try:
        payload = yaml.safe_load(target_file.read_text())
    except (OSError, yaml.YAMLError, ValueError) as exc:
        return {}, set(), f"{target_file} could not be read as RuleSpec YAML: {exc}"
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return {}, set(), f"{target_file} is not a RuleSpec v1 file"
    return _extract_rulespec_parameter_values(payload, source_label=str(target_file))


def _extract_rulespec_parameter_values(
    payload: dict[str, Any],
    *,
    source_label: str = "RuleSpec payload",
) -> tuple[dict[str, Any], set[str], str | None]:
    """Extract scalar/table parameter values from a RuleSpec payload."""
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return {}, set(), f"{source_label} has no `rules` list"

    values: dict[str, Any] = {}
    symbols: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        raw_name = rule.get("name")
        if not isinstance(raw_name, str) or not raw_name.strip():
            continue
        name = raw_name.strip()
        symbols.add(name)
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            table_values = version.get("values")
            if isinstance(table_values, dict):
                values[name] = {str(key): value for key, value in table_values.items()}
                continue
            scalar = _numeric_rule_value(version.get("formula"))
            if scalar is not None:
                values[name] = scalar[0]
    return values, symbols, None


def _compare_source_relation_verification_value(
    *,
    name: str,
    target: str,
    value_name: str,
    expected_value: Any,
    actual_value: Any,
) -> list[str]:
    """Return mismatch issues for one verified scalar or table value."""
    if isinstance(expected_value, dict):
        if not isinstance(actual_value, dict):
            return [
                "Source relation verification mismatch: "
                f"{name} expects `{value_name}` to be a table, but `{target}` "
                "defines a scalar."
            ]
        issues: list[str] = []
        for raw_key, expected_cell in expected_value.items():
            cell_key = str(raw_key)
            if cell_key not in actual_value:
                issues.append(
                    "Source relation verification target missing value: "
                    f"{name} expects `{value_name}[{cell_key}]` but `{target}` "
                    "does not define it."
                )
                continue
            actual_cell = actual_value[cell_key]
            if not _verification_values_equal(expected_cell, actual_cell):
                issues.append(
                    "Source relation verification mismatch: "
                    f"{name} expects `{value_name}[{cell_key}]` = "
                    f"{_format_verification_value(expected_cell)}, but `{target}` "
                    f"has {_format_verification_value(actual_cell)}."
                )
        return issues

    if isinstance(actual_value, dict):
        return [
            "Source relation verification mismatch: "
            f"{name} expects `{value_name}` to be a scalar, but `{target}` "
            "defines a table."
        ]
    if _verification_values_equal(expected_value, actual_value):
        return []
    return [
        "Source relation verification mismatch: "
        f"{name} expects `{value_name}` = "
        f"{_format_verification_value(expected_value)}, but `{target}` has "
        f"{_format_verification_value(actual_value)}."
    ]


def _verification_values_equal(expected_value: Any, actual_value: Any) -> bool:
    """Compare verification scalar values, allowing numeric text/int equivalence."""
    expected_numeric = _numeric_rule_value(expected_value)
    actual_numeric = _numeric_rule_value(actual_value)
    if expected_numeric is not None and actual_numeric is not None:
        return math.isclose(expected_numeric[1], actual_numeric[1], abs_tol=1e-12)
    return str(expected_value).strip() == str(actual_value).strip()


def _format_verification_value(value: Any) -> str:
    """Format a verification value for validation messages."""
    return repr(value)


def _embedded_integer_scale_selector(formula: str) -> str | None:
    normalized = re.sub(r"\s+", " ", formula)
    for match in re.finditer(r"\bmatch\s+([A-Za-z_][\w.]*)\s*:", normalized):
        numeric_arms = re.findall(
            r"=>\s*-?(?:\d{2,}|\d+\.\d+)",
            normalized[match.end() :],
        )
        if len(numeric_arms) >= 2:
            return match.group(1)
    return None


def numeric_value_is_grounded(value: float, source_numbers: set[float]) -> bool:
    """Return true when a generated number is present in extracted source numbers."""
    for source_value in source_numbers:
        if math.isclose(value, source_value, rel_tol=0, abs_tol=1e-12):
            return True
        if 0 < abs(value) <= 1 and math.isclose(
            value * 100,
            source_value,
            rel_tol=0,
            abs_tol=1e-12,
        ):
            return True
    return False


@dataclass
class ValidationResult:
    """Result from a single validator."""

    validator_name: str
    passed: bool
    score: Optional[float] = None  # 0-10 for reviewers, 0-1 for oracles
    issues: list[str] = field(default_factory=list)
    duration_ms: int = 0
    error: Optional[str] = None
    raw_output: Optional[str] = None
    prompt_sha256: Optional[str] = None
    details: dict[str, Any] = field(default_factory=dict)


@dataclass
class OracleSubprocessResult:
    """Structured result from a local oracle subprocess."""

    returncode: int
    stdout: str = ""
    stderr: str = ""


@dataclass
class PipelineResult:
    """Aggregated results from all validators."""

    results: dict[str, ValidationResult]
    total_duration_ms: int
    all_passed: bool
    oracle_context: dict = field(
        default_factory=dict
    )  # Context passed to LLM reviewers

    def to_review_results(self) -> ReviewResults:
        """Convert pipeline results to ReviewResults for encoding DB."""
        reviews = []
        for name in [
            "rulespec_reviewer",
            "formula_reviewer",
            "parameter_reviewer",
            "integration_reviewer",
        ]:
            vr = self.results.get(name, ValidationResult("", False))
            reviews.append(
                ReviewResult(
                    reviewer=name,
                    passed=vr.passed,
                    items_checked=len(vr.issues) + (1 if vr.passed else 0),
                    items_passed=1 if vr.passed else 0,
                    critical_issues=[issue for issue in (vr.issues or [])]
                    if not vr.passed
                    else [],
                    important_issues=vr.issues or [] if vr.passed else [],
                )
            )

        return ReviewResults(
            reviews=reviews,
            policyengine_match=self.results.get(
                "policyengine", ValidationResult("", False)
            ).score,
            taxsim_match=self.results.get("taxsim", ValidationResult("", False)).score,
            oracle_context=self.oracle_context,
        )

    @property
    def ci_pass(self) -> bool:
        """Check if CI passed."""
        return self.results.get("ci", ValidationResult("", False)).passed


def _rulespec_public_item_key(item: Any) -> str:
    if not isinstance(item, dict):
        return ""
    item_id = str(item.get("id") or "").strip()
    if item_id:
        return item_id
    return str(item.get("name") or "").strip()


def _canonical_rulespec_item_id_alias(
    item_id: str,
    *,
    policy_repo_path: Path,
) -> str | None:
    if ":" not in item_id:
        return None
    raw_prefix, raw_path = item_id.split(":", 1)
    canonical_prefix = jurisdiction_prefix(policy_repo_path)
    local_prefixes = _rulespec_local_item_prefixes(policy_repo_path)
    if raw_prefix != canonical_prefix and raw_prefix not in local_prefixes:
        return None
    canonical_path = _canonical_rulespec_item_path_for_policy_root(
        raw_path,
        policy_repo_path=policy_repo_path,
        canonical_prefix=canonical_prefix,
    )
    alias = f"{canonical_prefix}:{canonical_path}"
    if alias == item_id:
        return None
    return alias


def _rulespec_local_item_prefixes(policy_repo_path: Path) -> set[str]:
    """Return noncanonical prefixes the engine may stamp for this checkout."""
    canonical_prefix = jurisdiction_prefix(policy_repo_path)
    prefixes: set[str] = set()
    current = Path(policy_repo_path).resolve()
    for candidate in (current, *current.parents):
        name = candidate.name
        if name.startswith("rulespec-"):
            prefixes.add(name.removeprefix("rulespec-"))
            break
    local_prefix = Path(policy_repo_path).name.removeprefix("rulespec-")
    if local_prefix:
        prefixes.add(local_prefix)
    canonical_name = canonical_rulespec_repo_name(policy_repo_path)
    if canonical_name and canonical_name.startswith("rulespec-"):
        prefixes.add(canonical_name.removeprefix("rulespec-"))
    prefixes.discard(canonical_prefix)
    return {prefix for prefix in prefixes if prefix}


def _rulespec_local_item_prefix(policy_repo_path: Path) -> str | None:
    """Return the preferred engine-local prefix for same-repo test requests."""
    canonical_prefix = jurisdiction_prefix(policy_repo_path)
    current = Path(policy_repo_path).resolve()
    for candidate in (current, *current.parents):
        name = candidate.name
        if name.startswith("rulespec-"):
            prefix = name.removeprefix("rulespec-")
            if prefix and prefix != canonical_prefix:
                return prefix
            break
    return None


def _rulespec_content_prefix_segment(
    *,
    policy_repo_path: Path,
    canonical_prefix: str,
) -> str | None:
    """Return a monorepo content-root path segment when engine ids include it."""
    policy_path = Path(policy_repo_path)
    if policy_path.name == canonical_prefix and policy_path.parent.name.startswith(
        "rulespec-"
    ):
        return canonical_prefix
    if (policy_path / canonical_prefix).is_dir():
        return canonical_prefix
    return None


def _canonical_rulespec_item_path_for_policy_root(
    item_path: str,
    *,
    policy_repo_path: Path,
    canonical_prefix: str,
) -> str:
    content_segment = _rulespec_content_prefix_segment(
        policy_repo_path=policy_repo_path,
        canonical_prefix=canonical_prefix,
    )
    if content_segment and item_path.startswith(f"{content_segment}/"):
        return item_path.split("/", 1)[1]
    return item_path


def _engine_rulespec_item_path_for_policy_root(
    item_path: str,
    *,
    policy_repo_path: Path,
    canonical_prefix: str,
) -> str:
    content_segment = _rulespec_content_prefix_segment(
        policy_repo_path=policy_repo_path,
        canonical_prefix=canonical_prefix,
    )
    if content_segment and not item_path.startswith(f"{content_segment}/"):
        return f"{content_segment}/{item_path}"
    return item_path


def _rulespec_public_item_keys(
    item: Any,
    *,
    policy_repo_path: Path,
) -> set[str]:
    key = _rulespec_public_item_key(item)
    if not key:
        return set()
    keys = {key}
    if alias := _canonical_rulespec_item_id_alias(
        key,
        policy_repo_path=policy_repo_path,
    ):
        keys.add(alias)
    return keys


def _rulespec_item_friendly_name_and_legal_id(item: Any) -> tuple[str, str] | None:
    if not isinstance(item, dict):
        return None
    name = str(item.get("name") or "").strip()
    item_id = str(item.get("id") or "").strip()
    if not name or not item_id or name == item_id:
        return None
    return name, item_id


_RULESPEC_ABSOLUTE_REFERENCE = re.compile(r"^[a-z][a-z0-9_-]*:[^\s]+$")
_RULESPEC_IDENTIFIER = re.compile(r"\b[A-Za-z_][A-Za-z0-9_]*\b")
_RULESPEC_FORMULA_BUILTINS = {
    "False",
    "None",
    "True",
    "abs",
    "all",
    "and",
    "any",
    "ceil",
    "count",
    "count_where",
    "date_add_days",
    "days_between",
    "elif",
    "else",
    "floor",
    "if",
    "len",
    "match",
    "max",
    "min",
    "not",
    "or",
    "period_end",
    "period_start",
    "round",
    "sum",
    "sum_where",
    "true",
    "false",
}


@dataclass(frozen=True)
class _RuleSpecReferenceSummary:
    """Symbols a RuleSpec file can legitimately expose to companion tests."""

    derived: frozenset[str]
    parameters: frozenset[str]
    relations: frozenset[str]
    input_slots: frozenset[str]


def _rulespec_program_has_legal_ids(compiled_payload: dict[str, Any]) -> bool:
    program = (
        compiled_payload.get("program") if isinstance(compiled_payload, dict) else {}
    )
    if not isinstance(program, dict):
        return False
    for collection in ("derived", "parameters"):
        for item in program.get(collection, []):
            if _rulespec_item_friendly_name_and_legal_id(item) is not None:
                return True
    return False


def _rulespec_module_target(compiled_payload: dict[str, Any]) -> str | None:
    program = (
        compiled_payload.get("program") if isinstance(compiled_payload, dict) else {}
    )
    if not isinstance(program, dict):
        return None
    for collection in ("derived", "parameters"):
        for item in program.get(collection, []):
            if not isinstance(item, dict):
                continue
            item_id = str(item.get("id") or "").strip()
            if "#" in item_id:
                return item_id.split("#", 1)[0]
    return None


def _rulespec_runtime_name_from_absolute_test_reference(reference: str) -> str:
    if not _RULESPEC_ABSOLUTE_REFERENCE.match(reference) or "#" not in reference:
        return ""
    fragment = reference.split("#", 1)[1].strip()
    if ".input." in fragment:
        return fragment.rsplit(".input.", 1)[1].strip()
    for prefix in ("input.", "relation."):
        if fragment.startswith(prefix):
            return fragment.removeprefix(prefix).strip()
    return fragment


def _rulespec_formula_identifiers(payload: Any) -> set[str]:
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()

    identifiers: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, str):
                identifiers.update(_RULESPEC_IDENTIFIER.findall(formula))
    return identifiers - _RULESPEC_FORMULA_BUILTINS


def _rulespec_reference_summary(target_file: Path) -> _RuleSpecReferenceSummary:
    try:
        stat = target_file.stat()
        cache_path = target_file.resolve()
    except OSError:
        return _RuleSpecReferenceSummary(
            derived=frozenset(),
            parameters=frozenset(),
            relations=frozenset(),
            input_slots=frozenset(),
        )
    return _rulespec_reference_summary_cached(
        cache_path,
        stat.st_mtime_ns,
        stat.st_size,
    )


@functools.lru_cache(maxsize=8192)
def _rulespec_reference_summary_cached(
    target_file: Path,
    _mtime_ns: int,
    _size: int,
) -> _RuleSpecReferenceSummary:
    try:
        payload = yaml.safe_load(target_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        payload = {}
    if not isinstance(payload, dict):
        payload = {}

    derived: set[str] = set()
    parameters: set[str] = set()
    relations: set[str] = set()
    rules = payload.get("rules")
    if isinstance(rules, list):
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            name = str(rule.get("name") or "").strip()
            if not name:
                continue
            kind = str(rule.get("kind") or "").strip().lower()
            if kind == "parameter":
                parameters.add(name)
            elif kind == "derived":
                derived.add(name)
            elif kind == "data_relation":
                relations.add(name)

    formula_identifiers = _rulespec_formula_identifiers(payload)
    if isinstance(rules, list):
        for rule in rules:
            if (
                isinstance(rule, dict)
                and str(rule.get("kind") or "").lower() == "parameter"
            ):
                formula_identifiers.update(
                    _indexed_by_input_names(rule.get("indexed_by"))
                )
    input_slots = formula_identifiers - derived - parameters - relations
    return _RuleSpecReferenceSummary(
        derived=frozenset(derived),
        parameters=frozenset(parameters),
        relations=frozenset(relations),
        input_slots=frozenset(input_slots),
    )


def _rulespec_absolute_test_reference_issue(
    reference: str,
    *,
    label: str,
    policy_repo_path: Path | None,
    allow_input_slots: bool,
    allow_relations: bool,
    allow_outputs: bool,
) -> str | None:
    target_ref = _parse_rulespec_target(reference)
    if target_ref is None or not target_ref.symbol:
        return f"{label} `{reference}` must be an absolute legal RuleSpec reference."

    target_file = _resolve_rulespec_target_file(target_ref, policy_repo_path)
    if target_file is None:
        return (
            f"{label} `{reference}` points to a RuleSpec file that could not be "
            f"resolved: {target_ref.repo_name}/{target_ref.relative_path.as_posix()}."
        )

    summary = _rulespec_reference_summary(target_file)
    fragment = target_ref.symbol.strip()

    if ".input." in fragment:
        owner, input_slot = fragment.rsplit(".input.", 1)
        input_slot = input_slot.strip()
        owner = owner.strip()
        if owner and owner not in summary.derived and owner not in summary.parameters:
            return (
                f"{label} `{reference}` does not resolve to a derived rule or "
                f"parameter owner in {target_ref.relative_path.as_posix()}."
            )
        if input_slot in summary.input_slots:
            if allow_input_slots:
                return None
            return f"{label} `{reference}` resolves to an input slot, which is not allowed here."
        return (
            f"{label} `{reference}` does not resolve to an input slot in "
            f"{target_ref.relative_path.as_posix()}."
        )

    if fragment.startswith("input."):
        input_slot = fragment.removeprefix("input.").strip()
        if input_slot in summary.input_slots:
            if allow_input_slots:
                return None
            return f"{label} `{reference}` resolves to an input slot, which is not allowed here."
        return (
            f"{label} `{reference}` does not resolve to an input slot in "
            f"{target_ref.relative_path.as_posix()}."
        )

    if fragment.startswith("relation."):
        relation = fragment.removeprefix("relation.").strip()
        if relation in summary.relations:
            if allow_relations:
                return None
            return f"{label} `{reference}` resolves to a relation, which is not allowed here."
        return (
            f"{label} `{reference}` does not resolve to a declared relation in "
            f"{target_ref.relative_path.as_posix()}."
        )

    if fragment in summary.derived or fragment in summary.parameters:
        if allow_outputs:
            return None
        return f"{label} `{reference}` resolves to a derived rule or parameter, which is not allowed here."
    allowed_kinds = []
    if allow_input_slots:
        allowed_kinds.append("input slot")
    if allow_relations:
        allowed_kinds.append("relation")
    if allow_outputs:
        allowed_kinds.extend(["derived rule", "parameter"])
    allowed = ", ".join(allowed_kinds[:-1])
    if len(allowed_kinds) > 1:
        allowed = f"{allowed}, or {allowed_kinds[-1]}"
    elif allowed_kinds:
        allowed = allowed_kinds[0]
    else:
        allowed = "allowed RuleSpec target"
    article = "an" if allowed.startswith(("input", "allowed")) else "a"
    return (
        f"{label} `{reference}` does not resolve to {article} {allowed} in "
        f"{target_ref.relative_path.as_posix()}."
    )


def _rulespec_test_input_key_suggestion(
    friendly_name: str,
    *,
    legal_ids_by_friendly_name: dict[str, list[str]],
    module_target: str | None,
) -> str:
    legal_ids = legal_ids_by_friendly_name.get(friendly_name)
    if legal_ids:
        if len(legal_ids) == 1:
            return f"; use `{legal_ids[0]}`"
        legal_id_list = ", ".join(f"`{item}`" for item in legal_ids)
        return f"; use one of {legal_id_list}"
    if module_target:
        return (
            f"; use `{module_target}#input.{friendly_name}` for a local fact slot "
            "or the upstream absolute RuleSpec target for an imported legal value"
        )
    return ""


def _rulespec_runtime_name_for_test_input_key(
    input_key: str,
    *,
    label: str,
    require_legal_input_keys: bool,
    legal_ids_by_friendly_name: dict[str, list[str]],
    module_target: str | None,
    policy_repo_path: Path | None,
    allow_input_slots: bool,
    allow_relations: bool,
    allow_outputs: bool,
) -> str:
    if _RULESPEC_ABSOLUTE_REFERENCE.match(input_key):
        resolution_issue = _rulespec_absolute_test_reference_issue(
            input_key,
            label=label,
            policy_repo_path=policy_repo_path,
            allow_input_slots=allow_input_slots,
            allow_relations=allow_relations,
            allow_outputs=allow_outputs,
        )
        if resolution_issue:
            raise ValueError(resolution_issue)
        runtime_name = _rulespec_runtime_name_from_absolute_test_reference(input_key)
        if runtime_name:
            return runtime_name
        raise ValueError(
            f"{label} `{input_key}` must include a fragment naming the runtime slot."
        )

    if require_legal_input_keys:
        suggestion = _rulespec_test_input_key_suggestion(
            input_key,
            legal_ids_by_friendly_name=legal_ids_by_friendly_name,
            module_target=module_target,
        )
        raise ValueError(
            f"{label} `{input_key}` must use an absolute legal RuleSpec id "
            f"instead of the friendly name{suggestion}."
        )

    return input_key


def _rulespec_engine_request_name_for_test_key(
    test_key: str,
    runtime_name: str,
    *,
    require_legal_input_keys: bool,
    policy_repo_path: Path,
) -> str:
    if require_legal_input_keys and _RULESPEC_ABSOLUTE_REFERENCE.match(test_key):
        return test_key
    return runtime_name


def _rulespec_declared_relation_names(compiled_payload: dict[str, Any]) -> set[str]:
    program = (
        compiled_payload.get("program") if isinstance(compiled_payload, dict) else {}
    )
    if not isinstance(program, dict):
        return set()
    return {
        str(relation.get("name"))
        for relation in program.get("relations", [])
        if isinstance(relation, dict) and relation.get("name")
    }


class ValidatorPipeline:
    """Runs validators in 3 tiers with session event logging."""

    def __init__(
        self,
        policy_repo_path: Path,
        axiom_rules_path: Path,
        enable_oracles: bool = True,
        oracle_validators: tuple[str, ...] | None = None,
        max_workers: int = 4,
        encoding_db: Optional[EncodingDB] = None,
        session_id: Optional[str] = None,
        policyengine_country: str = "auto",
        policyengine_rule_hint: str | None = None,
        require_policy_proofs: bool = False,
        enforce_repository_layout: bool = True,
    ):
        self.policy_repo_path = Path(policy_repo_path)
        self.axiom_rules_path = Path(axiom_rules_path)
        self.enable_oracles = enable_oracles
        self.oracle_validators = oracle_validators or ("policyengine", "taxsim")
        self.max_workers = max_workers
        self.encoding_db = encoding_db
        self.session_id = session_id
        self.policyengine_country = policyengine_country
        self.policyengine_rule_hint = policyengine_rule_hint
        self.require_policy_proofs = require_policy_proofs
        self.enforce_repository_layout = enforce_repository_layout
        self.policyengine_registry = load_policyengine_registry()

    def _log_event(
        self, event_type: str, content: str = "", metadata: Optional[dict] = None
    ):
        """Log a validation event if session tracking is enabled."""
        if self.encoding_db and self.session_id:
            self.encoding_db.log_event(
                session_id=self.session_id,
                event_type=event_type,
                content=content,
                metadata=metadata,
            )

    def _pythonpath_env(self) -> dict[str, str]:
        """Build an env that prefers the configured Axiom rules engine checkout."""
        env = dict(os.environ)
        rules_src = self.axiom_rules_path / "src"
        if rules_src.exists():
            existing = env.get("PYTHONPATH", "")
            env["PYTHONPATH"] = (
                f"{rules_src}{os.pathsep}{existing}" if existing else str(rules_src)
            )
        return env

    def _rulespec_compile_env(self) -> dict[str, str]:
        """Build an env that can resolve canonical RuleSpec repo imports."""
        env = self._pythonpath_env()
        roots: list[Path] = []
        if Path(self.policy_repo_path).parent.name.startswith("rulespec-"):
            # A monorepo jurisdiction directory: sibling checkouts live next
            # to the monorepo checkout itself.
            incidental_roots = [
                self.policy_repo_path.parent,
                self.policy_repo_path.parent.parent,
            ]
        else:
            incidental_roots = [self.policy_repo_path.parent]
        monorepo_alias = _monorepo_rulespec_repo_alias(self.policy_repo_path)
        if monorepo_alias is not None:
            monorepo_alias_parent, _monorepo_canonical_name = monorepo_alias
            roots.append(monorepo_alias_parent)
        alias_parent = _rulespec_repo_alias_parent(self.policy_repo_path)
        if alias_parent is not None:
            roots.append(alias_parent)
        roots.append(self.policy_repo_path)
        existing_roots = env.get("AXIOM_RULESPEC_REPO_ROOTS", "")
        if existing_roots:
            roots.extend(
                Path(root) for root in existing_roots.split(os.pathsep) if root
            )
        roots.extend(incidental_roots)
        deduped_roots: list[str] = []
        seen: set[str] = set()
        for root in roots:
            raw = str(root)
            if raw and raw not in seen:
                seen.add(raw)
                deduped_roots.append(raw)
        env["AXIOM_RULESPEC_REPO_ROOTS"] = os.pathsep.join(deduped_roots)
        return env

    def validate(
        self, rulespec_file: Path, skip_reviewers: bool = False
    ) -> PipelineResult:
        """Run 4-tier validation on a RuleSpec file.

        Tiers run in order:
        0. Compile check - can the file compile to engine IR?
        1. CI checks (instant) - parse, lint, companion tests, structural validation
        2. Oracles (fast, ~10s) - PolicyEngine + TAXSIM comparison data
        3. LLM reviewers (uses oracle context) - diagnose issues

        Oracle results are passed to LLM reviewers as context.
        Each tier is logged as session events with timestamps.
        """
        start = time.time()
        results = {}

        # Tier 0: Compile check (fast, catches structural errors early)
        self._log_event(
            "validation_compile_start",
            f"Starting compilation check for {rulespec_file.name}",
        )
        compile_start = time.time()
        results["compile"] = self._run_compile_check(rulespec_file)
        self._log_event(
            "validation_compile_end",
            "Compilation check complete",
            {
                "passed": results["compile"].passed,
                "issues": results["compile"].issues,
                "duration_ms": int((time.time() - compile_start) * 1000),
            },
        )

        # Tier 1: CI checks (instant, blocks further validation if fails)
        self._log_event(
            "validation_ci_start", f"Starting CI validation for {rulespec_file.name}"
        )
        ci_start = time.time()
        try:
            results["ci"] = self._run_ci(rulespec_file)
        except Exception as e:
            results["ci"] = ValidationResult(
                validator_name="ci",
                passed=False,
                error=str(e),
                issues=[str(e)],
            )
        self._log_event(
            "validation_ci_end",
            "CI validation complete",
            {
                "passed": results["ci"].passed,
                "issues": results["ci"].issues,
                "duration_ms": int((time.time() - ci_start) * 1000),
            },
        )

        # Tier 2: Oracles (parallel, fast, generates comparison context)
        oracle_context = {}
        if self.enable_oracles:
            self._log_event(
                "validation_oracle_start", "Starting oracle validation (PE + TAXSIM)"
            )
            oracle_start = time.time()

            available_oracle_validators = {
                "policyengine": lambda: self._run_policyengine(rulespec_file),
                "taxsim": lambda: self._run_taxsim(rulespec_file),
            }
            oracle_validators = {
                name: available_oracle_validators[name]
                for name in self.oracle_validators
                if name in available_oracle_validators
            }

            with ThreadPoolExecutor(max_workers=2) as executor:
                futures = {
                    executor.submit(fn): name for name, fn in oracle_validators.items()
                }

                for future in as_completed(futures):
                    name = futures[future]
                    try:
                        results[name] = future.result()
                        # Build context for LLM reviewers (with full details)
                        oracle_context[name] = {
                            "score": results[name].score,
                            "passed": results[name].passed,
                            "issues": results[name].issues,
                            "duration_ms": results[name].duration_ms,
                            "details": results[name].details,
                        }
                    except Exception as e:
                        results[name] = ValidationResult(
                            validator_name=name,
                            passed=False,
                            error=str(e),
                        )
                        oracle_context[name] = {
                            "score": None,
                            "passed": False,
                            "issues": [str(e)],
                            "error": str(e),
                        }

            self._log_event(
                "validation_oracle_end",
                "Oracle validation complete",
                {
                    "oracle_context": oracle_context,
                    "duration_ms": int((time.time() - oracle_start) * 1000),
                },
            )

        # Tier 3: LLM reviewers (parallel, use oracle context)
        if skip_reviewers:
            self._log_event(
                "validation_llm_skipped",
                "Skipping LLM reviewers",
                {
                    "oracle_context_summary": {
                        k: v.get("score") for k, v in oracle_context.items()
                    },
                },
            )
        else:
            self._log_event(
                "validation_llm_start",
                "Starting LLM reviewers with oracle context",
                {
                    "oracle_context_summary": {
                        k: v.get("score") for k, v in oracle_context.items()
                    },
                },
            )
            llm_start = time.time()

            llm_validators = {
                "rulespec_reviewer": lambda: self._run_reviewer(
                    "rulespec-reviewer", rulespec_file, oracle_context
                ),
                "formula_reviewer": lambda: self._run_reviewer(
                    "Formula Reviewer", rulespec_file, oracle_context
                ),
                "parameter_reviewer": lambda: self._run_reviewer(
                    "Parameter Reviewer", rulespec_file, oracle_context
                ),
                "integration_reviewer": lambda: self._run_reviewer(
                    "Integration Reviewer", rulespec_file, oracle_context
                ),
            }

            with ThreadPoolExecutor(max_workers=self.max_workers) as executor:
                futures = {
                    executor.submit(fn): name for name, fn in llm_validators.items()
                }

                for future in as_completed(futures):
                    name = futures[future]
                    try:
                        results[name] = future.result()
                    except Exception as e:
                        results[name] = ValidationResult(
                            validator_name=name,
                            passed=False,
                            error=str(e),
                        )

            self._log_event(
                "validation_llm_end",
                "LLM reviewers complete",
                {
                    "scores": {
                        k: results[k].score
                        for k in llm_validators.keys()
                        if k in results
                    },
                    "duration_ms": int((time.time() - llm_start) * 1000),
                },
            )

        total_duration = int((time.time() - start) * 1000)
        all_passed = all(r.passed for r in results.values())

        return PipelineResult(
            results=results,
            total_duration_ms=total_duration,
            all_passed=all_passed,
            oracle_context=oracle_context,
        )

    def _is_rulespec_file(self, rules_file: Path) -> bool:
        """Return true for current RuleSpec files."""
        if rules_file.suffix not in {".yaml", ".yml"} or rules_file.name.endswith(
            ".test.yaml"
        ):
            return False
        try:
            payload = yaml.safe_load(rules_file.read_text())
        except (OSError, yaml.YAMLError, ValueError):
            return False
        return isinstance(payload, dict) and payload.get("format") == "rulespec/v1"

    def _rulespec_test_path(self, rules_file: Path) -> Path:
        """Return the companion RuleSpec test file path."""
        return rules_file.with_name(f"{rules_file.stem}.test.yaml")

    def _axiom_rules_binary(self) -> Path:
        """Resolve the local Axiom rules engine CLI binary."""
        candidates = [
            self.axiom_rules_path / "target" / "debug" / "axiom-rules-engine",
            self.axiom_rules_path / "target" / "release" / "axiom-rules-engine",
            self.axiom_rules_path / "axiom-rules-engine",
        ]
        for candidate in candidates:
            if candidate.exists():
                return candidate
        if resolved := shutil.which("axiom-rules-engine"):
            return Path(resolved)
        raise FileNotFoundError(
            f"axiom-rules-engine binary not found under {self.axiom_rules_path} or on PATH"
        )

    def _compile_rulespec_to_artifact(
        self,
        rules_file: Path,
        output_path: Path,
    ) -> tuple[subprocess.CompletedProcess[str], dict[str, Any] | None]:
        """Compile RuleSpec YAML to an Axiom rules engine artifact JSON file."""
        binary = self._axiom_rules_binary()
        compile_file = _canonical_rulespec_compile_path(
            rules_file,
            self.policy_repo_path,
        )
        result = subprocess.run(
            [
                str(binary),
                "compile",
                "--program",
                str(compile_file),
                "--output",
                str(output_path),
            ],
            capture_output=True,
            text=True,
            timeout=60,
            cwd=str(self.axiom_rules_path) if self.axiom_rules_path.exists() else None,
            env=self._rulespec_compile_env(),
        )
        if result.returncode != 0:
            return result, None
        return result, json.loads(output_path.read_text())

    def _rulespec_compile_success_output(self, payload: Any) -> str:
        """Return a concise successful compile summary for validator output."""
        program = payload.get("program") if isinstance(payload, dict) else {}
        if not isinstance(program, dict):
            program = {}
        rule_count = sum(
            len(program.get(key) or ())
            for key in ("parameters", "derived", "relations")
        )
        return f"Successfully compiled {rule_count} RuleSpec rule(s) with the Axiom rules engine"

    def _run_rulespec_compile_check(self, rules_file: Path) -> ValidationResult:
        """Compile RuleSpec YAML through the Axiom rules engine."""
        start = time.time()
        issues: list[str] = []
        try:
            with tempfile.TemporaryDirectory() as tmpdir:
                output_path = Path(tmpdir) / "compiled.json"
                result, payload = self._compile_rulespec_to_artifact(
                    rules_file, output_path
                )
                if result.returncode != 0:
                    detail = result.stderr.strip() or result.stdout.strip()
                    issues.append(f"Axiom rules engine compile failed: {detail}")
                    return ValidationResult(
                        validator_name="compile",
                        passed=False,
                        issues=issues,
                        duration_ms=int((time.time() - start) * 1000),
                        error=issues[0],
                        raw_output=result.stdout + result.stderr,
                    )
            return ValidationResult(
                validator_name="compile",
                passed=True,
                issues=[],
                duration_ms=int((time.time() - start) * 1000),
                raw_output=self._rulespec_compile_success_output(payload),
            )
        except Exception as exc:
            issues.append(f"Axiom rules engine compile failed: {exc}")
            return ValidationResult(
                validator_name="compile",
                passed=False,
                issues=issues,
                duration_ms=int((time.time() - start) * 1000),
                error=str(exc),
            )

    def _run_compile_check(self, rulespec_file: Path) -> ValidationResult:
        """Tier 0: Compile check against the Axiom rules engine RuleSpec."""
        if not self._is_rulespec_file(rulespec_file):
            return ValidationResult(
                validator_name="compile",
                passed=False,
                issues=["RuleSpec YAML artifacts are required."],
                error="RuleSpec YAML artifacts are required",
            )

        return self._run_rulespec_compile_check(rulespec_file)

    def _coerce_rulespec_period(self, value: Any) -> dict[str, Any]:
        """Coerce compact `.test.yaml` period shorthands to engine JSON."""
        if isinstance(value, dict):
            period = {
                key: (item.isoformat() if isinstance(item, date) else item)
                for key, item in value.items()
            }
            if period.get("period_kind") == "year":
                period["period_kind"] = "tax_year"
            required = {"period_kind", "start", "end"}
            missing = sorted(required - set(period))
            if missing:
                raise ValueError(
                    "period mapping missing required field(s): " + ", ".join(missing)
                )
            if period["period_kind"] not in {
                "month",
                "benefit_week",
                "tax_year",
                "custom",
            }:
                raise ValueError(f"unsupported period_kind: {period['period_kind']!r}")
            for key in ("start", "end"):
                try:
                    date.fromisoformat(str(period[key]))
                except ValueError as exc:
                    raise ValueError(
                        f"period {key} must be an ISO date, got {period[key]!r}"
                    ) from exc
            if period["period_kind"] == "custom" and not period.get("name"):
                raise ValueError("custom period mappings must include name")
            return period
        if isinstance(value, int):
            raise ValueError(
                "bare year periods are ambiguous; use an explicit period mapping "
                "with period_kind/start/end"
            )
        if isinstance(value, date):
            day = value.isoformat()
            return {
                "period_kind": "custom",
                "name": "day",
                "start": day,
                "end": day,
            }
        if isinstance(value, str):
            stripped = value.strip()
            if re.fullmatch(r"\d{4}", stripped):
                raise ValueError(
                    "bare year periods are ambiguous; use an explicit period "
                    "mapping with period_kind/start/end"
                )
            if re.fullmatch(r"\d{4}-\d{2}", stripped):
                year = int(stripped[:4])
                month = int(stripped[5:])
                return {
                    "period_kind": "month",
                    "start": date(year, month, 1).isoformat(),
                    "end": date(year, month, monthrange(year, month)[1]).isoformat(),
                }
        raise ValueError(f"unsupported period shorthand: {value!r}")

    def _rulespec_case_query_entity_id(
        self,
        case: dict[str, Any],
        query_entity: str,
        index: int,
    ) -> str:
        """Pick a stable entity id for a compact RuleSpec test case."""
        entity_key = f"{self._snake_case(query_entity)}_id"
        for key in ("entity_id", "id", entity_key):
            if key in case:
                return str(case[key])
        for key, value in case.items():
            if key.endswith("_id") and not isinstance(value, (dict, list)):
                return str(value)
        return f"case-{index}"

    def _rulespec_table_row_entity_id(
        self,
        table_entity: str,
        row: dict[str, Any],
        index: int,
    ) -> str:
        """Pick a stable entity id for a compact RuleSpec table row."""
        entity_key = f"{self._snake_case(table_entity)}_id"
        for key in ("entity_id", "id", entity_key):
            if key in row:
                return str(row[key])
        return f"{self._snake_case(table_entity)}-{index}"

    def _rulespec_case_table_rows(
        self,
        case: dict[str, Any],
        table_entity: str,
    ) -> list[tuple[str, dict[str, Any]]]:
        """Return row ids and mappings for a compact RuleSpec `tables:` entity."""
        tables = case.get("tables")
        if tables in (None, ""):
            return []
        if not isinstance(tables, dict):
            raise ValueError("tables must be a mapping")
        rows = tables.get(table_entity)
        if rows in (None, ""):
            return []
        if not isinstance(rows, list):
            raise ValueError(f"tables.{table_entity} must be a list of row mappings")

        resolved_rows: list[tuple[str, dict[str, Any]]] = []
        for row_index, row in enumerate(rows, 1):
            if not isinstance(row, dict):
                raise ValueError(
                    f"tables.{table_entity} row #{row_index} must be a mapping"
                )
            resolved_rows.append(
                (
                    self._rulespec_table_row_entity_id(
                        table_entity,
                        row,
                        row_index,
                    ),
                    row,
                )
            )
        return resolved_rows

    def _snake_case(self, value: str) -> str:
        """Convert a PascalCase/CamelCase label to snake_case."""
        value = re.sub(r"(.)([A-Z][a-z]+)", r"\1_\2", value)
        value = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", value)
        return value.replace("-", "_").lower()

    def _related_entity_from_relation(self, relation_name: str) -> str:
        """Infer a readable related-entity label for relation test inputs."""
        head = relation_name.split("_of_", 1)[0]
        return (
            "".join(part.capitalize() for part in head.split("_") if part) or "Related"
        )

    def _rulespec_scalar_value(self, value: Any) -> dict[str, Any]:
        """Coerce Python/YAML scalar values to Axiom rules engine ScalarValueSpec JSON."""
        if isinstance(value, bool):
            return {"kind": "bool", "value": value}
        if isinstance(value, int):
            return {"kind": "integer", "value": value}
        if isinstance(value, float):
            return {"kind": "decimal", "value": str(value)}
        if isinstance(value, Decimal):
            return {"kind": "decimal", "value": str(value)}
        if isinstance(value, date):
            return {"kind": "date", "value": value.isoformat()}
        if isinstance(value, str):
            stripped = value.strip()
            if re.fullmatch(r"\d{4}-\d{2}-\d{2}", stripped):
                return {"kind": "date", "value": stripped}
            if re.fullmatch(r"-?\d+", stripped):
                return {"kind": "integer", "value": int(stripped)}
            if re.fullmatch(r"-?(?:\d+\.\d*|\d*\.\d+)", stripped):
                return {"kind": "decimal", "value": stripped}
            return {"kind": "text", "value": value}
        raise ValueError(f"unsupported scalar test value {value!r}")

    def _rulespec_expected_scalar_value(self, value: Any) -> dict[str, Any]:
        """Coerce expected output YAML values without interpreting strings."""
        if isinstance(value, bool):
            return {"kind": "bool", "value": value}
        if isinstance(value, int):
            return {"kind": "integer", "value": value}
        if isinstance(value, float):
            return {"kind": "decimal", "value": str(value)}
        if isinstance(value, Decimal):
            return {"kind": "decimal", "value": str(value)}
        if isinstance(value, date):
            return {"kind": "date", "value": value.isoformat()}
        if isinstance(value, str):
            return {"kind": "text", "value": value}
        raise ValueError(f"unsupported expected scalar value {value!r}")

    def _build_rulespec_dataset(
        self,
        case_input: Any,
        *,
        case_tables: Any = None,
        period: dict[str, Any],
        query_entity: str,
        query_entity_id: str,
        require_legal_input_keys: bool = False,
        legal_ids_by_friendly_name: dict[str, list[str]] | None = None,
        module_target: str | None = None,
        declared_relation_names: set[str] | None = None,
    ) -> dict[str, Any]:
        """Build an Axiom rules engine dataset from compact RuleSpec test inputs."""
        if case_input in (None, ""):
            case_input = {}
        if not isinstance(case_input, dict):
            raise ValueError("input must be a mapping")

        interval = {"start": period["start"], "end": period["end"]}
        inputs: list[dict[str, Any]] = []
        relations: list[dict[str, Any]] = []
        legal_ids_by_friendly_name = legal_ids_by_friendly_name or {}
        declared_relation_names = declared_relation_names or set()

        for name, value in case_input.items():
            input_key = str(name)
            if isinstance(value, list):
                relation_name = _rulespec_runtime_name_for_test_input_key(
                    input_key,
                    label="relation input",
                    require_legal_input_keys=require_legal_input_keys,
                    legal_ids_by_friendly_name=legal_ids_by_friendly_name,
                    module_target=module_target,
                    policy_repo_path=self.policy_repo_path,
                    allow_input_slots=False,
                    allow_relations=True,
                    allow_outputs=False,
                )
                relation_request_name = _rulespec_engine_request_name_for_test_key(
                    input_key,
                    relation_name,
                    require_legal_input_keys=require_legal_input_keys,
                    policy_repo_path=self.policy_repo_path,
                )
                relation_request_names = [relation_request_name]
                if (
                    relation_name in declared_relation_names
                    and relation_name not in relation_request_names
                ):
                    relation_request_names.append(relation_name)
                related_entity = self._related_entity_from_relation(relation_name)
                for item_index, item in enumerate(value, 1):
                    if not isinstance(item, dict):
                        raise ValueError(
                            f"relation `{name}` item #{item_index} must be a mapping"
                        )
                    related_id = str(
                        item.get("id")
                        or item.get("entity_id")
                        or f"{query_entity_id}-{name}-{item_index}"
                    )
                    for current_relation_name in relation_request_names:
                        relations.append(
                            {
                                "name": current_relation_name,
                                "tuple": [related_id, query_entity_id],
                                "interval": interval,
                            }
                        )
                    for child_name, child_value in item.items():
                        if child_name in {"id", "entity_id"}:
                            continue
                        if isinstance(child_value, (dict, list)):
                            raise ValueError(
                                f"relation `{name}` input `{child_name}` must be scalar"
                            )
                        child_input_name = _rulespec_runtime_name_for_test_input_key(
                            str(child_name),
                            label="input",
                            require_legal_input_keys=require_legal_input_keys,
                            legal_ids_by_friendly_name=legal_ids_by_friendly_name,
                            module_target=module_target,
                            policy_repo_path=self.policy_repo_path,
                            allow_input_slots=True,
                            allow_relations=False,
                            allow_outputs=True,
                        )
                        child_input_key = str(child_name)
                        child_request_name = _rulespec_engine_request_name_for_test_key(
                            child_input_key,
                            child_input_name,
                            require_legal_input_keys=require_legal_input_keys,
                            policy_repo_path=self.policy_repo_path,
                        )
                        inputs.append(
                            {
                                "name": child_request_name,
                                "entity": related_entity,
                                "entity_id": related_id,
                                "interval": interval,
                                "value": self._rulespec_scalar_value(child_value),
                            }
                        )
                continue

            if isinstance(value, dict):
                raise ValueError(f"input `{name}` must be scalar or relation list")

            input_name = _rulespec_runtime_name_for_test_input_key(
                input_key,
                label="input",
                require_legal_input_keys=require_legal_input_keys,
                legal_ids_by_friendly_name=legal_ids_by_friendly_name,
                module_target=module_target,
                policy_repo_path=self.policy_repo_path,
                allow_input_slots=True,
                allow_relations=False,
                allow_outputs=True,
            )
            input_request_name = _rulespec_engine_request_name_for_test_key(
                input_key,
                input_name,
                require_legal_input_keys=require_legal_input_keys,
                policy_repo_path=self.policy_repo_path,
            )
            inputs.append(
                {
                    "name": input_request_name,
                    "entity": query_entity,
                    "entity_id": query_entity_id,
                    "interval": interval,
                    "value": self._rulespec_scalar_value(value),
                }
            )

        if case_tables not in (None, ""):
            if not isinstance(case_tables, dict):
                raise ValueError("tables must be a mapping")
            for table_entity_key, rows in case_tables.items():
                table_entity = str(table_entity_key)
                if not isinstance(rows, list):
                    raise ValueError(
                        f"tables.{table_entity} must be a list of row mappings"
                    )
                row_id_keys = {
                    "id",
                    "entity_id",
                    f"{self._snake_case(table_entity)}_id",
                }
                for row_index, row in enumerate(rows, 1):
                    if not isinstance(row, dict):
                        raise ValueError(
                            f"tables.{table_entity} row #{row_index} must be a mapping"
                        )
                    row_id = self._rulespec_table_row_entity_id(
                        table_entity,
                        row,
                        row_index,
                    )
                    for child_name, child_value in row.items():
                        child_key = str(child_name)
                        if child_key in row_id_keys:
                            continue
                        if isinstance(child_value, (dict, list)):
                            raise ValueError(
                                f"tables.{table_entity} row #{row_index} input "
                                f"`{child_key}` must be scalar"
                            )
                        child_input_name = _rulespec_runtime_name_for_test_input_key(
                            child_key,
                            label="input",
                            require_legal_input_keys=require_legal_input_keys,
                            legal_ids_by_friendly_name=legal_ids_by_friendly_name,
                            module_target=module_target,
                            policy_repo_path=self.policy_repo_path,
                            allow_input_slots=True,
                            allow_relations=False,
                            allow_outputs=True,
                        )
                        child_request_name = (
                            child_key
                            if _RULESPEC_ABSOLUTE_REFERENCE.match(child_key)
                            else child_input_name
                        )
                        inputs.append(
                            {
                                "name": child_request_name,
                                "entity": table_entity,
                                "entity_id": row_id,
                                "interval": interval,
                                "value": self._rulespec_scalar_value(child_value),
                            }
                        )

        return {"inputs": inputs, "relations": relations}

    def _rulespec_program_maps(
        self, compiled_payload: dict[str, Any]
    ) -> tuple[dict[str, Any], dict[str, Any]]:
        """Return compiled derived-output and scalar-parameter maps by public key."""
        program = (
            compiled_payload.get("program")
            if isinstance(compiled_payload, dict)
            else {}
        )
        if not isinstance(program, dict):
            program = {}
        derived: dict[str, Any] = {}
        for item in program.get("derived", []):
            for key in _rulespec_public_item_keys(
                item,
                policy_repo_path=self.policy_repo_path,
            ):
                derived[key] = item
        parameters: dict[str, Any] = {}
        for item in program.get("parameters", []):
            for key in _rulespec_public_item_keys(
                item,
                policy_repo_path=self.policy_repo_path,
            ):
                parameters[key] = item
        return derived, parameters

    def _rulespec_legal_ids_by_friendly_output_name(
        self, compiled_payload: dict[str, Any]
    ) -> dict[str, list[str]]:
        """Return legal output ids keyed by local friendly name for repo-backed rules."""
        program = (
            compiled_payload.get("program")
            if isinstance(compiled_payload, dict)
            else {}
        )
        if not isinstance(program, dict):
            program = {}

        legal_ids_by_name: dict[str, set[str]] = {}
        for collection in ("derived", "parameters"):
            for item in program.get(collection, []):
                pair = _rulespec_item_friendly_name_and_legal_id(item)
                if pair is None:
                    continue
                name, item_id = pair
                item_id = (
                    _canonical_rulespec_item_id_alias(
                        item_id,
                        policy_repo_path=self.policy_repo_path,
                    )
                    or item_id
                )
                legal_ids_by_name.setdefault(name, set()).add(item_id)
        return {name: sorted(item_ids) for name, item_ids in legal_ids_by_name.items()}

    def _rulespec_compiled_parameter_value(
        self,
        parameter: dict[str, Any],
        period: dict[str, Any],
        inputs: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        """Return the live scalar value for a compiled scalar or table parameter."""
        period_start = date.fromisoformat(str(period["start"]))
        versions = parameter.get("versions") or []
        live_versions = [
            version
            for version in versions
            if isinstance(version, dict)
            and date.fromisoformat(str(version["effective_from"])) <= period_start
        ]
        if not live_versions:
            raise ValueError(
                f"parameter `{parameter.get('name')}` has no version at {period['start']}"
            )
        version = max(
            live_versions,
            key=lambda item: date.fromisoformat(str(item["effective_from"])),
        )
        values = version.get("values") or {}
        value = values.get("0", values.get(0))
        indexed_by = parameter.get("indexed_by")
        if indexed_by:
            index_names = (
                [str(indexed_by)]
                if isinstance(indexed_by, str)
                else [str(item) for item in indexed_by]
            )
            if len(index_names) != 1:
                raise ValueError(
                    f"parameter `{parameter.get('name')}` has unsupported "
                    "multi-index test output"
                )
            input_value = self._rulespec_test_input_value(inputs or {}, index_names[0])
            if input_value is None:
                raise ValueError(
                    f"parameter `{parameter.get('name')}` needs input "
                    f"`{index_names[0]}` for indexed output"
                )
            value = values.get(str(input_value), values.get(input_value))
        if not isinstance(value, dict):
            raise ValueError(
                f"parameter `{parameter.get('name')}` has no scalar value "
                "for the requested test output"
            )
        return value

    def _rulespec_decimal(self, value: Any) -> Decimal:
        """Coerce a scalar value to Decimal for numeric equality checks."""
        try:
            return Decimal(str(value))
        except InvalidOperation as exc:
            raise ValueError(f"{value!r} is not numeric") from exc

    def _rulespec_scalar_values_equal(
        self,
        actual: dict[str, Any],
        expected: dict[str, Any],
    ) -> bool:
        """Compare Axiom rules engine scalar value specs, allowing int/decimal equality."""
        actual_kind = actual.get("kind")
        expected_kind = expected.get("kind")
        numeric = {"integer", "decimal"}
        if actual_kind in numeric and expected_kind in numeric:
            actual_decimal = self._rulespec_decimal(actual.get("value"))
            expected_decimal = self._rulespec_decimal(expected.get("value"))
            return abs(actual_decimal - expected_decimal) <= Decimal("1e-18")
        if actual_kind == "bool" and expected_kind == "bool":
            return bool(actual.get("value")) == bool(expected.get("value"))
        if actual_kind != expected_kind:
            return False
        return str(actual.get("value")) == str(expected.get("value"))

    def _format_rulespec_actual_value(self, output: dict[str, Any]) -> str:
        """Format a response/parameter output value for failure messages."""
        if output.get("kind") == "judgment":
            return str(output.get("outcome"))
        value = output.get("value") if output.get("kind") == "scalar" else output
        if isinstance(value, dict):
            return self._format_rulespec_scalar_value(value)
        return str(value)

    def _format_rulespec_scalar_value(self, value: dict[str, Any]) -> str:
        """Format a scalar value spec with its kind for failure messages."""
        return f"{value.get('kind')} {value.get('value')}"

    def _compare_rulespec_output(
        self,
        *,
        case_name: str,
        output_name: str,
        expected_value: Any,
        actual_output: Any,
    ) -> str | None:
        """Compare a single expected output; return an issue string on mismatch."""
        if isinstance(expected_value, list):
            if not isinstance(actual_output, list):
                return (
                    f"Test case `{case_name}` output `{output_name}` expected "
                    "a row-ordered list, but execution returned a scalar result."
                )
            if len(actual_output) != len(expected_value):
                return (
                    f"Test case `{case_name}` output `{output_name}` expected "
                    f"{len(expected_value)} row result(s), got {len(actual_output)}."
                )
            for row_index, (expected_item, actual_item) in enumerate(
                zip(expected_value, actual_output, strict=True),
                1,
            ):
                if isinstance(expected_item, list):
                    return (
                        f"Test case `{case_name}` output `{output_name}` row "
                        f"#{row_index} has a nested expected list; table output "
                        "expectations must be one scalar or judgment per row."
                    )
                mismatch = self._compare_rulespec_output(
                    case_name=case_name,
                    output_name=output_name,
                    expected_value=expected_item,
                    actual_output=actual_item,
                )
                if mismatch:
                    return f"{mismatch} (row #{row_index})"
            return None

        if isinstance(actual_output, list):
            return (
                f"Test case `{case_name}` output `{output_name}` expected a "
                "scalar or judgment, but execution returned a row-ordered list."
            )
        if not isinstance(actual_output, dict):
            return (
                f"Test case `{case_name}` output `{output_name}` returned "
                "an unrecognised value shape."
            )
        if actual_output.get("kind") == "judgment":
            expected = str(expected_value).strip().lower().replace("-", "_")
            if expected not in {"holds", "not_holds", "undetermined"}:
                return (
                    f"Test case `{case_name}` output `{output_name}` expected "
                    f"{expected_value!r}, but actual output is a judgment."
                )
            actual = str(actual_output.get("outcome"))
            if actual != expected:
                return (
                    f"Test case `{case_name}` output `{output_name}` expected "
                    f"{expected}, got {actual}."
                )
            return None

        actual_scalar = actual_output.get("value")
        if actual_output.get("kind") != "scalar":
            actual_scalar = actual_output
        if not isinstance(actual_scalar, dict):
            return (
                f"Test case `{case_name}` output `{output_name}` returned "
                "an unrecognised value shape."
            )
        if actual_scalar.get("kind") == "bool" and isinstance(expected_value, str):
            expected_judgment = expected_value.strip().lower().replace("-", "_")
            if expected_judgment in {"holds", "not_holds"}:
                expected_value = expected_judgment == "holds"
        expected_scalar = self._rulespec_expected_scalar_value(expected_value)
        if not self._rulespec_scalar_values_equal(actual_scalar, expected_scalar):
            return (
                f"Test case `{case_name}` output `{output_name}` expected "
                f"{self._format_rulespec_scalar_value(expected_scalar)}, got "
                f"{self._format_rulespec_actual_value(actual_output)}."
            )
        return None

    def _run_rulespec_derived_test_case(
        self,
        *,
        binary: Path,
        compiled_path: Path,
        case: dict[str, Any],
        case_name: str,
        case_index: int,
        period: dict[str, Any],
        output_names: list[str],
        output_runtime_keys: dict[str, str] | None = None,
        derived_by_key: dict[str, Any],
        require_legal_input_keys: bool,
        legal_ids_by_friendly_name: dict[str, list[str]],
        module_target: str | None,
        declared_relation_names: set[str],
    ) -> tuple[dict[str, Any] | None, list[str]]:
        """Execute one compact RuleSpec test case through `run-compiled`."""
        query_entity = str(derived_by_key[output_names[0]].get("entity") or "Case")
        query_entity_id = self._rulespec_case_query_entity_id(
            case, query_entity, case_index
        )
        try:
            dataset = self._build_rulespec_dataset(
                case.get("input", {}),
                case_tables=case.get("tables"),
                period=period,
                query_entity=query_entity,
                query_entity_id=query_entity_id,
                require_legal_input_keys=require_legal_input_keys,
                legal_ids_by_friendly_name=legal_ids_by_friendly_name,
                module_target=module_target,
                declared_relation_names=declared_relation_names,
            )
        except ValueError as exc:
            return None, [f"Test case `{case_name}` input invalid: {exc}"]

        output_map = case.get("output") if isinstance(case.get("output"), dict) else {}
        output_values_by_runtime_key: dict[str, Any] = {}
        if output_runtime_keys is None:
            output_runtime_keys = {}
        for output_key, runtime_key in output_runtime_keys.items():
            if output_key in output_map:
                output_values_by_runtime_key[runtime_key] = output_map[output_key]
        for output_name in output_names:
            if (
                output_name in output_map
                and output_name not in output_values_by_runtime_key
            ):
                output_values_by_runtime_key[output_name] = output_map[output_name]
        row_ordered_outputs = {
            output_name
            for output_name in output_names
            if isinstance(output_values_by_runtime_key.get(output_name), list)
        }
        query_entity_ids = [query_entity_id]
        if row_ordered_outputs:
            try:
                table_rows = self._rulespec_case_table_rows(case, query_entity)
            except ValueError as exc:
                return None, [f"Test case `{case_name}` tables invalid: {exc}"]
            if not table_rows:
                outputs = ", ".join(f"`{name}`" for name in sorted(row_ordered_outputs))
                return None, [
                    f"Test case `{case_name}` output {outputs} uses a row-ordered "
                    f"list but has no `tables.{query_entity}` rows."
                ]
            expected_row_count = len(table_rows)
            for output_name in row_ordered_outputs:
                expected_value = output_values_by_runtime_key.get(output_name)
                if (
                    isinstance(expected_value, list)
                    and len(expected_value) != expected_row_count
                ):
                    return None, [
                        f"Test case `{case_name}` output `{output_name}` expected "
                        f"{len(expected_value)} row value(s), but "
                        f"`tables.{query_entity}` has {expected_row_count} row(s)."
                    ]
            query_entity_ids = [row_id for row_id, _row in table_rows]

        request = {
            "mode": "explain",
            "dataset": dataset,
            "queries": [
                {
                    "entity_id": entity_id,
                    "period": period,
                    "outputs": output_names,
                }
                for entity_id in query_entity_ids
            ],
        }
        result = subprocess.run(
            [str(binary), "run-compiled", "--artifact", str(compiled_path)],
            input=json.dumps(request),
            capture_output=True,
            text=True,
            timeout=60,
            cwd=str(self.axiom_rules_path) if self.axiom_rules_path.exists() else None,
            env=self._rulespec_compile_env(),
        )
        if result.returncode != 0:
            detail = result.stderr.strip() or result.stdout.strip()
            return None, [f"Test case `{case_name}` execution failed: {detail}"]
        try:
            response = json.loads(result.stdout)
        except json.JSONDecodeError as exc:
            return None, [f"Test case `{case_name}` response JSON parse failed: {exc}"]
        results = response.get("results") if isinstance(response, dict) else None
        if not isinstance(results, list) or not results:
            return None, [f"Test case `{case_name}` returned no results."]
        if row_ordered_outputs:
            if len(results) != len(query_entity_ids):
                return None, [
                    f"Test case `{case_name}` returned {len(results)} row result(s), "
                    f"expected {len(query_entity_ids)}."
                ]
            aggregated_outputs: dict[str, list[Any]] = {
                output_name: [] for output_name in output_names
            }
            for row_index, row_result in enumerate(results, 1):
                outputs = row_result.get("outputs")
                if not isinstance(outputs, dict):
                    return None, [
                        f"Test case `{case_name}` row #{row_index} returned no "
                        "output map."
                    ]
                row_outputs = self._rulespec_outputs_by_reference(outputs)
                for output_name in output_names:
                    actual_output = row_outputs.get(output_name)
                    if actual_output is None:
                        return None, [
                            f"Test case `{case_name}` row #{row_index} output "
                            f"`{output_name}` missing from execution response."
                        ]
                    aggregated_outputs[output_name].append(actual_output)
            return aggregated_outputs, []
        outputs = results[0].get("outputs")
        if not isinstance(outputs, dict):
            return None, [f"Test case `{case_name}` returned no output map."]
        return self._rulespec_outputs_by_reference(outputs), []

    def _rulespec_outputs_by_reference(self, outputs: dict[str, Any]) -> dict[str, Any]:
        """Index runtime outputs by response key and durable id only."""
        outputs_by_reference: dict[str, Any] = {}
        for output_key, output in outputs.items():
            outputs_by_reference[str(output_key)] = output
            if not isinstance(output, dict):
                continue
            reference = str(output.get("id") or "").strip()
            if reference:
                outputs_by_reference[reference] = output
        return outputs_by_reference

    def _rulespec_output_satisfies_policyengine_hint(
        self,
        output_name: str,
        *,
        derived_by_key: dict[str, Any],
        parameter_by_key: dict[str, Any],
    ) -> bool:
        if output_name == self.policyengine_rule_hint:
            return True
        item = derived_by_key.get(output_name) or parameter_by_key.get(output_name)
        return (
            isinstance(item, dict)
            and str(item.get("name") or "") == self.policyengine_rule_hint
        )

    def _run_rulespec_test_cases(
        self,
        *,
        rules_file: Path,
        compiled_path: Path,
        compiled_payload: dict[str, Any],
        cases: list[Any],
    ) -> list[str]:
        """Run compact RuleSpec `.test.yaml` cases against the compiled artifact."""
        issues: list[str] = []
        binary: Path | None = None
        derived_by_key, parameter_by_key = self._rulespec_program_maps(compiled_payload)
        legal_ids_by_friendly_name = self._rulespec_legal_ids_by_friendly_output_name(
            compiled_payload
        )
        require_legal_input_keys = _rulespec_program_has_legal_ids(compiled_payload)
        module_target = _rulespec_module_target(compiled_payload)
        declared_relation_names = _rulespec_declared_relation_names(compiled_payload)

        for index, case in enumerate(cases, 1):
            if not isinstance(case, dict):
                issues.append(f"Test case #{index} must be a mapping.")
                continue
            case_name = str(case.get("name") or f"#{index}")
            if "name" not in case:
                issues.append(f"Test case #{index} is missing name.")
            if "period" not in case:
                issues.append(f"Test case `{case_name}` is missing period.")
                continue
            try:
                period = self._coerce_rulespec_period(case["period"])
            except ValueError as exc:
                issues.append(f"Test case `{case_name}` period invalid: {exc}")
                continue

            output_map = case.get("output")
            if "output" not in case:
                issues.append(f"Test case #{index} is missing output.")
                continue
            if not isinstance(output_map, dict) or not output_map:
                issues.append(f"Test case `{case_name}` output must be a mapping.")
                continue
            if self.policyengine_rule_hint and not any(
                self._rulespec_output_satisfies_policyengine_hint(
                    str(output_name),
                    derived_by_key=derived_by_key,
                    parameter_by_key=parameter_by_key,
                )
                for output_name in output_map
            ):
                issues.append(
                    f"Test case #{index} output must assert "
                    f"{self.policyengine_rule_hint}."
                )

            computed_input_keys = [
                input_name
                for input_name in _test_case_assignment_keys(case)
                if input_name in derived_by_key or input_name in parameter_by_key
            ]
            if computed_input_keys:
                key_display = ", ".join(f"`{key}`" for key in computed_input_keys[:4])
                if len(computed_input_keys) > 4:
                    key_display += f", and {len(computed_input_keys) - 4} more"
                issues.append(
                    f"Test case `{case_name}` assigns computed RuleSpec "
                    f"output(s) as input: {key_display}. Imported parameters "
                    "and derived outputs are computed by the compiled program; "
                    "assign their upstream `#input.*` or `#relation.*` facts "
                    "instead."
                )
                continue

            derived_outputs: list[str] = []
            parameter_outputs: list[str] = []
            output_runtime_keys: dict[str, str] = {}
            for output_name in output_map:
                output_key = str(output_name)
                runtime_key = output_key
                if (
                    _RULESPEC_ABSOLUTE_REFERENCE.match(output_key)
                    and output_key not in parameter_by_key
                    and output_key not in derived_by_key
                ):
                    local_key = _rulespec_runtime_name_from_absolute_test_reference(
                        output_key
                    )
                    if local_key in parameter_by_key or local_key in derived_by_key:
                        runtime_key = local_key
                output_runtime_keys[output_key] = runtime_key
                if runtime_key in parameter_by_key:
                    runtime_key = (
                        _rulespec_public_item_key(parameter_by_key[runtime_key])
                        or runtime_key
                    )
                    output_runtime_keys[output_key] = runtime_key
                    parameter_outputs.append(runtime_key)
                elif runtime_key in derived_by_key:
                    runtime_key = (
                        _rulespec_public_item_key(derived_by_key[runtime_key])
                        or runtime_key
                    )
                    output_runtime_keys[output_key] = runtime_key
                    derived_outputs.append(runtime_key)
                else:
                    if _RULESPEC_ABSOLUTE_REFERENCE.match(output_key):
                        resolution_issue = _rulespec_absolute_test_reference_issue(
                            output_key,
                            label="output",
                            policy_repo_path=self.policy_repo_path,
                            allow_input_slots=False,
                            allow_relations=False,
                            allow_outputs=True,
                        )
                        if resolution_issue:
                            issues.append(f"Test case `{case_name}` {resolution_issue}")
                            continue
                    legal_ids = legal_ids_by_friendly_name.get(output_key)
                    if legal_ids:
                        if len(legal_ids) == 1:
                            issue = (
                                f"Test case `{case_name}` output `{output_key}` "
                                f"must use legal RuleSpec id `{legal_ids[0]}` "
                                "instead of the friendly name."
                            )
                        else:
                            legal_id_list = ", ".join(f"`{item}`" for item in legal_ids)
                            issue = (
                                f"Test case `{case_name}` output `{output_key}` "
                                "must use a legal RuleSpec id instead of the "
                                f"ambiguous friendly name; use one of {legal_id_list}."
                            )
                        issues.append(issue)
                        continue
                    issues.append(
                        f"Test case `{case_name}` output `{output_key}` is not "
                        f"a compiled derived output or scalar parameter in {rules_file.name}."
                    )

            actual_outputs: dict[str, Any] = {}
            if derived_outputs:
                derived_entities = {
                    str(derived_by_key[output_name].get("entity") or "Case")
                    for output_name in derived_outputs
                }
                if len(derived_entities) > 1:
                    entities = ", ".join(sorted(derived_entities))
                    issues.append(
                        f"Test case `{case_name}` mixes derived output entities "
                        f"({entities}); put outputs for each entity in separate "
                        "test cases."
                    )
                    continue
                if binary is None:
                    binary = self._axiom_rules_binary()
                response_outputs, execution_issues = (
                    self._run_rulespec_derived_test_case(
                        binary=binary,
                        compiled_path=compiled_path,
                        case=case,
                        case_name=case_name,
                        case_index=index,
                        period=period,
                        output_names=derived_outputs,
                        output_runtime_keys=output_runtime_keys,
                        derived_by_key=derived_by_key,
                        require_legal_input_keys=require_legal_input_keys,
                        legal_ids_by_friendly_name=legal_ids_by_friendly_name,
                        module_target=module_target,
                        declared_relation_names=declared_relation_names,
                    )
                )
                issues.extend(execution_issues)
                if response_outputs is not None:
                    actual_outputs.update(response_outputs)

            for output_name in parameter_outputs:
                try:
                    parameter_value = self._rulespec_compiled_parameter_value(
                        parameter_by_key[output_name],
                        period,
                        case.get("input", {}),
                    )
                except ValueError as exc:
                    issues.append(f"Test case `{case_name}` parameter failed: {exc}")
                    continue
                actual_outputs[output_name] = {
                    "kind": "scalar",
                    "value": parameter_value,
                }

            for output_name, expected_value in output_map.items():
                output_key = str(output_name)
                runtime_key = output_runtime_keys.get(output_key, output_key)
                actual_output = actual_outputs.get(output_key) or actual_outputs.get(
                    runtime_key
                )
                if actual_output is None:
                    if (
                        runtime_key in derived_outputs
                        or runtime_key in parameter_outputs
                    ):
                        issues.append(
                            f"Test case `{case_name}` output `{output_key}` missing "
                            "from execution response."
                        )
                    continue
                mismatch = self._compare_rulespec_output(
                    case_name=case_name,
                    output_name=output_key,
                    expected_value=expected_value,
                    actual_output=actual_output,
                )
                if mismatch:
                    issues.append(mismatch)

        return issues

    def _run_rulespec_ci(self, rules_file: Path) -> ValidationResult:
        """Run RuleSpec compile, executable tests, and source-grounding checks."""
        start = time.time()
        issues: list[str] = []
        content = rules_file.read_text()
        raw_output: str | None = None
        compiled_payload: dict[str, Any] | None = None
        compiled_path: Path | None = None

        issues.extend(find_source_table_row_scalar_parameter_issues(content))
        issues.extend(find_interval_table_reencoding_issues(content))
        issues.extend(self._check_embedded_scalar_literals(rules_file))

        tmpdir_cm = tempfile.TemporaryDirectory()
        tmpdir = Path(tmpdir_cm.name)
        try:
            compiled_path = tmpdir / "compiled.json"
            compile_result, payload = self._compile_rulespec_to_artifact(
                rules_file, compiled_path
            )
            raw_output = compile_result.stdout + compile_result.stderr
            if compile_result.returncode != 0:
                detail = compile_result.stderr.strip() or compile_result.stdout.strip()
                issues.append(f"Axiom rules engine compile failed: {detail}")
            elif isinstance(payload, dict):
                compiled_payload = payload
                raw_output = self._rulespec_compile_success_output(payload)
            else:
                issues.append(
                    "Axiom rules engine compile did not return an artifact payload."
                )
        except Exception as exc:
            issues.append(f"Axiom rules engine compile failed: {exc}")

        issues.extend(find_ungrounded_numeric_issues(content))
        issues.extend(find_deprecated_source_url_issues(content))
        issues.extend(find_source_claim_reference_issues(content))
        issues.extend(find_empty_rules_module_issues(content))
        proof_issues = (
            validate_rulespec_proofs(
                content,
                require_policy_proofs=self.require_policy_proofs,
            ).issues
            if self.require_policy_proofs
            else find_rulespec_proof_issues(content)
        )
        issues.extend(proof_issues)
        issues.extend(find_structured_scale_parameter_issues(content))
        issues.extend(find_versioned_derived_formula_issues(content))
        issues.extend(find_upstream_placement_issues(content, rules_file=rules_file))
        issues.extend(find_source_verification_issues(content))
        issues.extend(find_source_condition_coverage_issues(content))
        issues.extend(find_anaphoric_scope_omission_issues(content))
        issues.extend(find_filtered_entity_dependency_issues(content))
        issues.extend(find_source_scope_consistency_issues(content))
        issues.extend(find_employer_scoped_entity_issues(content))
        issues.extend(find_shared_statutory_rate_entity_suffix_name_issues(content))
        issues.extend(find_person_scoped_rate_base_unit_issues(content))
        issues.extend(find_person_scoped_definition_unit_issues(content))
        issues.extend(
            find_imported_person_scoped_definition_unit_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(find_helper_only_definition_issues(content))
        issues.extend(find_deferred_output_issues(content))
        issues.extend(find_mixed_case_rule_name_token_issues(content))
        # Read the requested-source target from the nearby eval workspace or
        # the durable apply manifest so subparagraph-coverage scoping respects
        # encoder intent even when the corpus served a parent-fallback source
        # slice (issue #71).
        requested_source = _requested_source_from_metadata(
            _load_nearby_eval_source_metadata(rules_file)
        )
        if requested_source is None:
            requested_source = _requested_source_from_metadata(
                _load_applied_encoding_manifest_source_metadata(
                    rules_file,
                    self.policy_repo_path,
                )
            )
        issues.extend(
            find_out_of_scope_rule_source_issues(
                content,
                requested_source=requested_source,
            )
        )
        issues.extend(
            find_source_subparagraph_coverage_issues(
                content,
                rules_file=rules_file,
                requested_source=requested_source,
            )
        )
        issues.extend(find_tax_status_component_local_input_issues(content))
        issues.extend(find_unused_modifier_parameter_issues(content))
        issues.extend(find_tax_filing_status_enum_representation_issues(content))
        issues.extend(find_tax_filing_status_surviving_spouse_issues(content))
        issues.extend(find_formula_date_literal_issues(content))
        issues.extend(find_temporal_value_fact_name_issues(content))
        issues.extend(find_judgment_conditional_formula_issues(content))
        issues.extend(find_nonnegative_amount_reduction_issues(content))
        issues.extend(
            find_current_year_final_amount_table_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(find_relation_aggregate_syntax_issues(content))
        issues.extend(find_role_limited_relation_scope_issues(content))
        issues.extend(find_entity_limited_aggregation_order_issues(content))
        issues.extend(find_source_limitation_application_issues(content))
        issues.extend(find_partial_extent_zeroing_issues(content))
        issues.extend(find_scoped_exception_category_gate_issues(content))
        issues.extend(find_current_purpose_placeholder_issues(content))
        issues.extend(find_deferred_purpose_specific_limitation_issues(content))
        issues.extend(
            find_imported_deferred_branch_composition_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(find_broad_application_passthrough_issues(content))
        issues.extend(find_formula_absolute_reference_issues(content))
        issues.extend(find_import_shape_issues(content))
        issues.extend(find_unused_import_issues(content))
        issues.extend(find_proof_import_reference_issues(content))
        issues.extend(
            find_proof_import_hash_consistency_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(
            find_copied_cross_reference_source_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(
            find_missing_same_section_subsection_import_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(
            find_missing_child_exception_import_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(find_aggregate_exception_predicate_issues(content))
        issues.extend(find_unconsumed_local_exception_output_issues(content))
        issues.extend(self._check_cross_reference_exception_placeholders(rules_file))
        issues.extend(self._check_encoded_cross_reference_placeholders(rules_file))
        issues.extend(self._check_cross_reference_numeric_placeholders(rules_file))
        issues.extend(self._check_unrelated_same_section_term_imports(rules_file))
        issues.extend(self._check_flattened_thresholded_imported_rates(rules_file))
        issues.extend(self._check_unapplied_cross_reference_base_mechanics(rules_file))
        issues.extend(
            find_source_relation_issues(content, policy_repo_path=self.policy_repo_path)
        )
        issues.extend(
            find_delegated_policy_setting_issues(content, rules_file=rules_file)
        )
        issues.extend(
            find_rule_name_path_suffix_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        issues.extend(find_sibling_rule_name_collision_issues(content, rules_file))
        issues.extend(find_synthetic_source_authorized_input_issues(content))
        issues.extend(
            find_child_fragment_reencoding_issues(
                content,
                rules_file=rules_file,
                policy_repo_path=self.policy_repo_path,
            )
        )
        strict_layout_checks = (
            _strict_rules_repo_layout_checks_enabled(
                policy_repo_path=self.policy_repo_path,
                rules_file=rules_file,
            )
            and self.enforce_repository_layout
        )
        if strict_layout_checks:
            issues.extend(find_rule_source_metadata_issues(content))

        test_path = self._rulespec_test_path(rules_file)
        if test_path.exists():
            try:
                payload = yaml.safe_load(test_path.read_text())
            except (yaml.YAMLError, ValueError) as exc:
                issues.append(f"Test YAML parse failed: {exc}")
            else:
                if payload in (None, ""):
                    if not self._is_nonassertable_rulespec_artifact(rules_file):
                        issues.append("No tests found.")
                elif not isinstance(payload, list):
                    if isinstance(payload, dict) and isinstance(
                        payload.get("cases"), list
                    ):
                        payload = payload["cases"]
                    else:
                        issues.append("RuleSpec tests must be a YAML list of cases.")
                        payload = None
                if isinstance(payload, list) and compiled_payload and compiled_path:
                    pre_test_issue_count = len(issues)
                    if strict_layout_checks:
                        issues.extend(
                            find_missing_derived_companion_output_issues(
                                content,
                                payload,
                                rules_file=rules_file,
                                policy_repo_path=self.policy_repo_path,
                            )
                        )
                        issues.extend(
                            find_judgment_positive_companion_output_issues(
                                content,
                                payload,
                                rules_file=rules_file,
                                policy_repo_path=self.policy_repo_path,
                            )
                        )
                    issues.extend(find_test_input_assignment_issues(content, payload))
                    issues.extend(find_tax_filing_status_test_input_issues(payload))
                    issues.extend(find_exception_test_coverage_issues(content, payload))
                    issues.extend(
                        find_zero_branch_test_coverage_issues(content, payload)
                    )
                    if len(issues) == pre_test_issue_count:
                        issues.extend(
                            self._run_rulespec_test_cases(
                                rules_file=rules_file,
                                compiled_path=compiled_path,
                                compiled_payload=compiled_payload,
                                cases=payload,
                            )
                        )
        elif not issues and not self._is_nonassertable_rulespec_artifact(rules_file):
            issues.append("No tests found.")

        duration = int((time.time() - start) * 1000)
        try:
            return ValidationResult(
                validator_name="ci",
                passed=len(issues) == 0,
                issues=issues,
                duration_ms=duration,
                error=issues[0] if issues else None,
                raw_output=raw_output,
            )
        finally:
            tmpdir_cm.cleanup()

    def _is_nonassertable_rulespec_artifact(self, rules_file: Path) -> bool:
        """Return true when a RuleSpec artifact intentionally has no assertions."""
        try:
            payload = yaml.safe_load(rules_file.read_text())
        except (yaml.YAMLError, ValueError):
            return False
        if not isinstance(payload, dict):
            return False
        module = payload.get("module")
        status = (
            str(module.get("status", "")).strip()
            if isinstance(module, dict)
            else str(payload.get("status", "")).strip()
        )
        rules = payload.get("rules")
        if (
            isinstance(rules, list)
            and rules
            and all(
                isinstance(rule, dict)
                and str(rule.get("kind") or "").lower() == "source_relation"
                for rule in rules
            )
        ):
            return True
        return status in {"deferred", "entity_not_supported"} and not payload.get(
            "rules"
        )

    def _run_ci(self, rulespec_file: Path) -> ValidationResult:
        """Run CI checks for RuleSpec artifacts."""
        if not self._is_rulespec_file(rulespec_file):
            return ValidationResult(
                validator_name="ci",
                passed=False,
                issues=["RuleSpec YAML artifacts are required."],
                error="RuleSpec YAML artifacts are required",
            )
        return self._run_rulespec_ci(rulespec_file)

    def _copy_validation_import_closure(
        self,
        rulespec_file: Path,
        destination_root: Path,
        root_destination_relative: Path | None = None,
        include_root_companion_test: bool = False,
    ) -> None:
        """Copy a RuleSpec file and dependencies into a temp tree."""
        source_root = self._validation_source_root(rulespec_file)
        root_resolved = rulespec_file.resolve()
        pending = [root_resolved]
        copied: set[Path] = set()

        while pending:
            current = pending.pop()
            resolved = current.resolve()
            if resolved in copied:
                continue
            copied.add(resolved)

            if resolved == root_resolved and root_destination_relative is not None:
                relative = root_destination_relative
            else:
                relative = current.relative_to(source_root)
            target = destination_root / relative
            target.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(current, target)

            if include_root_companion_test and resolved == root_resolved:
                companion_test = self._rulespec_test_path(current)
                if companion_test.exists():
                    companion_target = self._rulespec_test_path(target)
                    companion_target.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(companion_test, companion_target)

            for dependency in self._resolve_import_dependencies(current, source_root):
                if dependency.resolve() not in copied:
                    pending.append(dependency)

    def _validation_source_root(self, rulespec_file: Path) -> Path:
        """Resolve the root directory used for import lookup during CI validation."""
        resolved_file = rulespec_file.resolve()
        resolved_root = self.policy_repo_path.resolve()
        with contextlib.suppress(ValueError):
            resolved_file.relative_to(resolved_root)
            return resolved_root
        if resolved_file.parent.name == "source":
            runner_root = resolved_file.parent.parent
            if any(
                (runner_root / sibling).exists()
                for sibling in ("external", "legislation", "regulation", "statutes")
            ):
                return runner_root
        return resolved_file.parent

    def _resolve_import_dependencies(
        self,
        rulespec_file: Path,
        source_root: Path,
    ) -> list[Path]:
        """Resolve imported RuleSpec files for a single file."""
        dependencies: list[Path] = []
        for import_path in self._extract_import_paths(rulespec_file.read_text()):
            target = source_root / self._import_to_relative_rulespec_path(import_path)
            if target.exists():
                dependencies.append(target)
        return dependencies

    def _extract_import_paths(self, content: str) -> list[str]:
        """Extract import file references from an imports block."""
        return [
            self._normalize_rulespec_import_path(item)
            for item in self._extract_import_items(content)
            if item.split("#", 1)[0].strip()
        ]

    def _extract_import_items(self, content: str) -> list[str]:
        """Extract raw import items from an imports block."""
        paths: list[str] = []
        in_imports = False
        imports_indent = 0

        for line in content.splitlines():
            imports_match = re.match(r"^(\s*)imports:\s*$", line)
            if imports_match:
                in_imports = True
                imports_indent = len(imports_match.group(1))
                continue

            if not in_imports:
                continue

            if not line.strip():
                continue

            indent = len(line) - len(line.lstrip())
            top_level_sequence_item = (
                indent == imports_indent and IMPORT_ITEM_PATTERN.match(line)
            )
            if indent <= imports_indent and not top_level_sequence_item:
                in_imports = False
                continue

            item_match = IMPORT_ITEM_PATTERN.match(line)
            if item_match:
                item = item_match.group(2).strip()
            else:
                mapping_match = IMPORT_MAPPING_PATTERN.match(line)
                if not mapping_match:
                    continue
                item = mapping_match.group(2).strip()
            item = item.strip().strip("\"'")
            if item:
                paths.append(item)

        return paths

    def _import_to_relative_rulespec_path(self, import_target: str) -> Path:
        """Convert an import target like 26/24/c#name into 26/24/c.yaml."""
        normalized = self._normalize_rulespec_import_path(import_target)
        if normalized.endswith((".yaml", ".yml")):
            return Path(normalized)
        return Path(f"{normalized}.yaml")

    def _extract_defined_symbols(self, content: str) -> list[str]:
        """Extract RuleSpec rule names."""
        with contextlib.suppress(yaml.YAMLError, TypeError, ValueError):
            payload = yaml.safe_load(content)
            if isinstance(payload, dict) and isinstance(payload.get("rules"), list):
                return sorted(
                    {
                        str(rule.get("name")).strip()
                        for rule in payload["rules"]
                        if isinstance(rule, dict) and str(rule.get("name", "")).strip()
                    }
                )
        return []

    def _check_cross_statute_definition_imports(self, rulespec_file: Path) -> list[str]:
        """Flag missing imports for explicit cross-statute definition references."""
        if rulespec_file.stem == rulespec_file.parent.name:
            return []

        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        title = self._infer_title_from_rulespec_path(rulespec_file)
        if not title:
            return []

        imports = set(self._extract_import_paths(content))
        issues: list[str] = []
        for citation, import_path in self._extract_definition_cross_references(
            source_text, title
        ):
            if not self._rulespec_import_target_exists(import_path):
                continue
            if self._imports_cover_path(imports, import_path):
                continue
            issues.append(
                "Cross-statute definition import missing: "
                f"source text references section {citation} but file does not import "
                f"from {import_path}"
            )
        return issues

    def _rulespec_import_target_exists(self, import_path: str) -> bool:
        """Return whether a canonical statute import target exists locally."""
        target = (
            self.policy_repo_path
            / "statutes"
            / self._import_to_relative_rulespec_path(import_path)
        )
        if target.exists():
            return True
        return target.with_suffix("").is_dir()

    def _check_cross_reference_exception_placeholders(
        self, rulespec_file: Path
    ) -> list[str]:
        """Reject local placeholder facts for cited exception sections."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text or not re.search(
            r"\b(?:except|unless|notwithstanding)\b"
            r"|shall\s+not\s+apply"
            r"|not\s+(?:be\s+)?treated",
            source_text,
            flags=re.IGNORECASE,
        ):
            return []

        title = self._infer_title_from_rulespec_path(rulespec_file)
        if not title:
            return []
        current_section = self._infer_section_from_rulespec_path(rulespec_file)

        import_items = self._extract_import_items(content)
        issues: list[str] = []
        seen: set[tuple[str, str]] = set()
        for block in self._extract_definition_blocks(content):
            formula = "\n".join(str(line) for line in block["body_lines"])
            identifiers = _formula_local_identifiers(formula)
            identifiers.update(_exception_formula_inputs(formula))
            for identifier in sorted(identifiers):
                import_base = self._cross_reference_placeholder_import_base(
                    identifier,
                    title=title,
                    current_section=current_section,
                    source_text=source_text,
                )
                if not import_base:
                    import_base = self._semantic_section_placeholder_import_base(
                        identifier,
                        title=title,
                        current_section=current_section,
                        source_text=source_text,
                    )
                if not import_base:
                    continue
                if self._imports_cover_placeholder_identifier(
                    import_items,
                    import_base,
                    identifier,
                    rulespec_file=rulespec_file,
                ) or self._imports_cover_relation_field_placeholder(
                    import_items,
                    import_base,
                    identifier,
                    formula=formula,
                    rulespec_file=rulespec_file,
                ):
                    continue
                if self._is_source_stated_category_boundary(
                    block=block,
                    identifier=identifier,
                    import_base=import_base,
                    source_text=source_text,
                ):
                    continue
                key = (str(block["name"]), identifier)
                if key in seen:
                    continue
                seen.add(key)
                resolution = (
                    f"Import `{import_base}` instead of creating a local "
                    "cross-reference input."
                )
                if not self._rulespec_import_target_exists(
                    import_base.removeprefix("statutes/")
                ):
                    resolution = (
                        f"Encode `{import_base}` first, or emit "
                        "`module.status: deferred` or "
                        "`module.status: entity_not_supported` with `rules: []` "
                        "if this provision cannot be computed without that "
                        "upstream source."
                    )
                issues.append(
                    "Cross-reference placeholder: "
                    f"`{block['name']}` uses local fact `{identifier}` "
                    f"for a cited legal section. {resolution}"
                )
        return issues

    def _is_source_stated_category_boundary(
        self,
        *,
        block: dict[str, object],
        identifier: str,
        import_base: str,
        source_text: str,
    ) -> bool:
        """Allow cited-law category labels without allowing cited mechanics."""
        if identifier.startswith(("section_", "subsection_")):
            return False
        if not re.search(
            r"(?:^|_)(?:included|constitutes|covered|entered|established|treated|meaning)(?:_|$)",
            identifier,
            flags=re.IGNORECASE,
        ):
            return False

        proof_excerpts = block.get("proof_excerpts")
        scoped_text = (
            " ".join(str(item) for item in proof_excerpts)
            if isinstance(proof_excerpts, list)
            else ""
        ).strip()
        if not scoped_text:
            scoped_text = source_text
        if not self._source_text_mentions_import_base(scoped_text, import_base):
            return False
        if not re.search(
            r"\b(?:"
            r"included\s+under|"
            r"constitutes\b|"
            r"covered\s+by|"
            r"entered\s+into\s+pursuant\s+to|"
            r"established\s+by|"
            r"treated\s+(?:pursuant\s+to|under|as)|"
            r"meaning\s+given"
            r")\b",
            scoped_text,
            flags=re.IGNORECASE,
        ):
            return False
        return bool(
            re.search(
                r"\b(?:"
                r"agreement|category|class|employee|employment|instrumentality|"
                r"member|officer|official|position|retirement\s+system|service|"
                r"status|worker"
                r")\b",
                scoped_text,
                flags=re.IGNORECASE,
            )
        )

    def _source_text_mentions_import_base(
        self, source_text: str, import_base: str
    ) -> bool:
        parts = import_base.split("/")
        try:
            statutes_index = parts.index("statutes")
        except ValueError:
            return False
        citation_parts = parts[statutes_index + 1 :]
        if len(citation_parts) < 2:
            return False
        section = re.escape(citation_parts[1])
        fragments = "".join(
            rf"\s*\(\s*{re.escape(fragment)}\s*\)" for fragment in citation_parts[2:]
        )
        return bool(
            re.search(
                rf"\bsection\s+{section}{fragments}(?:\b|\s|,|\))",
                source_text,
                flags=re.IGNORECASE,
            )
        )

    def _check_encoded_cross_reference_placeholders(
        self, rulespec_file: Path
    ) -> list[str]:
        """Reject local cross-reference placeholders when the cited source exists."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        title = self._infer_title_from_rulespec_path(rulespec_file)
        if not title:
            return []
        current_section = self._infer_section_from_rulespec_path(rulespec_file)
        import_items = self._extract_import_items(content)
        local_blocks = {
            str(block["name"]): block
            for block in self._extract_definition_blocks(content)
        }

        issues: list[str] = []
        seen: set[tuple[str, str]] = set()
        for block in local_blocks.values():
            formula = "\n".join(str(line) for line in block["body_lines"])
            for identifier in sorted(_formula_local_identifiers(formula)):
                import_base = self._cross_reference_placeholder_import_base(
                    identifier,
                    title=title,
                    current_section=current_section,
                    source_text=source_text,
                )
                if not import_base:
                    import_base = self._semantic_section_placeholder_import_base(
                        identifier,
                        title=title,
                        current_section=current_section,
                        source_text=source_text,
                    )
                if not import_base:
                    continue
                target_import_base = import_base.removeprefix("statutes/")
                target_exists = self._rulespec_import_target_exists(target_import_base)
                if not target_exists and not self._source_text_requires_upstream_import(
                    source_text
                ):
                    continue
                if (
                    self._imports_cover_placeholder_identifier(
                        import_items,
                        import_base,
                        identifier,
                        rulespec_file=rulespec_file,
                    )
                    or self._imports_cover_relation_field_placeholder(
                        import_items,
                        import_base,
                        identifier,
                        formula=formula,
                        rulespec_file=rulespec_file,
                    )
                    or self._local_definition_resolves_cross_reference_placeholder(
                        local_blocks,
                        import_items,
                        import_base,
                        identifier,
                        rulespec_file=rulespec_file,
                    )
                ):
                    continue
                key = (str(block["name"]), identifier)
                if key in seen:
                    continue
                seen.add(key)
                resolution = (
                    f"Import `{import_base}` and reference "
                    "the upstream output instead of keeping a local "
                    "cross-reference input."
                )
                if not target_exists:
                    resolution = (
                        f"Encode `{import_base}` first, or emit "
                        "`module.status: deferred` or "
                        "`module.status: entity_not_supported` with `rules: []` "
                        "if this provision cannot be computed without that "
                        "upstream source."
                    )
                issues.append(
                    "Encoded cross-reference placeholder: "
                    f"`{block['name']}` uses local `{identifier}` for an already "
                    f"encoded or required cited source. {resolution}"
                )
        return issues

    def _local_definition_resolves_cross_reference_placeholder(
        self,
        local_blocks: dict[str, dict[str, object]],
        import_items: list[str],
        expected_path: str,
        identifier: str,
        *,
        rulespec_file: Path,
    ) -> bool:
        """Return whether a local helper composes an imported cited source.

        Section-looking local inputs are placeholders. A same-file derived helper
        with a section-looking name can still be legitimate when it directly
        references an imported output from that cited section and applies the
        current source's own condition around it.
        """
        block = local_blocks.get(identifier)
        if block is None:
            return False

        formula = "\n".join(str(line) for line in block["body_lines"])
        formula_identifiers = _formula_local_identifiers(formula)
        if not formula_identifiers:
            return False

        expected = expected_path.strip("/")
        for import_item in import_items:
            normalized = self._normalize_rulespec_import_path(import_item)
            if not self._imports_cover_path({normalized}, expected):
                continue

            fragment = self._import_item_fragment(import_item)
            if fragment and fragment in formula_identifiers:
                return True

            import_file = _resolve_rulespec_import_file_static(
                import_item,
                rules_file=rulespec_file,
                policy_repo_path=self.policy_repo_path,
            )
            if import_file is None:
                continue
            with contextlib.suppress(OSError):
                imported_symbols = set(
                    self._extract_defined_symbols(import_file.read_text())
                )
                if formula_identifiers & imported_symbols:
                    return True
        return False

    def _check_cross_reference_numeric_placeholders(
        self, rulespec_file: Path
    ) -> list[str]:
        """Reject local numeric placeholders for rates/percentages set upstream."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        title = self._infer_title_from_rulespec_path(rulespec_file)
        if not title:
            return []

        obligations = self._extract_cross_reference_numeric_obligations(
            source_text,
            title=title,
        )
        if not obligations:
            return []

        import_items = self._extract_import_items(content)
        import_paths = {
            self._normalize_rulespec_import_path(import_item)
            for import_item in import_items
        }

        issues: list[str] = []
        seen: set[tuple[str, str, str]] = set()
        for label, import_base, source_child in obligations:
            if self._imports_cover_path(import_paths, import_base):
                continue

            target_import_base = import_base.removeprefix("statutes/")
            target_exists = self._rulespec_import_target_exists(target_import_base)
            resolution = (
                f"Import `{import_base}` and reference the upstream output "
                "instead of keeping a local numeric cross-reference input."
            )
            if not target_exists:
                resolution = (
                    f"Encode `{import_base}` first, or emit "
                    "`module.status: deferred` or "
                    "`module.status: entity_not_supported` with `rules: []` "
                    "if this provision cannot be computed without that "
                    "upstream source."
                )

            for block in self._extract_definition_blocks(content):
                block_source_child = self._rule_source_top_level_child(block)
                if (
                    source_child
                    and block_source_child
                    and block_source_child != source_child
                ):
                    continue
                formula = "\n".join(str(line) for line in block["body_lines"])
                for identifier in sorted(_formula_local_identifiers(formula)):
                    if not self._identifier_matches_numeric_cross_reference(
                        identifier,
                        label,
                    ):
                        continue
                    key = (str(block["name"]), identifier, import_base)
                    if key in seen:
                        continue
                    seen.add(key)
                    issues.append(
                        "Cross-reference numeric placeholder: "
                        f"`{block['name']}` uses local `{identifier}` for "
                        f"`{label}` set by a cited legal section. {resolution}"
                    )
        return issues

    def _check_flattened_thresholded_imported_rates(
        self, rulespec_file: Path
    ) -> list[str]:
        """Reject formulas that flatten thresholded imported rates into flat rates."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        imported_rate_sources: dict[str, str] = {}
        for import_item in self._extract_import_items(content):
            fragment = self._import_item_fragment(import_item)
            if not fragment or "rate" not in fragment.lower():
                continue
            import_file = _resolve_rulespec_import_file_static(
                import_item,
                rules_file=rulespec_file,
                policy_repo_path=self.policy_repo_path,
            )
            if import_file is None:
                continue
            with contextlib.suppress(OSError):
                imported_content = import_file.read_text()
                if _imported_rate_source_is_thresholded(
                    imported_content,
                    fragment,
                ):
                    imported_rate_sources[fragment] = import_item

        if not imported_rate_sources:
            return []

        issues: list[str] = []
        for block in self._extract_definition_blocks(content):
            formula = "\n".join(str(line) for line in block["body_lines"])
            identifiers = _formula_local_identifiers(formula)
            for rate_name, import_item in sorted(imported_rate_sources.items()):
                if rate_name not in identifiers:
                    continue
                if _block_is_source_stated_composite_rate(block, source_text):
                    continue
                if _formula_preserves_thresholded_rate_mechanics(formula):
                    continue
                issues.append(
                    "Flattened thresholded imported rate: "
                    f"`{block['name']}` uses imported `{rate_name}` from "
                    f"`{import_item}` without the cited source's threshold, "
                    "cap, base, or excess-amount mechanics. Import and compose "
                    "the cited executable amount or the cited base/threshold "
                    "outputs, or defer the affected output instead of applying "
                    "the rate as a flat percentage."
                )
        return issues

    def _check_unrelated_same_section_term_imports(
        self,
        rulespec_file: Path,
    ) -> list[str]:
        """Reject imports that substitute an unrelated same-named section term.

        A common failure mode is importing another credit's `qualified_wages_*`
        output because the words match, even though the current section already
        defines or defers its own `qualified_wages`. In that case the generated
        artifact should import the same-section definition or defer, not borrow
        a same-named concept from an unrelated section.
        """
        content = rulespec_file.read_text()
        source_root = self._validation_source_root(rulespec_file)
        relative_info = self._rulespec_relative_parts_and_root(
            rulespec_file,
            source_root=source_root,
        )
        if relative_info is None:
            return []
        relative_parts, rulespec_root = relative_info
        if len(relative_parts) < 4 or relative_parts[0] != "statutes":
            return []

        current_section_parts = relative_parts[:3]
        same_section_terms: dict[str, Path] = {}
        for (
            section_source_root,
            current_section_root,
        ) in self._same_section_candidate_roots(
            current_section_parts,
            rulespec_root=rulespec_root,
        ):
            for term, term_file in self._same_section_output_terms(
                current_section_root=current_section_root,
                current_file=rulespec_file,
                source_root=section_source_root,
            ).items():
                same_section_terms.setdefault(term, term_file)
        if not same_section_terms:
            return []

        source_text = extract_embedded_source_text(content)
        formula_identifiers = self._rulespec_formula_identifiers(content)
        issues: list[str] = []
        seen: set[tuple[str, str]] = set()
        for import_item in self._extract_import_items(content):
            import_parts = self._normalized_import_parts(import_item)
            if len(import_parts) < 3 or import_parts[0] != "statutes":
                continue
            if import_parts[:3] == current_section_parts:
                continue

            imported_section = import_parts[2]
            imported_symbols = self._imported_symbols_for_same_section_term_check(
                import_item,
                rulespec_file=rulespec_file,
                formula_identifiers=formula_identifiers,
            )
            for local_term, local_file in same_section_terms.items():
                overlapping_symbols = [
                    symbol
                    for symbol in imported_symbols
                    if _identifier_phrase_occurs(local_term, symbol)
                ]
                if not overlapping_symbols:
                    continue
                if all(
                    _same_section_term_overlap_is_rate_import(
                        local_term,
                        symbol,
                        import_item,
                    )
                    for symbol in overlapping_symbols
                ):
                    continue
                if self._source_summary_cites_import_for_term(
                    source_text,
                    section=imported_section,
                    term=local_term,
                ):
                    continue
                key = (import_item, local_term)
                if key in seen:
                    continue
                seen.add(key)
                relative_local = self._rulespec_relative_display_path(
                    local_file,
                    rulespec_root,
                    source_root,
                    self.policy_repo_path,
                )
                issues.append(
                    "Unrelated same-section term import: "
                    f"`{import_item}` overlaps same-section term `{local_term}` "
                    f"defined or deferred in `{relative_local}`. Import the "
                    "same-section output or defer the dependent output instead "
                    "of using an unrelated section's same-named concept."
                )
        return issues

    def _rulespec_formula_identifiers(self, content: str) -> set[str]:
        identifiers: set[str] = set()
        for block in self._extract_definition_blocks(content):
            formula = "\n".join(str(line) for line in block["body_lines"])
            identifiers.update(_formula_local_identifiers(formula))
        return identifiers

    def _imported_symbols_for_same_section_term_check(
        self,
        import_item: str,
        *,
        rulespec_file: Path,
        formula_identifiers: set[str],
    ) -> list[str]:
        fragment = self._import_item_fragment(import_item)
        if fragment:
            return [fragment]

        import_file = _resolve_rulespec_import_file_static(
            import_item,
            rules_file=rulespec_file,
            policy_repo_path=self.policy_repo_path,
        )
        if import_file is None:
            return []
        try:
            imported_content = import_file.read_text()
        except OSError:
            return []

        symbols = [
            *self._extract_defined_symbols(imported_content),
            *self._extract_deferred_output_symbols(imported_content),
        ]
        return [
            symbol
            for symbol in symbols
            if symbol in formula_identifiers
            or _normalize_identifier(symbol) in formula_identifiers
        ]

    def _rulespec_relative_parts_and_root(
        self,
        rulespec_file: Path,
        *,
        source_root: Path,
    ) -> tuple[tuple[str, ...], Path] | None:
        resolved = rulespec_file.resolve()
        source_root_resolved = source_root.resolve()
        with contextlib.suppress(ValueError):
            relative = resolved.relative_to(source_root_resolved)
            if relative.parts and relative.parts[0] == "statutes":
                return tuple(relative.parts), source_root

        parts = resolved.parts
        for index in range(len(parts) - 1, -1, -1):
            if parts[index] != "statutes":
                continue
            relative_parts = tuple(parts[index:])
            if len(relative_parts) < 4:
                continue
            return relative_parts, Path(*parts[:index])
        return None

    def _same_section_candidate_roots(
        self,
        current_section_parts: tuple[str, ...],
        *,
        rulespec_root: Path,
    ) -> list[tuple[Path, Path]]:
        candidates: list[tuple[Path, Path]] = []
        seen: set[Path] = set()
        for source_root in (rulespec_root, self.policy_repo_path):
            section_root = source_root.joinpath(*current_section_parts)
            if not section_root.is_dir():
                continue
            resolved = section_root.resolve()
            if resolved in seen:
                continue
            seen.add(resolved)
            candidates.append((source_root, section_root))
        return candidates

    def _same_section_output_terms(
        self,
        *,
        current_section_root: Path,
        current_file: Path,
        source_root: Path,
    ) -> dict[str, Path]:
        terms: dict[str, Path] = {}
        for candidate_file in sorted(current_section_root.rglob("*.yaml")):
            if candidate_file.name.endswith(".test.yaml"):
                continue
            if candidate_file.resolve() == current_file.resolve():
                continue
            try:
                content = candidate_file.read_text()
            except OSError:
                continue
            for symbol in (
                *self._extract_defined_symbols(content),
                *self._extract_deferred_output_symbols(content),
            ):
                term = _normalize_identifier(symbol)
                if not _same_section_term_is_specific(term):
                    continue
                terms.setdefault(term, candidate_file)
        return terms

    def _rulespec_relative_display_path(self, path: Path, *roots: Path) -> str:
        resolved = path.resolve()
        for root in roots:
            with contextlib.suppress(ValueError):
                return resolved.relative_to(root.resolve()).as_posix()
        parts = resolved.parts
        for index, part in enumerate(parts):
            if part == "statutes":
                return Path(*parts[index:]).as_posix()
        return path.as_posix()

    def _extract_deferred_output_symbols(self, content: str) -> list[str]:
        try:
            payload = yaml.safe_load(content)
        except (yaml.YAMLError, ValueError, TypeError):
            return []
        if not isinstance(payload, dict):
            return []
        module = payload.get("module")
        if not isinstance(module, dict):
            return []
        deferred_outputs = module.get("deferred_outputs")
        if not isinstance(deferred_outputs, list):
            return []
        symbols: list[str] = []
        for item in deferred_outputs:
            output = None
            if isinstance(item, dict):
                output = item.get("output")
            elif isinstance(item, str):
                output = item
            if not isinstance(output, str):
                continue
            fragment = output.split("#", 1)[1] if "#" in output else output
            fragment = fragment.strip()
            if fragment:
                symbols.append(fragment)
        return symbols

    def _normalized_import_parts(self, import_item: str) -> tuple[str, ...]:
        normalized = self._normalize_rulespec_import_path(import_item)
        parts = tuple(Path(normalized).with_suffix("").parts)
        if parts and parts[0] == "statutes":
            return parts
        if len(parts) >= 2 and re.fullmatch(r"[0-9A-Za-z.-]+", parts[0]):
            return ("statutes", *parts)
        return parts

    def _source_summary_cites_import_for_term(
        self,
        source_text: str,
        *,
        section: str,
        term: str,
    ) -> bool:
        if not source_text.strip():
            return False
        term_phrase = term.replace("_", r"\s+")
        section_phrase = rf"(?:section|sections)\s+{re.escape(section)}\b"
        citation_pattern = re.compile(
            rf"{term_phrase}.{{0,120}}{section_phrase}|"
            rf"{section_phrase}.{{0,120}}{term_phrase}",
            flags=re.IGNORECASE | re.DOTALL,
        )
        definitional_pattern = re.compile(
            r"\b(?:"
            r"as\s+defined|defined\s+(?:in|under|by)|"
            r"meaning\s+(?:given|provided)|same\s+meaning|"
            r"determined\s+(?:under|by|in|with\s+reference\s+to)|"
            r"computed\s+(?:under|by)|calculated\s+(?:under|by)"
            r")\b",
            flags=re.IGNORECASE,
        )
        exclusion_pattern = re.compile(
            r"\b(?:"
            r"coordination|double\s+benefit|disallow(?:ed|ance)?|"
            r"exclud(?:e|es|ed|ing)|except|not\s+taken|offset|"
            r"reduc(?:e|es|ed|ing|tion)|shall\s+not|"
            r"taken\s+into\s+account\s+under|without"
            r")\b",
            flags=re.IGNORECASE,
        )
        for match in citation_pattern.finditer(source_text):
            window = match.group(0)
            if exclusion_pattern.search(window):
                continue
            if definitional_pattern.search(window):
                return True
        return False

    def _check_unapplied_cross_reference_base_mechanics(
        self,
        rulespec_file: Path,
    ) -> list[str]:
        """Reject raw-base tax formulas when source requires cited base mechanics."""
        content = rulespec_file.read_text()
        source_text = _extract_source_verification_text(content)
        if not source_text:
            source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        obligations = _extract_cross_reference_base_obligations(source_text)
        if not obligations:
            return []

        import_items = self._extract_import_items(content)
        imports_by_fragment = {
            self._import_item_fragment(import_item): import_item
            for import_item in import_items
            if self._import_item_fragment(import_item)
        }

        issues: list[str] = []
        for block in self._extract_definition_blocks(content):
            source_child = self._rule_source_top_level_child(block)
            if not source_child:
                continue
            dtype = str(block.get("dtype") or "").strip().lower()
            if dtype != "money":
                continue
            formula = "\n".join(str(line) for line in block["body_lines"])
            identifiers = _formula_local_identifiers(formula)
            if not _formula_uses_raw_compensation_base(identifiers):
                continue
            for obligation in obligations:
                if obligation.affected_children and source_child not in (
                    (child,) for child in obligation.affected_children
                ):
                    continue
                if _formula_uses_cross_reference_base_mechanics(
                    identifiers,
                    imports_by_fragment=imports_by_fragment,
                    section=obligation.section,
                ):
                    continue
                citation = f"section {obligation.section}" + (
                    obligation.subsections if obligation.subsections else ""
                )
                issues.append(
                    "Cross-reference base mechanics omitted: "
                    f"`{block['name']}` cites source child "
                    f"`{''.join(f'({part})' for part in source_child)}` and "
                    "computes on a raw compensation, wage, remuneration, or "
                    f"payment base without applying {citation}'s base mechanics. "
                    "Import and compose the cited base, cap, exclusion, or "
                    "excess outputs, or defer this output under "
                    "`module.deferred_outputs` instead of multiplying the raw base."
                )
                break
        return issues

    def _extract_cross_reference_numeric_obligations(
        self,
        source_text: str,
        *,
        title: str,
    ) -> list[tuple[str, str, tuple[str, ...] | None]]:
        """Return source numeric terms that must come from a cited section."""
        patterns = [
            re.compile(
                r"\b(?P<label>applicable\s+percentage)\b"
                r".{0,500}?\b(?:sum\s+of\s+the\s+)?rates?\b"
                r".{0,500}?\b(?:under|in\s+effect\s+under)\s+"
                r"(?:subsections?\s+\([^)]+\)"
                r"(?:\s+and\s+\([^)]+\))?\s+of\s+)?"
                r"section\s+(?P<section>[0-9][A-Za-z0-9.-]*)",
                flags=re.IGNORECASE | re.DOTALL,
            ),
            re.compile(
                r"\b(?P<label>(?:applicable\s+)?(?:percentage|rate|amount))"
                r"\s+(?:determined|in\s+effect|provided)\s+under\s+"
                r"section\s+(?P<section>[0-9][A-Za-z0-9.-]*)",
                flags=re.IGNORECASE,
            ),
        ]

        source_segments = _top_level_source_subparagraph_segments(source_text)
        if source_segments:
            texts_to_scan: list[tuple[tuple[str, ...] | None, str]] = [
                ((label,), text) for label, text in source_segments
            ]
        else:
            texts_to_scan = [(None, source_text)]

        obligations: list[tuple[str, str, tuple[str, ...] | None]] = []
        seen: set[tuple[str, str, tuple[str, ...] | None]] = set()
        for source_child, segment_text in texts_to_scan:
            for pattern in patterns:
                for match in pattern.finditer(segment_text):
                    label = _normalize_identifier(match.group("label"))
                    section = match.group("section")
                    if _section_reference_to_named_act_without_title(
                        section,
                        source_text,
                        identifier=label,
                    ):
                        continue
                    target_title = (
                        _title_qualified_reference_for_section(section, source_text)
                        or title
                    )
                    import_base = "/".join(["statutes", target_title, section])
                    key = (label, import_base, source_child)
                    if key in seen:
                        continue
                    seen.add(key)
                    obligations.append(key)
        return obligations

    def _rule_source_top_level_child(
        self,
        block: dict[str, object],
    ) -> tuple[str, ...] | None:
        source = str(block.get("source") or "").strip()
        if not source:
            return None
        match = re.search(r"\(([A-Za-z0-9]+)\)", source)
        if not match:
            return None
        return (match.group(1).lower(),)

    def _identifier_matches_numeric_cross_reference(
        self,
        identifier: str,
        label: str,
    ) -> bool:
        """Return whether a formula identifier is a local stand-in for a term."""
        normalized_identifier = _normalize_identifier(identifier)
        normalized_label = _normalize_identifier(label)
        if normalized_label in normalized_identifier:
            return True
        if normalized_label in {"percentage", "rate", "amount"}:
            return any(
                token in normalized_identifier
                for token in ("percentage", "rate", "amount")
            )
        return False

    def _source_text_requires_upstream_import(self, source_text: str) -> bool:
        """Return whether cited-section semantics must import or defer."""
        return bool(
            re.search(
                r"\bsame\s+meaning\b.*\bsection\s+[0-9]"
                r"|\btreated\s+as\b.*\bunder\s+section\s+[0-9]"
                r"|\bunder\s+section\s+[0-9].*\btreated\s+as\b"
                r"|\brules\s+similar\s+to\b.*\bsection\s+[0-9]"
                r"|\bin\s+accordance\s+with\s+section\s+[0-9]",
                source_text,
                flags=re.IGNORECASE | re.DOTALL,
            )
        )

    def _imports_cover_placeholder_identifier(
        self,
        import_items: list[str],
        expected_path: str,
        identifier: str,
        *,
        rulespec_file: Path,
    ) -> bool:
        """Return whether an import covers a cross-reference placeholder symbol."""
        expected = expected_path.strip("/")
        for import_item in import_items:
            normalized = self._normalize_rulespec_import_path(import_item)
            if not self._imports_cover_path({normalized}, expected):
                continue

            fragment = self._import_item_fragment(import_item)
            if fragment == identifier:
                return True

            import_file = _resolve_rulespec_import_file_static(
                import_item,
                rules_file=rulespec_file,
                policy_repo_path=self.policy_repo_path,
            )
            if import_file is None:
                continue
            with contextlib.suppress(OSError):
                if identifier in self._extract_defined_symbols(import_file.read_text()):
                    return True
        return False

    def _imports_cover_relation_field_placeholder(
        self,
        import_items: list[str],
        expected_path: str,
        identifier: str,
        *,
        formula: str,
        rulespec_file: Path,
    ) -> bool:
        """Return whether a section-looking relation only exposes imported fields."""
        matches = list(
            re.finditer(
                rf"(?<![A-Za-z0-9_]){re.escape(identifier)}(?![A-Za-z0-9_])", formula
            )
        )
        if not matches:
            return False

        expected = expected_path.strip("/")
        imported_fields: set[str] = set()
        for import_item in import_items:
            normalized = self._normalize_rulespec_import_path(import_item)
            if not self._imports_cover_path({normalized}, expected):
                continue

            fragment = self._import_item_fragment(import_item)
            if fragment:
                imported_fields.add(fragment)

            import_file = _resolve_rulespec_import_file_static(
                import_item,
                rules_file=rulespec_file,
                policy_repo_path=self.policy_repo_path,
            )
            if import_file is None:
                continue
            with contextlib.suppress(OSError):
                imported_fields.update(
                    self._extract_defined_symbols(import_file.read_text())
                )

        if not imported_fields:
            return False

        covered_any = False
        for match in matches:
            field_match = re.match(
                r"\.(?P<field>[A-Za-z_][A-Za-z0-9_]*)",
                formula[match.end() :],
            )
            if not field_match:
                return False
            if field_match.group("field") not in imported_fields:
                return False
            covered_any = True
        return covered_any

    def _import_item_fragment(self, import_item: str) -> str | None:
        """Return the imported symbol fragment for an import item, if any."""
        if "#" not in import_item:
            return None
        fragment = import_item.split("#", 1)[1].strip().strip("\"'")
        return fragment or None

    def _normalize_rulespec_import_path(self, import_path: str) -> str:
        """Normalize a RuleSpec import path for repository-local comparison."""
        normalized = import_path.split("#", 1)[0].strip().strip("\"'")
        if ":" in normalized:
            _, tail = normalized.split(":", 1)
            normalized = tail
        return normalized.strip("/")

    def _imports_cover_path(self, imports: set[str], expected_path: str) -> bool:
        """Return whether any import covers an expected repo-relative path."""
        expected_aliases = _rulespec_import_path_aliases_static(expected_path)
        for import_path in imports:
            for import_alias in _rulespec_import_path_aliases_static(import_path):
                for expected in expected_aliases:
                    if import_alias == expected:
                        return True
                    if import_alias.startswith(expected + "/"):
                        return True
                    if expected.startswith(import_alias + "/"):
                        return True
        return False

    def _cross_reference_placeholder_import_base(
        self,
        identifier: str,
        *,
        title: str,
        current_section: str | None,
        source_text: str,
    ) -> str | None:
        """Infer the canonical imported path from a section/subsection placeholder."""
        subsection_match = re.match(
            r"^subsection_(?P<subsection>[A-Za-z0-9]+)(?:_(?P<tail>[A-Za-z0-9_]+))?$",
            identifier,
        )
        if subsection_match and current_section:
            subsection = subsection_match.group("subsection")
            if re.search(
                rf"\bsubsection\s+\({re.escape(subsection)}\)",
                source_text,
                flags=re.IGNORECASE,
            ):
                return "/".join(["statutes", title, current_section, subsection])

        match = re.match(
            r"^section_(?P<section>[0-9][A-Za-z0-9.-]*)(?:_(?P<tail>[A-Za-z0-9_]+))?$",
            identifier,
        )
        if not match:
            return None
        if current_section and match.group("section") == current_section:
            return None
        if not (
            _is_exception_identifier(identifier)
            or re.search(
                rf"\bsection\s+{re.escape(match.group('section'))}\b",
                source_text,
                flags=re.IGNORECASE,
            )
        ):
            return None
        fragments: list[str] = []
        for fragment in (match.group("tail") or "").split("_"):
            if fragment in {
                "and",
                "exception",
                "exceptions",
                "except",
                "exclusion",
                "exclusions",
                "carve",
                "carveout",
                "applies",
                "apply",
                "preclude",
                "precludes",
                "displace",
                "displaces",
                "requirements",
                "met",
            }:
                break
            if fragment and self._is_cross_reference_path_fragment(fragment):
                fragments.append(fragment)
                continue
            break
        section = match.group("section")
        if _section_reference_to_named_act_without_title(
            section,
            source_text,
            identifier=identifier,
        ):
            return None
        target_title = (
            _title_qualified_reference_for_section(section, source_text) or title
        )
        return "/".join(["statutes", target_title, section, *fragments])

    def _semantic_section_placeholder_import_base(
        self,
        identifier: str,
        *,
        title: str,
        current_section: str | None,
        source_text: str,
    ) -> str | None:
        """Infer import path from a semantic legal cross-reference placeholder."""
        match = re.search(
            r"(?:^|_)(?:"
            r"under"
            r"|provided_in"
            r"|provided_by"
            r"|allowed_under"
            r"|allowable_under"
            r"|allowed_by"
            r"|allowable_by"
            r"|excluded_under"
            r"|excludable_under"
            r"|excluded_from_gross_income_under"
            r"|income_excluded_from_gross_income_under"
            r"|amount_excluded_from_gross_income_under"
            r"|deduction_under"
            r"|deduction_provided_in"
            r"|credit_allowed_under"
            r"|credits_allowable_under"
            r"|in_effect_under"
            r"|to_which"
            r")_section_(?P<section>[0-9][A-Za-z0-9.-]*)"
            r"(?P<tail>(?:_[A-Za-z0-9]+)*)",
            identifier,
        )
        if not match:
            return None
        section = match.group("section")
        if current_section and section == current_section:
            return None

        fragments: list[str] = []
        for fragment in (match.group("tail") or "").split("_"):
            if not fragment:
                continue
            if self._is_cross_reference_path_fragment(fragment):
                fragments.append(fragment)
                continue
            break
        citation = section + "".join(f"({fragment})" for fragment in fragments)
        if (
            not re.search(
                rf"\bsection\s+{re.escape(section)}(?:\b|\s|\()",
                source_text,
                flags=re.IGNORECASE,
            )
            and citation.lower() not in source_text.lower()
        ):
            return None
        if _section_reference_to_named_act_without_title(
            section,
            source_text,
            identifier=identifier,
        ):
            return None
        target_title = (
            _title_qualified_reference_for_section(section, source_text) or title
        )
        return "/".join(["statutes", target_title, section, *fragments])

    def _is_cross_reference_path_fragment(self, fragment: str) -> bool:
        """Return whether an identifier tail fragment is a citation path token."""
        return bool(
            re.fullmatch(r"\d+[A-Za-z]?|[A-Za-z]|[ivxlcdm]+", fragment)
            and fragment.lower() not in {"and"}
        )

    def _check_resolved_defined_term_imports(self, rulespec_file: Path) -> list[str]:
        """Flag missing imports for known legally-defined terms mentioned in source text."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        imports = set(self._extract_import_paths(content))
        issues: list[str] = []
        for term in resolve_defined_terms_from_text(source_text):
            import_base = term.import_target.split("#", 1)[0]
            if self._imports_cover_path(imports, import_base):
                continue
            issues.append(
                "Defined term import missing: "
                f"`{term.term}` resolves to {term.citation} but file does not import "
                f"from {import_base}"
            )
        return issues

    def _check_resolved_canonical_concept_imports(
        self, rulespec_file: Path
    ) -> list[str]:
        """Flag missing imports for uniquely resolved nearby canonical concepts."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        imports = set(self._extract_import_paths(content))
        source_root = self._validation_source_root(rulespec_file)
        issues: list[str] = []
        for concept in resolve_canonical_concepts_from_text(
            source_text,
            source_root,
            current_file=rulespec_file,
        ):
            import_base = concept.import_target.split("#", 1)[0]
            if self._imports_cover_path(imports, import_base):
                continue
            issues.append(
                "Canonical concept import missing: "
                f"`{concept.term}` resolves to {concept.citation} via "
                f"{concept.import_target} but file does not import from {import_base}"
            )
        return issues

    def _check_promoted_stub_file(self, rulespec_file: Path) -> list[str]:
        """Flag committed RuleSpec stubs when their corpus source exists."""
        source_root = self._validation_source_root(rulespec_file)
        try:
            relative = rulespec_file.resolve().relative_to(source_root.resolve())
        except ValueError:
            return []

        if not rulespec_content_has_stub_status(rulespec_file.read_text()):
            return []
        if not has_corpus_provision_for_import_target(
            relative.with_suffix("").as_posix(), source_root
        ):
            return []

        return [
            "Promoted RuleSpec stub with corpus source: "
            f"{relative.as_posix()} still declares `status: stub` even though corpus.provisions has source text; "
            "replace the stub with a real encoding before promotion"
        ]

    def _check_imported_stub_dependencies(self, rulespec_file: Path) -> list[str]:
        """Flag imports that point at stubs even though corpus source exists."""
        source_root = self._validation_source_root(rulespec_file)
        issues: list[str] = []

        for import_path in self._extract_import_paths(rulespec_file.read_text()):
            target = source_root / self._import_to_relative_rulespec_path(import_path)
            if not rulespec_file_has_stub_status(target):
                continue
            if not has_corpus_provision_for_import_target(import_path, source_root):
                continue
            issues.append(
                "Imported stub dependency with corpus source: "
                f"{rulespec_file.name} imports `{import_path}` but `{target.relative_to(source_root).as_posix()}` "
                "is still a stub while corpus.provisions has source text; encode the upstream file instead"
            )

        return issues

    def _check_placeholder_fact_variables(self, rulespec_file: Path) -> list[str]:
        """Flag local factual predicates encoded as constant/deferred placeholders."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []
        source_metadata = _load_nearby_eval_source_metadata(rulespec_file)

        issues: list[str] = []
        for block in self._extract_definition_blocks(content):
            if block["dtype"] != "Boolean":
                continue
            if block["imports"]:
                continue

            status = str(block["status"] or "").lower()
            constant_boolean = bool(block["constant_boolean"])
            if not (constant_boolean or status == "deferred"):
                continue
            if _source_metadata_sets_target_symbol(source_metadata, block["name"]):
                continue

            issues.append(
                "Placeholder fact variable: "
                f"{block['name']} line {block['line']} is a source-stated factual predicate "
                f"but is encoded as {'a constant boolean' if constant_boolean else '`status: deferred`'}; "
                "expose it as a plain fact-shaped input or import a canonical definition instead"
            )
        return issues

    def _check_except_where_carve_out_logic(self, rulespec_file: Path) -> list[str]:
        """Flag carve-out branches that incorrectly treat the exception as satisfaction."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []
        if not re.search(
            r"\bexcept where\b.+\bapplies\b",
            source_text,
            flags=re.IGNORECASE | re.DOTALL,
        ):
            return []

        issues: list[str] = []
        for block in self._extract_definition_blocks(content):
            if block["dtype"] != "Boolean":
                continue
            for line_number, expression in self._iter_true_on_applies_patterns(
                block["body_lines"]
            ):
                issues.append(
                    "Carve-out logic inverted: "
                    f"{block['name']} line {line_number} treats `{expression}` as automatically satisfied "
                    "when an `except where ... applies` carve-out should displace this slice"
                )
        return issues

    def _check_embedded_scalar_literals(self, rulespec_file: Path) -> list[str]:
        """Flag substantive scalar literals embedded inside formulas."""
        issues: list[str] = []
        content = rulespec_file.read_text()
        imported_parameter_scalar_values = (
            self._imported_source_backed_parameter_scalar_values(
                rulespec_file,
                content,
            )
        )
        for (
            line_number,
            name,
            literal,
            expression,
        ) in self._collect_embedded_scalar_literals(
            content,
            imported_parameter_scalar_values=imported_parameter_scalar_values,
        ):
            issues.append(
                "Embedded scalar literal: "
                f"{name} line {line_number} embeds {literal} in `{expression}`; "
                "extract the value to its own named numeric concept or indexed table/grid value"
            )
        return issues

    def _imported_source_backed_parameter_scalar_values(
        self,
        rulespec_file: Path,
        content: str,
    ) -> dict[str, set[str]]:
        """Return scalar values for source-backed parameters imported by this file."""
        source_root = self._validation_source_root(rulespec_file)
        values: dict[str, set[str]] = {}
        for item in self._extract_import_items(content):
            base, separator, symbol = item.partition("#")
            if not separator:
                continue
            symbol = symbol.strip()
            if not symbol:
                continue
            target = source_root / self._import_to_relative_rulespec_path(base)
            if not target.exists():
                continue
            try:
                payload = yaml.safe_load(target.read_text())
            except (OSError, yaml.YAMLError, ValueError):
                continue
            if not isinstance(payload, dict) or not isinstance(
                payload.get("rules"),
                list,
            ):
                continue
            imported_values = _source_backed_parameter_scalar_values(payload["rules"])
            if symbol in imported_values:
                values.setdefault(symbol, set()).update(imported_values[symbol])
        return values

    def _check_decomposed_date_scalars(self, rulespec_file: Path) -> list[str]:
        """Flag numeric year/month/day scalars derived from non-substantive date references."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []
        if not (
            GROUNDING_DATE_PATTERN.search(source_text)
            or _MONTH_NAME_PATTERN.search(source_text)
        ):
            return []

        issues: list[str] = []
        for occurrence in extract_named_scalar_occurrences(content):
            tokens = set(occurrence.name.lower().split("_"))
            if not (_DATE_DECOMPOSITION_CUE_TOKENS & tokens):
                continue
            if (
                "year" in tokens
                and occurrence.value.is_integer()
                and 1900 <= occurrence.value <= 2100
            ):
                issues.append(
                    "Decomposed date scalar: "
                    f"{occurrence.name} line {occurrence.line} encodes calendar year "
                    f"{int(occurrence.value)} as a numeric scalar; keep legal date references "
                    "semantic instead of splitting them into year/month/day variables"
                )
            elif (
                "month" in tokens
                and occurrence.value.is_integer()
                and 1 <= occurrence.value <= 12
            ):
                issues.append(
                    "Decomposed date scalar: "
                    f"{occurrence.name} line {occurrence.line} encodes calendar month "
                    f"{int(occurrence.value)} as a numeric scalar; keep legal date references "
                    "semantic instead of splitting them into year/month/day variables"
                )
            elif (
                "day" in tokens
                and occurrence.value.is_integer()
                and 1 <= occurrence.value <= 31
            ):
                issues.append(
                    "Decomposed date scalar: "
                    f"{occurrence.name} line {occurrence.line} encodes calendar day "
                    f"{int(occurrence.value)} as a numeric scalar; keep legal date references "
                    "semantic instead of splitting them into year/month/day variables"
                )
        return issues

    def _check_branch_specific_output_names(self, rulespec_file: Path) -> list[str]:
        """Flag branch leaves whose principal output name drops the deepest branch token."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        expected_branch = self._extract_expected_branch_token(source_text)
        if expected_branch is None:
            return []

        blocks = self._extract_definition_blocks(content)
        if not blocks:
            return []

        principal_name = str(blocks[-1]["name"]).lower()
        if self._name_contains_branch_token(principal_name, expected_branch):
            return []

        return [
            "Branch-specific output name missing: "
            f"source text targets branch ({expected_branch}), but the principal output "
            f"`{principal_name}` does not encode that deepest branch token"
        ]

    def _check_function_style_variable_calls(self, rulespec_file: Path) -> list[str]:
        """Flag variable references that incorrectly use function-call syntax."""
        content = rulespec_file.read_text()
        defined_symbols = set(self._extract_defined_symbols(content))
        if not defined_symbols:
            return []

        issues: list[str] = []
        for block in self._extract_definition_blocks(content):
            for offset, line in enumerate(block["body_lines"], start=1):
                stripped = line.strip()
                if not stripped or stripped.endswith(":"):
                    continue
                for symbol in defined_symbols:
                    if symbol == block["name"]:
                        continue
                    if re.search(rf"\b{re.escape(symbol)}\s*\(", stripped):
                        issues.append(
                            "Function-style variable reference: "
                            f"{block['name']} line {block['line'] + offset} calls `{symbol}(...)`; "
                            "reference RuleSpec variables by bare name instead of function-call syntax"
                        )
        return issues

    def _check_exclusion_list_principal_outputs(self, rulespec_file: Path) -> list[str]:
        """Flag exclusion-list leaves whose principal output collapses to a constant."""
        content = rulespec_file.read_text()
        source_text = extract_embedded_source_text(content)
        if not source_text:
            return []

        normalized_source = " ".join(source_text.lower().split())
        if (
            "except the following which is not to be treated as qualifying income"
            not in normalized_source
        ):
            return []

        blocks = self._extract_definition_blocks(content)
        if not blocks:
            return []

        principal = blocks[-1]
        status = str(principal["status"] or "").lower()
        if not principal["constant_boolean"] and status != "deferred":
            return []

        principal_name = str(principal["name"])
        detail = (
            "a constant boolean"
            if principal["constant_boolean"]
            else "`status: deferred`"
        )
        return [
            "Exclusion-list leaf collapsed to placeholder output: "
            f"`{principal_name}` encodes a qualifying-income exclusion branch as {detail}; "
            "encode either the excluded amount itself or a fact-sensitive classification that changes with the source-stated subject/input"
        ]

    def _extract_definition_blocks(self, content: str) -> list[dict[str, object]]:
        """Extract simple summaries of RuleSpec rules."""
        try:
            payload = yaml.safe_load(content)
        except (yaml.YAMLError, ValueError):
            return []
        if not isinstance(payload, dict) or not isinstance(payload.get("rules"), list):
            return []

        blocks: list[dict[str, object]] = []
        for index, rule in enumerate(payload["rules"], start=1):
            if not isinstance(rule, dict):
                continue
            name = str(rule.get("name") or "").strip()
            if not name:
                continue
            formula_lines: list[str] = []
            constant_boolean = False
            versions = rule.get("versions")
            if isinstance(versions, list):
                for version in versions:
                    if not isinstance(version, dict):
                        continue
                    formula = version.get("formula")
                    if isinstance(formula, bool):
                        constant_boolean = True
                        formula_lines.append(str(formula).lower())
                    elif isinstance(formula, (int, float)):
                        formula_lines.append(str(formula))
                    elif isinstance(formula, str):
                        stripped_formula = formula.strip()
                        if stripped_formula.lower() in {"true", "false"}:
                            constant_boolean = True
                        formula_lines.extend(stripped_formula.splitlines())

            imports_payload = rule.get("imports")
            imports = (
                [str(item) for item in imports_payload]
                if isinstance(imports_payload, list)
                else []
            )
            blocks.append(
                {
                    "name": name,
                    "line": index,
                    "body_lines": formula_lines,
                    "imports": imports,
                    "dtype": rule.get("dtype"),
                    "source": rule.get("source"),
                    "status": rule.get("status"),
                    "proof_excerpts": _rule_proof_source_excerpts(rule),
                    "constant_boolean": constant_boolean,
                }
            )
        return blocks

    def _iter_true_on_applies_patterns(
        self, body_lines: list[str]
    ) -> list[tuple[int, str]]:
        """Return `(line_number_offset, condition)` pairs for `if <applies>: true` branches."""
        findings: list[tuple[int, str]] = []
        for index, line in enumerate(body_lines):
            inline_match = re.search(
                r"\bif\s+([A-Za-z_]\w*applies[A-Za-z_0-9]*)\b[^:\n]*:\s*true\b",
                line,
                flags=re.IGNORECASE,
            )
            if inline_match:
                findings.append((index + 1, inline_match.group(1)))
                continue

            branch_match = re.match(
                r"^\s*if\s+([A-Za-z_]\w*applies[A-Za-z_0-9]*)\b[^:\n]*:\s*$",
                line,
                flags=re.IGNORECASE,
            )
            if not branch_match:
                continue
            if index + 1 >= len(body_lines):
                continue
            next_line = body_lines[index + 1].strip().lower()
            if next_line == "true":
                findings.append((index + 1, branch_match.group(1)))
        return findings

    def _extract_expected_branch_token(self, source_text: str) -> str | None:
        """Return the deepest non-numeric structural branch token from source text."""
        tokens: list[str] = []
        for line in source_text.splitlines():
            stripped = line.strip()
            if not _STRUCTURAL_SOURCE_LINE_PATTERN.match(stripped):
                continue
            token = stripped.strip("()[] .").lower()
            if token.isdigit():
                continue
            tokens.append(token)
        return tokens[-1] if tokens else None

    def _name_contains_branch_token(self, name: str, token: str) -> bool:
        """Return True when a definition name encodes a structural branch token."""
        return bool(re.search(rf"(?:^|_){re.escape(token)}(?:_|$)", name))

    def _collect_embedded_scalar_literals(
        self,
        content: str,
        *,
        imported_parameter_scalar_values: dict[str, set[str]] | None = None,
    ) -> list[tuple[int, str, str, str]]:
        """Return embedded substantive scalar literals found in RuleSpec formulas."""
        issues: list[tuple[int, str, str, str]] = []
        try:
            payload = yaml.safe_load(content)
        except (yaml.YAMLError, ValueError):
            return []
        if not isinstance(payload, dict) or not isinstance(payload.get("rules"), list):
            return []
        selector_table_keys = _rulespec_index_selector_keys(payload["rules"])
        source_text = extract_embedded_source_text(content) or ""
        parameter_scalar_values = _source_backed_parameter_scalar_values(
            payload["rules"],
        )
        for name, values in (imported_parameter_scalar_values or {}).items():
            parameter_scalar_values.setdefault(name, set()).update(values)

        for rule_index, rule in enumerate(payload["rules"], start=1):
            if not isinstance(rule, dict):
                continue
            name = str(rule.get("name") or "<unknown>")
            versions = rule.get("versions")
            if not isinstance(versions, list):
                continue
            for version in versions:
                if not isinstance(version, dict):
                    continue
                formula = version.get("formula")
                if isinstance(formula, (bool, int, float)):
                    continue
                if not isinstance(formula, str):
                    continue
                stripped_formula = formula.strip()
                if self._is_direct_scalar_expression(stripped_formula):
                    continue
                if _is_source_backed_simple_fraction_parameter(
                    rule,
                    stripped_formula,
                    source_text,
                ):
                    continue
                structural_selector_keys = (
                    selector_table_keys.get(name)
                    if _is_structural_selector_rule(rule)
                    else None
                )
                previous_stripped = ""
                for line in formula.splitlines() or [formula]:
                    stripped = line.strip()
                    if not stripped:
                        continue
                    expression = stripped
                    if (
                        structural_selector_keys
                        and previous_stripped.endswith(":")
                        and re.fullmatch(r"\d+(?:\.0+)?", stripped)
                    ):
                        expression = f"{previous_stripped} {stripped}"
                    if _line_compares_extracted_parameter_to_own_scalar(
                        stripped,
                        parameter_scalar_values,
                    ):
                        previous_stripped = stripped
                        continue
                    issues.extend(
                        (rule_index, name, literal, stripped)
                        for literal in self._extract_embedded_scalar_literals(
                            expression,
                            structural_selector_keys=structural_selector_keys,
                        )
                    )
                    previous_stripped = stripped
        return issues

    def _is_direct_scalar_expression(self, expression: str) -> bool:
        normalized = expression.replace(",", "")
        return bool(_EMBEDDED_SCALAR_DIRECT_VALUE.fullmatch(normalized))

    def _extract_embedded_scalar_literals(
        self,
        expression: str,
        *,
        structural_selector_keys: set[str] | None = None,
    ) -> list[str]:
        literals: list[str] = []
        scrubbed_expression = _QUOTED_STRING_PATTERN.sub(" ", expression)
        half_up_rounding_expression = _is_half_up_rounding_expression(
            scrubbed_expression
        )
        for match in _EMBEDDED_SCALAR_NUMBER.finditer(scrubbed_expression):
            start, end = match.span()
            prev = scrubbed_expression[start - 1] if start > 0 else ""
            nxt = scrubbed_expression[end] if end < len(scrubbed_expression) else ""
            if (prev.isalnum() or prev in {"_", ".", "/"}) or (
                nxt.isalnum() or nxt in {"_", ".", "/"}
            ):
                continue
            literal = match.group(0)
            if literal in _EMBEDDED_SCALAR_ALLOWED_VALUES:
                continue
            if literal == "0.5" and half_up_rounding_expression:
                continue
            if _is_structural_table_key_literal(
                scrubbed_expression,
                literal,
                span=(start, end),
            ):
                continue
            if _is_structural_table_index_clamp_literal(
                scrubbed_expression,
                literal,
                span=(start, end),
            ):
                continue
            if _is_structural_mapping_key_literal(
                scrubbed_expression,
                literal,
                span=(start, end),
            ):
                continue
            if _is_structural_schedule_index_literal(
                scrubbed_expression,
                literal,
                span=(start, end),
            ):
                continue
            if _is_structural_enum_index_literal(
                scrubbed_expression,
                literal,
                span=(start, end),
            ):
                continue
            if _is_structural_selector_result_literal(
                scrubbed_expression,
                literal,
                structural_selector_keys,
                span=(start, end),
            ):
                continue
            literals.append(literal)
        return sorted(set(literals))

    def _build_import_advisories(self, rulespec_file: Path) -> list[str]:
        """Return non-blocking advice about likely shared concepts."""
        content = rulespec_file.read_text()
        definitions = self._extract_defined_symbols(content)
        if not definitions:
            return []

        source_root = self._validation_source_root(rulespec_file)
        search_root = self._candidate_concept_search_root(rulespec_file, source_root)
        if not search_root.exists():
            return []

        imports = set(self._extract_import_paths(content))
        advisories: list[str] = []
        seen: set[tuple[str, str]] = set()

        for candidate_file in search_root.rglob("*.yaml"):
            if candidate_file.name.endswith(".test.yaml"):
                continue
            if candidate_file.resolve() == rulespec_file.resolve():
                continue
            candidate_defs = set(
                self._extract_defined_symbols(candidate_file.read_text())
            )
            overlap = sorted(set(definitions) & candidate_defs)
            if not overlap:
                continue
            import_base = self._relative_import_base(candidate_file, source_root)
            if not import_base or import_base in imports:
                continue
            for name in overlap:
                key = (name, import_base)
                if key in seen:
                    continue
                seen.add(key)
                advisories.append(
                    "Shared concept advisory: "
                    f"`{name}` is also defined in `{import_base}#{name}`. "
                    "If the semantics match, prefer importing or re-exporting that "
                    "canonical concept instead of duplicating it locally."
                )
        return advisories

    def _candidate_concept_search_root(
        self, rulespec_file: Path, source_root: Path
    ) -> Path:
        """Choose a nearby subtree for conservative shared-concept advisories."""
        with contextlib.suppress(ValueError):
            relative = rulespec_file.resolve().relative_to(source_root.resolve())
            if len(relative.parts) >= 2:
                return source_root / relative.parts[0] / relative.parts[1]
        return rulespec_file.parent

    def _relative_import_base(
        self, candidate_file: Path, source_root: Path
    ) -> str | None:
        """Convert a RuleSpec path to an import base."""
        with contextlib.suppress(ValueError):
            relative = candidate_file.resolve().relative_to(source_root.resolve())
            return str(relative.with_suffix("")).replace(os.sep, "/")
        return None

    def _extract_definition_cross_references(
        self, source_text: str, title: str
    ) -> list[tuple[str, str]]:
        """Extract cited sections that the source text explicitly uses as definitions."""
        refs: list[tuple[str, str]] = []
        seen: set[str] = set()
        for match in _DEFINITION_CROSS_REFERENCE_PATTERN.finditer(source_text):
            citation = match.group("section")
            target_title = match.group("title") or title
            import_path = self._section_reference_to_import_path(target_title, citation)
            if not import_path or import_path in seen:
                continue
            seen.add(import_path)
            refs.append((citation, import_path))
        return refs

    def _section_reference_to_import_path(
        self, title: str, section_reference: str
    ) -> str | None:
        """Convert `152(c)(1)(A)` into `26/152/c/1/A`."""
        match = re.match(
            r"^(?P<section>[0-9A-Za-z.-]+)(?P<tail>(?:\([^)]+\))*)$",
            section_reference.strip(),
        )
        if not match:
            return None
        fragments = re.findall(r"\(([^)]+)\)", match.group("tail"))
        return "/".join([title, match.group("section"), *fragments])

    def _infer_title_from_rulespec_path(self, rulespec_file: Path) -> str | None:
        """Infer the USC title from the RuleSpec file path."""
        resolved_root = self.policy_repo_path.resolve()
        resolved_file = rulespec_file.resolve()
        with contextlib.suppress(ValueError):
            relative = resolved_file.relative_to(resolved_root)
            if (
                len(relative.parts) >= 2
                and relative.parts[0] == "statutes"
                and re.fullmatch(r"[0-9A-Za-z.-]+", relative.parts[1])
                and any(ch.isdigit() for ch in relative.parts[1])
            ):
                return relative.parts[1]
            if (
                relative.parts
                and re.fullmatch(r"[0-9A-Za-z.-]+", relative.parts[0])
                and any(ch.isdigit() for ch in relative.parts[0])
            ):
                return relative.parts[0]
            return None

        parts = list(resolved_file.parts)
        with contextlib.suppress(ValueError):
            statutes_idx = parts.index("statutes")
            if statutes_idx + 1 < len(parts):
                return parts[statutes_idx + 1]
        return None

    def _infer_section_from_rulespec_path(self, rulespec_file: Path) -> str | None:
        """Infer the USC section from the RuleSpec file path."""
        resolved_root = self.policy_repo_path.resolve()
        resolved_file = rulespec_file.resolve()
        with contextlib.suppress(ValueError):
            relative = resolved_file.relative_to(resolved_root)
            if (
                len(relative.parts) >= 3
                and relative.parts[0] == "statutes"
                and re.fullmatch(r"[0-9A-Za-z.-]+", Path(relative.parts[2]).stem)
                and any(ch.isdigit() for ch in Path(relative.parts[2]).stem)
            ):
                return Path(relative.parts[2]).stem
            if (
                len(relative.parts) >= 2
                and re.fullmatch(r"[0-9A-Za-z.-]+", Path(relative.parts[1]).stem)
                and any(ch.isdigit() for ch in Path(relative.parts[1]).stem)
            ):
                return Path(relative.parts[1]).stem
            return None

        parts = list(resolved_file.parts)
        with contextlib.suppress(ValueError):
            statutes_idx = parts.index("statutes")
            if statutes_idx + 2 < len(parts):
                return Path(parts[statutes_idx + 2]).stem
        return None

    def _run_reviewer(
        self,
        reviewer_type: str,
        rulespec_file: Path,
        oracle_context: Optional[dict] = None,
        review_context: str | None = None,
    ) -> ValidationResult:
        """Run a reviewer agent via Claude Code CLI with oracle context.

        Args:
            reviewer_type: Type of reviewer (rulespec-reviewer, formula-reviewer, etc.)
            rulespec_file: Path to the RuleSpec file to review
            oracle_context: Results from oracle validators (PE, TAXSIM) for context

        Returns:
            ValidationResult with score, issues, and raw output
        """
        start = time.time()

        # Read RuleSpec file content
        try:
            rulespec_content = Path(rulespec_file).read_text()
            test_content = None
            companion_test = self._rulespec_test_path(rulespec_file)
            if companion_test.exists():
                test_content = companion_test.read_text()
        except Exception as e:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name=reviewer_type,
                passed=False,
                score=0.0,
                issues=[f"Failed to read RuleSpec file: {e}"],
                duration_ms=duration,
                error=str(e),
            )

        # Build review prompt based on reviewer type
        review_focus = {
            "rulespec-reviewer": "structure, legal citations, imports, entity hierarchy, RuleSpec compliance",
            "formula-reviewer": "logic correctness, edge cases, circular dependencies, return statements, type consistency",
            "parameter-reviewer": "no magic numbers (only -1,0,1,2,3 allowed), parameter sourcing, time-varying values",
            "integration-reviewer": "test coverage, dependency resolution, documentation, completeness",
            "generalist-reviewer": "overall statutory fidelity, missing or merged branches, defined terms, factual predicates, and suspicious semantic compression",
            "Formula Reviewer": "logic correctness, edge cases, circular dependencies, return statements",
            "Parameter Reviewer": "no magic numbers (only -1,0,1,2,3 allowed), parameter sourcing",
            "Integration Reviewer": "test coverage, dependency resolution, documentation",
        }.get(reviewer_type, "overall quality")
        prompt_template = {
            "rulespec-reviewer": RULESPEC_REVIEWER_PROMPT,
            "generalist-reviewer": GENERALIST_REVIEWER_PROMPT,
        }.get(reviewer_type)

        # Build oracle context section if available
        oracle_section = ""
        if oracle_context:
            oracle_section = "\n## Oracle Validation Results (use to diagnose issues)\n"
            for oracle_name, ctx in oracle_context.items():
                oracle_section += f"\n### {oracle_name.upper()}\n"
                oracle_section += f"- Score: {ctx.get('score', 'N/A')}\n"
                oracle_section += f"- Passed: {ctx.get('passed', 'N/A')}\n"
                if ctx.get("issues"):
                    oracle_section += f"- Issues: {', '.join(ctx['issues'][:3])}\n"
        review_context_section = ""
        if review_context:
            review_context_section = f"\n## Review Context\n{review_context}\n"
        test_section = ""
        if test_content:
            test_section = (
                "\n## Companion Test File\n"
                f"{test_content[:3000]}{'...' if len(test_content) > 3000 else ''}\n"
            )

        if prompt_template is not None:
            prompt = f"""{prompt_template}

---

# TASK

Review this encoding holistically.

File: benchmark artifact (RuleSpec YAML)

Content:
{rulespec_content[:6000]}{"..." if len(rulespec_content) > 6000 else ""}
{test_section}{review_context_section}{oracle_section}
If oracle validators show discrepancies, investigate WHY the encoding differs from consensus.

Output ONLY valid JSON matching the schema above.
"""
        else:
            prompt = f"""Review this RuleSpec file for: {review_focus}

File: {rulespec_file}

Content:
{rulespec_content[:3000]}{"..." if len(rulespec_content) > 3000 else ""}
{test_section}{review_context_section}{oracle_section}
If oracle validators show discrepancies, investigate WHY the encoding differs from consensus.

Output ONLY valid JSON:
{{
  "score": <float 1-10>,
  "passed": <boolean>,
  "issues": ["issue1", "issue2"],
  "reasoning": "<brief explanation>"
}}
"""
        prompt_sha256 = _sha256_text(prompt)

        try:
            reviewer_timeout = int(
                os.getenv("AXIOM_ENCODE_REVIEWER_TIMEOUT_SECONDS", "300")
            )
            output, returncode = run_claude_code(
                prompt,
                model=REVIEWER_CLI_MODEL,
                timeout=reviewer_timeout,
                cwd=self.policy_repo_path,
            )
            if returncode != 0:
                output_excerpt = output.strip()[:500] or "no output"
                raise RuntimeError(
                    f"Reviewer CLI exited {returncode}: {output_excerpt}"
                )

            # Parse JSON from output. If parsing fails, return a
            # structured "reviewer_parse_failed" result instead of
            # letting the generic except below swallow the detail.
            try:
                data = _extract_json_object(output)
            except (ValueError, json.JSONDecodeError) as parse_err:
                duration = int((time.time() - start) * 1000)
                raw_snippet = (output or "").strip()
                truncated = raw_snippet[:500]
                if len(raw_snippet) > 500:
                    truncated += "... [truncated]"
                logger.warning(
                    "Reviewer %s output failed to parse as JSON: %s. "
                    "Raw output (first 500 chars): %s",
                    reviewer_type,
                    parse_err,
                    truncated,
                )
                return ValidationResult(
                    validator_name=reviewer_type,
                    passed=False,
                    score=None,
                    issues=[
                        "reviewer_parse_failed",
                        f"Could not parse reviewer JSON output: {parse_err}",
                    ],
                    duration_ms=duration,
                    raw_output=output,
                    error=f"reviewer_parse_failed: {parse_err}",
                    prompt_sha256=prompt_sha256,
                )

            score = float(data.get("score", 5.0))
            if reviewer_type == "generalist-reviewer":
                blocking_issues = data.get("blocking_issues", [])
                non_blocking_issues = data.get("non_blocking_issues", [])
                if not isinstance(blocking_issues, list):
                    blocking_issues = [str(blocking_issues)]
                if not isinstance(non_blocking_issues, list):
                    non_blocking_issues = [str(non_blocking_issues)]

                if "passed" in data:
                    passed = bool(data["passed"])
                elif "blocking_issues" in data:
                    passed = len(blocking_issues) == 0
                else:
                    passed = score >= 7.0

                reported_issues = data.get("issues", [])
                if not isinstance(reported_issues, list):
                    reported_issues = [str(reported_issues)]
                issues = list(blocking_issues)
                issues.extend(
                    f"[non-blocking] {issue}" for issue in non_blocking_issues
                )
                for issue in reported_issues:
                    if issue not in issues:
                        issues.append(issue)
            else:
                passed = bool(data.get("passed", score >= 7.0))
                issues = data.get("issues", [])
            if not isinstance(issues, list):
                issues = [str(issues)]
            if score < 7.0:
                if passed:
                    issues.append(
                        "reviewer_score_below_pass_threshold: "
                        f"score {score:.1f}/10 is below 7.0"
                    )
                passed = False

            duration = int((time.time() - start) * 1000)

            return ValidationResult(
                validator_name=reviewer_type,
                passed=passed,
                score=score,
                issues=issues,
                duration_ms=duration,
                raw_output=output,
                prompt_sha256=prompt_sha256,
            )

        except Exception as e:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name=reviewer_type,
                passed=False,
                score=None,
                issues=[f"Reviewer error: {e}"],
                duration_ms=duration,
                error=str(e),
                prompt_sha256=prompt_sha256,
            )

    def _detect_policyengine_country(
        self, rulespec_file: Path, rulespec_content: str
    ) -> str:
        """Infer which PolicyEngine country package to use."""
        if self.policyengine_country in {"us", "uk"}:
            return self.policyengine_country

        haystack = f"{rulespec_file}\n{rulespec_content}".lower()
        if "legislation.gov.uk" in haystack or re.search(
            r"\b(?:ukpga|uksi|asp|ssi|wsi|nisi|anaw|asc)(?:/|-)", haystack
        ):
            return "uk"
        return "us"

    def _find_pe_python(self, country: str = "us") -> Optional[str]:
        """Find a Python interpreter with the requested PolicyEngine package installed.

        Checks: 1) explicit env override, 2) known PE checkout/worktree venv paths,
        3) current interpreter, 4) auto-install.
        Returns the path to a working Python, or None.
        """
        module_name = f"policyengine_{country}"
        package_name = f"policyengine-{country}"
        repo_name = f"policyengine-{country}"
        env_var_name = f"AXIOM_ENCODE_POLICYENGINE_{country.upper()}_PYTHON"

        def _python_imports_policyengine(python_path: str) -> bool:
            try:
                result = subprocess.run(
                    [
                        python_path,
                        "-c",
                        f"from {module_name} import Simulation; print('ok')",
                    ],
                    capture_output=True,
                    text=True,
                    timeout=30,
                )
                return result.returncode == 0 and "ok" in result.stdout
            except Exception:
                return False

        env_python = os.getenv(env_var_name)
        if env_python and Path(env_python).exists():
            if _python_imports_policyengine(env_python):
                return env_python

        pe_venv_paths = [
            Path.home()
            / "worktrees"
            / f"{repo_name}-main-view"
            / ".venv"
            / "bin"
            / "python",
            Path.home() / "worktrees" / repo_name / ".venv" / "bin" / "python",
            Path.home() / repo_name / ".venv" / "bin" / "python",
            Path.home() / "TheAxiomFoundation" / repo_name / ".venv" / "bin" / "python",
            Path.home() / "PolicyEngine" / repo_name / ".venv" / "bin" / "python",
        ]
        for pe_python in pe_venv_paths:
            if pe_python.exists() and _python_imports_policyengine(str(pe_python)):
                return str(pe_python)

        # Try current interpreter after explicit checkout/worktree environments so
        # local source trees win over stale globally-installed packages.
        if _python_imports_policyengine(sys.executable):
            return sys.executable

        # Try auto-installing into current venv as last resort
        try:
            print("  PolicyEngine not found, attempting install...")
            install_result = subprocess.run(
                [sys.executable, "-m", "pip", "install", package_name],
                capture_output=True,
                text=True,
                timeout=300,
            )
            if install_result.returncode == 0:
                return sys.executable
            else:
                print(f"  Install failed: {install_result.stderr[:200]}")
        except Exception as e:
            print(f"  Auto-install failed: {e}")

        return None

    def _run_pe_subprocess(self, script: str, pe_python: str) -> Optional[str]:
        """Run a Python script using the PE-capable interpreter.

        Returns stdout on success, None on failure.
        """
        result = self._run_pe_subprocess_detailed(script, pe_python)
        if result.returncode == 0:
            return result.stdout
        return None

    def _run_pe_subprocess_detailed(
        self, script: str, pe_python: str
    ) -> OracleSubprocessResult:
        """Run a Python script using the PE-capable interpreter with stderr."""
        timeout = int(os.getenv("AXIOM_ENCODE_POLICYENGINE_TIMEOUT_SECONDS", "300"))
        try:
            idle_timeout = min(
                timeout,
                max(
                    0,
                    int(
                        os.getenv(
                            "AXIOM_ENCODE_POLICYENGINE_IDLE_TIMEOUT_SECONDS",
                            "45",
                        )
                    ),
                ),
            )
            result = _run_subprocess_with_idle_timeout(
                [pe_python, "-c", script],
                timeout=timeout,
                idle_timeout=idle_timeout,
            )
            return OracleSubprocessResult(
                returncode=result.returncode,
                stdout=result.output or "",
                stderr="",
            )
        except subprocess.TimeoutExpired as exc:
            return OracleSubprocessResult(
                returncode=124,
                stdout=getattr(exc, "stdout", "") or "",
                stderr=(getattr(exc, "stderr", "") or "").strip()
                or f"Timeout after {timeout}s",
            )
        except Exception as exc:
            return OracleSubprocessResult(returncode=1, stderr=str(exc))

    def _is_pe_unsupported_error(self, error_text: str) -> bool:
        """Return True when PE cannot evaluate the cited period or variable."""
        if not error_text:
            return False
        return any(
            pattern.search(error_text) for pattern in _PE_UNSUPPORTED_ERROR_PATTERNS
        )

    def _summarize_oracle_error(self, error_text: str) -> str:
        """Collapse multi-line stderr into a short human-readable issue."""
        if not error_text:
            return "unknown error"
        for line in reversed(error_text.splitlines()):
            stripped = line.strip()
            if stripped:
                return stripped[:200]
        return "unknown error"

    def _run_policyengine(self, rulespec_file: Path) -> ValidationResult:
        """Validate against PolicyEngine oracle.

        Uses scenario-based comparison: builds standard PE households from
        RuleSpec test case inputs and compares the PE-calculated output variable
        against the RuleSpec test's expected value.

        For programs like SNAP where RuleSpec tests use intermediate inputs
        (snap_net_income, thrifty_food_plan_cost), we run PE with equivalent
        raw household scenarios and compare at the output variable level.
        """
        start = time.time()
        issues = []

        # Read companion RuleSpec test content.
        try:
            rulespec_content = self._read_test_content(rulespec_file)
        except Exception as e:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="policyengine",
                passed=False,
                score=0.0,
                issues=[f"Failed to read RuleSpec/test file: {e}"],
                duration_ms=duration,
                error=str(e),
            )

        try:
            rulespec_source_content = rulespec_file.read_text()
        except Exception:
            rulespec_source_content = ""
        source_metadata = _load_nearby_eval_source_metadata(rulespec_file)

        country = self._detect_policyengine_country(
            rulespec_file, rulespec_source_content
        )

        # Extract RuleSpec test cases.
        tests = self._extract_rulespec_tests(rulespec_content)

        if not tests:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="policyengine",
                passed=True,
                score=None,
                issues=["No test cases with expected values found"],
                duration_ms=duration,
            )

        # Find a PE-capable Python interpreter
        pe_python = self._find_pe_python(country)
        if not pe_python:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="policyengine",
                passed=False,
                score=None,
                issues=[
                    "No PolicyEngine-capable Python found (tried local, known venvs, auto-install)"
                ],
                duration_ms=duration,
                error=f"policyengine-{country} not available",
                details={
                    "coverage": PolicyEngineOracleCoverage(setup_errors=1).as_dict()
                },
            )

        # Run comparison for each legal-ID keyed test output.
        matches = 0
        total = 0
        coverage = PolicyEngineOracleCoverage()
        for test in tests:
            test_rule_name = str(test.get("variable", ""))
            raw_test_rule_name = str(test.get("raw_variable") or test_rule_name)
            oracle_rule_name = self.policyengine_rule_hint or raw_test_rule_name
            if not self._should_compare_pe_test_output(
                country, raw_test_rule_name, oracle_rule_name
            ):
                coverage.skipped += 1
                continue
            expected = test.get("expect")
            raw_inputs = test.get("inputs", {})
            inputs = dict(raw_inputs) if isinstance(raw_inputs, dict) else raw_inputs
            policyengine_inputs = {}
            oracle_inputs = test.get("oracle_inputs", {})
            if isinstance(inputs, dict) and isinstance(oracle_inputs, dict):
                raw_policyengine_inputs = oracle_inputs.get("policyengine", {})
                if isinstance(raw_policyengine_inputs, dict):
                    policyengine_inputs = dict(raw_policyengine_inputs)
                    inputs.update(policyengine_inputs)
            period = (
                test.get("period")
                or test.get("date")
                or (inputs.get("period") if isinstance(inputs, dict) else None)
                or (inputs.get("date") if isinstance(inputs, dict) else None)
                or "2024-01"
            )
            period_str = _policyengine_period_string(period)
            year = period_str.split("-")[0] if "-" in period_str else period_str
            if isinstance(inputs, dict):
                inputs.pop("period", None)
                inputs.pop("date", None)

            if expected is None:
                continue
            coverage.total_outputs += 1

            mapping = self._resolve_pe_mapping(country, raw_test_rule_name)
            pe_var = mapping.policyengine_variable if mapping else None
            pe_parameter = mapping.policyengine_parameter if mapping else None
            pe_target = pe_var or pe_parameter
            if mapping is not None and not mapping.comparable:
                coverage.unsupported += 1
                continue

            mappability_inputs = policyengine_inputs or inputs
            if (
                country == "us"
                and not policyengine_inputs
                and isinstance(mappability_inputs, dict)
            ):
                mappability_inputs = self._pe_us_projectable_inputs_for_mappability(
                    mappability_inputs,
                    pe_var,
                    mapping=mapping,
                )
            mappable, reason = self._is_pe_test_mappable(
                country,
                raw_test_rule_name,
                mappability_inputs,
                expected,
                pe_var=pe_var,
                mapping=mapping,
            )
            if not mappable:
                issues.append(
                    f"PolicyEngine unavailable for '{test.get('name', test_rule_name)}': {reason}"
                )
                coverage.unsupported += 1
                continue

            if not pe_target:
                coverage.unmapped += 1
                continue

            # Build and run PE scenario — include period in inputs for monthly detection
            inputs_with_period = {**inputs, "period": str(period)}
            inputs_with_period = {
                **_policyengine_us_snap_input_aliases(inputs_with_period),
                **inputs_with_period,
            }
            source_jurisdiction = None
            if country == "us":
                source_jurisdiction = _source_metadata_jurisdiction(
                    source_metadata
                ) or _infer_us_state_code_from_rulespec_path(
                    rulespec_file,
                    rulespec_source_content,
                )
                if source_jurisdiction and "state_code_str" not in inputs_with_period:
                    inputs_with_period["state_code_str"] = source_jurisdiction
                if (
                    source_jurisdiction
                    and inputs_with_period.get("snap_utility_allowance_type")
                    and "snap_utility_region_str" not in inputs_with_period
                ):
                    inputs_with_period["snap_utility_region_str"] = (
                        _default_snap_utility_region_for_jurisdiction(
                            source_jurisdiction
                        )
                    )
                if pe_var in {
                    "snap_standard_utility_allowance",
                    "snap_limited_utility_allowance",
                    "snap_individual_utility_allowance",
                }:
                    default_utility_type = _default_snap_utility_type_for_rule(pe_var)
                    if (
                        inputs_with_period.get("snap_utility_allowance_type")
                        in (None, "NONE")
                        and default_utility_type is not None
                    ):
                        inputs_with_period["snap_utility_allowance_type"] = (
                            default_utility_type
                        )
                    if source_jurisdiction:
                        inputs_with_period.setdefault(
                            "snap_utility_region_str",
                            _default_snap_utility_region_for_jurisdiction(
                                source_jurisdiction
                            ),
                        )
            if pe_parameter:
                try:
                    scenario_script = self._build_pe_parameter_script(
                        mapping,
                        inputs_with_period,
                        year,
                    )
                except ValueError as exc:
                    issues.append(
                        f"PolicyEngine unavailable for '{test.get('name', test_rule_name)}': {exc}"
                    )
                    coverage.unsupported += 1
                    continue
            else:
                scenario_script = self._build_pe_scenario_script(
                    pe_var,
                    inputs_with_period,
                    year,
                    expected,
                    country=country,
                    rule_name=pe_var,
                )
            output = self._run_pe_subprocess_detailed(scenario_script, pe_python)

            if output.returncode != 0:
                summary = self._summarize_oracle_error(output.stderr or output.stdout)
                if self._is_pe_unsupported_error(output.stderr or output.stdout):
                    issues.append(
                        f"PolicyEngine unavailable for '{test.get('name', test_rule_name)}': {summary}"
                    )
                    coverage.unsupported += 1
                    continue
                issues.append(
                    "PE calculation failed for "
                    f"'{test.get('name', test_rule_name)}' "
                    f"({raw_test_rule_name} -> {pe_target}): {summary}"
                )
                coverage.adapter_errors += 1
                total += 1
                continue

            # Parse result
            try:
                lines = output.stdout.strip().split("\n")
                result_line = [line for line in lines if line.startswith("RESULT:")]
                if result_line:
                    parts = result_line[0].split(":")
                    pe_value = float(parts[1])
                    if mapping and mapping.result_multiplier is not None:
                        pe_value *= mapping.result_multiplier
                    expected_float = _policyengine_expected_float(expected)
                    match = self._values_match(pe_value, expected_float, tolerance=0.02)
                    if match:
                        matches += 1
                        coverage.passed += 1
                    else:
                        issues.append(
                            f"'{test.get('name', test_rule_name)}' "
                            f"({raw_test_rule_name} -> {pe_target}): "
                            f"PE={pe_value:.2f}, RuleSpec expects={expected_float:.2f}"
                        )
                        coverage.failed += 1
                    coverage.comparable += 1
                    total += 1
                else:
                    issues.append(
                        "No RESULT in PE output for "
                        f"'{test.get('name', test_rule_name)}' "
                        f"({raw_test_rule_name} -> {pe_target})"
                    )
                    coverage.adapter_errors += 1
                    total += 1
            except Exception as parse_err:
                issues.append(
                    f"Parse error for '{test.get('name', test_rule_name)}' "
                    f"({raw_test_rule_name} -> {pe_target}): {parse_err}"
                )
                coverage.adapter_errors += 1
                total += 1

        if total == 0:
            duration = int((time.time() - start) * 1000)
            if coverage.unmapped:
                issues.append(
                    "PolicyEngine could not evaluate unclassified legal outputs"
                )
            if not issues and not coverage.unsupported:
                issues.append("No PolicyEngine-comparable tests found")
            return ValidationResult(
                validator_name="policyengine",
                passed=True,
                score=None,
                issues=issues,
                duration_ms=duration,
                details={"coverage": coverage.as_dict()},
            )

        score = matches / total if total > 0 else None
        passed = score is not None and score >= 0.8

        duration = int((time.time() - start) * 1000)
        return ValidationResult(
            validator_name="policyengine",
            passed=passed,
            score=score,
            issues=issues,
            duration_ms=duration,
            details={"coverage": coverage.as_dict()},
        )

    def _read_test_content(self, rulespec_file: Path) -> str:
        """Read test content from the companion RuleSpec `.test.yaml` file."""
        test_file = self._rulespec_test_path(rulespec_file)
        if test_file.exists():
            return test_file.read_text()
        return ""

    def _run_taxsim(self, rulespec_file: Path) -> ValidationResult:
        """Validate against TAXSIM oracle.

        Converts test cases to TAXSIM format, runs through TAXSIM API,
        and compares relevant outputs. Returns match rate as score (0-1).
        """
        start = time.time()
        issues = []

        # Read companion RuleSpec test content.
        try:
            rulespec_content = self._read_test_content(rulespec_file)
        except Exception as e:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="taxsim",
                passed=False,
                score=0.0,
                issues=[f"Failed to read RuleSpec/test file: {e}"],
                duration_ms=duration,
                error=str(e),
            )

        # Extract RuleSpec test cases.
        tests = self._extract_rulespec_tests(rulespec_content)

        if not tests:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="taxsim",
                passed=True,
                score=None,
                issues=["No test cases found — cannot validate"],
                duration_ms=duration,
            )

        # Try to run through TAXSIM
        try:
            import requests

            # TAXSIM API endpoint
            taxsim_url = "https://taxsim.nber.org/taxsim35/taxsim.cgi"

            matches = 0
            total = 0
            unmappable = 0

            for test in tests:
                try:
                    # Convert test to TAXSIM input format
                    taxsim_input = self._build_taxsim_input(test.get("inputs", {}))

                    if not taxsim_input:
                        issues.append(
                            f"TAXSIM could not map inputs for '{test.get('name', 'unknown')}'"
                        )
                        unmappable += 1
                        continue

                    # Submit to TAXSIM
                    response = requests.post(
                        taxsim_url,
                        data=taxsim_input,
                        timeout=30,
                    )

                    if response.status_code == 200:
                        # Parse TAXSIM output and compare
                        taxsim_result = self._parse_taxsim_output(response.text)
                        expected = test.get("expect")

                        if expected is not None and self._values_match(
                            taxsim_result, expected
                        ):
                            matches += 1

                    total += 1

                except requests.RequestException as req_error:
                    issues.append(f"TAXSIM request failed: {req_error}")
                    total += 1
                except Exception as test_error:
                    issues.append(
                        f"Test '{test.get('name', 'unknown')}' failed: {test_error}"
                    )
                    total += 1

            if total == 0:
                duration = int((time.time() - start) * 1000)
                if unmappable:
                    issues.append(
                        "TAXSIM could not evaluate any oracle-comparable tests"
                    )
                return ValidationResult(
                    validator_name="taxsim",
                    passed=True,
                    score=None,
                    issues=issues or ["No TAXSIM-comparable tests found"],
                    duration_ms=duration,
                )

            score = matches / total
            passed = score >= 0.8

            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="taxsim",
                passed=passed,
                score=score,
                issues=issues,
                duration_ms=duration,
            )

        except ImportError:
            # requests not installed
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="taxsim",
                passed=False,
                score=None,
                issues=["requests package not installed for TAXSIM API"],
                duration_ms=duration,
                error="requests not available",
            )
        except Exception as e:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="taxsim",
                passed=False,
                score=None,
                issues=[f"TAXSIM validation error: {e}"],
                duration_ms=duration,
                error=str(e),
            )

    def _run_microdata_benchmark(
        self,
        output_path: Path,
        pe_variable: str = "eitc",
        year: int = 2024,
        sample_size: int | None = None,
    ) -> ValidationResult:
        """Benchmark RuleSpec encoding against PolicyEngine using CPS microdata.

        Runs PE Microsimulation on ECPS, extracts the target
        variable for all tax units, and reports the benchmark. This establishes
        the PE baseline that RuleSpec must match as inputs get wired up.

        Args:
            output_path: Directory containing RuleSpec files for the section.
            pe_variable: PE variable to benchmark against (e.g., "eitc").
            year: Tax year for the simulation.
            sample_size: If set, only use this many tax units (for speed).

        Returns:
            ValidationResult with benchmark statistics.
        """
        start = time.time()
        issues = []

        # Find PE-capable Python
        pe_python = self._find_pe_python()
        if not pe_python:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="microdata_benchmark",
                passed=False,
                score=0.0,
                issues=["No PolicyEngine-capable Python found"],
                duration_ms=duration,
                error="policyengine-us not available",
            )

        # Run PE microsimulation and collect statistics
        script = f"""
import json
import numpy as np
from policyengine_us import Microsimulation

m = Microsimulation()
values = m.calculate('{pe_variable}', {year})
weights = m.calculate('tax_unit_weight', {year})

# Core stats
total = len(values)
nonzero = int(np.sum(np.array(values) > 0))
weights_arr = np.array(weights)
values_arr = np.array(values)
weighted_nonzero = float(np.sum(weights_arr * (values_arr > 0)))
weighted_total = float(np.sum(weights_arr))
weighted_sum = float(np.sum(weights_arr * values_arr))
mean_val = float(values.mean())
median_val = float(np.median(values))
max_val = float(values.max())
p25 = float(np.percentile(values[values > 0], 25)) if nonzero > 0 else 0
p75 = float(np.percentile(values[values > 0], 75)) if nonzero > 0 else 0

result = {{
    "variable": "{pe_variable}",
    "year": {year},
    "total_tax_units": total,
    "nonzero_count": nonzero,
    "weighted_nonzero": weighted_nonzero,
    "weighted_total": weighted_total,
    "weighted_sum_billions": weighted_sum / 1e9,
    "mean": mean_val,
    "median": median_val,
    "max": max_val,
    "p25_nonzero": p25,
    "p75_nonzero": p75,
}}
print("BENCHMARK:" + json.dumps(result))
"""

        output = self._run_pe_subprocess(script, pe_python)

        if output is None:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="microdata_benchmark",
                passed=False,
                score=0.0,
                issues=["PE microsimulation failed to run"],
                duration_ms=duration,
                error="Microsimulation execution failed",
            )

        # Parse benchmark results
        try:
            benchmark_line = [
                line
                for line in output.strip().split("\n")
                if line.startswith("BENCHMARK:")
            ]
            if not benchmark_line:
                duration = int((time.time() - start) * 1000)
                return ValidationResult(
                    validator_name="microdata_benchmark",
                    passed=False,
                    score=0.0,
                    issues=[f"No BENCHMARK output from PE. Output: {output[:200]}"],
                    duration_ms=duration,
                )

            stats = json.loads(benchmark_line[0].split("BENCHMARK:")[1])

            # RuleSpec match rate starts at 0% until runtime replay is wired here.
            rulespec_match_rate = 0.0

            issues = [
                f"PE benchmark for {pe_variable} ({year}):",
                f"  Tax units: {stats['total_tax_units']:,} "
                f"({stats['nonzero_count']:,} with {pe_variable} > 0)",
                f"  Weighted recipients: {stats['weighted_nonzero']:,.0f}",
                f"  Weighted total: ${stats['weighted_sum_billions']:.1f}B",
                f"  Mean: ${stats['mean']:,.0f}, Median: ${stats['median']:,.0f}, "
                f"Max: ${stats['max']:,.0f}",
                f"  P25-P75 (nonzero): ${stats['p25_nonzero']:,.0f}-${stats['p75_nonzero']:,.0f}",
                f"  RuleSpec match rate: {rulespec_match_rate:.1%} "
                f"(runtime replay not wired here — benchmark only)",
            ]

            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="microdata_benchmark",
                passed=False,  # 0% match until runtime replay is wired here.
                score=rulespec_match_rate,
                issues=issues,
                duration_ms=duration,
                raw_output=json.dumps(stats, indent=2),
            )

        except Exception as e:
            duration = int((time.time() - start) * 1000)
            return ValidationResult(
                validator_name="microdata_benchmark",
                passed=False,
                score=0.0,
                issues=[f"Failed to parse benchmark output: {e}"],
                duration_ms=duration,
                error=str(e),
            )

    def _build_pe_situation(self, inputs: dict) -> dict:
        """Build PolicyEngine situation dictionary from test inputs."""
        # Default situation structure
        situation = {
            "people": {"person": {}},
            "tax_units": {"tax_unit": {"members": ["person"]}},
            "households": {"household": {"members": ["person"]}},
        }

        # Map inputs to PE variables
        for key, value in inputs.items():
            # Simple mapping - real impl would be more sophisticated
            if "person." in key:
                var_name = key.replace("person.", "")
                situation["people"]["person"][var_name] = value
            elif "tax_unit." in key:
                var_name = key.replace("tax_unit.", "")
                situation["tax_units"]["tax_unit"][var_name] = value
            else:
                # Default to person-level
                situation["people"]["person"][key] = value

        return situation

    def _build_taxsim_input(self, inputs: dict) -> Optional[str]:
        """Build TAXSIM input string from test inputs.

        Returns None if inputs cannot be mapped to TAXSIM format.
        """
        # TAXSIM input mapping
        # See: https://taxsim.nber.org/taxsim35/

        # Build input line
        values = ["0"] * 27  # TAXSIM expects 27 fields

        # Set defaults
        values[0] = "1"  # taxsimid
        values[1] = "2024"  # year
        values[2] = "0"  # state
        values[3] = "1"  # marital status (single)

        # Map inputs
        mapped = False
        for key, value in inputs.items():
            key_lower = key.lower()
            if "wage" in key_lower:
                values[7] = str(value)
                mapped = True
            elif "self_employment" in key_lower or "semp" in key_lower:
                values[9] = str(value)
                mapped = True
            elif "year" in key_lower:
                values[1] = str(value)
                mapped = True

        if not mapped:
            return None

        return ",".join(values)

    def _parse_taxsim_output(self, output: str) -> Optional[float]:
        """Parse TAXSIM output and extract federal tax liability."""
        try:
            # TAXSIM returns comma-separated values
            # Field 7 is typically federal tax liability
            lines = output.strip().split("\n")
            if len(lines) >= 2:
                # Skip header line
                data_line = lines[-1]
                values = data_line.split(",")
                if len(values) > 7:
                    return float(values[7])
        except Exception:
            pass
        return None

    def _values_match(
        self, actual: Any, expected: Any, tolerance: float = 0.01
    ) -> bool:
        """Check if two values match within tolerance."""
        try:
            actual_float = float(actual) if actual is not None else 0.0
            expected_float = float(expected) if expected is not None else 0.0

            if expected_float == 0:
                return actual_float == 0

            relative_diff = abs(actual_float - expected_float) / abs(expected_float)
            return relative_diff <= tolerance
        except (ValueError, TypeError):
            # Fall back to string comparison
            return str(actual) == str(expected)

    def _extract_rulespec_tests(self, test_content: str) -> list[dict]:
        """Extract oracle-comparable cases from a RuleSpec `.test.yaml` file."""
        tests = []

        def normalize_variable_name(value: Any) -> str:
            text = str(value)
            if "#" in text:
                return text.rsplit("#", 1)[1]
            return text

        def normalize_test_value(value: Any) -> Any:
            if isinstance(value, dict):
                lowered_keys = {str(key).lower() for key in value.keys()}
                if "value" in lowered_keys and lowered_keys.issubset(
                    {"entity", "value"}
                ):
                    for key, inner in value.items():
                        if str(key).lower() == "value":
                            return normalize_test_value(inner)
                singleton_entity_value_keys = {
                    "person",
                    "people",
                    "family",
                    "families",
                    "household",
                    "households",
                    "tax_unit",
                    "taxunit",
                    "tax_units",
                    "benunit",
                    "benunits",
                }
                if "value" in lowered_keys:
                    other_keys = lowered_keys - {"value"}
                    if (
                        len(other_keys) == 1
                        and next(iter(other_keys)) in singleton_entity_value_keys
                    ):
                        for key, inner in value.items():
                            if str(key).lower() == "value":
                                return normalize_test_value(inner)
                normalized = {
                    key: normalize_test_value(inner) for key, inner in value.items()
                }
                if len(normalized) == 1:
                    only_value = next(iter(normalized.values()))
                    if not isinstance(only_value, (dict, list)):
                        return only_value
                return normalized
            if isinstance(value, list):
                normalized_items = [normalize_test_value(item) for item in value]
                if len(normalized_items) == 1 and not isinstance(
                    normalized_items[0], (dict, list)
                ):
                    return normalized_items[0]
                return normalized_items
            if isinstance(value, str):
                compact = value.replace(",", "").strip()
                if re.fullmatch(r"-?\d+", compact):
                    return int(compact)
                if re.fullmatch(r"-?\d+\.\d+", compact):
                    return float(compact)
            return value

        def normalize_input_value(key: Any, value: Any) -> Any:
            key_text = str(key)
            if "#relation." in key_text or ".relation." in key_text:
                return value
            return normalize_test_value(value)

        def normalized_input_alias(key: Any) -> str:
            key_text = str(key)
            if "#" not in key_text:
                return ""
            fragment = key_text.split("#", 1)[1].strip()
            if ".input." in fragment:
                return fragment.rsplit(".input.", 1)[1].strip()
            if fragment.startswith("input."):
                return fragment.removeprefix("input.").strip()
            return ""

        def unwrap_entity_wrapper(value: Any) -> Any:
            if not isinstance(value, dict) or len(value) != 1:
                return value
            wrapper, inner = next(iter(value.items()))
            if not isinstance(inner, dict):
                return value
            wrapper_key = str(wrapper).lower().replace(" ", "_")
            entity_wrappers = {
                "person",
                "people",
                "family",
                "families",
                "household",
                "households",
                "tax_unit",
                "taxunit",
                "tax_units",
                "benunit",
                "benunits",
            }
            if wrapper_key not in entity_wrappers:
                return value
            if len(inner) == 1:
                _, nested = next(iter(inner.items()))
                if isinstance(nested, dict):
                    return nested
            return inner

        try:
            content_lines = []
            for line in test_content.split("\n"):
                stripped = line.strip()
                if stripped.startswith("#"):
                    continue
                content_lines.append(line)

            clean_content = "\n".join(content_lines)
            parsed = yaml.safe_load(clean_content)

            def append_top_level_io_tests(test_cases: Any) -> None:
                if not isinstance(test_cases, list):
                    return
                for test_case in test_cases:
                    if not isinstance(test_case, dict):
                        continue
                    outputs = test_case.get("output", test_case.get("expect"))
                    if not isinstance(outputs, dict):
                        continue
                    inputs = test_case.get("input", test_case.get("inputs", {}))
                    inputs = unwrap_entity_wrapper(inputs)
                    outputs = unwrap_entity_wrapper(outputs)
                    normalized_inputs = (
                        {
                            key: normalize_input_value(key, value)
                            for key, value in inputs.items()
                        }
                        if isinstance(inputs, dict)
                        else inputs or {}
                    )
                    if isinstance(normalized_inputs, dict):
                        for key, value in list(normalized_inputs.items()):
                            alias = normalized_input_alias(key)
                            if alias:
                                normalized_inputs.setdefault(alias, value)
                    oracle_inputs = test_case.get("oracle_inputs", {})
                    normalized_oracle_inputs: dict[str, dict[str, Any]] = {}
                    if isinstance(oracle_inputs, dict):
                        for oracle_name, oracle_raw_inputs in oracle_inputs.items():
                            if not isinstance(oracle_raw_inputs, dict):
                                continue
                            normalized_oracle_inputs[str(oracle_name)] = {
                                str(key): normalize_input_value(key, value)
                                for key, value in oracle_raw_inputs.items()
                            }
                    for variable, expected in outputs.items():
                        tests.append(
                            {
                                "variable": normalize_variable_name(variable),
                                "raw_variable": str(variable),
                                "name": test_case.get("name"),
                                "period": test_case.get("period"),
                                "inputs": normalized_inputs,
                                "expect": normalize_test_value(expected),
                                **(
                                    {"oracle_inputs": normalized_oracle_inputs}
                                    if normalized_oracle_inputs
                                    else {}
                                ),
                            }
                        )

            if isinstance(parsed, dict) and isinstance(parsed.get("cases"), list):
                append_top_level_io_tests(parsed["cases"])
            elif isinstance(parsed, dict) and isinstance(parsed.get("tests"), list):
                append_top_level_io_tests(parsed["tests"])
            elif isinstance(parsed, list):
                append_top_level_io_tests(parsed)
        except Exception:
            pass

        return tests

